            | otherwise = aux2 (State m ((Pacman (PacState (a,(x,y),c,d,e,f) g h i)):xs) ni) ys (x1,y2)
controleEspacoSeguranca:: State -> (Int,Int) -> Play
controleEspacoSeguranca (State m ((Pacman (PacState (a,(x,y),c,d,e,f) g h i)):xs) ni) (x1,y1)
    | abs (x-x1) + (abs y-y1) <= 4 = (Move a (mudaOrientation d))
