-- | Função que define um espaço para o qual o pacman se sente ameaçado pelo ghost
--
espacoDeSeguranca :: State -> (Int,Int) -> Bool 
espacoDeSeguranca (State m ((Pacman (PacState (a,(x,y),c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs) ni) (x1,y1) = if abs (x-x1) + abs (y-y1) >= 4  then True else False  

-- | Função que faz o caminho mais curto para o ghost 
-- 
caminhoMaisCurtoGhost :: (Int,Int)-> State -> Play 
caminhoMaisCurtoGhost (a,b) (State m ((Pacman (PacState (a1,(x,y),c,d,e,f) g h i)):xs) ni)  | abs (x-a) == abs (y-b) && (x-a) < 0 && (y-b) <0 = (Move a1 U)
                                                                                            | abs (x-a) == abs (y-b) && (x-a) > 0 && (y-b) >0 = (Move a1 D)
                                                                                            | abs (x-a) == abs (y-b) && (x-a) > 0 && (y-b) <0 = (Move a1 U)
                                                                                            | abs (x-a) == abs (y-b) && (x-a) < 0 && (y-b) >0 = (Move a1 D) 
                                                                                            | abs (x-a) >= abs (y-b) && (x-a) > 0 && (y-b) <0 = (Move a1 L)
                                                                                            | abs (x-a) >= abs (y-b) && (x-a) > 0 && (y-b) >0 = (Move a1 L)
                                                                                            | abs (x-a) >= abs (y-b) && (x-a) < 0 && (y-b) <0 = (Move a1 R)
                                                                                            | abs (x-a) >= abs (y-b) && (x-a) < 0 && (y-b) >0 = (Move a1 R)
                                                                                            | abs (x-a) <= abs (y-b) && (x-a) < 0 && (y-b) >0 = (Move a1 D)
                                                                                            | abs (x-a) <= abs (y-b) && (x-a) < 0 && (y-b) <0 = (Move a1 U)
                                                                                            | abs (x-a) <= abs (y-b) && (x-a) > 0 && (y-b) <0 = (Move a1 U)
                                                                                            | abs (x-a) <= abs (y-b) && (x-a) > 0 && (y-b) >0 = (Move a1 D)
                                                                                            | otherwise = caminhoMaisCurtoGhost (a,b) (State m xs ni)
-- | Função que da o ghost mais perto 
-- 
ghostMaisProxima :: [(Int,Int)]-> State -> (Int,Int)
ghostMaisProxima ((x,y):xs) (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i)):ys) ni) = aux1 ((x,y):xs) (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i)):ys) ni) (0,0)
                                                                                      where aux1 [] (State m l ni) (x2,y2) = (x2,y2)
                                                                                            aux1 ((x,y):xs) (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i)):ys) ni) (x2,y2)
                                                                                             | abs (x1-x) + abs (y1-y) > abs (x1-x2) + abs (y1-y2) = aux1 xs (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i)):ys) ni) (x2,y2)
                                                                                             | abs (x1-x) + abs (y1-y) <= abs (x1-x2) + abs (y1-y2) = aux1 xs (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i)):ys) ni) (x,y)
                                                                                             | otherwise = aux1 xs (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i)):ys) ni) (x2,y2)

-- | Função que faz o bot comer o Ghost 
-- 
comeGhost :: State -> Play 
comeGhost (State m ((Pacman (PacState (a1,(x,y),c,d,e,f) g h i)):xs) ni) = caminhoMaisCurtoGhost ( ghostMaisProxima (coordenadasG (State m ((Pacman (PacState (a1,(x,y),c,d,e,f) g h i)):xs) ni) ) (State m ((Pacman (PacState (a1,(x,y),c,d,e,f) g h i)):xs) ni)) (State m ((Pacman (PacState (a1,(x,y),c,d,e,f) g h i)):xs) ni)

-- | Função final 
-- 
bot :: Int -> State -> Maybe Play
bot id (State m [] ni) = Nothing
bot id (State m ((Pacman (PacState (a1,b,c,d,e,f) g h i)):(Ghost (GhoState (a2,b1,c1,d1,e1,f1) g1 )): xs) ni) 
 | id ==a1 && (espacoDeSeguranca (State m ((Pacman (PacState (a1,b,c,d,e,f) g h i)):(Ghost (GhoState (a2,b1,c1,d1,e1,f1) g1 )): xs) ni) (ghostMaisProxima(coordenadasG (State m ((Pacman (PacState (a1,b,c,d,e,f) g h i)):(Ghost (GhoState (a2,b1,c1,d1,e1,f1) g1 )): xs) ni)) (State m ((Pacman (PacState (a1,b,c,d,e,f) g h i)):(Ghost (GhoState (a2,b1,c1,d1,e1,f1) g1 )): xs) ni)))==True =Just (comeComida(State m ((Pacman (PacState (a1,b,c,d,e,f) g h i)):(Ghost (GhoState (a2,b1,c1,d1,e1,f1) g1 )): xs) ni))
 | id ==a1 && i == Mega = Just (comeGhost (State m ((Pacman (PacState (a1,b,c,d,e,f) g h i)):(Ghost (GhoState (a2,b1,c1,d1,e1,f1) g1 )): xs) ni))
 

{- |
=Introdução  
Os desafios que foram propostos nesta Tarefa são fazer plays para o ghost.Tendo em conta os respetivos "modos" do pacman. Os resultados que obtive nesta Tarefa são minimamente aceitaveis 
pois consegui obter as melhores plays para o ghost, tendo em conta todos os factores 

=Desenvolvimento 
A estrategia por mim pensada, foi de ver qual era a melhor play , tendo para isso utilizado a seguinte estrategia : 
   -Ver as coordenadas do ghost 
   - Ver as coordenadas do pacman 
   - Ver os caminhos mais curtos entre o pacman e o ghost 
   - Com base nisto , calcular a melhor play entre o ghost e o pacman 
   
=Conclusao   
Os resultados obtidos aqui, foram minimamente aceitaveis pois conseguimos obter as melhores plays para o ghost ir ter com o pacman 
-}

-- | Exemeplo de um state 
-- 
teste :: State 
teste = (State (geraLabirintoFinal 14 16 1567) [(Pacman (PacState (1,(3,3),1,L,5,2) 0 Open Normal )),(Ghost (GhoState (25,(1,2),1,D,0,1) Alive)),(Ghost (GhoState (3,(3,4),1,U,0,3) Dead))] 4)
-- |Função que nos dá para cada coordenada o tipo de peça que tem no Maze
-- 
verPecaDoMaze :: Maze -> Coords -> Piece 
verPecaDoMaze l (x,y) = ((l!!y)!!x)

-- |Função que retira o pacman em players  
-- 
ficaSemPacmans [] = []
ficaSemPacmans ((Pacman (PacState (a,b,c,d,e,f) g h i)):xs) = xs 
ficaSemPacmans (x:xs) = x:ficaSemPacmans xs 
-- |Função que de me dá apenas pacman 
-- 
dapacman :: [Player] -> Player
dapacman ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs) = (Pacman (PacState (a,b,c,d,e,f) g h i))
dapacman (y:ys) = dapacman ys 
-- |Colocar os pacmans todos em primeiro lugar na lista 
-- 
trocaOrdem :: [Player] -> [Player]
trocaOrdem (x:xs)= (dapacman (x:xs): ficaSemPacmans (x:xs))


-- | Função que determina a posição do pacman , quando o fantasma esta em modo alive 
-- 
daCoordsPacman:: State -> (Int,Int)
daCoordsPacman (State m [] ni) = error "Impossivel de calcular"
daCoordsPacman (State m ((Pacman (PacState (a,(x,y),c,d,e,f) g h i)):(Ghost (GhoState (a1,(x1,y1),c1,d1,e1,f1) g1 )):xs) ni) =  (x,y)

-- | Função que calcula o caminho mais curto a partir do ghost para o pacman 
-- 
caminhoMaisCurto :: (Int,Int)-> State -> Orientation
caminhoMaisCurto (x1,y1) (State m ((Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) Alive )):xs) ni) |   abs (x-x1) == abs (y-y1) && (y-y1) < 0 = R
                                                                                            |   abs (x-x1) == abs (y-y1) && (y-y1) > 0 = L
                                                                                            |   abs (x-x1) > abs (y-y1) && (y-y1) < 0  = R 
                                                                                            |   abs (x-x1) > abs (y-y1) && (y-y1) > 0  = L 
                                                                                            |   abs (x-x1) < abs (y-y1) && (x-x1) < 0  = D
                                                                                            |   abs (x-y1) < abs (y-y1) && (x-x1) > 0  = U
                                                                                            |   x1 == x &&  (y-y1) < 0 = R
                                                                                            |   x1 == x &&  (y+y1) > 0 = L
                                                                                            |   y1 == y &&  (x-x1) < 0 = D
                                                                                            |   y1 == y &&  (x-x1) > 0 = U
                                                                                            |   otherwise = error " Impossivel de calcular caminho mais curto"
                                                                                      

                                                                              
-- | Função que faz os fantasmas irem atras do pacman 
-- 

chaseMode :: State -> Int -> Play
chaseMode (State m [(Pacman (PacState (a,(x1,y1),c,d,e,f) g h i))] ni) id = error "Impossivel de realizar jogadas"
chaseMode (State m ((Pacman (PacState (a,b,c,d,e,f) g h Normal )):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) Alive )):xs) ni) x1  
 | x1== a1 && verPecaDoMaze m (x-1,y) == Wall && d1==U = (Move a1 (caminhoMaisCurto (daCoordsPacman (State m ((Pacman (PacState (a,b,c,d,e,f) g h Normal )):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) Alive )):xs) ni)) (State m ((Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) Alive )):xs) ni)))
 | x1==a1  && d1== U = (Move a1 U)
 | x1== a1 && verPecaDoMaze m (x+1,y) == Wall && d1==D = (Move a1 (caminhoMaisCurto (daCoordsPacman (State m ((Pacman (PacState (a,b,c,d,e,f) g h Normal )):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) Alive )):xs) ni)) (State m ((Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) Alive )):xs) ni)))
 | x1==a1  && d1== D = (Move a1 D)
 | x1== a1 && verPecaDoMaze m (x,y+1) == Wall && d1==R = (Move a1 (caminhoMaisCurto (daCoordsPacman (State m ((Pacman (PacState (a,b,c,d,e,f) g h Normal )):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) Alive )):xs) ni)) (State m ((Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) Alive )):xs) ni)))
 | x1==a1  && d1==R = (Move a1 R)
 | x1== a1 && verPecaDoMaze m (x,y-1) == Wall &&  d1==L = (Move a1 (caminhoMaisCurto (daCoordsPacman (State m ((Pacman (PacState (a,b,c,d,e,f) g h Normal )):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) Alive )):xs) ni)) (State m ((Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) Alive )):xs) ni)))
 | x1==a1  && d1 == L = (Move a1 L)
 | otherwise = chaseMode (State m ((Pacman (PacState (a,b,c,d,e,f) g h Normal )):xs) ni) x1 
-- | Função que faz o fantasma fugir pela sua direita,quando encontra uma parede, em modo Dead 
-- 
scatterMode :: State -> Int -> Play  
scatterMode (State m [(Pacman (PacState (a,(x1,y1),c,d,e,f) g h i))] ni) id = error "Impossivel de realizar jogadas"
scatterMode (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h Mega)):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) Dead )):xs) ni) id     | verPecaDoMaze m (x,y+1) == Wall && d1==R && id==a1 =(Move a1 D) 
                                                                                                                                      | d1==R && id==a1 = (Move a1 R)
                                                                                                                                      | verPecaDoMaze m (x,y-1) == Wall && d1==L && id==a1=(Move a1 U)
                                                                                                                                      | d1 == L && id==a1 = (Move a1 L)
                                                                                                                                      | verPecaDoMaze m (x-1,y) == Wall && d1==U && id==a1  =(Move a1 R)
                                                                                                                                      | d1 == U && id==a1 = (Move a1 U )
                                                                                                                                      | verPecaDoMaze m (x+1,y) == Wall && d1==D && id==a1 =(Move a1 L)
                                                                                                                                      | d1 ==D && id==a1 = (Move a1 D)
                                                                                                                                      |otherwise = scatterMode (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h Mega)):xs) ni) id

-- | Função Final 
-- 

ghostPlay :: State -> [Play]
ghostPlay (State m [(Pacman (PacState (a,(x1,y1),c,d,e,f) g h i))] ni) = []
ghostPlay (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) g1 )):xs) ni) = (chaseMode (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) g1 )):xs) ni) a1): (chaseMode (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) g1 )):xs) ni) a1): []

-- | Função que dá um state atualizado com base nas plays que recebe
--
play' :: [Play]-> State -> State 
play' ((Move x3 o):ys) (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) g1 )):xs) ni) | x3==a1  && d1==L && o==L =  play'(tail(ghostPlay (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) g1 )):xs) ni) ))(State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x,y-1),c1,L,e1,f1) g1 )):xs) ni)
                                                                                                                                      | x3==a1  && d1==L && o/=L =  play'(tail(ghostPlay (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) g1 )):xs) ni) ))(State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x,y),c1,L,e1,f1) g1 )):xs) ni)
                                                                                                                                      | x3==a1  && d1==R && o==R =  play'(tail(ghostPlay (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) g1 )):xs) ni) ))(State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x,y+1),c1,R,e1,f1) g1 )):xs) ni)
                                                                                                                                      | x3==a1  && d1==R && o/=R =  play'(tail(ghostPlay (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) g1 )):xs) ni) ))(State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x,y),c1,R,e1,f1) g1 )):xs) ni)
                                                                                                                                      | x3==a1  && d1==U && o==U =  play'(tail(ghostPlay (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) g1 )):xs) ni) ))(State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x+1,y),c1,U,e1,f1) g1 )):xs) ni)
                                                                                                                                      | x3==a1  && d1==U && o/=U =  play'(tail(ghostPlay (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) g1 )):xs) ni) ))(State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x,y),c1,U,e1,f1) g1 )):xs) ni)
                                                                                                                                      | x3==a1  && d1==D && o==D =  play'(tail(ghostPlay (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) g1 )):xs) ni) ))(State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x-1,y),c1,D,e1,f1) g1 )):xs) ni)
                                                                                                                                      | x3==a1  && d1==D && o/=D =  play'(tail(ghostPlay (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) g1 )):xs) ni) ))(State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i )):(Ghost (GhoState (a1,(x,y),c1,D,e1,f1) g1 )):xs) ni)
-- | Contacto entre os fantasmas e o pacman (Normal) e o resultado disso 
-- 

contactoPacManGhostN':: State -> State
contactoPacManGhostN' (State m [] ni) = (State m [] ni)
contactoPacManGhostN' (State m [Pacman(PacState (a,(x,y),c,d,e,f) g h i),Ghost(GhoState (a1,(x1,y1),c1,d1,e1,f1) i1)] ni)  |(x==x1 && y==y1) && f>1 && i==Normal = (State m [Pacman(PacState (a,(y,x),c,d,e,(f-1)) g h Normal),Ghost(GhoState (a1,(y1,x1),c1,d1,e1,f1) i1)] ni)
                                                                                                                          |(x==x1 && y==y1) && (f<=1 && f>=0) && i==Normal = (State m [Pacman(PacState (a,(y,x),c,d,e,0) g h Dying),Ghost(GhoState (a1,(y1,x1),c1,d1,e1,f1) i1)] ni)
contactoPacManGhostN' (State m ((Pacman(PacState (a,(x,y),c,d,e,f) g h i)):(Ghost(GhoState (a1,(x1,y1),c1,d1,e1,f1) i1)):xs) ni)  |(x==x1 && y==y1) && f>1 && i==Normal = (State m ((Pacman(PacState (a,(x,y),c,d,e,(f-1)) g h Normal)):(Ghost(GhoState (a1,(x1,y1),c1,d1,e1,f1) i1)):xs) ni)
                                                                                                                                 |(x==x1 && y==y1) && (f<=1 && f>=0) && i==Normal = (State m ((Pacman(PacState (a,(x,y),c,d,e,f) g h Dying)):(Ghost(GhoState (a1,(x1,y1),c1,d1,e1,f1) i1)):xs) ni)
                                                                                                                                 |otherwise= contactoPacManGhostN' (State m ((Pacman(PacState (a,(x,y),c,d,e,f) g h i)):xs) ni)
-- | Contacto entre os fantasmas e o pacman (Mega) e o resultado disso 
-- 
contactoPacManGhostM':: State -> State
contactoPacManGhostM' (State m [] ni) = (State m [] ni)
contactoPacManGhostM' (State m [Pacman(PacState (a,(x,y),c,d,e,f) g h Mega),Ghost(GhoState (a1,(x1,y1),c1,d1,e1,f1) Dead )] ni) |  x==x1 && y==y1 && mod (length m) 2==0 = (State m [Pacman(PacState(a,(y,x),c,d,(e+10),f) g h Mega), Ghost(GhoState(a1,(div (length m) 2,(div(length(m!!0))2)),c1,d1,e1,f1) Alive)] ni) 
                                                                                                                               |  x==x1 && y==y1 && mod (length m) 2/=0 = (State m [Pacman(PacState(a,(y,x),c,d,(e+10),f) g h Mega), Ghost(GhoState(a1,(((div (length m) 2)+1),(div(length(m!!0))2)),c1,d1,e1,f1) Alive)] ni)

contactoPacManGhostM'(State m ((Pacman(PacState (a,(x,y),c,d,e,f) g h Mega)):(Ghost(GhoState (a1,(x1,y1),c1,d1,e1,f1) Dead )):xs) ni) |  x==x1 && y==y1 && mod (length m) 2==0 = (State m ((Pacman(PacState(a,(y,x),c,d,(e+10),f) g h Mega)):(Ghost(GhoState(a1,(div (length m) 2,(div(length(m!!0))2)),c1,d1,e1,f1) Alive)):xs) ni) 
                                                                                                                                      |  x==x1 && y==y1 && mod (length m) 2/=0 = (State m ((Pacman(PacState(a,(y,x),c,d,(e+10),f) g h Mega)): (Ghost(GhoState(a1,(((div (length m) 2)+1),(div(length(m!!0))2)),c1,d1,e1,f1) Alive)):xs) ni)
                                                                                                                                      | otherwise= (State m ((Pacman(PacState (a,(x,y),c,d,e,f) g h Mega)):xs) ni) 

