-- | Função que faz com que a boca abra e fecha 
bocaAbreFecha' :: State -> State 
bocaAbreFecha' (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs) ni) = if h == Closed then (State m ((Pacman (PacState (a,b,c,d,e,f) g Open i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs) ni) 
                                                                                                                         else (State m ((Pacman (PacState (a,b,c,d,e,f) g Closed i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs) ni) 
-- | Função do tempo em Mega 
-- 
tempoMega' (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs) ni)    | i==Mega && g>0.25 && g1==Dead  = (State m ((Pacman (PacState (a,b,c,d,e,f) (g-0.25) h Mega)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) Dead )):xs) ni) 
                                                                                                                   | i==Mega && g==0.25&& g1==Dead  = (State m ((Pacman (PacState (a,b,c,d,e,f) 0 h Normal)):fantasmasParaOModoAlive ((Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs))ni)
                                                                                                                   | otherwise = (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs) ni)
-- | O Pacman deve voltar ao modo Normal se o tempo mega for <=0 e estiver em Mega
-- 
devolveEstadoNormal :: State -> State
devolveEstadoNormal (State m [] ni) = (State  m [] ni)
devolveEstadoNormal (State m [(Pacman (PacState (a,b,c,d,e,f) g h i)),(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 ))] ni) = (State m [(Pacman (PacState (a,b,c,d,e,f) 0 h Normal)),(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 ))] ni) 
devolveEstadoNormal (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs) ni) | g<=0 && i==Mega = (State m ((Pacman (PacState (a,b,c,d,e,f) 0 h Normal)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs) ni) 
                                                                                                                         | otherwise =(State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs) ni)
-- | Os Fantasmas devem voltar ao modo Alive se não houver nenhum Pacman em modo Mega
-- 
fantasmasParaOModoAlive :: [Player] -> [Player]
fantasmasParaOModoAlive [] = []
fantasmasParaOModoAlive [(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 ))]= [(Ghost (GhoState (a1,b1,1,d1,e1,f1) Alive ))]
fantasmasParaOModoAlive ((Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs) = ((Ghost (GhoState (a1,b1,1,d1,e1,f1) Alive ))) : fantasmasParaOModoAlive xs 
-- | Função que atualiza o estado do jogo tendo por base uma jogada aplicada em cada player (Basicamente é a função play e a função ghostPlay juntas)
-- 
fazerPlay :: State -> State 
fazerPlay (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):ys) ni) = aux (((State m (trocaOrdem ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):ys)) ni))) (ghostPlay (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):ys) ni))

aux :: State -> [Play]-> State 
aux (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):ys) ni) [] = (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):ys) ni)
aux (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):ys) ni) (x:xs) = (aux (play x (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):ys) ni))xs)
-- | Função que faz a jogada com o pacman 
-- 
fazJogadaOuNao :: State -> Int -> State 
fazJogadaOuNao (State m ((Pacman (PacState (a,b,c,d,e,f) g h Dying)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):ys) ni) a2 = (State m ((Pacman (PacState (a,b,c,d,e,f) g h Dying)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):ys) ni)
fazJogadaOuNao (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):ys) ni) a2 | veElemento g [(0.25),(0.75)..(9.75)]  && a2==0 = (play (Move a d) (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):ys) ni))
                                                                                                                       | veElemento g [0,(0.5)..10] && a2==0 = fazerPlay(play (Move a d) (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):ys) ni))
                                                                                                                       | veElemento g [(0.25),(0.75)..(9.75)] && a2>=1 = (play (Move a d) (fazerPlay (play (Move a d)(State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):ys) ni))))
                                                                                                                       | veElemento g [0,(0.5).. 10] && a2 >=1 = (fazJogadaOuNao (fazJogadaOuNao (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):ys) ni) (a2-1)) (a2-1))
-- | Função que vê se um dado elemento pertence a uma dada lista 
-- 
veElemento :: Double -> [Double]-> Bool 
veElemento x [] = False 
veElemento x (y:ys) = if x==y then True else veElemento x ys 
-- | Função Final 
-- 
passTime :: Int -> State -> State
passTime a2 (State m [] ni) = (State m [] ni) 
passTime a2 (State m  ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):ys) ni)= devolveEstadoNormal $ tempoMega' $ bocaAbreFecha'(fazJogadaOuNao (State m (trocaOrdem ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):ys)) ni ) a2) 



instance Show Piece where
   show (  Wall ) = "Wall"
   show (  Empty ) = "Empty"
   show ( Food Big ) =  "Food Big"
   show ( Food Little ) =  "Food Little"

type Instructions = [Instruction]

data Instruction = Instruct [(Int, Piece)]
                 | Repeat Int deriving (Show, Eq)
type Maze = [Corridor]
type Corridor = [Piece]
data Piece =  Food FoodType | Empty | Wall deriving (Eq)
data FoodType = Big | Little deriving (Eq)





m:: Maze 
m = [
                [Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall,Wall],
                [Wall,Food Little,Food Big,Empty,Food Little,Food Big,Empty,Food Little,Wall],
                [Empty,Food Big, Food Little,Empty,Food Big,Food Little,Empty,Food Big,Empty], 
                [Wall,Food Little,Food Little,Food Little,Food Big,Empty,Food Big,Food Little,Wall],
                [Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall,Wall]
    ]

-- |Converter uma peça numa instrução 
--

convertPiece:: Piece -> (Int,Piece)
convertPiece (Food Big) = (1,Food Big)
convertPiece (Food Little) =(1,Food Little)
convertPiece (Wall) = (1,Wall)
convertPiece (Empty) = (1,Empty)
-- |Juntar duas instruções 
--
juntarinstrucoes:: Instruction -> Instruction -> Instruction 
juntarinstrucoes (Instruct (x:xs))(Instruct (y:ys))= Instruct ((x:xs)++(y:ys))
-- |Converter uma lista de peças numa lista de pares (Int,Piece)
-- |Padrões horizontais compactados 
--
convertePieceNumaLista:: Corridor -> [(Int,Piece)]
convertePieceNumaLista []= []
convertePieceNumaLista [x]= [convertPiece(x)]
convertePieceNumaLista (x:y:xs) | x==y = ((fst (convertPiece x)) + (length (takeWhile (==x) (y:xs))),x): convertePieceNumaLista ((dropWhile (==x) (x:y:xs))) 
                                | otherwise = convertPiece x : convertePieceNumaLista (y:xs) 
 
-- |Converter uma lista de pares (Int,Piece) numa instrução 
--
converteNumaInstrucao:: Corridor -> Instruction 
converteNumaInstrucao []= Instruct []
converteNumaInstrucao [x]= Instruct (convertePieceNumaLista [x])
converteNumaInstrucao (x:xs)= Instruct (convertePieceNumaLista (x:xs))

-- |Função que nos diz se uma instrução é repetida
--
verInstrucoesRepetidas:: Instruction -> Instruction -> Bool 
verInstrucoesRepetidas (Instruct [])(Instruct [])= True 
verInstrucoesRepetidas (Instruct [x])(Instruct [])= False 
verInstrucoesRepetidas (Instruct [])(Instruct [x])= False 
verInstrucoesRepetidas (Instruct (a:xs))(Instruct(a1:ys)) | fst a== fst a1 && snd a == snd a1 = verInstrucoesRepetidas (Instruct xs) (Instruct ys) 
                                                          | otherwise =  False 
verInstrucoesRepetidas _ _=False 
-- |Função que dada uma instrução e uma lista de instruções, dá-nos a lista de instruções sem a repetida
--  
padroesVertCompact:: Instructions-> Int  -> Instructions
padroesVertCompact  [] i = []
padroesVertCompact (x:xs) f  = x : padroesVertCompact (comOsMesmasInstrucoes x xs f) (f+1)

-- | Padrões verticais compactados 
--
comOsMesmasInstrucoes :: Instruction -> Instructions -> Int -> Instructions
comOsMesmasInstrucoes  i [] x = []
comOsMesmasInstrucoes i (y:ys) x = if verInstrucoesRepetidas i y == True then  Repeat x : comOsMesmasInstrucoes i ys x else y: comOsMesmasInstrucoes i ys x 

-- | Função final 
--
compactarOMaze:: Maze -> Instructions 
compactarOMaze m = padroesVertCompact (map converteNumaInstrucao m) 0







