ex = (State (generateMaze 15 10 47183) [(Pacman ((PacState (0,(2,10),1,U,4,18)) 0 Open Normal)),(Ghost ((GhoState (1,(4,7),1,R,0,1)) Alive)),(Ghost ((GhoState (2,(8,5),1,L,0,4)) Alive))] 1)

-- | Exemplo de um State2 para testes no terminal
--
ex2 :: State
ex2 = (State (generateMaze 15 10 47183) [(Pacman ((PacState (0,(5,1),1,L,4,18)) 5 Open Mega)),(Ghost ((GhoState (1,(3,1),0.5,U,0,1)) Dead)),(Ghost ((GhoState (2,(8,5),0.5,L,0,4)) Dead))] 1)

-- | Função que localiza e remove o pacman de uma lista de Players
--
tiraPacman :: [Player] -> [Player]
tiraPacman (Pacman (PacState (x,(c1,c2),v,o,h,l) q c d ):xs) = xs
tiraPacman (x:xs) = x : tiraPacman xs

{- |  Função que em sintonia com as duas anteriores devolve uma lista com o pacman à sua cabeça

@
>>> pacmanEmPrimeiro [(Ghost (GhoState (1,(2,3),1,L,1,1) Alive )),(Pacman (PacState (0,(5,6),1,U,1,1) 0 Open Normal ))]
[(Pacman (PacState (0,(5,6),1,U,1,1) 0 Open Normal )),(Ghost (GhoState (1,(2,3),1,L,1,1) Alive ))]
@

-}
pacmanEmPrimeiro :: [Player] -> [Player]
pacmanEmPrimeiro (x:xs) = (encontraPacman (x:xs)) : (tiraPacman (x:xs))

-- | Função que localiza o pacman numa lista de Players
--
encontraPacman :: [Player] -> Player
encontraPacman (Pacman (PacState (x,(c1,c2),v,o,h,l) q c d ):xs) = Pacman (PacState (x,(c1,c2),v,o,h,l) q c d )
encontraPacman (x:xs) = encontraPacman xs

-- | Função que diz qual a peça que se encontra numa determinada coordenada de um Labirinto
--
pecaCoordenada :: Coords -> Maze -> Piece
pecaCoordenada (c1,c2) (h:t) = ((!!) ((!!) (h:t) c1) c2)

-- | Função que inverte a orientacao do Ghost quando este se torna Dead
--
inverteOt :: Orientation -> Orientation
inverteOt L = R
inverteOt R = L
inverteOt U = D
inverteOt D = U

-- | Função que transforma uma lista de Ghosts em modo Alive para modo Dead
--
ghostParaDead :: [Player] -> [Player]
ghostParaDead [] = []
ghostParaDead ((Ghost (GhoState (x1,(c3,c4),v1,z1,h1,l1) k)):xs) = (Ghost (GhoState (x1,(c3,c4),0.5,inverteOt z1,h1,l1) Dead )) : ghostParaDead xs

-- | Função que traça os movimentos dos Ghosts para fugir do Pacman (nesta função a orientação do Ghost já foi invertida)
--
scatterMode :: State -> Int -> Play
scatterMode (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le ) id 
    | x1 == id && mod (length m) 2 == 0 && (c3,c4) == ((div (length m) 2) - 1,div (length (head m)) 2) = (Move x1 U)
    | x1 == id && mod (length m) 2 == 1 && (c3,c4) == ((div (length m) 2),div (length (head m)) 2) = (Move x1 U)
    | x1 == id && z1 == L && pecaCoordenada (c3,c4-1) m == Wall = (Move x1 U)
    | x1 == id && z1 == L = (Move x1 L)
    | x1 == id && z1 == R && pecaCoordenada (c3,c4+1) m == Wall = (Move x1 D)
    | x1 == id && z1 == R = (Move x1 R)
    | x1 == id && z1 == U && pecaCoordenada (c3-1,c4) m == Wall = (Move x1 R)
    | x1 == id && z1 == U = (Move x1 U)
    | x1 == id && z1 == D && pecaCoordenada (c3+1,c4) m == Wall = (Move x1 L)
    | x1 == id && z1 == D = (Move x1 D)
    | otherwise = (Move x1 z1)

-- | Função que traça os movimentos dos Ghosts para perseguir o Pacman
--
chaseMode :: State -> Int -> Play
chaseMode (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le ) id
    | x1 == id && mod (length m) 2 == 0 && (c3,c4) == ((div (length m) 2) - 1,div (length (head m)) 2) = (Move x1 U)
    | x1 == id && mod (length m) 2 == 1 && (c3,c4) == ((div (length m) 2),div (length (head m)) 2) = (Move x1 U)
    | x1 == id && z1 == L && (pecaCoordenada (c3,c4-1) m) == Wall = (Move x1 (encontrarOt (Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )) (pacmanCoords (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le ))))
    | x1 == id && z1 == L = (Move x1 L)
    | x1 == id && z1 == R && (pecaCoordenada (c3,c4+1) m) == Wall = (Move x1 (encontrarOt (Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )) (pacmanCoords (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le ))))
    | x1 == id && z1 == R = (Move x1 R)
    | x1 == id && z1 == U && (pecaCoordenada (c3-1,c4) m) == Wall = (Move x1 (encontrarOt (Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )) (pacmanCoords (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le ))))
    | x1 == id && z1 == U = (Move x1 U)
    | x1 == id && z1 == D && (pecaCoordenada (c3+1,c4) m) == Wall = (Move x1 (encontrarOt (Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )) (pacmanCoords (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le ))))
    | x1 == id && z1 == D = (Move x1 D)
    | otherwise = (Move x1 z1)

-- | Função que descobre as coordenadas do Pacman
--
pacmanCoords :: State -> Coords
pacmanCoords (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c k1 )):xs) le ) = (c1,c2)

-- | Função que dá a melhor orientação possível para cada Ghost tomar após saber a localização exata do Pacman
--
encontrarOt :: Player -> Coords -> Orientation
encontrarOt (Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )) (c1,c2)
    | c3==c1 && (c4-c2) < 0 = R
    | c3==c1 && (c4-c2) > 0 = L
    | c4==c2 && (c3-c1) < 0 = D
    | c4==c2 && (c3-c1) > 0 = U
    | abs (c3-c1) < abs (c4-c2) && (c3-c1) < 0 = D
    | abs (c3-c1) < abs (c4-c2) && (c3-c1) > 0 = U
    | abs (c3-c1) > abs (c4-c2) && (c4-c2) < 0 = R
    | abs (c3-c1) > abs (c4-c2) && (c4-c2) > 0 = L
    | abs (c3-c1) == abs (c4-c2) && (c4-c2) < 0 = R
    | abs (c3-c1) == abs (c4-c2) && (c4-c2) > 0 = L

-- | Função que produz o melhor movimento possível que cada Ghost deverá tomar na jogada seguinte
--
ghostPlay :: State -> [Play]
ghostPlay (State m [(Pacman (PacState (x,(c1,c2),y,z,h,l) q c k ))] le ) = []
ghostPlay (State m ps le ) = ghostPlay' (State m (pacmanEmPrimeiro ps) le ) 

-- | Função auxiliar da função ghostPlay, que tem o mesmo propósito mas com o pacman à cabeça de qualquer lista
--
ghostPlay' :: State -> [Play]
ghostPlay' (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le ) = (scatterMode (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le ) x1) : ghostPlay (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Mega )):xs) le )
ghostPlay' (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le ) = (chaseMode (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le ) x1) : ghostPlay (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):xs) le ) 
{- |

=Introdução
 Na Tarefa 4 o objetivo era definir o efeito da passagem do tempo no State do jogo. 

=Objetivos
 Nesta Tarefa começamos por definir a função animaçãoBoca e a função timeMega, presentes na Tarefa2.
 Depois o grande desafio era definir a função passTime que usa a função play da Tarefa2 para definir o efeito da passagem do State do jogo.
 Então, o primeiro passo foi aplicar as jogadas dos fantasmas, definidas na Tarefa5, no State do jogo, voltando a definir a função play da Tarefa2 mas desta vez com as jogadas dos fantasmas (função playGhost).
 O próximo passo foi usar a função play atualizada para definir a função final da Tarefa que define que o Pacman pode jogar em todas as iterações e que os fantamas (quando o pacman está em modo Mega) só podem realizar uma jogada a cada 2 iterações. 

=Discussão e conclusão
 Acreditamos que cumprimos com todos os objetivos que tinhamos definido.

-}



-- dados para a realização da Tarefa

defaultDelayTime = 250 -- 250 ms

------------------------------------------------------------------ Realização da Tarefa

passTime :: Int  -> State -> State
passTime k (State m [] n) = (State m [] n)
passTime k (State m (p:ps) n) = (passTime' k (State m (pacmanEmPrimeiro (p:ps)) n))

passTime' :: Int  -> State -> State
passTime' k (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Dying )):ps) n) = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Dying )):ps) n)
passTime' k (State m (p:ps) n) = (passTime'' k (State m (p:ps) n))

passTime'' :: Int  -> State ->  State
passTime'' k (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):ps) n) = (realizaPlaysG ((play (Move x z) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):ps) n))))
passTime'' k (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d)):ps) n)
    | (mod k 2) == 0 = (realizaPlaysG ((play (Move x z) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d)):ps) n))))
    | otherwise = (play (Move x z) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d)):ps) n))

