   | i == 0 && elem q [0,(0.5)..10] = realizaPlaysG (play (Move x z) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):xs) le))
   | i == 0 && elem q [(0.25),(0.75)..(9.75)] = (play (Move x z) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):xs) le))
   | i >= 1 && elem q [0,(0.5)..10] = passTime' 0 (passTime' (i-1) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):xs) le))
   | i >= 1 && elem q [(0.25),(0.75)..(9.75)] = (passTime' (i-1) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):xs) le))
-}
{- |

=Introdução
 O objetivo desta tarefa é codificar o Labirinto para como uma sequência de instruções que, quando executadas, produzem o mesmo labirinto compactado

=Objetivos
 Ao longo da Tarefa, de forma a compactar o labirinto, começamos por substituir as peças pelo seu nome e depois a substituir um conjunto de peças por uma lista com os nomes dos mesmos.
 Com isto, de forma a reduzir o seu tamanho, agrupamos peças iguais consecutivas por uma lista que continha o seu nome e a quantidade de peças. 
 Por fim, agrupamos todas estas listas numa só, obtendo assim o Maze. Para simplificar ainda mais a interpretação do observador, substituímos linhas repetidas 
 pelo tipo "Repeat  n", sendo n a posição ocupada pela linha n no maze.

=Discussão e conclusão
 Acreditamos que cumprimos com todos os objetivos pretendidos 

-}



{- | Este bloco de dados serve para podermos inserir os Tuplos de forma a que a sua construção seja da forma pretendida

@
>>> pieceParaTuplo Wall
(1,Wall)
@

ao invés de 

@
>>> pieceParaTuplo Wall
(1,#)
@

-}
type Maze = [Corridor]
type Corridor = [Piece]
data Piece =  Food FoodType | Empty | Wall deriving (Eq)
data FoodType = Big | Little deriving (Eq)

type Instructions = [Instruction]
data Instruction = Instruct [(Int, Piece)]
                 | Repeat Int deriving (Show, Eq)

instance Show FoodType where
   show (Big) =  "Food Big"
   show (Little) =  "Food Little"

instance Show Piece where
   show (Wall) = "Wall" 
   show (Empty) = "Empty"
   show (Food z) = (show z)

-------------------------------------------------------------------------------------------------------------------------------

-- | Função que transforma uma peça num tuplo
--
pieceParaTuplo :: Piece -> (Int,Piece)
pieceParaTuplo Wall = (1,Wall)
pieceParaTuplo Empty = (1,Empty)
pieceParaTuplo (Food Big) = (1,Food Big)
pieceParaTuplo (Food Little) = (1,Food Little)

-- | Função que aplica o padrão horizontal a um corredor
--
corredorListaTuplo :: [Piece] -> [(Int,Piece)]
corredorListaTuplo [] = []
corredorListaTuplo [x] = [pieceParaTuplo x]
corredorListaTuplo (x:xs) = if x == head xs then ((fst (pieceParaTuplo x)) + length (takeWhile (==x) xs),x) : corredorListaTuplo (dropWhile (==x) (x:xs))
                              else (pieceParaTuplo x : corredorListaTuplo xs)

-- | Função que transforma um corredor numa Instruction, com o padrão horizontal aplicado
--
corredorParaInstruction :: [Piece] -> Instruction
corredorParaInstruction [] = Instruct []
corredorParaInstruction (x:xs) = Instruct (corredorListaTuplo (x:xs))

-- | Função que converte um Labirinto numa lista de corredores do tipo Instruction, com o padrão horizontal aplicado
--
mazeParaInstructions :: Maze -> Instructions
mazeParaInstructions [] = []
mazeParaInstructions (x:xs) = (corredorParaInstruction x : mazeParaInstructions xs)

-- | Função que aplica o padrão vertical ao Labirinto
--
inserirRepeats :: [Instruction] -> Int -> [Instruction]
inserirRepeats [] k = []
inserirRepeats (i:is) k = i : (inserirRepeats (substitui is i k) (k+1))

-- | Função que troca corredores iguais por uma Instruction do tipo Repeat (Padrão vertical)
--
substitui :: [Instruction] -> Instruction -> Int -> [Instruction]
substitui [] k i = []
substitui ((Repeat f):t) k i = (Repeat f) : substitui t k i
substitui (h:t) k i = if h == k then (Repeat i) : substitui t k i
                      else h : substitui t k i

-- | Função final da Tarefa 3, que compacta um Labirinto transformando corredores iguais em Instructions do tipo Repeat
--
compactMaze :: Maze -> Instructions
compactMaze l = inserirRepeats (mazeParaInstructions l) 0
{- |

=Introdução
 O objetivo desta tarefa é definir o efeito de uma jogada num State de jogo.

=Objetivos
 Começamos por definir o efeito de uma jogado num estado de jogo em várias situações: movimentação do Player, o efeito da entrada de um pacman num labirinto , 2 funções que definem o movimento contra as comidas quando o pacman esta em estado Normal e em estado Mega e da mesma forma definimos o movimento contra um fantasma.
 Por fim juntamos todas estas funções na função final play que dado uma jogada e um state devolve o novo state atualizado.

=Discussão e conclusão
 Acreditamos que cumprimos com todos os objetivos pretendidos
 
-}



