-- | Função que devolve lista de Players com os Fantasmas todos no estado Alive
--
ghostsParaAlive :: [Player] -> [Player]
ghostsParaAlive [] = []
ghostsParaAlive ((Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs) = (Ghost (GhoState (x1,(c3,c4),1,z1,h1,l1) Alive )) : ghostsParaAlive xs                 

-- | Função que diz se o Pacman está em modo Mega ou não
--
pacmanMega :: Player -> Bool
pacmanMega (Pacman (PacState (x,(c1,c2),y,z,h,l) q c Mega )) = True
pacmanMega (Pacman (PacState (x,(c1,c2),y,z,h,l) q c d ))    = False

-- | Função que dá o ID do Pacman
--
idPacman :: [Player] -> Int
idPacman ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):xs) = x
idPacman (x:xs) = idPacman xs

-- | Função que altera o estado da boca do pacman (Não foi utilizada pois não sabíamos se era para aplicar nesta Tarefa ou só no Futuro)
--
animacaoBoca :: State -> State
animacaoBoca (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):xs) le) = if c == Open then (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q Closed d )):xs) le)
                                                                                else (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q Open d )):xs) le)

-- | Função que define a unidade temporal timeMega
--
timeMega1 :: State -> State
timeMega1 (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs) le ) 
    | d==Mega && k==Dead && q > 0.25  = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) (q-0.25) c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):ghostParaDead xs) le ) 
    | d==Mega && k==Dead && q == 0.25 = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) 0 c Normal )):(Ghost (GhoState (x1,(c3,c4),1,z1,h1,l1) Alive )):ghostsParaAlive xs) le )
    | otherwise = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs) le )

{-
-- | Função final da Tarefa 2, que aplica uma jogada a um State e devolve o novo State atualizado
--
play :: Play -> State -> State
play (Move a b) (State m ps le)
    | a == (idPacman ps) && pacmanMega (head (pacmanEmPrimeiro ps)) == True = animacaoBoca (timeMega1 ((movimentoContraFantasma2 (Move a b) (State m (pacmanEmPrimeiro ps) le))))
    | a == (idPacman ps) && pacmanMega (head (pacmanEmPrimeiro ps)) == False = animacaoBoca (timeMega1((movimentoContraFantasma (Move a b) (State m (pacmanEmPrimeiro ps) le))))
    | otherwise = (playGhost (Move a b) (State m (pacmanEmPrimeiro ps) le))
-}

play :: Play -> State -> State
play (Move a b) (State m ps le) = play' (Move a b) (State m (pacmanEmPrimeiro ps) le)

play' :: Play -> State -> State
play' (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs) le)
    | elem (pacmanCoords (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs) le)) (coordsGhosts (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs) le)) && mod (length m) 2 == 0 = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,((div (length m) 2) - 1,div (length (head m)) 2),y1,z1,h1,l1) k )):xs) le)
    | elem (pacmanCoords (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs) le)) (coordsGhosts (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs) le)) = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,((div (length m) 2),div (length (head m)) 2),y1,z1,h1,l1) k )):xs) le)
    | a == (idPacman ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs)) && pacmanMega (head ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs)) == True = animacaoBoca (timeMega1 ((movimentoContraFantasma2 (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs) le))))
    | a == (idPacman ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs)) && pacmanMega (head ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs)) == False = animacaoBoca (timeMega1((movimentoContraFantasma (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs) le))))
    | otherwise = (playGhost (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs) le))

-- | Função que dá um State após ter sido realizada uma play para um Ghost
--
playGhost :: Play -> State -> State
playGhost (Move id ot) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs) le)
    | id == x1 && ot == L && z1 == L && pecaCoordenada (c3,c4-1) m == Wall = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,U,h1,l1) k )):xs) le)
    | id == x1 && ot == L && z1 == L = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4-1),y1,L,h1,l1) k )):xs) le)
    | id == x1 && ot == R && z1 == R && pecaCoordenada (c3,c4+1) m == Wall = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,D,h1,l1) k )):xs) le)
    | id == x1 && ot == R && z1 == R = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4+1),y1,R,h1,l1) k )):xs) le)
    | id == x1 && ot == U && z1 == U && pecaCoordenada (c3-1,c4) m == Wall = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,R,h1,l1) k )):xs) le)
    | id == x1 && ot == U && z1 == U = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3-1,c4),y1,U,h1,l1) k )):xs) le)
    | id == x1 && ot == D && z1 == D && pecaCoordenada (c3+1,c4) m == Wall = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,L,h1,l1) k )):xs) le)
    | id == x1 && ot == D && z1 == D = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3+1,c4),y1,D,h1,l1) k )):xs) le)
    | id == x1 && ot == L && z1 /= L = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,L,h1,l1) k )):xs) le)
    | id == x1 && ot == R && z1 /= R = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,R,h1,l1) k )):xs) le)
    | id == x1 && ot == U && z1 /= U = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,U,h1,l1) k )):xs) le)
    | id == x1 && ot == D && z1 /= D = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,D,h1,l1) k )):xs) le)
    | otherwise = playGhost (Move id ot) (State m (ghostSegundoLugar ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs) id) le)

-- | Função que coloca um Ghost com certo ID atrás do Pacman numa lista de Players com Pacman na cabeça
--
ghostSegundoLugar :: [Player] -> Int -> [Player]
ghostSegundoLugar ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):xs) id = (Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )) : (ghostNaHead xs id)

-- | Função que coloca o Ghost com certo ID na cabeça de uma lista
--
ghostNaHead :: [Player] -> Int -> [Player]
ghostNaHead ((Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs) id 
    | x1 == id = ((Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs)
    | otherwise = (ghostNaHead xs id) ++ [Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )]

coordsGhosts :: State -> [Coords]
coordsGhosts (State m [] le) = []
coordsGhosts (State m ((Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs) le) = (c3,c4) : coordsGhosts (State m xs le)
coordsGhosts (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):xs) le) = coordsGhosts (State m xs le)
{- |

=Introdução
 Nesta Tarefa o objetivo era fazer um labirinto completo do Pacman com: todo o tipo de peças, a casa dos fantasmas e o túnel.

=Objetivos
 Para conseguirmos cumprir o objetivo, começamos por fazer um "molde" do labirinto aplicando paredes a toda a volta o labirinto.
 Seguidamente, fizemos várias funções com o objetivo de aplicar um espaço vazio à altura ideal criando assim o túnel.
 Finalmente, fizemos dois exemplos de casa dos fantasmas, para quando o comprimento do labirinto é par e para quando é ímpar. Inserimos estes exemplos em localizações diferentes dependendo da altura do Maze ser par ou ímpar. 

=Discussão e conclusão
 Cumprimos com os objetivos desta Tarefa.

-}



-- | Maze example
--
sampleMaze :: Maze
sampleMaze = [
                [Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall],
                [Empty, Food Little, Food Little, Food Big, Food Little, Food Big, Food Little, Empty],
                [Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall]
            ]

-- | Given a seed returns a list of n integer randomly generated
--
geraAleatorios :: Int -> Int -> [Int]
geraAleatorios n seed = let gen = mkStdGen seed -- creates a random generator
                        in take n $ randomRs (0,9) gen -- takes the first n elements from an infinite series of random numbers between 0-9

-- | Given a seed returns an integer randomly generated
--
nrAleatorio :: Int -> Int
nrAleatorio seed = head $ geraAleatorios 1 seed

-- Converssta list into a list of list of size n
--
subLista :: Int -> [a] -> [[a]]
subLista _ [] = []
subLista n l = take n l: subLista n (drop n l)
--
convertePiece :: Int -> Piece
convertePiece x 
         | x == 3 = Food Big 
         | x == 5 = Empty 
         | x >= 0 && x<7 = Food Little
         |x >= 7 && x <= 9 = Wall 

-- | Converts a Corridor to a string
printCorridor :: Corridor -> String
printCorridor [] = "\n"
printCorridor (h:t) = show h ++ printCorridor t 

-- | Converts a list of integers into a Corridor
converteCorridor :: [Int] -> Corridor
converteCorridor l = map convertePiece l 

-- | Converts a list of lists of integers into a Maze
converteMaze :: [[Int]] -> Maze
converteMaze l = map converteCorridor l

geraMaze :: Int -> Int -> Int -> Maze
geraMaze x y s =
                 let random_nrs = geraAleatorios (x*y) s
                 in converteMaze $ subLista x random_nrs

----------------------------------------------------------------Construção do Labirinto ---------------------------------------------------------------

-- | Função que coloca a cabeça e o último elemento de cada corredor com a peça Wall
--
paredesLados :: Corridor -> Corridor
paredesLados (h:t) = [Wall] ++ (init t) ++ [Wall]

-- | Repete a função anterior nos vários corredores de um Maze
--
aplicaEmTodas :: Maze -> Maze
aplicaEmTodas (h:t) = let corridor = map paredesLados (init t)
                      in (replicate (length h) Wall): corridor ++ [replicate (length h) Wall]

-- | Função que gera um Labirinto com paredes laterais
--
geraLabirintoValido1 :: Int -> Int -> Int -> Maze
geraLabirintoValido1 x y s = aplicaEmTodas (geraMaze x y s)

-- | Função que apresenta o Labirinto verticalmente
--
displayMaze :: Maze -> IO ()
displayMaze m = putStrLn $ printMaze m

-- | Função que determina se o número de corredores é par ou ímpar
--
alturaParMaze :: Maze -> Bool
alturaParMaze l = if mod (length l) 2 == 0 then True
                  else False

-- | Função que converte um Corredor num tunel
--
tunel :: Corridor -> Corridor
tunel (h:t) = Empty : (init t) ++ [Empty]

-- | Função que insere 1 ou 2 túneis dependendo da altura do labirinto, centrados no mesmo
--
insereTunel :: Maze -> Maze
insereTunel [] = []
insereTunel l | alturaParMaze l = (take ((div (length l) 2)) l) ++ [tunel ((!!) l ((div (length l) 2) - 1))] ++ [tunel ((!!) l (div (length l) 2))] ++ (drop ((div (length l) 2) + 2) l)
              | otherwise = (take ((div (length l) 2) + 1) l) ++ [tunel ((!!) l (div (length l) 2))] ++ (drop ((div (length l) 2) + 2) l)

-- | Função que em junção com a função displayMaze gera o Labirinto
--
geraLabirintoValido2 :: Int -> Int -> Int -> Maze
geraLabirintoValido2 x y s = insereTunel (geraLabirintoValido1 x y s)

-- | Estrutura da casa dos fantasmas num Labirinto com corredores de comprimento par
--
casaFantasmasParl1 = ([Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]) 
casaFantasmasParl2 = ([Empty]++[Wall]++[Wall]++[Wall]++[Empty]++[Empty]++[Wall]++[Wall]++[Wall]++[Empty])
casaFantasmasParl3 = ([Empty]++[Wall]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Wall]++[Empty])
casaFantasmasParl4 = ([Empty]++[Wall]++[Wall]++[Wall]++[Wall]++[Wall]++[Wall]++[Wall]++[Wall]++[Empty])
casaFantasmasParl5 = ([Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty])

-- | Estrutura da casa dos fantasmas num Labirinto com corredores de comprimento ímpar
--
casaFantasmasImparl1 = ([Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty])
casaFantasmasImparl2 = ([Empty]++[Wall]++[Wall]++[Wall]++[Empty]++[Empty]++[Empty]++[Wall]++[Wall]++[Wall]++[Empty])
casaFantasmasImparl3 = ([Empty]++[Wall]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Wall]++[Empty])
casaFantasmasImparl4 = ([Empty]++[Wall]++[Wall]++[Wall]++[Wall]++[Wall]++[Wall]++[Wall]++[Wall]++[Wall]++[Empty])
casaFantasmasImparl5 = ([Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty])

{- | Função que testa se comprimento do corredor é par ou ímpar

@
>>> comprimentoCorridorPar [Wall,Wall,Empty,Empty,Wall]
False
@

e

@
>>> comprimentoCorridorPar [Wall,Wall,Empty,Empty,Wall,Wall]
True
@

-}
comprimentoCorridorPar :: Corridor -> Bool
comprimentoCorridorPar l = if mod (length l) 2 == 0 then True
                           else False

-- | Função que insere a casa dos fantasmas no labirinto, utilizando as estruturas anteriormente definidas
--
insereCFLabirinto :: Maze -> Maze
insereCFLabirinto l | alturaParMaze l && comprimentoCorridorPar (head l)                   = (take ((div (length l) 2) - 3) l) ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasParl1) ((!!) l ((div (length l) 2) - 2))] ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasParl2) ((!!) l ((div (length l) 2) - 1))] ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasParl3) ((!!) l ((div (length l) 2)))] ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasParl4) ((!!) l ((div (length l) 2) + 1))] ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasParl5) ((!!) l ((div (length l) 2) + 2))] ++ (drop ((div (length l) 2) + 2) l)
                    | alturaParMaze l == False && comprimentoCorridorPar (head l) == False = (take ((div (length l) 2) - 2) l) ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasImparl1) ((!!) l ((div (length l) 2) - 1))] ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasImparl2) ((!!) l ((div (length l) 2)))] ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasImparl3) ((!!) l ((div (length l) 2) + 1))] ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasImparl4) ((!!) l ((div (length l) 2) + 2))] ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasImparl5) ((!!) l ((div (length l) 2) + 3))] ++ (drop ((div (length l) 2 ) + 3) l)
                    | alturaParMaze l && comprimentoCorridorPar (head l) == False          = (take ((div (length l) 2) - 3) l) ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasImparl1) ((!!) l ((div (length l) 2) - 2))] ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasImparl2) ((!!) l ((div (length l) 2) - 1))] ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasImparl3) ((!!) l ((div (length l) 2)))] ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasImparl4) ((!!) l ((div (length l) 2) + 1))] ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasImparl5) ((!!) l ((div (length l) 2) + 2))] ++ (drop ((div (length l) 2) + 2) l)
                    | alturaParMaze l == False && comprimentoCorridorPar (head l)          = (take ((div (length l) 2) - 2) l) ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasParl1) ((!!) l ((div (length l) 2) - 1))] ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasParl2) ((!!) l ((div (length l) 2)))] ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasParl3) ((!!) l ((div (length l) 2) + 1))] ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasParl4) ((!!) l ((div (length l) 2) + 2))] ++ [insereListaCasaFantasmasemListaMaze (casaFantasmasParl5) ((!!) l ((div (length l) 2) + 3))] ++ (drop ((div (length l) 2 ) + 3) l)

-- | Função que cria um espaço centralizado num corredor para inserir a casa dos fantasmas (auxiliar da função insereCFLabirinto)
--
insereListaCasaFantasmasemListaMaze :: Corridor -> Corridor -> Corridor
insereListaCasaFantasmasemListaMaze k l | mod (length l) 2 == 0 = (take ((div (length l) 2) - 5) l) ++ k ++ (drop ((div (length l) 2) + 5) l)
                                        | otherwise             = (take ((div (length l) 2) - 5) l) ++ k ++ (drop ((div (length l) 2) + 6) l)

-- | Função final da Tarefa 1, que cria um Labirinto com todos os seus componentes (junto com a função displayMaze, este é representado verticalmente)
--
generateMaze :: Int -> Int -> Int -> Maze
generateMaze x y s = insereCFLabirinto ( geraLabirintoValido2 x y s)


data Manager = Manager 
    {   
        state   :: State
    ,    pid    :: Int
    ,    step   :: Int
    ,    before :: Integer
    ,    delta  :: Integer
    ,    delay  :: Integer
    } 

mapa = (State aux1 aux2 0)
aux1 = (generateMaze 25 19 4)
aux2 = [ghost1,pacman,ghost2,ghost3]
pacman = (Pacman (PacState (1,(11,10),1,L,10,2) 0 Open Normal))
ghost1 = (Ghost (GhoState (2,(10,0),1,R,1,1) Alive))
ghost2 = (Ghost (GhoState (3,(13,10),1,R,1,1) Alive))
ghost3 = (Ghost (GhoState (5,(4,9),1,R,1,1) Alive))

loadManager :: Manager
loadManager = ( Manager mapa 0 0 0 0 defaultDelayTime )

updateControlledPlayer :: Key -> Manager -> Manager
updateControlledPlayer k (Manager (State m ps le) pid sp be de del) = updateControlledPlayer' k (Manager (State m (pacmanEmPrimeiro ps) le) pid sp be de del) 

updateControlledPlayer' :: Key -> Manager -> Manager
updateControlledPlayer' k (Manager (State m (Pacman (PacState (x,(c1,c2),v,o,h,l) q c d ):xs) le) pid sp be de del)
    | k == KeyUpArrow = (Manager (State m (Pacman (PacState (x,(c1,c2),v,U,h,l) q c d ):xs) le) pid sp be de del)
    | k == KeyDownArrow = (Manager (State m (Pacman (PacState (x,(c1,c2),v,D,h,l) q c d ):xs) le) pid sp be de del)
    | k == KeyLeftArrow = (Manager (State m (Pacman (PacState (x,(c1,c2),v,L,h,l) q c d ):xs) le) pid sp be de del)
    | k == KeyRightArrow = (Manager (State m (Pacman (PacState (x,(c1,c2),v,R,h,l) q c d ):xs) le) pid sp be de del)
    | otherwise = (Manager (State m (Pacman (PacState (x,(c1,c2),v,o,h,l) q c d ):xs) le) pid sp be de del)

updateScreen :: Window  -> ColorID -> Manager -> Curses ()
updateScreen w a man =
                  do
                    updateWindow w $ do
                      clear
                      setColor a
                      moveCursor 0 0 
                      drawString $ show (state man)
                    render

currentTime :: IO Integer
currentTime = fmap ( round . (* 1000) ) getPOSIXTime

-- | Função que atualiza o tempo do jogo
--
updateTime :: Integer -> Manager -> Manager
updateTime now man = man {delta = (now - before man)} 

resetTimer :: Integer -> Manager -> Manager
resetTimer now man = man {delta = 0, before = now} 

nextFrame :: Integer -> Manager -> Manager
nextFrame now man =  let update = (resetTimer now man) 
                     in update { state= (passTime (step man) (state man)), step = (step man) +1 }

loop :: Window -> Manager -> Curses ()
loop w man@(Manager s pid step bf delt del ) = do 
  color_schema <- newColorID ColorBlue ColorWhite  10
  now <- liftIO  currentTime
  updateScreen w  color_schema man
  if ( delt > del )
    then loop w $ nextFrame now man
    else do
          ev <- getEvent w $ Just 0
          case ev of
                Nothing -> loop w (updateTime now man)
                Just (EventSpecialKey arrow ) -> loop w $ updateControlledPlayer arrow (updateTime now man)
                Just ev' ->
                  if (ev' == EventCharacter 'q')
                    then return ()
                    else loop w (updateTime now man)

main :: IO ()
main =
  runCurses $ do
    setEcho False
    setCursorMode CursorInvisible
    w <- defaultWindow
    loop w loadManager




loadMaze :: String -> State
loadMaze filepath = unsafePerformIO $ readStateFromFile filepath



readStateFromFile :: String -> IO State
readStateFromFile f = do
                content <- readFile f
                let llines = lines content 
                    (new_map,pl) = convertLinesToPiece llines 0 []
                return (State new_map pl 1)



convertLinesToPiece :: [String] -> Int -> [Player] -> (Maze,[Player])
convertLinesToPiece [] _ l = ([],l)
convertLinesToPiece (x:xs) n l  = let (a,b) = convertLineToPiece x n 0 l 
                                      (a1,b1) = convertLinesToPiece xs (n+1) b
                                  in (a:a1,b1)

convertLineToPiece :: String -> Int -> Int -> [Player] -> ([Piece],[Player])
convertLineToPiece [] _ _ l = ([],l)
convertLineToPiece (z:zs) x y l = let (a,b ) = charToPiece z x y l
                                      (a1,b1) = convertLineToPiece zs x (y+1) b 
                                  in (a:a1,b1)


charToPiece :: Char -> Int -> Int -> [Player] -> (Piece,[Player])
charToPiece c x y l
    | c == '{' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Normal ))   :l) )
    | c == '<' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Closed Normal )) :l) )
    | c == '}' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Open Normal ))   :l) )
    | c == '>' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Closed Normal )) :l) )
    | c == 'V' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Open Normal ))   :l) )
    | c == 'v' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Closed Normal )) :l) )
    | c == '^' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Open Normal ))   :l) )
    | c == '|' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Closed Normal )) :l) )
    | c == 'X' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Dying ))    :l) )
    | c == 'M' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Alive))            :l) )
    | c == '?' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Dead))             :l) )
    | c == 'o' =  (Food Big,l)
    | c == '.' =  (Food Little,l)
    | c == '#' =  (Wall,l)
    | otherwise = (Empty,l)



-- apresenta o labirinto com o playersState e o level
data State = State 
    {
        maze :: Maze
    ,   playersState :: [Player]
    ,   level :: Int
    }

type Maze = [Corridor]
type Corridor = [Piece]
data Piece =  Food FoodType | PacPlayer Player| Empty | Wall | T1 | T2 | T3 | T4 deriving (Eq)
data Player =  Pacman PacState | Ghost GhoState deriving (Eq)

data Orientation = L | R | U | D | Null deriving (Eq,Show)
data PacState= PacState 
    {   
        pacState :: PlayerState
    ,   timeMega :: Double
    ,   openClosed :: Mouth
    ,   pacmanMode :: PacMode
    
    } deriving Eq

data GhoState= GhoState 
    {
        ghostState :: PlayerState
    ,   ghostMode :: GhostMode
    } deriving Eq

type Coords = (Int,Int)
type PlayerState = (Int, Coords, Double , Orientation, Int, Int)
--                 (ID,  (x,y), velocity, orientation, points, lives) 
data Mouth = Open | Closed deriving (Eq,Show)
data PacMode = Dying | Mega | Normal deriving (Eq,Show)
data GhostMode = Dead  | Alive deriving (Eq,Show)
data FoodType = Big | Little deriving (Eq)
data Color = Blue | Green | Purple | Red | Yellow | None deriving Eq 

data Play = Move Int Orientation deriving (Eq,Show)

type Instructions = [Instruction]

data Instruction = Instruct [(Int, Piece)]
                 | Repeat Int deriving (Show, Eq)



instance Show State where
  show (State m ps p) = printMaze mz ++ "Level: " ++ show p ++ "\nPlayers: \n" ++ (foldr (++) "\n" (map (\y-> printPlayerStats y) ps))
                          where mz = placePlayersOnMap ps m

instance Show PacState where
   show ( PacState s o m Dying  ) =  "X"
   show ( PacState (a,b,c,R,i,l) _ Open m  ) =  "{"
   show ( PacState (a,b,c,R,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,L,i,l) _ Open m  ) =  "}"
   show ( PacState (a,b,c,L,i,l) _ Closed m  ) =  ">"
   show ( PacState (a,b,c,U,i,l) _ Open m  ) =  "V"
   show ( PacState (a,b,c,U,i,l) _ Closed m  ) =  "v"
   show ( PacState (a,b,c,D,i,l) _ Open m  ) =  "^"
   show ( PacState (a,b,c,D,i,l) _ Closed m  ) =  "|"
   show ( PacState (a,b,c,Null,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,Null,i,l) _ Open m  ) =  "{"

instance Show Player where
   show (Pacman x ) =  show x
   show ( Ghost x ) =   show x

instance Show GhoState where
   show (GhoState x Dead ) =  "?"
   show (GhoState x Alive ) =  "M"

instance Show FoodType where
   show ( Big ) =  "o"
   show ( Little ) =  "."

instance Show Piece where
   show (  Wall ) = coloredString "#" None
   show (  Empty ) = coloredString " " None
   show (  Food z ) = coloredString (show z )   Green
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Normal ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Normal)  ) Yellow
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Mega   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Mega)  ) Blue
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Dying  ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Dying)  ) Red
   show ( PacPlayer (Ghost z) ) = coloredString (show z)  Purple


coloredString :: String -> Color -> String
coloredString x y
    | y == Blue ="\x1b[36m" ++  x ++ "\x1b[0m"
    | y == Red = "\x1b[31m" ++ x ++ "\x1b[0m"
    | y == Green = "\x1b[32m" ++ x ++ "\x1b[0m"
    | y == Purple ="\x1b[35m" ++ x ++ "\x1b[0m"
    | y == Yellow ="\x1b[33m" ++ x ++ "\x1b[0m"
    | otherwise =  "\x1b[0m" ++ x 


placePlayersOnMap :: [Player] -> Maze -> Maze
placePlayersOnMap [] x = x
placePlayersOnMap (x:xs) m = placePlayersOnMap xs ( replaceElemInMaze (getPlayerCoords x) (PacPlayer x) m )


printMaze :: Maze -> String
printMaze []  =  ""
printMaze (x:xs) = foldr (++) "" ( map (\y -> show y) x )  ++ "\n" ++ printMaze ( xs )

printPlayerStats :: Player -> String
printPlayerStats p = let (a,b,c,d,e,l) = getPlayerState p
                     in "ID:" ++ show a ++  " Points:" ++ show e ++ " Lives:" ++ show l ++"\n"

getPlayerID :: Player -> Int
getPlayerID (Pacman (PacState (x,y,z,t,h,l) q c d )) = x
getPlayerID  (Ghost (GhoState (x,y,z,t,h,l) q )) = x
 
getPlayerPoints :: Player -> Int
getPlayerPoints (Pacman (PacState (x,y,z,t,h,l) q c d )) = h
getPlayerPoints (Ghost (GhoState (x,y,z,t,h,l) q )) = h

setPlayerCoords :: Player -> Coords -> Player
setPlayerCoords (Pacman (PacState (x,y,z,t,h,l) q c d )) (a,b) = Pacman (PacState (x,(a,b),z,t,h,l) q c d )
setPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) q )) (a,b) = Ghost (GhoState (x,(a,b),z,t,h,l) q )

--Acho que nao serve para nada
getPieceOrientation :: Piece -> Orientation
getPieceOrientation (PacPlayer p) =  getPlayerOrientation p
getPieceOrientation _ = Null

getPacmanMode :: Player -> PacMode
getPacmanMode (Pacman (PacState a b c d)) = d

-- dá o estado do player
getPlayerState :: Player -> PlayerState
getPlayerState (Pacman (PacState a b c d )) = a
getPlayerState (Ghost (GhoState a b )) = a

--para onde esta virado
getPlayerOrientation :: Player -> Orientation
getPlayerOrientation (Pacman (PacState (x,y,z,t,h,l) q c d )) = t
getPlayerOrientation  (Ghost (GhoState (x,y,z,t,h,l) q )) = t

--quando come uma peça substitui por espaço
replaceElemInMaze :: Coords -> Piece -> Maze -> Maze
replaceElemInMaze (a,b) _ [] = []
replaceElemInMaze (a,b) p (x:xs) 
  | a == 0 = replaceNElem b p x : xs 
  | otherwise = x : replaceElemInMaze (a-1,b) p xs


replaceNElem :: Int -> a -> [a] -> [a]
replaceNElem i _ [] = [] 
replaceNElem i el (x:xs)
  |  i == 0 = el : xs 
  | otherwise =  x : replaceNElem (i-1) el xs

--dá as coordenadas do player
getPlayerCoords :: Player -> Coords
getPlayerCoords (Pacman (PacState (x,y,z,t,h,l) b c d )) = y
getPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) b )) = y


