-- | Inserts a piece in a list in the form of (Int,Piece)
--
insertPiece :: Piece -- ^ Piece which will be inserted 
            -> [(Int,Piece)] -- ^ List on which the Piece will be inserted
            -> [(Int,Piece)]
insertPiece x [] = [(1,x)]
insertPiece n x | n == snd(last x) = init x ++ [(fst(last x) + 1, n)]
                | otherwise = x ++ [(1,n)] 

-- | Transforms a Corridor into a list in the form of (Int,Piece) 
--
defineLine :: Corridor -- ^ Corridor which will be transformed
           -> [(Int, Piece)] -- ^ List where the corridor will be inserted
           -> [(Int, Piece)]
defineLine [] x = x
defineLine (h:t) x = defineLine t (insertPiece h x)

-- | Transforms a Maze into a list in the form of [(Int,Piece)] 
--
defineMaze :: Maze -> [[(Int,Piece)]]
defineMaze [] = []
defineMaze (h:t) = defineLine h [] : defineMaze t
                 
-- | Transforms a list in the form of [(Int,Piece)] into Instructions
--                 
listToInst :: [[(Int,Piece)]] -> Instructions
listToInst [a] = [Instruct a]
listToInst (a:b:c) = [Instruct a] ++ listToInst (b:c)


-- | Transforms a Maze into Intructions
--
compactMaze :: Maze -> Instructions
compactMaze m = listToInst (defineMaze m)

