-- | Gives a certain corridor 
--
line :: Int -- ^ Index of the corridor 
     -> Maze -- ^ Maze of the corridor
     -> Corridor
line x (h:t) | x == 0 = h
             | otherwise = line (x-1) t

-- | Using the function line, it gives a certain piece
--
collumn :: Int -- ^ Index of the piece
        -> Corridor -- ^ Corridor of the piece
        -> Piece
collumn y (h:t) | y == 0 = h
                | otherwise = collumn (y-1) t 

-- | Gives the Piece in the coordinates of a maze
--
piece :: Coords -- ^ Coords of the piece
      -> Maze -- ^ Maze of the piece
      -> Piece
piece (a,b) m  =  collumn b (line a m)

lengthCorridor :: Maze -> Int
lengthCorridor (x:xs) = length x     

-- | Gives the piece in front of a player
--
--getPlayerCoords

pieceInFrontP :: Coords -- ^ Player pretended
              -> Orientation
              -> Maze -- ^ Maze of the piece
              -> Piece
pieceInFrontP (x,y) o m | o == R = piece (x,y+1) m 
                        | o == U = piece (x-1,y) m 
                        | o == L = piece (x,y-1) m 
                        | otherwise = piece (x+1,y) m

-- | Pacman moves to the right in an maze with an odd number of lines
--
mRPacO :: Player -> Maze -> Player
mRPacO (Pacman (PacState(i,(x,y),ve,R,p,l) c b Normal)) m | ((y==((lengthCorridor m)-1)) && (x == ((div (length m) 2) - 1))) = Pacman (PacState (i,(x,0),ve,R,p,l) c Closed Normal)
                                                          | ((pieceInFrontP (x,y) R m) == Empty) = Pacman (PacState (i,(x,y+1),ve,R,p,l) c Closed Normal)
                                                          | ((pieceInFrontP (x,y) R m) == Food Little) = Pacman (PacState (i,(x,y+1),ve,R,p+1,l) c Open Normal)
                                                          | ((pieceInFrontP (x,y) R m) == Food Big) = Pacman (PacState (i, (x,y+1),ve,R,p+5,l) c Open Mega)
                                                          | otherwise = Pacman (PacState (i,(x,y),ve,R,p,l) c Open Normal)

-- | Pacman moves to the right in an maze with an even number of lines
--
mRPacE :: Player -> Maze -> Player
mRPacE (Pacman (PacState(i,(x,y),ve,R,p,l) c b Normal)) m | ((y == ((lengthCorridor m)-1)) && (x == (div (length m) 2))) = Pacman (PacState (i,(x,0),ve,R,p,l) c Closed Normal)
                                                          | ((y == ((lengthCorridor m)-1)) && (x == ((div (length m) 2) - 1))) = Pacman (PacState (i,(x,0),ve,R,p,l) c Closed Normal)
                                                          | (pieceInFrontP (x,y) R m) == Empty = Pacman (PacState (i,(x,y+1),ve,R,p,l) c Closed Normal)
                                                          | (pieceInFrontP (x,y) R m) == Food Little = Pacman (PacState (i,(x,y+1),ve,R,p+1,l) c Open Normal)
                                                          | (pieceInFrontP (x,y) R m) == Food Big = Pacman (PacState (i, (x,y+1),ve,R,p+5,l) c Open Mega)
                                                          | otherwise = Pacman (PacState (i,(x,y),ve,R,p,l) c Open Normal)

-- | Pacman moves to the left in an maze with an odd number of lines
--
mLPacO :: Player -> Maze -> Player
mLPacO (Pacman (PacState(i,(x,y),ve,L,p,l) c b Normal)) m | ((y==0) && (x == ((div (length m) 2) + 1))) = Pacman (PacState (i,(x,(lengthCorridor m) - 1),ve,L,p,l) c Closed Normal)
                                                          | (pieceInFrontP (x,y) L m) == Empty = Pacman (PacState (i,(x,y-1),ve,L,p,l) c Closed Normal)
                                                          | (pieceInFrontP (x,y) L m) == Food Little = Pacman (PacState (i,(x,y-1),ve,L,p+1,l) c Open Normal)
                                                          | (pieceInFrontP (x,y) L m) == Food Big = Pacman (PacState (i, (x,y-1),ve,L,p+5,l) c Open Mega)
                                                          | otherwise = Pacman (PacState (i,(x,y),ve,L,p,l) c Open Normal)

-- | Pacman moves to the left in an maze with an even number of lines
--
mLPacE :: Player -> Maze -> Player
mLPacE (Pacman (PacState(i,(x,y),ve,L,p,l) c b Normal)) m | ((y == 0) && (x == (div (length m) 2))) = Pacman (PacState (i,(x,(lengthCorridor m) - 1),ve,L,p,l) c Closed Normal)
                                                          | ((y == 0) && (x == ((div (length m) 2) - 1))) = Pacman (PacState (i,(x,(lengthCorridor m) - 1),ve,L,p,l) c Closed Normal)
                                                          | (pieceInFrontP (x,y) L m) == Empty = Pacman (PacState (i,(x,y-1),ve,L,p,l) c Closed Normal)
                                                          | (pieceInFrontP (x,y) L m) == Food Little = Pacman (PacState (i,(x,y-1),ve,L,p+1,l) c Open Normal)
                                                          | (pieceInFrontP (x,y) L m) == Food Big = Pacman (PacState (i, (x,y-1),ve,L,p+5,l) c Open Mega)
                                                          | otherwise = Pacman (PacState (i,(x,y),ve,L,p,l) c Open Normal)

-- | Pacman moves up
--
mUPac :: Player -> Maze -> Player
mUPac (Pacman (PacState (i,(x,y),ve,U,p,l) c b Normal)) m | (pieceInFrontP (x,y) U m) == Empty = Pacman (PacState (i,(x-1,y),ve,U,p,l) c Closed Normal)
                                                          | (pieceInFrontP (x,y) U m) == Food Little = Pacman (PacState (i,(x-1,y),ve,U,p+1,l) c Open Normal)
                                                          | (pieceInFrontP (x,y) U m) == Food Big = Pacman (PacState (i,(x-1,y),ve,U,p+5,l) c Open Mega)
                                                          | otherwise = Pacman (PacState (i,(x,y),ve,U,p,l) c Open Normal)

-- | Pacman moves down
--
mDPac :: Player -> Maze -> Player
mDPac (Pacman (PacState (i,(x,y),ve,D,p,l) c b Normal)) m | (pieceInFrontP (x,y) D m) == Empty = Pacman (PacState (i,(x+1,y),ve,D,p,l) c Closed Normal)
                                                          | (pieceInFrontP (x,y) D m) == Food Little = Pacman (PacState (i,(x+1,y),ve,D,p+1,l) c Open Normal)
                                                          | (pieceInFrontP (x,y) D m) == Food Big = Pacman (PacState (i,(x+1,y),ve,D,p+5,l) c Open Mega) 
                                                          | otherwise = Pacman (PacState (i,(x,y),ve,D,p,l) c Open Normal)

-- | Mega pacman moves to the right in a maze with an odd number of lines
--
mRMegO :: Player -> Maze -> Player
mRMegO (Pacman (PacState(i,(x,y),ve,R,p,l) c b Mega)) m | ((y==((lengthCorridor m)-1)) && (x == ((div (length m) 2) - 1))) = Pacman (PacState (i,(x,0),ve,R,p,l) (c-1) Closed Mega)
                                                        | (pieceInFrontP (x,y) R m) == Empty = Pacman (PacState (i,(x,y+1),ve,R,p,l) (c-1) Closed Mega)
                                                        | (pieceInFrontP (x,y) R m) == Food Little = Pacman (PacState (i,(x,y+1),ve,R,p+1,l) (c-1) Open Mega)
                                                        | (pieceInFrontP (x,y) R m) == Food Big = Pacman (PacState (i, (x,y+1),ve,R,p+5,l) c Open Mega) 
                                                        | otherwise = Pacman (PacState (i,(x,y),ve,R,p,l) (c-1) Open Mega)

