-- | dado um id e uma lista de players devolve o jogador com o id igual ao dado
idP :: Int -> [Player] -> Player                                                                                
idP a (p:t) 
 | a==getPlayerID p = p
 | otherwise = idP a t 

-- | usando as funções acima defenidas esta função dá-nos a melhor jogada pra o fantasma se aproximar do pacman do pacman     
chaseMode :: State -> Int -> Play
chaseMode (State lab xs l) id = (Move id o)
 where o = orifav cp pf lab 
       cp = getPlayerCoords $ distinguep xs 
       pf = idP id xs 


-- | define a melhor orientação para afastar o fantasma do pacman
caminhoP ::  Coords -> Coords -> Orientation
caminhoP (x,y) (x1,y1) 
 | x1 - x > 0 = U
 | x1 - x < 0 = D
 | y1 - y > 0 = L
 | y1 - y <0 =  R
 | otherwise = Null 


-- | pega na lista de tuplos em que o primeiro corresponde á distâncias e segundo ás coordenadas e devolve as coordenadas associadas á maior distância 
maiordist :: [(Float,Coords)] -> Coords
maiordist l = snd $ last $ sortOn fst l

-- | devolve a coordenanda que está associada á maior distância entre o fantasma e ghost
finalmaior :: PlayerState -> Maze -> Coords -> Coords
finalmaior p lab (x,y) = maiordist $ comparaCoords (coordF p lab) (x,y)

-- | dáda a coordenada associada á maior distância entre o fantas e o pacman devolve a orientação que o fantasma deve tomar para se afastar do pacman
orifavmaior :: Coords -> Player -> Maze -> Orientation 
orifavmaior (x,y) (Ghost(GhoState (i, (x1,y1), v', o' ,p', l') m')) lab = caminhoP (x1,y1) bc 
 where ps = (i, (x1,y1), v', o' ,p', l')
       bc = finalmaior ps lab (x,y) 

-- | usando as funções acima defenidas esta função dá-nos a melhor jogada pra o fantasma se afastar do pacman do pacman
scatterMode :: State -> Int -> Play
scatterMode (State lab xs l) id = (Move id o)
 where o = orifavmaior cp pf lab 
       cp = getPlayerCoords $ distinguep xs 
       pf = idP id xs 


-- | juntamos a função chaseMode e scatterMode 
ghostPlay :: State -> [Play]
ghostPlay (State lab [(Pacman (PacState (id, (x,y), v, o ,p, l) t oc m))] lv) = []
ghostPlay (State lab [] lv) = []
ghostPlay (State lab  ((Pacman (PacState (id, (x,y), v, o ,p, l) t oc m)):tail) lv) = ghostPlay (State lab (tail++[(Pacman (PacState (id, (x,y), v, o ,p, l) t oc m))]) lv) 
ghostPlay s@(State lab ((Ghost(GhoState (i', (x1,y1), v', o' ,p', l') m)):xs) lv) 
 | m == Alive = (chaseMode s i') : ghostPlay (State lab xs lv)  
 | otherwise = (scatterMode s i') : ghostPlay (State lab xs lv) 



{- |

= Introdução 

O objetivo desta tarefa é calcular o efeito da passagem de um instante de tempo no estado de jogo.

= Solução

Para esta tarefa foi importada a biblioteca nCurses que foi usada para a movimentação do jogador atráves do pressionamento das setas no teclado.
Para simular a passagem do tempo foi implementado um tipo Data Manager que consiste no State do jogo, o identificador unico do jogador, o step que é um inteiro que
representa quantas iterações do jogo já passou, o before que representa o instante de tempo de tempo em que foi efetuada a última jogada, o delta que representa o tempo
decorrido em milissegundos desde a última jogada e o delay que representa o intervalo de tempo entre jogadas que foi estabelecido em 250 ms.
Para movimentar os jogadores foi usada a função jogaTodos que aquando o estado do jogador vai atualizar o labirinto de acordo com o estado dos fantasmas que podem perseguir
o Pacman ou fugir dele se estiver em estado Mega. Esta função joga todos foi depois utilizada na função passtime.

= Conclusão

Com isto conseguimos controlar o jogador com as setas do teclado e visualizar as jogadas no ecrâ consoante a passagem do tempo.
-}




defaultDelayTime = 250 -- 250 ms

-- | se o jogador estiver em modo mega vamos tirar um ao tempo mega restante do jogador
iftimeMega :: Player -> Player 
iftimeMega (Pacman (PacState (id, or, v, o ,p, l) tm oc Mega)) = (Pacman (PacState (id, or, v, o ,p, l) (tm-0.25) oc Mega))

-- | vê se o jogador está em modo mega
isPacmanMega :: Player -> Bool
isPacmanMega (Ghost(GhoState (i, (x1,y1), v', o' ,p', l') m')) = False
isPacmanMega (Pacman (PacState (id, or, v, o ,p, l) tm oc mega))  
 | mega == Mega = True
 | otherwise = False 

-- | vê se o jogador é um fantasma
isGhost :: Player -> Bool
isGhost (Ghost(GhoState (id1, (x1,y1), v1, o1 ,p1, l1) m')) = True
isGhost _ = False

-- | vẽ se o fantasma está vivo
isGhostAlive :: Player -> Bool
isGhostAlive (Ghost(GhoState (id1, (x1,y1), v1, o1 ,p1, l1) m'))
 | m' == Alive = True
 | otherwise = False

isPacAlive :: Player -> Bool 
isPacAlive (Pacman (PacState (id, or, v, o ,p, l) tm oc mega))
 | l<0 = False 
 | otherwise = True  


-- | atualiza a lista de jogadores no state usando as fuções definidas anteriormente 
jogaTodos :: [Player] -> State -> Int -> State 
jogaTodos [] state i = state 
jogaTodos (x:xs) state i 
  | isGhost x && isGhostAlive x = let s3 = play (chaseMode state (getPlayerID x)) state
                               in jogaTodos xs s3 i
  | isGhost x && even i = let s3 = play (scatterMode state (getPlayerID x)) state
                               in jogaTodos xs s3 i
  | isGhost x = jogaTodos xs state i 
  | isPacmanMega x = let novo = iftimeMega x
                         s1 = play (Move (getPlayerID x) (getPlayerOrientation x)) state
                      in jogaTodos xs s1 i
  | isPacmanMega x == False = let s2 = play (Move (getPlayerID x) (getPlayerOrientation x)) state 
                                in jogaTodos xs s2 i  
 

passTime :: Int  -> State -> State
passTime x (State m ps lvl) = (jogaTodos ps (State m ps lvl)x)


-- | dá o jogador como um certo ID
playerID :: Int -> State -> Player
playerID i (State m (x:xs) l ) 
 | i == getPlayerID x = x
 | otherwise = playerID i (State m xs l)

-- | rodar o jogador para a orientação dada
rotatePlayer :: Player -> Orientation -> Player
rotatePlayer (Pacman (PacState (id, (x,y), v, o ,p, l) t oc m)) or
 | or == R = (Pacman (PacState (id, (x,y), v, R ,p, l) t oc m))
 | or == L = (Pacman (PacState (id, (x,y), v, L ,p, l) t oc m))
 | or == U = (Pacman (PacState (id, (x,y), v, U ,p, l) t oc m))
 | or == D = (Pacman (PacState (id, (x,y), v, D ,p, l) t oc m))
 

-- | substituir um jogador atualizado na lista de jogadores do State
replacePlayerinState :: Player -> State -> State
replacePlayerinState p (State m (xs) l) = (State m (replacePlayerinlist p xs) l)

-- | substituir um jogador atualizado numa lista de jogadores
replacePlayerinlist :: Player -> [Player] -> [Player]
replacePlayerinlist x [] = []
replacePlayerinlist x (y:ys) = if getPlayerID x == getPlayerID y then (x:ys) else y : replacePlayerinlist x ys

{- |

= Introdução 

O objetivo desta tarefa é converter um labirinto valido em instruções de forma a ser mais compacto para leitura. Para ser valida a instrução não pode conter um numero maior
ou menor de peças que a largura do labirinto.

= Solução

As instruções foram definidas como um tuplo cujo primeiro valor é um inteiro e um segundo uma peça, estas serão usadas para escrever o labirinto “por extenso”
Para a máxima compactação do labirinto usamos funções que verificam se 2 corredores são iguais, , corredoresIguais, com o objetivo de substituir os corredores iguais apenas
por Repeat seguido da posição do corredor igual com a função addRepeat.

= Conclusão

Com isto somos capazes de compactar um labirinto com o tipo Instructions que obedece aos parâmetros estabelecidos no enunciado.
-}


-- | verifica se 2 corredores são iguais
corredoresIguais :: Corridor -> Corridor -> Bool 
corredoresIguais [] [] = True
corredoresIguais _ [] = False 
corredoresIguais [] _ = False 
corredoresIguais (x:xs) (y:ys) 
                          | x==y = corredoresIguais xs ys
                          | x /=y = False


-- | verifica se num labirinto ha corredores iguais a um dado corredor e guarda a sua posição
posCorredorMaze :: Maze -> Int -> Corridor -> Int 
posCorredorMaze [] a corr = a 
posCorredorMaze (x:xs) q y 
                    | corredoresIguais x y = q
                    | otherwise = posCorredorMaze xs (q+1) y


-- | compara dois labirintos e guarda a posicao dos corredores que são iguais 
comparaMaze :: Maze -> Maze -> [Int] 
comparaMaze _ [] = []
comparaMaze [] _ = [] 
comparaMaze (x:xs) l = (posCorredorMaze l 0 x) : (comparaMaze xs l) 

-- | dado um labirinto e dois inteiros, dá o corredor que se encontra na posião do primeiro numero inteiro 
encontraCorredor :: Int -> Int -> Maze -> Corridor 
encontraCorredor a b (x:xs) 
                  | a == b = x
                  | a /= b =  encontraCorredor (a+1) b xs


-- | dado um corredor e um inteiro, passa o corredor para uma lista de pares de inteiros e peças
corrParaInst :: Corridor -> Int -> [(Int,Piece)]
corrParaInst [x] y = [(y,x)] 
corrParaInst (x:t:xs) y 
                  | x == t = (corrParaInst (t:xs) (y+1)) 
                  | x /= t = (y,x) : (corrParaInst (t:xs) 1)


-- | dado um labirinto e um inteiro, passa o labirinto para o tipo Instruction
labParaInt :: Maze -> Int -> Instruction
labParaInt [] y = Instruct []
labParaInt x y = Instruct (corrParaInst (encontraCorredor 0 y x) 1)

-- | dado um labirinto um inteiro e uma lista de inteiros, substitui em corredores repetidos o tipo instructions por Repeat da posição do corredor que era repetido
addRepeat :: Maze -> Int -> [Int] -> Instructions 
addRepeat a b [] = [] 
addRepeat a b (x:xs) 
               | b == x = (labParaInt a x) : (addRepeat a (b+1) xs)
               | b /= x = (Repeat x) : (addRepeat a (b+1) xs)



-- | Dado um maze, transforma-o em tipo Instructions 
compactMaze :: Maze -> Instructions 
compactMaze [] = [] 
compactMaze x = addRepeat x 0 (comparaMaze x x)














{- |

= Introdução 

Na tarefa 2 o objetivo foi dado uma descrição do estado do jogo e uma jogada de um jogador, determinar se a jogada é valida e executar o efeito dessa jogada no estado do jogo, 
isto para todos os jogadores do tipo Pacman e Ghost. 

= Solução

Para esta tarefa foi implementado um tipo Data para definir os diferentes tipos de movimentação consoante a sua orientação
Foi também implementado um tipo Data para definir o estado do labirinto que consistia na estrutura do labirinto, um playerstate que continha a lista de todos os jogadores
e o nível em que o jogo se encontra, foi também definido um tipo Data para o jogador, que poderia ser um Pacman ou um fantasma, nesta tarefa o foco foi os jogadores tipo Pacman
que é definido por um tipo de dados, PacState que nos da informações sobre o seu tempo restante em modo Mega, o estado da sua boca (aberta ou fechada) e o seu modo
(Mega, Normal ou Dying). O playerstate da nos informações relativas ao ID do jogador, a sua posição, a velocidade, orientação, pontos e o numero de vidas
O processamento da jogada foi sujeito a regras, quando o jogador se movimenta para uma direção diferente da sua orientação devia-se manter na mesma posição alterando apenas
a sua orientação, caso contrário este deverá avançar uma posição da direção imposta pelo jogador.
Para processar as diferentes jogadas usamos uma função PlayerActions para cada orientação diferente que recebia um jogador, um labirinto e processava o que acontecia em todas
as diferentes possibilidades de estado do labirinto 
Foram necessárias funções extra para casos especificos como quando o Pacman bate contra um fantasma usando a função testeF que aquando o estado do Pacman e do Ghost
atualiza-os depois da colisão, foram necessária também duas funções, funcaoTunelR e funcaoTunelL, para fazer o Pacman atravessar o tunel quando este o atravessava.

= Conclusão 

Com isto somos capazes de executar jogadas com o Pacman fazendo-o reagir apropriadamente às diferentes situações de jogo. 

-}


-- | dado um labirinto e um jogador dá-nos a peça que se encontra nas coordenadas do jogador
quePeca :: Maze -> PlayerState -> Piece                        
quePeca m (i,(0,0),a,d,z,l) = (head (head m))
quePeca ((x:xs):y) (i,(b,c),a,d,z,l)
 | b==0 = quePeca1 (x:xs) (i,(0,c),a,d,z,l)
 | b/=0 = quePeca y (i,(b-1,c),a,d,z,l)

-- | função auxiliar á função quePeca que procura a peça no corredor
quePeca1 :: Corridor -> PlayerState -> Piece                   
quePeca1 (x:xs) (i,(0,c),a,d,z,l)
 | c==0 = x
 | c/=0 = quePeca1 xs (i,(0,c-1),a,d,z,l)

-- | obtem o labirinto a partir de um state
getMazeFromState :: State -> Maze 
getMazeFromState (State m l n) = m 

-- | atualiza as coordenadas do jogador  quando este entra no tunel á direita           
funcaoTunelR :: Player -> Maze -> Player                                                                   
funcaoTunelR (Pacman (PacState (id, (x,y), v, o ,p, l) t oc m)) maze 
  | (x,y)== (x,(length (head maze))-1) = (Pacman (PacState (id, (x,0), v, o ,p, l) t oc m))
  | otherwise = (Pacman (PacState (id, (x,y), v, o ,p, l) t oc m))

-- | atualiza as coordenadas do jogador  quando este entra no tunel á esquerda 
funcaoTunelL :: Player -> Maze -> Player                                                         
funcaoTunelL (Pacman (PacState (id, (x,y), v, o ,p, l) t oc m)) maze 
  | (x,y)==(x,0)  = (Pacman (PacState (id,(x,(length (head maze))-1) , v, o ,p, l) t oc m))
  | otherwise= (Pacman (PacState (id, (x,y), v, o ,p, l) t oc m))

-- | atualiza o estado do fantasma com o pacman fica no estado Mega 
mataFantasmas :: Player -> Maze -> [Player] -> [Player]                            
mataFantasmas p lab [] = []
mataFantasmas pl@(Pacman (PacState (id, (x,y), v, o ,p, l) b oc m)) lab (Ghost(GhoState (i, (x1,y1), v', o' ,p', l') m'):t)        
 | quePeca lab (id, (x,y), v, o ,p, l) == Food Big = (Ghost(GhoState (i, (x1,y1), v', o' ,p', l') Dead)):(mataFantasmas pl lab t) 
 | otherwise = (Ghost(GhoState (i, (x1,y1), v', o' ,p', l') Alive)):t


-- | atualiza o estado do jogador caso ele colida com um fantasma 
testeF :: Player -> Player -> [Player] -> Player                                                                
testeF (Pacman (PacState (id2, (x2,y2), v2, o2 ,p2, l2) b2 oc2 m2)) (Pacman (PacState (id, (x,y), v, o ,p, l) b oc m)) [] = Pacman (PacState (id, (x,y), v, o ,p, l) b oc m)
testeF (Pacman (PacState (id2, (x2,y2), v2, o2 ,p2, l2) b2 oc2 m2)) (Pacman (PacState (id, (x,y), v, o ,p, l) b oc m)) (Ghost(GhoState (i, (x1,y1), v', o' ,p', l') m'):t)   
 | m==Normal && x == x1 && y == y1 && l==0 && m' == Alive = (Pacman (PacState (id2, (x2,y2), v2, o2 ,p2, 0) b2 oc2 Dying)) 
 | m==Normal && x == x1 && y == y1 && m' == Alive = (Pacman (PacState (id2, (x2,y2), v2, o2 ,p2, l-1) b2 oc2 m2)) 
 | m==Mega && x == x1 && y == y1 && m' == Dead = (Pacman (PacState (id2, (x,y), v, o ,p+10, l) b oc m)) 
 | otherwise = testeF (Pacman (PacState (id2, (x2,y2), v2, o2 ,p2, l2) b2 oc2 m2)) (Pacman (PacState (id, (x,y), v, o ,p, l) b oc m)) t 

-- | atualiza o estado do pacman quando este realiza ações para cima
playerActionsU :: Player -> Maze -> Player                                                    
playerActionsU (Pacman (PacState (id, (x,y), v, o ,p, l) b oc m)) maze 
                                  | coiso == Empty = (Pacman (PacState (id, (x-1,y), v, o ,p, l) b oc m))
                                  | coiso == Food Little = (Pacman (PacState (id, (x-1,y), v, o ,p+1, l) b oc m))
                                  | coiso == Food Big = (Pacman (PacState (id, (x-1,y), v, o ,p+5, l) 10 oc Mega))
                                  | coiso == Wall = (Pacman (PacState (id, (x,y), v, o ,p, l) b oc m))
                                  | otherwise = (Pacman (PacState (id, (x-1,y), v, o ,p, l) b oc m))
                                  where coiso = quePeca  maze (id, (x-1,y), v, o ,p, l)

-- | atualiza o estado do pacman quando este realiza ações para baixo
playerActionsD :: Player -> Maze -> Player                                                  
playerActionsD (Pacman (PacState (id, (x,y), v, o ,p, l) b oc m)) maze 
                                  | coiso == Empty = (Pacman (PacState (id, (x+1,y), v, o ,p, l) b oc m))
                                  | coiso == Food Little = (Pacman (PacState (id, (x+1,y), v, o ,p+1, l) b oc m))
                                  | coiso == Food Big = (Pacman (PacState (id, (x+1,y), v, o ,p+5, l) 10 oc Mega))
                                  | coiso == Wall = (Pacman (PacState (id, (x,y), v, o ,p, l) b oc m))
                                  | otherwise = (Pacman (PacState (id, (x+1,y), v, o ,p, l) b oc m))
                                  where coiso = quePeca  maze (id, (x+1,y), v, o ,p, l)
                                  
-- | atualiza o estado do pacman quando este realiza ações para a esquerda
playerActionsL :: Player -> Maze -> Player                                                 
playerActionsL (Pacman (PacState (id, (x,y), v, o ,p, l) b oc m)) maze 
                                  | y == 0 = funcaoTunelL (Pacman (PacState (id, (x,y), v, o ,p, l) b oc m)) maze
                                  | coiso == Empty = (Pacman (PacState (id, (x,y-1), v, o ,p, l) b oc m))
                                  | coiso == Food Little = (Pacman (PacState (id, (x,y-1), v, o ,p+1, l) b oc m))
                                  | coiso == Food Big = (Pacman (PacState (id, (x,y-1), v, o ,p+5, l) 10 oc Mega))
                                  | coiso == Wall = (Pacman (PacState (id, (x,y), v, o ,p, l) b oc m))
                                  | otherwise =  (Pacman (PacState (id, (x,y-1), v, o ,p, l) b oc m))
                                  where coiso = quePeca  maze (id, (x,y-1), v, o ,p, l)
                                  
                                  
-- | atualiza o estado do pacman quando este realiza ações para a direita
playerActionsR :: Player -> Maze -> Player                                                 
playerActionsR (Pacman (PacState (id, (x,y), v, o ,p, l) b oc m)) maze 
                                  | y == ((length(head maze))-1) = funcaoTunelR (Pacman (PacState (id, (x,y), v, o ,p, l) b oc m)) maze
                                  | coiso == Empty = (Pacman (PacState (id, (x,y+1), v, o ,p, l) b oc m))
                                  | coiso == Food Little = (Pacman (PacState (id, (x,y+1), v, o ,p+1, l) b oc m))
                                  | coiso == Food Big = (Pacman (PacState (id, (x,y+1), v, o ,p+5, l) 10 oc Mega))
                                  | coiso == Wall = (Pacman (PacState (id, (x,y), v, o ,p, l) b oc m))
                                  | otherwise = (Pacman (PacState (id, (x,y+1), v, o ,p, l) b oc m))
                                  where coiso = quePeca  maze (id, (x,y+1), v, o ,p, l)
                                  

-- | junta a s funções playerAction todas 
action :: Player -> Maze -> Orientation -> Player                                      
action (Pacman (PacState (id, (x,y), v, o ,p, l) b oc m)) maze ori 
 | ori == R && o == R = playerActionsR (Pacman (PacState (id, (x,y), v, o ,p, l) b (abreFecha oc) m)) maze 
 | ori == L && o == L = playerActionsL (Pacman (PacState (id, (x,y), v, o ,p, l) b (abreFecha oc) m)) maze 
 | ori == U && o == U = playerActionsU (Pacman (PacState (id, (x,y), v, o ,p, l) b (abreFecha oc) m)) maze 
 | ori == D && o == D = playerActionsD (Pacman (PacState (id, (x,y), v, o ,p, l) b (abreFecha oc) m)) maze 
 | otherwise = (Pacman (PacState (id, (x,y), v, ori ,p, l) b oc m))


-- | atualiza o labirinto deixando um espaço branco por onde o pacman passa
updateMaze :: Player -> [Player] -> Maze -> Orientation -> Maze                                                        
updateMaze (Pacman (PacState (id, (x,y), v, o ,p, l) t oc m)) lpac lab R = placePlayersOnMap lpac (replaceElemInMaze (x,y) Empty lab)
updateMaze (Pacman (PacState (id, (x,y), v, o ,p, l) t oc m)) lpac lab L = placePlayersOnMap lpac (replaceElemInMaze (x,y) Empty lab)
updateMaze (Pacman (PacState (id, (x,y), v, o ,p, l) t oc m)) lpac lab U = placePlayersOnMap lpac (replaceElemInMaze (x,y) Empty lab)
updateMaze (Pacman (PacState (id, (x,y), v, o ,p, l) t oc m)) lpac lab D = placePlayersOnMap lpac (replaceElemInMaze (x,y) Empty lab)
updateMaze _ lpac lab _ = lab 



-- | mete os fantasmas no meio da casa de fantatsmas qunado ele morre 
meioF :: Player -> [Player] -> Maze -> [Player]                               
meioF (Pacman (PacState (id, (x,y), v, o ,p, l) t oc m)) [] lab = []
meioF (Pacman (PacState (id, (x,y), v, o ,p, l) t oc m)) (Ghost(GhoState (i, (x1,y1), v', o' ,p', l') m'):xs)  lab 
 | x==x1 && y==y1 && m==Mega && m'==Dead = (Ghost(GhoState (i, ((div (length lab) 2 ),(div (length (head lab)) 2)), v', o' ,p', l') Alive)) : meioF (Pacman (PacState (id, (x,y), v, o ,p, l) t oc m)) xs lab
 | otherwise = (Ghost(GhoState (i, (x1,y1), v', o' ,p', l') m')) : meioF (Pacman (PacState (id, (x,y), v, o ,p, l) t oc m)) xs lab

-- | distingue o jogador pelo ID
distingueP :: Int -> [Player] -> Player                                                                            
distingueP a (p:t) 
 | a==getPlayerID p = p
 | otherwise = distingueP a t 


-- | distingue se é fantasma
distingueF :: [Player] -> [Player]                                       
distingueF ((Ghost(GhoState (id1, (x1,y1), v1, o1 ,p1, l1) m')):tail) = (Ghost(GhoState (id1, (x1,y1), v1, o1 ,p1, l1) m')): distingueF tail
distingueF ((Pacman (PacState (id, (x,y), v, o ,p, l) t oc m)):tail) = distingueF tail 
distingueF [] = []


-- | junta os pacmans e os ghosts numa lista 
juntaPG :: Player -> [Player] -> [Player]                                             
juntaPG (Pacman (PacState (id, (x,y), v, o ,p, l) t oc m)) lp = (Pacman (PacState (id, (x,y), v, o ,p, l) t oc m)) : lp

-- | se o jogador da lista tiver o mesmo id que o id dado, esse jogador vai ser retirado da lista
tira :: [Player] -> Int -> [Player]
tira [] id = []
tira (x:xs) id 
 | getPlayerID x == id = xs 
 | otherwise = x: tira xs id  


-- | executa uma jogada dado um Maze state 
play :: Play -> State -> State
play (Move i d) (State m ps l) 
  | getPlayerID (distinguep ps) == i = (State ( updateMaze (distingueP i ps) lpac m d ) lpac l)
  | otherwise = let ghost = distingueP i ps 
                    lp = tira ps i 
                    ghost1 = actionF ghost m d 
                    lp1 = ghost1:lp 
                in State m lp1 l 
 where lpac = (juntaPG (testeF (distingueP i ps) (action  (distingueP i ps) m d) (distingueF ps)) (mataFantasmas (action  (distingueP i ps) m d) m (meioF (testeF (distingueP i ps) (action  (distingueP i ps) m d) (distingueF ps)) (distingueF ps) m )))
       

-- | atualiza o estado do Fantasma quando este realiza ações para baixo
playerActionsUF :: Player -> Maze -> Player                                                    
playerActionsUF (Ghost(GhoState (id1, (x1,y1), v1, o1 ,p1, l1) m')) maze                                
                                  | coiso == Wall = (Ghost(GhoState (id1, (x1,y1), v1, o1 ,p1, l1) m')) 
                                  | otherwise = (Ghost(GhoState (id1, (x1-1,y1), v1, o1 ,p1, l1) m')) 
                                  where coiso = quePeca  maze (id1, (x1-1,y1), v1, o1 ,p1, l1)

-- | atualiza o estado do Fantasma quando este realiza ações para baixo
playerActionsDF :: Player -> Maze -> Player                                                  
playerActionsDF (Ghost(GhoState (id1, (x1,y1), v1, o1 ,p1, l1) m')) maze
                                  | coiso == Wall = (Ghost(GhoState (id1, (x1,y1), v1, o1 ,p1, l1) m'))
                                  | otherwise = (Ghost(GhoState (id1, (x1+1,y1), v1, o1 ,p1, l1) m'))
                                  where coiso = quePeca  maze (id1, (x1+1,y1), v1, o1 ,p1, l1)
                                  
-- | atualiza o estado do Fantasma quando este realiza ações para a esquerda
playerActionsLF :: Player -> Maze -> Player                                                 
playerActionsLF (Ghost(GhoState (id1, (x1,y1), v1, o1 ,p1, l1) m')) maze 
                                  | coiso == Wall = (Ghost(GhoState (id1, (x1,y1), v1, o1 ,p1, l1) m'))
                                  | otherwise =  (Ghost(GhoState (id1, (x1,y1-1), v1, o1 ,p1, l1) m'))
                                  where coiso = quePeca  maze (id1, (x1,y1-1), v1, o1 ,p1, l1)
                                  
                                  
-- | atualiza o estado do Fantasma quando este realiza ações para a direita
playerActionsRF :: Player -> Maze -> Player                                                 
playerActionsRF (Ghost(GhoState (id1, (x1,y1), v1, o1 ,p1, l1) m')) maze
                                  | coiso == Wall = (Ghost(GhoState (id1, (x1,y1), v1, o1 ,p1, l1) m'))
                                  | otherwise = (Ghost(GhoState (id1, (x1,y1+1), v1, o1 ,p1, l1) m'))
                                  where coiso = quePeca  maze (id1, (x1,y1+1), v1, o1 ,p1, l1)

-- | junta todas a playerActions dos fantasmas 
actionF :: Player -> Maze -> Orientation -> Player                                      
actionF (Ghost(GhoState (id1, (x1,y1), v1, o1 ,p1, l1) m')) maze ori 
 | ori == R && o1 == R = playerActionsRF (Ghost(GhoState (id1, (x1,y1), v1, o1 ,p1, l1) m')) maze 
 | ori == L && o1 == L = playerActionsLF (Ghost(GhoState (id1, (x1,y1), v1, o1 ,p1, l1) m')) maze 
 | ori == U && o1 == U = playerActionsUF (Ghost(GhoState (id1, (x1,y1), v1, o1 ,p1, l1) m')) maze 
 | ori == D && o1 == D = playerActionsDF (Ghost(GhoState (id1, (x1,y1), v1, o1 ,p1, l1) m')) maze 
 | otherwise = (Ghost(GhoState (id1, (x1,y1), v1, ori ,p1, l1) m'))


abreFecha :: Mouth -> Mouth
abreFecha b
 | b == Closed = Open
 | otherwise = Closed









{- |
= Introdução 

Na tarefa 1 o objetivo foi a criação de uma função que dada o numero de corredores horizontais e o seu comprimento, bem como um numero inteiro positivo para usar como semente
num gerador pseudoaleatório, que gera um labirinto, formado por diferentes tipos de peças que determinam o caminho por onde o jogador pode andar e maneiras diferentes de ganhar 
pontos, este labirinto também deveria estar dentro de certos parâmetros estabelecidos previamente.
Estes parâmetros eram a inclusão de um túnel em cada extremidade central do labirinto que deveria ser formada por 1 corredor caso a altura do labirinto fosse impar ou 2
corredores caso a altura do labirinto fosse par.
Um labirinto valido também deveria incluir uma casa de fantasmas com altura de 3, um comprimento de 9 caso o comprimento do labirinto fosse impar ou 8 caso o comprimento do 
labirinto fosse par, esta casa também deveria ser rodeada por espaços vazios.

= Objetivos

Para alcançar isto foi usada uma função que trocava dois corredores dados os mesmos e um inteiro que representava a posição onde deveria começar a troca, ReplaceInCorridor,
o que nos permitiu substituir os corredores do meio com a casa dos fantasmas e o túnel, localizando os mesmos com a função, get5MiddleCorridor.
Para gerar um labirinto aleatório usámos as funções tunel, que substitui no sitio adequado as paredes da extremidade central do labirinto por um tunel, funçãof, que coloca no 
centro do labirinto uma casa dos fantasmas, e geralablimites que gera aleatoriamente um labirinto rodeado de paredes onde serão aplicadas as outras 2 funções.

= Conclusão

Com isto somos capazes de gerar um labirinto semi-aleatório que obedece aos parâmetros estabelecidos no enunciado.
-}



-- | constroi um corredor só com paredes horizontais 
muralha :: Int -> Corridor                                      
muralha 0 = []
muralha x = Wall : muralha (x-1)


-- | constroi um corredor so com paredes verticais
muralhaV :: Maze -> Maze                                  
muralhaV [] = []
muralhaV (x:xs) = [[Wall] ++ x ++ [Wall]] ++ muralhaV xs


-- | gera um labirinto delimitado por paredes verticalmente e horizontalmente 
geraLabLimites :: Int -> Int -> Int -> Maze                         
geraLabLimites 0 0 0 = []
geraLabLimites x y z = muralhaV  (geraLab (y-2) (x-2) z)


-- | adiciona um dado corredor a um dado labirinto 
addCorridor :: Maze -> Corridor -> Maze                               
addCorridor [] c = [c]
addCorridor (x:xs) c = x : addCorridor xs c

-- | gera um labirinto  onde o primeiro e ultimo corredor sao paredes
geraLab :: Int -> Int -> Int -> Maze                                           
geraLab a l s = addCorridor ((muralha l):(geraMaze l (a-2) s)) (muralha l)


-- | gera uma casa de fantasmas baseada na altura do labirinto  
casaFantasma :: Int -> Maze                                                       
casaFantasma x 
 | even x = [[Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty],
             [Empty,Wall,Wall,Wall,Empty,Empty,Wall,Wall,Wall,Empty],
             [Empty,Wall,Empty,Empty,Empty,Empty,Empty,Empty,Wall,Empty],
             [Empty,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Empty],
             [Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty]]
 

 | otherwise = [[Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty,Empty],
                [Empty,Wall,Wall,Wall,Empty,Empty,Empty,Wall,Wall,Wall,Empty],
                [Empty,Wall,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Wall,Empty],
                [Empty,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Empty],
                [Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty,Empty]]



-- | dado um labirinto diz a sua largura
nrColunas :: Maze -> Int                                                       
nrColunas (x:xs) = length (x) 


-- | dada uma lista e um numero, retorna o elemento que está na posicão do numero dado
exclamacao :: [a] -> Int -> a                                                    
exclamacao (x:xs) 0 = x 
exclamacao (x:xs) n = exclamacao xs (n-1) 

-- | dado um labirinto dá as suas 5 linhas do meio 
get5MiddleCorridor :: Maze -> [Corridor]                                            
get5MiddleCorridor (x:xs) = let meio = (div (length (x:xs)) 2) -1
                              in [exclamacao (x:xs) meio,exclamacao (x:xs) (meio+1),exclamacao (x:xs) (meio-1),exclamacao (x:xs) (meio+2),exclamacao (x:xs) (meio-2)]
                            

-- | dado dois Corredores vais substituir o primeiro no segundo começando na posição dada 
replaceInCorridor :: Int -> Corridor -> Corridor -> Corridor                             
replaceInCorridor x [] [a] = [a] 
replaceInCorridor x [a] [] = [a] 
replaceInCorridor x l (z:zs) 
                        | x == 0 = l ++ (drop (length l) (z:zs))
                        | x /= 0 = z : replaceInCorridor (x-1) l zs 



-- | dado um labirinto diz a sua altura
nrLinhas :: Maze -> Int                                          
nrLinhas (x:xs) = length (x:xs)



-- | dado um labirinto troca as suas 5 linhas do meio pela casa dos fantasmas
funcaof :: Maze -> Maze                                                     
funcaof [] = []
funcaof l      
              | even (length l) = take ((div (length l) 2)-2) l ++ 
                           [replaceInCorridor ((div (length (head l)) 2)-5)  (exclamacao (casaFantasma (length (head l) )) 0 ) (exclamacao (get5MiddleCorridor l) 0 )] ++
                           [replaceInCorridor ((div (length (head l)) 2)-5)  (exclamacao (casaFantasma (length (head l) )) 1 ) (exclamacao (get5MiddleCorridor l) 1 )] ++
                           [replaceInCorridor ((div (length (head l)) 2)-5)  (exclamacao (casaFantasma (length (head l) )) 2 ) (exclamacao (get5MiddleCorridor l) 2 )] ++
                           [replaceInCorridor ((div (length (head l)) 2)-5)  (exclamacao (casaFantasma (length (head l) )) 3 ) (exclamacao (get5MiddleCorridor l) 3 )] ++
                           [replaceInCorridor ((div (length (head l)) 2)-5)  (exclamacao (casaFantasma (length (head l) )) 4 ) (exclamacao (get5MiddleCorridor l) 4 )] ++
                           (drop ((div (length l) 2)+1) l)

              | otherwise = take ((div (length l) 2)-1) l ++ 
                              [replaceInCorridor ((div (length (head l)) 2)-5)  (exclamacao (casaFantasma (length (head l) )) 0 ) (exclamacao (get5MiddleCorridor l) 0 )] ++
                              [replaceInCorridor ((div (length (head l)) 2)-5)  (exclamacao (casaFantasma (length (head l) )) 1 ) (exclamacao (get5MiddleCorridor l) 1 )] ++
                              [replaceInCorridor ((div (length (head l)) 2)-5)  (exclamacao (casaFantasma (length (head l) )) 2 ) (exclamacao (get5MiddleCorridor l) 2 )] ++
                              [replaceInCorridor ((div (length (head l)) 2)-5)  (exclamacao (casaFantasma (length (head l) )) 3 ) (exclamacao (get5MiddleCorridor l) 3 )] ++
                              [replaceInCorridor ((div (length (head l)) 2)-5)  (exclamacao (casaFantasma (length (head l) )) 4 ) (exclamacao (get5MiddleCorridor l) 4 )] ++
                               (drop ((div (length l) 2)+2) l)

-- | dado um labirinto troca as extremidades de uma (caso a altura seja impar) ou duas linhas (caso a altura seja par) do centro por chão              
tunel :: Maze -> Maze                                  
tunel [] = []
tunel l
 | even (length l) = take ((div (length l) 2)-1) l ++ 
                     [(Empty:(init (tail (exclamacao (get5MiddleCorridor l ) 0 ))) ++ [Empty])] ++ 
                     [(Empty:(init (tail (exclamacao (get5MiddleCorridor l ) 1 ))) ++ [Empty])] ++
                     drop ((div (length l) 2) + 1) l
 | otherwise = take ((div (length l) 2)) l ++ 
                     [(Empty:(init (tail (exclamacao (get5MiddleCorridor l ) 1 ))) ++ [Empty])] ++ 
                     drop ((div (length l) 2) + 1) l


-- | gera um labirinto válido incluindo a casa dos fantasmas no seu centro e o tunel nas extremidades do mesmo
generateMaze :: 
                Int ->                                                                                   
                  Int ->                                                   
                    Int -> Maze                                                                      
generateMaze a b c = tunel $ funcaof $ geraLabLimites a b c 


