-- | Dado um estado do jogo, devolve um conjunto de jogadas, uma de cada fantasma, com a melhor alternativa que cada consegue para reagir ao Pacman.
ghostPlay :: State -> [Play]
ghostPlay (State maze [] lvl) = []
ghostPlay s@(State maze l@(x:xs) lvl) | (isNotPacman (x:xs)) == [] = []
                                      | getGhostMode (head (isNotPacman (x:xs))) == Alive = (chaseMode s (getPlayerID (head (isNotPacman (x:xs))))) : ghostPlay (State maze (tail (isNotPacman l)) lvl)
                                      | getGhostMode (head (isNotPacman (x:xs))) == Dead = (scatterMode s (getPlayerID (head (isNotPacman (x:xs))))): ghostPlay (State maze (tail (isNotPacman l)) lvl)
                                      | otherwise = []

-- | Dado um estado do jogo e um id, devolve a jogada com a melhor alternativa que o Ghost com o dado id consegue para reagir ao Pacman.
chaseMode :: State -> Int -> Play
chaseMode s@(State maze l@(x:xs) lvl) id | isGhostHouse (getPlayerbyID id l) maze = Move id U
                                         | (podeMovimentar id l maze (getPlayerOrientation (getPlayerbyID id (x:xs))))== False = getBestPlay l id 
                                         | isPieceWall (getPlayerbyID id l) maze = pieceWall (getPlayerbyID id l) maze
                                         | otherwise = (Move id (getPlayerOrientation (getPlayerbyID id l)))

-- | Dado um estado do jogo e um id, devolve a jogada com a melhor alternativa que o Ghost com o dado id consegue para reagir ao Pacman.
scatterMode :: State -> Int -> Play
scatterMode s@(State maze l@(x:xs) lvl) id | isPieceWall (getPlayerbyID id l) maze = pieceWall (getPlayerbyID id l) maze
                                           | (podeMovimentar id l maze (getPlayerOrientation (getPlayerbyID id (x:xs)))) == False = deadGhost (getBestPlay l id) id
                                           | otherwise = (Move id (getPlayerOrientation (getPlayerbyID id l)))


-- | Devolve uma Play com a direção contrária 
deadGhost :: Play-> Int -> Play 
deadGhost p id | p == (Move id U) = (Move id D)
               | p == (Move id D) = (Move id U)  
               | p == (Move id R) = (Move id L)
               | p == (Move id L) = (Move id R)
               | otherwise = Move id Null


-- | Procura a menor distância ao Pacman, e devolve a melhor jogada
getBestPlay :: [Player] -> Int -> Play
getBestPlay l id | distM  (((fst(getPlayerCoords(getPlayerbyID id l)))+1),(snd(getPlayerCoords(getPlayerbyID id l)))) (getPlayerCoords ((getPacman l))) == (minimum ( listaDistM [(((fst(getPlayerCoords(getPlayerbyID id l)))+1),(snd(getPlayerCoords(getPlayerbyID id l)))) , ((fst(getPlayerCoords(getPlayerbyID id l))),(snd(getPlayerCoords(getPlayerbyID id l)))+1) , (((fst(getPlayerCoords(getPlayerbyID id l)))-1),(snd(getPlayerCoords(getPlayerbyID id l)))) , ((fst(getPlayerCoords(getPlayerbyID id l))),(snd(getPlayerCoords(getPlayerbyID id l)))-1) ] (getPlayerCoords ((getPacman l))) )) = Move id D
                 | distM  (((fst(getPlayerCoords(getPlayerbyID id l)))-1),(snd(getPlayerCoords(getPlayerbyID id l)))) (getPlayerCoords ((getPacman l))) == (minimum ( listaDistM [(((fst(getPlayerCoords(getPlayerbyID id l)))+1),(snd(getPlayerCoords(getPlayerbyID id l)))) , ((fst(getPlayerCoords(getPlayerbyID id l))),(snd(getPlayerCoords(getPlayerbyID id l)))+1) , (((fst(getPlayerCoords(getPlayerbyID id l)))-1),(snd(getPlayerCoords(getPlayerbyID id l)))) , ((fst(getPlayerCoords(getPlayerbyID id l))),(snd(getPlayerCoords(getPlayerbyID id l)))-1) ] (getPlayerCoords ((getPacman l))) )) = Move id U
                 | distM  ((fst(getPlayerCoords(getPlayerbyID id l))),(snd(getPlayerCoords(getPlayerbyID id l)))+1) (getPlayerCoords ((getPacman l))) == (minimum ( listaDistM [(((fst(getPlayerCoords(getPlayerbyID id l)))+1),(snd(getPlayerCoords(getPlayerbyID id l)))) , ((fst(getPlayerCoords(getPlayerbyID id l))),(snd(getPlayerCoords(getPlayerbyID id l)))+1) , (((fst(getPlayerCoords(getPlayerbyID id l)))-1),(snd(getPlayerCoords(getPlayerbyID id l)))) , ((fst(getPlayerCoords(getPlayerbyID id l))),(snd(getPlayerCoords(getPlayerbyID id l)))-1) ] (getPlayerCoords ((getPacman l))) )) = Move id L
                 | otherwise= Move id R



-- | Dá a lista de distâncias dos Ghosts ao Pacman 
listaDistM :: [Coords] -> Coords -> [Int]
listaDistM [] (a,b) = []
listaDistM (x:xs) (a,b) = distM x (a,b) : listaDistM xs (a,b) 


-- | Calcula a distância de Manhattan entre duas posições.
distM :: (Int,Int) -> (Int,Int) -> Int
distM (x1,y1) (x2,y2) = abs (x1 - x2) + abs (y1 - y2)


-- | Vê se a posição para onde o jogador pretende ir é ou não uma peça parede
isPieceWall :: Player-> Maze -> Bool
isPieceWall (Ghost (GhoState (id,(x,y),z,o,h,l) d )) maze | getpiece (x-1,y) maze == Wall = True
                                                          | getpiece (x+1,y) maze == Wall = True
                                                          | getpiece (x,y-1) maze == Wall = True
                                                          | getpiece (x,y+1) maze == Wall = True
                                                          | otherwise = False
 
-- | Verifica se o jogador em questao encontra-se perante uma parede do labirinto
pieceWall :: Player -> Maze-> Play
pieceWall (Ghost (GhoState (id,(x,y),z,Null,h,l) d )) maze = Move id Null
pieceWall (Ghost (GhoState (id,(x,y),z,o,h,l) d )) maze | getpiece (x-1,y) maze == Wall && o == U = Move id R
                                                        | getpiece (x+1,y) maze == Wall && o == D = Move id L
                                                        | getpiece (x,y-1) maze == Wall && o == L = Move id U
                                                        | getpiece (x,y+1) maze == Wall && o == R = Move id D
                                                        | otherwise = Move id o

-- | Vê se o jogador em questão encontra-se numa casa de fantasmas
isGhostHouse :: Player -> Maze -> Bool
isGhostHouse (Ghost (GhoState (id,(x,y),z,o,h,l) d )) maze = (x,y) == (((length (maze) `div` 2)),(length (head maze) `div` 2)) || (x,y) == (((length (maze) `div` 2)-1), (length (head maze) `div` 2))


-- | Testes
getLp (State maze l@(x:xs) lvl) = l
