-- | Testa se um player possui orientação igual à dada (Delvove True no caso afirmativo)
sameOrientation:: Player -> Orientation -> Bool
sameOrientation j o = if getPlayerOrientation (j) == o then True else False -- PacPlayer 


-- | Dadas umas coordenadas e uma orientação devolve as coordenadas correspondentes ao movimento pela respetiva oreientação
move :: Coords -> Orientation -> Coords
move (x,y) U = (x-1,y)
move (x,y) D = (x+1,y)
move (x,y) R = (x,y+1)
move (x,y) L = (x,y-1)
move (x,y) Null = (x,y)


-- | Infere a ação do Pacman e devolve a sua pontuação
setPlayerPoints :: Player -> Maze -> Coords -> Int
setPlayerPoints p maze (x,y) | getpiece (x,y) maze == (Food Little)= (getPlayerPoints p) +1
                             | getpiece (x,y) maze == (Food Big)  = (getPlayerPoints p)+5
                             | getpiece (x,y) maze == (Empty)  = (getPlayerPoints p)
                             | getpiece (x,y) maze == (Wall)  = (getPlayerPoints p)
                             | getpiece (x,y) maze /= Empty && getPacmanMode (p) == Mega = (getPlayerPoints p) +10 -------------mudar o empty por a peca fantasma
                             | otherwise = getPlayerPoints p

-- | Infere a ação do Pacman e devolve as suas lives (vidas)
setPlayerLives :: Player-> Maze -> GhostMode -> Player
setPlayerLives (Pacman (PacState (a,(x,y),z,o,h,l) q c d)) maze gM | getpiece (x,y) maze == (Food Little) = (Pacman (PacState (a,(x,y),z,o,h,l) q c d)) 
                                                                   | getpiece (x,y) maze == (Food Big) =(Pacman (PacState (a,(x,y),z,o,h,l) q c d))
                                                                   | getpiece (x,y) maze == (Wall) = (Pacman (PacState (a,(x,y),z,o,h,l) q c d))
                                                                   | getpiece (x,y) maze == (Empty) = (Pacman (PacState (a,(x,y),z,o,h,l) q c d))
                                                                   | null(filtraPorGhosts2 [(getpiece (x,y) maze)]) == False && gM == Alive && l >=1 =(Pacman (PacState (a,(((length (maze) `div` 2)+3), (length (head maze) `div` 2)),z,o,h,(l-1)) q c d)) --- mudar o empty pela peca fantasma
                                                                   | otherwise = (Pacman (PacState (a,(x,y),z,o,h,l) q c d))

-- | Dado um corredor devolve os fantasmas desse corredor
filtraPorGhosts2 :: [Piece] -> [Piece]
filtraPorGhosts2 [] = []
filtraPorGhosts2 ((PacPlayer (Ghost (GhoState (x,y,z,t,h,l) b ))):r) = (PacPlayer (Ghost (GhoState (x,y,z,t,h,l) b ))) : filtraPorGhosts2 r
filtraPorGhosts2 (h:t) = filtraPorGhosts2 t                                                                   

-- | Dada uma lista de jogadores devolve a lista com o Pacman
isPacman :: [Player] -> [Player]
isPacman [] = []
isPacman ((Pacman (PacState a b c d )) : r) = (Pacman (PacState a b c d)) : isPacman r
isPacman (x:r) = isPacman r 
--isPacman _ = [(Pacman (PacState (0,(7,11),1,R,1,1) 0 Open Normal))]               


-- | Infere a ação do Ghost e devolve o Pacman com o Mode alterado
setPacmanPMode :: Player-> Maze -> GhostMode -> Player
setPacmanPMode p@(Pacman (PacState (a,(x,y),z,o,h,l) q c d)) maze _ | l < 1 = (Pacman (PacState (a,(x,y),z,o,h,0) q c Dying))
setPacmanPMode p@(Pacman (PacState (a,(x,y),z,o,h,l) q c d)) maze Dead = (Pacman (PacState (a,(x,y),z,o,h,l) q c Mega))
setPacmanPMode p@(Pacman (PacState (a,(x,y),z,o,h,l) q c d)) maze Alive | (getpiece (getPlayerCoords p) maze) == Food Big = (Pacman (PacState (a,(x,y),z,o,h,l) 10 c Mega))
                                                                        | (getpiece (getPlayerCoords p) maze) /= Empty && getPacmanMode p == Normal && getPlayerLifes (p) == 0 = (Pacman (PacState (a,(x,y),z,o,h,l) q c Dying))
                                                                        | otherwise = (Pacman (PacState (a,(x,y),z,o,h,l) q c Normal))

-- | Infere a ação do Ghost e devolve o Ghost com o Mode alterado    
setGhostPMode :: Player-> Maze -> PacMode -> Player
setGhostPMode g@(Ghost (GhoState (a,(x,y),z,o,h,l) d )) maze Mega = (Ghost (GhoState (a,(x,y),z,o,h,l) Dead ))
setGhostPMode g@(Ghost (GhoState (a,(x,y),z,o,h,l) d )) maze Dying = (Ghost (GhoState (a,(x,y),z,o,h,l) Alive ))
setGhostPMode g@(Ghost (GhoState (a,(x,y),z,o,h,l) d )) maze Normal | (getpiece (move (x,y) o) maze) /= Empty && d == Alive = (Ghost (GhoState (a,(x,y),z,o,h,l) Alive))
                                                                    | (getpiece (move (x,y) o) maze) /= Empty && d == Dead = (Ghost (GhoState (a,(x,y),z,o,h,l) Alive ))
                                                                    | otherwise = (Ghost (GhoState (a,(x,y),z,o,h,l) Alive ))

-- | Dá a velocidade dos players
getPlayerSpeed :: Player -> Double
getPlayerSpeed (Pacman (PacState (x,y,z,t,h,l) q c d )) = z
getPlayerSpeed (Ghost (GhoState (x,y,z,t,h,l) q )) = z


-- | Altera a velocidade do Ghost 
setPlayerSpeed :: Player -> GhostMode -> Double
setPlayerSpeed g gM | gM == Dead  =  ((getPlayerSpeed g) / 2)
                    | otherwise = getPlayerSpeed g

-- | Dá o Mode do Ghost
getGhostMode :: Player -> GhostMode
getGhostMode (Ghost (GhoState a d)) = d
getGhostMode _ = Alive

 
-- | Dá as vidas dos jogador
getPlayerLifes :: Player -> Int
getPlayerLifes (Pacman (PacState (x,y,z,t,h,l) b c d )) = l
getPlayerLifes (Ghost (GhoState (x,y,z,t,h,l) b )) = l

-- | Altera o estado de um fantamsma
setPlayerGMode :: Player -> GhostMode -> Player
setPlayerGMode (Ghost (GhoState (x,y,z,t,h,l) q )) pm | pm == Dead = Ghost (GhoState (x,y,z,t,h,l) Dead )
                                                      | otherwise = Ghost (GhoState (x,y,z,t,h,l) Alive )



-- | Passa os Fantasmas para mortos ou vivos consoante o modo do pacman
mata :: [Player] -> [Player]
mata x
 | checkm x = killG x
 | checka x = aliveG x
 | otherwise = x

-- | Vê se o pacman esta em modo Mega
checkm :: [Player] -> Bool
checkm [] = False
checkm ((Pacman x):xs)
 | getPacmanMode (Pacman x) == Mega = True
 | otherwise = checkm xs
checkm (x:xs) = checkm xs

-- | Coloca o fantasmas mortos
killG :: [Player] -> [Player]
killG [] = []
killG ((Ghost (GhoState x y )):xs) = Ghost(GhoState x Dead) : killG xs
killG (x:xs) = x:killG xs

-- | Vê se o pacman encontra-se com o estado Normal
checka :: [Player] -> Bool
checka [] = False
checka ((Pacman x):xs)
 | getPacmanMode (Pacman x) == Normal = True
 | otherwise = checka xs
checka (x:xs) = checka xs

-- | Coloca os fantasmas vivios
aliveG :: [Player] -> [Player]
aliveG [] = []
aliveG ((Ghost (GhoState x y )):xs) = Ghost(GhoState x Alive) : aliveG xs
aliveG (x:xs) = x:aliveG xs


-- | Da a lista com as coordenadas de todos os ghosts presentes na lista de players
daCoordsGhost :: [Player] -> [Coords]
daCoordsGhost [] = [] 
daCoordsGhost (g@(Ghost (GhoState x y )):xs) = (getPlayerCoords g) : daCoordsGhost xs
daCoordsGhost (x:xs) = daCoordsGhost xs

-- | Testa se a posição para onde o player se deseja movimentar é uma parede (False corresponde a parede, True corresponde a pode movimentar-se)
podeMovimentar :: Int -> [Player] -> Maze -> Orientation -> Bool
podeMovimentar id lp maze o | getpiece (move (getPlayerCoords (getPlayerbyID id lp)) o) maze == Wall = False
                            | otherwise = True

-- | Dada uma lista de jogadores retorna uma lista apenas com aqueles que não são um Pacman
isNotPacman :: [Player] -> [Player]
isNotPacman [] = []
isNotPacman ((Ghost (GhoState (x,y,z,t,h,l) q )) : r) = (Ghost (GhoState (x,y,z,t,h,l) q )) : isNotPacman r
isNotPacman (x:r) = isNotPacman r


-- | Dada uma lista de Players devolve o Pacman
getPacman :: [Player] -> Player
getPacman ((Pacman (PacState a b c d )) : r) = (Pacman (PacState a b c d))
getPacman (x:r) = getPacman r
getPacman _ = (Pacman (PacState (0,(7,11),1,R,1,1) 0 Open Normal))    
 
-- | Verifica se um Player é um Ghost (Devolve True no caso afirmativo)
isGhostAux :: Player -> Bool
isGhostAux (Ghost (GhoState (x,y,z,t,h,l) b )) = True
isGhostAux (Pacman (PacState (x,y,z,t,h,l) b c d )) = False
 

-- | Verifica se as coordenadas dadas correspondem a um túnel, e se tal acontecer devolve as coordenadas de destino do tunel
isTunnel :: Maze -> Coords-> Orientation-> Coords
isTunnel maze (x,y) o | y<0 && o == L = (x,((length (head maze))-1))
                      | y>((length (head maze))-1) && o == R = (x,0)
                      | otherwise = (x,y)


-- | Verifica se o Pacman pode comer os Fantasmas, e se tal acontecer devolve as coordenadas de destino dos Fantasmas (Casa Fantasmas)
isDead :: Maze -> GhostMode -> Coords -> Coords -> Coords
isDead maze gM (x,y) (x2,y2)| gM == Dead && x == x2 && y==y2 = ((length (maze) `div` 2), (length (head maze) `div` 2))
                            | otherwise = (x,y)

-- | Dadas uma lista de players e um Id, devolve a lista de players sem o player com o respetivo id
dropPlayerbyID :: Int -> [Player] -> [Player]
dropPlayerbyID id [] = []
dropPlayerbyID id (x:y) |getPlayerID x == id = dropPlayerbyID id y
                        |otherwise = x:dropPlayerbyID id y

-- | Devolve um Pacman com toda a informação atualizada, resultadnte da jogada feita
setPacmanState :: Player -> Maze -> GhostMode -> Player
setPacmanState p@(Pacman (PacState (a,(x,y),z,o,h,l) q c d)) maze gM | podeMovimentar a [p] maze o == False && gM == Alive = setPlayertimeMega (setPacmanPMode (setPlayerLives (Pacman (PacState (a,(((x,y))),z,o,(setPlayerPoints p maze (move (x,y) o)),l) q (setPlayerImage c) d)) maze Alive) maze Alive)
                                                                     | podeMovimentar a [p] maze o == False && gM == Dead = setPlayertimeMega (setPacmanPMode (setPlayerLives (Pacman (PacState (a,(((x,y))),z,o,(setPlayerPoints p maze (move (x,y) o)),l) q (setPlayerImage c) d)) maze Dead) maze Dead)
                                                                     | gM == Dead = setPlayertimeMega (setPacmanPMode(setPlayerLives (Pacman (PacState (a,(isTunnel maze (move (x,y) o) o),z,o,(setPlayerPoints p maze (move (x,y) o)),l) q (setPlayerImage c) d))  maze Dead) maze Dead)
                                                                     | otherwise = setPlayertimeMega (setPacmanPMode (setPlayerLives (Pacman (PacState (a,(isTunnel maze (move (x,y) o) o),z,o,(setPlayerPoints p maze (move (x,y) o)),l) q (setPlayerImage c) d)) maze gM) maze gM)


-- | Devolve uma lista de Ghosts com toda a informação atualizada, resultadnte da jogada feita
setGhoState :: [Player] -> Maze -> PacMode -> Coords -> [Player]
setGhoState [] _ _ _ = []
setGhoState w@(Ghost (GhoState (a,(x,y),z,o,h,l) d ):xs) maze pM (x2,y2) | pM == Normal = (setGhostPMode (Ghost (GhoState (a,((x,y)),(setPlayerSpeed (head w) (getGhostMode (head w))),o,h,l) d)) maze Normal) : (setGhoState xs maze Normal (x2,y2))
                                                                         | pM == Mega = (setGhostPMode (Ghost (GhoState (a,(isDead maze d ((x,y)) (x2,y2)),(setPlayerSpeed (head w) (getGhostMode (head w))),o,h,l) d)) maze Mega) : (setGhoState xs maze Mega (x2,y2))
                                                                         | otherwise = (setGhostPMode (Ghost (GhoState (a,(x,y),(setPlayerSpeed (head w) (getGhostMode (head w))),o,h,l) d)) maze  Dying) : (setGhoState xs maze Dying (x2,y2))
setGhoState (p@(Pacman (PacState (a,(x,y),z,o,h,l) q c d)):xs) maze pM (x2,y2) = p : setGhoState xs maze pM (x2,y2)

-- | Efetua uma jogada para um determinado jogador sobre um determinado estado, retornando o novo estado após a jogada ser efetuada.
play :: Play -> State -> State
play (Move id o) (State maze l@(x:xs) lvl) | isGhostAux (getPlayerbyID id (x:xs)) = playGhosts (Move id o) (State maze (x:xs) lvl)
                                           | getPacmanMode (getPlayerbyID id (x:xs)) == Dying = (State maze (x:xs) lvl)
                                           | (sameOrientation (getPlayerbyID id (x:xs)) o) && (podeMovimentar id (x:xs) maze o) = State (replaceElemInMaze (getPlayerCoords (getPlayerbyID id (x:xs))) Empty maze) (mata (((setPacmanState (getPlayerbyID id (x:xs)) (placePlayersOnMap l maze) (getGhostMode (head (isNotPacman (x:xs))))) : (setGhoState (isNotPacman (x:xs)) (placePlayersOnMap l maze)  (getPacmanMode (setPacmanPMode (getPlayerbyID id (x:xs)) maze (getGhostMode (head (isNotPacman (x:xs)))))) (getPlayerCoords (getPlayerbyID id l)))))) lvl -- se a nova orientação for igual e poder movimentar-se, há uma açã
                                           | (podeMovimentar id (x:xs) maze o) == False = (State maze (mata (((setPacmanState (getPlayerbyID id (x:xs)) (placePlayersOnMap l maze) (getGhostMode (head (isNotPacman (x:xs))))) : (setGhoState (isNotPacman (x:xs)) (placePlayersOnMap l maze)  (getPacmanMode (setPacmanPMode (getPlayerbyID id (x:xs)) maze (getGhostMode (head (isNotPacman (x:xs)))))) (getPlayerCoords (getPlayerbyID id l)))))) lvl)
                                           | otherwise = (State maze ([setPlayerOrientation (getPlayerbyID id (x:xs)) o]++dropPlayerbyID id (x:xs)) lvl) -- se a nova orientação for diferente ou não poder movimentar, apenas muda a orientação


-- | Efetua uma jogada para um fantasma
playGhosts :: Play -> State -> State
playGhosts (Move id o) s@(State maze lp@(x:xs) lvl)| (sameOrientation (getPlayerbyID id (x:xs)) o) && (podeMovimentar id (x:xs) maze o) = State maze ((([setGhost(setPlayerOrientation(getPlayerbyID id (x:xs)) o)]++ setGhoState (dropPlayerbyID id (x:xs)) (placePlayersOnMap lp maze) (getPacmanMode (getPacman lp)) (getPlayerCoords (getPacman lp))))) lvl 
                                                   | otherwise = (State maze ([setPlayerOrientation (getPlayerbyID id (x:xs)) o]++dropPlayerbyID id (x:xs)) lvl)

-- | Devolve o fantasma com as coordenadas resultantes de um movimento
setGhost :: Player -> Player
setGhost (Ghost(GhoState (id,(x,y),z,o,h,l) q)) = (Ghost (GhoState (id,(moveG (x,y) o),z,o,h,l) q))
setGhost p@(Pacman(PacState (id,(x,y),z,o,h,l) q c d)) = p
 
-- | Altera umas coordenadas de acordo com uma orientação
moveG :: Coords -> Orientation -> Coords
moveG (x,y) U = (x-1,y)
moveG (x,y) D = (x+1,y)
moveG (x,y) R = (x,y+1)
moveG (x,y) L = (x,y-1)
moveG (x,y) Null = (x-1,y)




{-|
