= Introdução

Na Tarefa1 pretendeu-se implementar um mecanismo de geração de labirintos tendo como inputs o número de corredores horizontais (altura) e 
o seu comprimento (largura), e um número inteiro positivo para usar como semente num gerador pseudo-aleatório.

= Objetivos

Nesta Tarefa, em que tínhamos como objetivo gerar um labirinto, tivemos de começar por gerar números aleatórios entre 0 e 99 para posteriormente
serem convertidos em peças, (Empty, Wall, Food Big ou Food Little); as peças das bordas do labirinto exigem-se todas Wall. Depois disto, um 
labirinto válido necessitava também de possuir túneis (1 no caso da altura ímpar e 2 no caso da altura par). Para finalizar, um labirinto válido 
requer também uma casa dos fantasmas, colocada no meio deste.
Optamos por realizar estas exigências pela ordem referida, começando por gerar números aleatórios, converte-los, colocar as bordas, colocar o (os)
túnel (túneis) e a casa dos fantasmas.

= Discussão e Conclusão

Sendo esta a primeira tarefa do trabalho ainda não tínhamos noção daquilo que seria o desenrolar do processo de realização do mesmo, olhando para 
trás consideramos que fizemos um trabalho satisfatório dentro daquilo que tínhamos definido como objetivo. A tarefa cumpre as exigências e os
parâmetros, bem como um código eficaz.

-}







-- | Given a seed returns a list of n integer randomly generated
--
generateRandoms :: Int -> Int -> [Int]
generateRandoms n seed = let gen = mkStdGen seed -- creates a random generator
                        in take n $ randomRs (0,99) gen -- takes the first n elements from an infinite series of random numbers between 0-9


-- | Given a seed returns an integer randomly generated
--
nrAleatorio :: Int -> Int
nrAleatorio seed = head $ generateRandoms 1 seed


-- | Converts a list into a list of list of size n
--
subLista :: Int -> [a] -> [[a]]
subLista _ [] = []
subLista n l = take n l: subLista n (drop n l)


-- | Converts an integer number into a Piece
--
convertePiece :: Int -> Piece
convertePiece x 
 | x == 3 = Food Big
 | x < 70 && x >= 0 = Food Little
 | x >= 70 && x<=99 = Wall
 | otherwise = Empty


-- | Converts a Corridor to a string
--
printCorridor :: Corridor -> String
printCorridor [] = "\n"
printCorridor (x:xs) = show x ++ printCorridor xs----para juntar strings :



-- | Converts a Maze to a string
--
printMaze :: Maze -> String
printMaze []  = []
printMaze (x:xs) = printCorridor x ++ printMaze xs---------para juntar listas ++

-- | Converts a list of integers into a Corridor
converteCorridor :: [Int] -> Corridor
converteCorridor [] = []
converteCorridor (x:xs) = convertePiece x : converteCorridor xs

-- | Converts a list of lists of integers into a Maze
converteMaze :: [[Int]] -> Maze
converteMaze [] = []
converteMaze (x:xs) = converteCorridor x : converteMaze xs

-- | Given a length a height and a seed returns a Maze
geraMaze :: Int -> Int -> Int -> Maze
geraMaze x y s =
                 let random_nrs = generateRandoms ((x)*(y)) s
                 in converteMaze $ subLista x random_nrs

------------------------------------------------------------------------------------------------------------------------------------------------------------
-- | Converte uma lista de inteiros num corredor com parede no inicio 
converteCorridorParedeI :: [Int] -> Corridor
converteCorridorParedeI [] = []
converteCorridorParedeI (x:xs) = Wall : convertePiece x : converteCorridor xs

-- | Converte uma lista de inteiros num corredor com parede no fim 
converteCorridorParedeF :: [Int] -> Corridor
converteCorridorParedeF [] = []
converteCorridorParedeF [x] = Wall : converteCorridorParedeF []
converteCorridorParedeF (x:xs) = convertePiece x : converteCorridorParedeF xs

-- | Converte uma lista de inteiros num corredor com paredes no inicio e fim
converteCorridorParedes :: [Int] -> Corridor
converteCorridorParedes [] = []
converteCorridorParedes (x:xs) = Wall : convertePiece x : converteCorridorParedeF xs

-- | Converte uma lista de listas de inteiros num Maze com paredes do lado esquerdo 
converteMazeE :: [[Int]] -> Maze
converteMazeE [] = []
converteMazeE (x:xs) = converteCorridorParedeI x : converteMazeE xs

-- | Dado uma largura uma altura e uma seed gera um Maze com paredes à esquerda
geraMazeParedeE :: Int -> Int -> Int -> Maze
geraMazeParedeE x y s =
                 let random_nrs = generateRandoms ((x)*(y)) s
                 in converteMazeE $ subLista x random_nrs


-- | Converte uma lista de listas de inteiros num Maze com paredes do lado direito
converteMazeD :: [[Int]] -> Maze
converteMazeD [] = []
converteMazeD (x:xs) = converteCorridorParedeF x : converteMazeD xs

-- | Dado uma largura uma altura e uma seed gera um Maze com paredes à direita
geraMazeParedeD :: Int -> Int -> Int -> Maze
geraMazeParedeD x y s =
                 let random_nrs = generateRandoms ((x)*(y)) s
                 in converteMazeD $ subLista x random_nrs

-- | Converte uma lista de listas num Maze com paredes à direita e à esquerda
converteMazes :: [[Int]] -> Maze
converteMazes [] = []
converteMazes (x:xs) = converteCorridorParedes x : converteMazes xs

-- | Dado uma largura uma altura e uma seed gera um Maze com paredes à direita e à esquerda
geraMazes :: Int -> Int -> Int -> Maze
geraMazes x y s =
                 let random_nrs = generateRandoms ((x)*(y)) s
                 in converteMazes $ subLista x random_nrs

-- | Gera paredes na parte de cima do Labirinto
geraWallCima:: Int-> Corridor
geraWallCima 0 = [Wall]
geraWallCima f = Wall : geraWallCima (f-1)


-- | Gera a parte de cima o Labirinto
geraMazeCima:: Int->Int->Int->Maze
geraMazeCima l a s = (geraWallCima l) : (geraMazes l (a-2) s)

-- | Gera a parte de baixo do labirinto
geraMazeBaixo:: Int -> Int -> Int-> Maze-- altura, largura, semente
geraMazeBaixo l a s = (corredorFinal (geraMazes l (a-2) s) (geraWallCima l))

-- | Coloca um corredor de paredes no fim do Maze
corredorFinal :: Maze->Corridor->Maze
corredorFinal [] c = [c]
corredorFinal (x:xs) c = x : corredorFinal xs c


-- | Coloca a lista com o túnel no fim no Maze
juntatuneis :: Int-> Int-> Int -> Maze 
juntatuneis l a s = replaceNth (getMiddleL (labirintoFinal l a s)) (faztuneisF l a s) (labirintoFinal l a s)
                  where faztuneisF l a s = replaceNth l Empty ((faztuneis l a s)!!(getMiddleL (labirintoFinal l a s))) -- Coloca uma peça Empty no fim do corredor do meio
-- | Coloca a lista com o túnel no início no Maze
faztuneis :: Int-> Int-> Int -> Maze 
faztuneis l a s = replaceNth (getMiddleL (labirintoFinal l a s)) (faztuneisI l a s) (labirintoFinal l a s)
                  where faztuneisI l a s = replaceNth 0 Empty ((labirintoFinal l a s)!!(getMiddleL (labirintoFinal l a s))) -- Coloca uma peça Empty no início do corredor do meio

-- | Verifica se o Maze tem altura par ou ímpar
faztuneisImpar :: Int-> Int-> Int -> Maze
faztuneisImpar l a s 
              |even a = replaceNth ((getMiddleL (labirintoFinal l a s))-1) (faztuneis2 l a s) (juntatuneis l a s) -- Se tiver altura ímpar,
              |otherwise = juntatuneis l a s -- Se tiver altura par

-- | Coloca uma peça Empty no fim do corredor do meio
faztuneis2 :: Int-> Int-> Int -> Corridor
faztuneis2 l a s = replaceNth l Empty ((faztuneis3 l a s)!!((getMiddleL (labirintoFinal l a s))-1))

-- | Coloca a lista com o túnel no inicio no Maze
faztuneis3 :: Int-> Int-> Int -> Maze 
faztuneis3 l a s = replaceNth ((getMiddleL (labirintoFinal l a s))-1) (faztuneis4 l a s) (labirintoFinal l a s)

-- | Coloca uma peça Empty no início do corredor do meio
faztuneis4 :: Int-> Int-> Int -> Corridor 
faztuneis4 l a s = replaceNth 0 Empty ((labirintoFinal l a s)!!((getMiddleL (labirintoFinal l a s))-1))


-- | Dada uma posição, um elemento e uma lista, devolve a lista com o novo elemento dado, na posição dada
replaceNth :: Int -> a -> [a] -> [a]
replaceNth _ _ [] = []
replaceNth n newVal (x:xs)
   | n == 0 = newVal:xs
   | otherwise = x:replaceNth (n-1) newVal xs



-- | Dá metade do labirinto
getMiddleL :: Maze -> Int
getMiddleL l = length (l) `div` 2

-- | Divide o labirinto em dois pela altura(meio do Maze)
getMiddlelab ::  Maze-> Int
getMiddlelab lab = length (lab) `div` 2

-- | Função predefinida posição
exclamacao:: [Piece]->Int->Piece
exclamacao [] _ = Empty
exclamacao (x:xs) 0 = x
exclamacao (x:xs) n = exclamacao xs (n-1)

-- | Auxiliar chamada para devolver linha a linha a casa dos fantasmas
casaFantasman :: Int -> Int -> Corridor
casaFantasman l n
 | even l && n==0= [Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty]
 | even l && n==1= [Empty,Wall,Wall,Wall,Empty,Empty,Wall,Wall,Wall,Empty]
 | even l && n==2= [Empty,Wall,Empty,Empty,Empty,Empty,Empty,Empty,Wall,Empty]
 | even l && n==3= [Empty,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Empty]
 | even l && n==4= [Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty]
 | odd l && n==0 = [Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty]
 | odd l && n==1 = [Empty,Wall,Wall,Wall,Empty,Empty,Empty,Wall,Wall,Wall,Empty]
 | odd l && n==2= [Empty,Wall,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Wall,Empty]
 | odd l && n==3= [Empty,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Empty]
 | odd l && n==4 = [Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty]
 | otherwise = []


-- | Dado uma largura uma linha atual das casa dos fantasmas e uma seed devolve um corredor com a casa dos Fantasmas
larguraf :: Int-> Int-> Int -> Corridor
larguraf l n s =concat (geraMazeParedeE((l-10)`div` 2) 1 s ++ [casaFantasman l n] ++ (geraMazeParedeD ((l-10)`div` 2) 1 (s+10)))

-- | Dada uma largura uma altura e uma seed devolve um Maze com a altua da casa dos fantamas e com esta no centro
geraCasaFantasmas :: Int->Int->Int ->Maze
geraCasaFantasmas l n s | n>=5 = []
geraCasaFantasmas l n s = larguraf l n s : geraCasaFantasmas l (n+1) (s+1) 

-- | Dada uma largura uma altura e uma seed devolve um Maze com a casa dos fantamas centrada 
labirintoFinal :: Int->Int->Int->Maze
labirintoFinal l a s =concat (geraMazeCima l ((a-2)`div`2) s : [geraCasaFantasmas l 0 s] ++ [(geraMazeBaixo l ((a-3)`div`2)) (s+10)])

-- | Função final que dada a largura a altura e uma seed devolve o labirinto completo
generateMaze:: Int->Int->Int -> Maze
generateMaze l a s = faztuneisImpar l a s





