{- | Função que verifica o número de peças comestíveis no tabuleiro do jogo.
     Retorna True caso o jogo tenha acabado, retorna False caso contrário. -}
verifyGame :: State -> Bool 
verifyGame (State maze jogadores nivel) 
    | (count $ maze) == 0 = True
    | otherwise = False

{- | Juntamente com a função *count* esta função remove todas as peças não comestíveis pelo pacman (i.e. Wall | Empty)-}
compact :: Maze -> Maze
compact [] = []
compact (x:y) = filter (\p -> case p of {Food a -> True; otherwise -> False}) (x) : compact y 

{- | Esta função conta o número de peças nos corredores, previamente reduzidos pela *compact*.-}
count :: Maze -> Int
count [] = 0
count maze = length(x) + count y
    where (x:y) = compact maze

{-==================================================================================================================-}
-- > { Normal Play Above Threshold }

{- | Esta função simula todas as jogadas possiveis do Pacman.
     Estas, serão posteriormente analizadas e apenas uma será escolhida. -}
bot_play :: State -> Maybe Play
bot_play s@(State m j i) 
    | c == Normal = Just (autoplay s)
    | c == Mega = Just (mega_play s)
    | otherwise = Nothing
    where (Pacman (PacState (id, (y,x), v, o, p, l) a b c)) = getPacm' j

{- | Tendo em conta threshold e a distância do Pacman ao fantasma mais próximo, esta função decide a proxima jogada do mesmo.  -}
autoplay :: State -> Play
autoplay (State m j l)
    | cd > th =  Move id (get_orientation (State m j l))
    | otherwise = (bellow_play (State m j l))
    where th = threshold m
          cd = current_distance $ calculate $ j
          id = getPacID' (State m j l)

{- | Para não criar um cluster na função *autoplay* foi criada esta função para apenas retirar a orientação da lista dos triplos.-}
get_orientation :: State -> Orientation
get_orientation state = o
    where (c,o,p) = last $ choose_piece $ takeWalls $ possible_plays state

{- | Esta função gera a lista dos triplos que contém as coordenadas, orientação e a peça.
     Cada triplo é analizado e escolhido conforme o valor da peça seguinte.-}
possible_plays :: State -> [(Coords,Orientation,Piece)]
possible_plays (State m j l) = [((y,x+1),R,seek_future m (Pacman (PacState (id, (y,x), v, R, p, l) a b c))),
                                ((y,x-1),L,seek_future m (Pacman (PacState (id, (y,x), v, L, p, l) a b c))),
                                ((y+1,x),D,seek_future m (Pacman (PacState (id, (y,x), v, D, p, l) a b c))),
                                ((y-1,x),U,seek_future m (Pacman (PacState (id, (y,x), v, U, p, l) a b c)))]
    where pac@(Pacman (PacState (id, (y,x), v, o, p, l) a b c)) = getPacm' j

{- | Esta função é responsável por filtrar todos os triplos que contenham Wall como piece.
     Com isto podemos poupar tempo e evitar loops desnecessários. -}
takeWalls :: [(Coords,Orientation,Piece)] -> [(Coords,Orientation,Piece)]
takeWalls s@((a,b,c):y) = filter (\(a,b,c) -> case c of Wall -> False; otherwise -> True) s

{- | Esta função calcula as peças adjacentes ao jogador.
     As peças são depois filtradas pela *takeWalls*. -}
seek_future :: Maze -> Player -> Piece
seek_future maze (Pacman (PacState (id, (y,x), v, o, p, l) a b c)) 
    | o == L = corridor!!(x-1)
    | o == R = corridor!!(x+1) 
    | o == U = (maze!!(y-1))!!x
    | o == D = (maze!!(y+1))!!x
    where corridor = (maze!!y)

-- | Foi definido um sistema de valores entre as peças.
-- | Esta função ordena a lista tendo em conta esse valor: 
-- 
-- * Empty < Food Little < Food Big
--
-- | O sistema de valores não inclui a peça Wall pois é ela filtrada antes desta função executar.
-- | A peça de melhor valor fica no final da lista.
choose_piece :: [(Coords,Orientation,Piece)] -> [(Coords,Orientation,Piece)]
choose_piece [] = []
choose_piece (x:y) = insertP x (choose_piece y)
    where insertP (x,y,z) [] = [(x,y,z)]
          insertP (x,y,z) ((a,b,c):i) 
            | z <= c = ((x,y,z):(a,b,c):i)
            | otherwise = (a,b,c):(insertP (x,y,z) i)          

{- | Esta instância foi criada para podermos comparar peças.
     Ficou definido que Empty < Food Little < Food Big. 
     A peça Wall não é incluida sendo que ela é filtrada.-}
instance Ord Piece where 
    (<=) (Food Big) (Food Little) = False
    (<=) (Food Big) (Empty) = False
    (<=) (Food Big) (Food Big) = True
    (<=) (Food Little) (Empty) = False
    (<=) (Food Little) (Food Big) = True
    (<=) (Food Little) (Food Little) = True
    (<=) (Empty) (Food Big) = True
    (<=) (Empty) (Food Little) = True
    (<=) (Empty) (Empty) = True

{-==================================================================================================================-}
-- > { Mega Play }

{- | Esta funcão define a jogada que o bot deverá fazer caso esteja em modo Mega. 
     Caso exista um fantasma no mesmo corredor que o Pacman (averiguado pela *is_ghost*), este deverá mover-se segundo a função *right_left* que verifica se o fantásma está à esquerda ou direita do jogador.
     Caso não exista nenhum fantasma no mesmo corredor que o Pacman, este continuará a procurar fantasmas segundo a função *look_for_ghost*, tentando mudar de corredor se possível. -}
mega_play :: State -> Play 
mega_play (State maze j l) 
    | is_ghost j = if (right_left j == 1) then (Move id R) else (Move id L)
    | otherwise = look_for_ghost maze j
    where pac@(Pacman (PacState (id, (y,x), v, o, p, l) a b c)) = getPacm' j

{- | Esta função verifica se existe algum fantasma no corredor em que o Pacman se encontra. -}
is_ghost :: [Player] -> Bool 
is_ghost jr = y `elem` (y_list jr)
    where pac@(Pacman (PacState (id, (y,x), v, o, p, l) a b c)) = getPacm' jr

{- | Para sabermos se existe ou não pelo menos um fantasma no mesmo corredor que o pacman, esta função cria uma lista com os *yys* dos fantasmas.
     Esta lista é aplicada na função *is_ghost* onde se verifica se o *y* do Pacman está nessa lista. -}
y_list :: [Player] -> [Int]
y_list [] = []
y_list ((Ghost (GhoState (id, (y,x), (v), o, p, l) mode)):r) = (y):(y_list r)
y_list ((Pacman (PacState (id, (y,x), v, o, p, l) a b c)):r) = y_list r

{- | Esta função define o movimento do Pacman na presença de fantasmas.
     Se um fantasma se encontrar à direita do Pacman (x' > x), este deverá movimentar-se para a direita. Caso contrário, deverá movimentrar-se para a esquerda. -}
right_left :: [Player] -> Int -- 1 <-> direita | 0 <-> esquerda
right_left l 
    | x' > x = 1
    | otherwise = 0
    where pac@(Pacman (PacState (id, (y,x), v, o, p, l') a b c)) = getPacm' l 
          id_ghost = which_ghost pac l
          (y',x') = get_coord id_ghost l

{- | Esta função retorna o ID do fantasmas que se encontra no mesmo corredor que o Pacman. 
     Poderá existir mais do que um fantasma no mesmo corredor, porém esta função apenas escolhe o primeiro pelo qual itera. -} 
which_ghost :: Player -> [Player] -> Int
which_ghost i@(Pacman (PacState (id, (y,x), v, o, p, l') a' b' c)) (a:b) 
    = case a of (Ghost (GhoState (id', (y',x'), v', o', p', l) mode)) -> if (y' == y) then id' else which_ghost i b 
                otherwise -> which_ghost i b
    
{- | Esta função dá-nos as coordenadas de um fantasma quando dado um ID.
     Estas coordenadas são importantes e são comparadas na função *right_left*. -}
get_coord :: Int -> [Player] -> Coords
get_coord id ((Ghost (GhoState (id', (y,x), (v), o, p, l) mode)):r) = if id == id' then (y,x) else get_coord id r
get_coord id ((Pacman (PacState (id', (y,x), v, o, p, l) a b c)):r) = get_coord id r

-- | Esta função define a maneira como o Pacman se irá movimentar de modo a encontrar fantasmas.
-- | O Pacman verifica as suas opções (mover para cima ou para baixo): 
--
-- * Se ambos os caminhos estiverem obstruidos, o Pacman movimenta-se para a direita.
-- * Caso seja possível o Pacman se mover para cima, ele move-se para cima.
-- * Caso seja possível mover-se para baixo, move-se para baixo.
-- * Quando é possível tanto mover para cima como mover para baixo, o Pacman move-se na direção cuja distância ao limite do mapa é maior (pois terá maior área e, portanto, maior probabilidade de existir um fantasma.)
look_for_ghost :: Maze -> [Player] -> Play
look_for_ghost maze l 
    | (up == Wall) && (down == Wall) = (Move id R)    --(False,False)
    | (up == Wall) && (down /= Wall) = (Move id D)    --(False,True)
    | (up /= Wall) && (down /= Wall) = (Move id U)    --(True,True)
    | (up /= Wall) && (down == Wall) = (Move id U)    --(True,False)
    where pac@(Pacman (PacState (id, (y,x), v, o, p, l') a b c)) = getPacm' l 
          up = nextPiece maze (y-1,x)
          down = nextPiece maze (y+1,x)
          new_orientation = choose_updown maze pac

{- | Esta função faz com que o Pacman se movimente para cima ou para baixo conforme esteja acima ou abaixo do(s) corredor(es) central(ais).
     Se estiver acima, irá movimentrar-se para baixo. Caso contrário, irá movimentar-se para cima.
     Esta função é quem decide o que fazer quando ambas peças, acima e abaixo, estão disponivéis para mover. -}
choose_updown :: Maze -> Player -> Orientation
choose_updown maze (Pacman (PacState (id, (y,x), v, o, p, l') a b c))
    | (length (maze) `div` 2) - y < 0 = U 
    | otherwise = D
    
{-==================================================================================================================-}
-- > { Normal Play Bellow Threshold }

{- | Esta função junta tudo retornando a jogada que o Pacman tem de fazer. -}
bellow_play :: State -> Play
bellow_play s@(State m j l) = (Move id new_o)
    where corridor = c_ghost s (four_play s) 
          vertical = u_ghost s (four_play s) 
          new_o = orientationX $ choose_play $ join_filter corridor vertical
          (Pacman (PacState (id, (y,x), v, o, p, l') a b c)) = getPacm' j

{- Devido à pureza desta maravilhosa linguagem de programação o output "random" gerado será sempre o mesmo.-}
orientationX :: (Coords,Orientation,Piece,Bool) -> Orientation
orientationX ((0,0),Null,Empty,False) = D
    -- where (rand,_) = randomR (0,3) generator  
    --       random_orientation = [R,L,U,D] !! rand
orientationX (a,b,c,d) = b

{- Função não usada devido pois não funciona. -}
seed :: Int
seed = 420
generator = mkStdGen seed 

{- Função não usada devido pois não funciona. -}
choose_play :: [(Coords,Orientation,Piece,Bool)] -> (Coords,Orientation,Piece,Bool)
choose_play [] = ((0,0),Null,Empty,False)
choose_play [x] = x
choose_play (x:y) = (x:y) !! rand 
    where n = length (x:y)
          (rand, _) = randomR (0,(n-1)) generator

{- | Esta função é a função mestre para a estratégia tomada. Recebe os outputs das funções *c_ghost* e *u_ghost*, compara-os e filtra a lista deixando apenas a jogada segura. Caso não existam jogadas seguras o Pacman joga para a baixo.-}
join_filter :: [(Coords,Orientation,Piece,Bool)] -> [(Coords,Orientation,Piece,Bool)] -> [(Coords,Orientation,Piece,Bool)]
join_filter [] s = s
join_filter s [] = s
join_filter ((a,b,c,d):x) ((a',b',c',d'):y) 
    | (a == a') && (d == False) && (d == d') = (a,b,c,d):join_filter x y
    | otherwise = join_filter x y

{- | Esta função calcula todas as possíveis que o Pacman pode efetuar. Retorna um triplo contendo as próximas coordenadas, a orientação dessa jogada e a que peça cooresponde.-}
four_play :: State -> [(Coords,Orientation,Piece)]
four_play state = choose_piece $ takeWalls $ possible_plays state

{- | Quando dada uma lista com as possíveis jogadas que o Pacmna pode fazer esta função filtra as quais não têm fantasmas no mesmo corredor que o Pacman, deixando apenas as jogadas seguras. -}
c_ghost :: State -> [(Coords,Orientation,Piece)] -> [(Coords,Orientation,Piece,Bool)]
c_ghost s [] = []
c_ghost s@(State m j l) ((a,b,c):y)
    | is_horizontal s a = (a,b,c,True):c_ghost s y
    | otherwise = (a,b,c,False):c_ghost s y

{- | Esta função verifica se existem fantasmas no mesmo corredor que o Pacman.-}
is_horizontal :: State -> Coords -> Bool 
is_horizontal (State maze j l) (y,x) = y `elem` (ghosts)
    where ghosts = y_list j

-- filter_true :: [(Coords,Orientation,Piece,Bool)] -> [(Coords,Orientation,Piece,Bool)]
-- filter_true (x:y) = filter (\(a,b,c,d) -> if (d == True) then False else True ) (x:y)

-- filter_true $ c_ghost $ four_play
-- filter_true $ u_ghost $ four_play

{- | Quando dada uma lista com as possíveis jogadas que o Pacmna pode fazer esta função filtra as quais não têm fantasmas acima ou abaixo do Pacman. -}
u_ghost :: State -> [(Coords,Orientation,Piece)] -> [(Coords,Orientation,Piece,Bool)]
u_ghost s [] = []
u_ghost s@(State m j l) ((a,b,c):y)
    | in_vertical s a = (a,b,c,True):u_ghost s y
    | otherwise = (a,b,c,False):u_ghost s y

{- | Esta função junta as duas funções abaixo para retornar um valor booleano no que toca à existência de fantasmas acima do Pacman.-}
in_vertical :: State -> Coords -> Bool
in_vertical (State maze j l) (y,x) = check_ghost ghost_coords (y,x)
    where ghost_coords = get_gcoords j

{- | Esta função verifica se existem fantasmas acima ou abaixo do Pacman quando dadas as suas coordenadas.-}
check_ghost :: [Coords] -> Coords -> Bool 
check_ghost [] c = False
check_ghost ((y,x):z) (a,b) 
    | (x == b) && (y > a) = True || check_ghost z (a,b)
    | (x == b) && (y < a) = True || check_ghost z (a,b)
    | otherwise = False

{- | Esta função, quando dada uma lista de jogadores, extrai as coordenadas apenas dos fantasmas.-}
get_gcoords :: [Player] -> [Coords]
get_gcoords [] = []
get_gcoords ((Ghost (GhoState (id, (y,x), v, o, p, l) m)):z) = ((y,x):get_gcoords z)
get_gcoords ((Pacman a):z) = get_gcoords z

{-==================================================================================================================-}

{- | Esta função é responsável por gerar o proximo movimento do Pacman. 
     Primeiro verifica se ainda existem peças a comer, caso existam o Pacman não joga.
     Se existirem peças por comer, a função chama a *bot_play* que vai gerar um movimento tendo em conta o estado do Pacman.-}
bot :: Int -> State -> Maybe Play
bot id s@(State maze jr l) 
    | verifyGame s = Nothing 
    | otherwise = (bot_play s)
{-|
Module      : Tarefa5
Description : Ghost Bot
Copyright   : (c) Guilherme Sampaio, 2020
