-- Atualização de coordenadas 

{- | Atualiza as coordenadas do jogador baseando-se na sua orientação.
     Primeiro verifica se o jogador é um Pacman.
     De seguida, verifica se o seu ID é o mesmo ID presente na jogada (Play).
     Finalmente, executa ainda uma outra função para atualizar as coordenadas.
     Todas as funções main irão procurar sempre pelo jogador na lista de jogadores:
     @case x of Pacman a@ e @checkID move x@ são responsáveis por tal. -}

updateCoord :: Play -> [Player] -> [Player]
updateCoord move@(Move id o) (x:y)
    = case x of Pacman a -> if checkID move x 
                            then (changeCoord move x):y
                            else (x):(updateCoord move y) 
                otherwise -> if checkGID move x 
                             then (changeGhostCoord move x ):y
                             else (x):(updateCoord move y) 

-- | Dado uma jogada (Play) e um jogador (Player), esta função retorna um valor booleano se o ID na jogada for igual ao ID do jogador.
checkID :: Play -> Player -> Bool
checkID (Move id o) (Pacman (PacState (id2, (y,x), v, ori, p, l) a b c))
    | id == id2 = True 
    | otherwise = False

-- | Faz o mesmo que a *checkID* mas procura pelos ID's dos fantasmas (GID).
checkGID :: Play -> Player -> Bool 
checkGID (Move id o) x
    = case x of (Ghost (GhoState (id2, (y,x), v, o2, p, l) s)) -> if id == id2 then True else False
                otherwise -> False
                
{- | Esta função é a base para o bom funcionamento da *updateCoord* uma vez que
     irá fazer a maior parte do trabalho. Verifica a orientação de ambos os jogador
     e jogada e, se forem a mesma, atualiza as coordenadas do jogador. Se não forem
     a mesma, apenas muda as coordenadas do jogador pelas coordenadas da jogada. -}
changeCoord :: Play -> Player -> Player
changeCoord (Move id o) (Pacman (PacState (id2, (y,x), v, ori, p, l) a b c))
    | o == ori = (Pacman (PacState (id2, newcoord, v, ori, p, l) a b c))
    | otherwise =  (Pacman (PacState (id2, (y,x), v, o, p, l) a b c))
    where newcoord = incrementCoord (Move id o) (y,x)

{- | Esta função pertence à tarefa 5 e tem o mesmo objetivo da função acima, porém funciona apenas para fantasmas.-}
changeGhostCoord :: Play -> Player -> Player 
changeGhostCoord (Move id o) (Ghost (GhoState (id2, (y,x), v, o2, p, l) s))
    | o == o2 = (Ghost (GhoState (id2, newcoord, v, o2, p, l) s))
    | otherwise = (Ghost (GhoState (id2, (y,x), v, o, p, l) s))
    where newcoord = incrementCoord (Move id o) (y,x)

{- | Dada uma jogada e coordenadas, atualiza as coordenadas baseando-se na orientação. 
   (@U -> (y-1,x)@ neste caso tem de ser @y-1@ uma vez que o índice do labirinto está a diminuir. -}
incrementCoord :: Play -> Coords -> Coords
incrementCoord (Move id o) (y,x) = case o of R -> (y,x+1)
                                             L -> (y,x-1)  
                                             U -> (y-1,x)
                                             D -> (y+1,x)
                                             Null -> (y,x)

-- Verificação da próxima peça 

{- | Esta função retorna a peça para a qual o player se irá movimentar.
     Localiza o jogador, verifica no labirinto as suas novas coordenadas e retorna-as.
     Esta função é posteriormente usada na *checkMove*. -}
checkPiece :: Play -> [Player] -> Maze -> Piece
checkPiece move@(Move id o) players@(x:y) maze
    = case x of Pacman a -> if checkID move x
                            then getPiece move x maze
                            else checkPiece move y maze
                otherwise -> if checkGID move x 
                             then getPiece move x maze
                             else checkPiece move y maze

{- | Indica a peça baseando-se nas coordenadas do jogador. -}
getPiece :: Play -> Player -> Maze -> Piece 
getPiece move@(Move id o) (Pacman (PacState (id2, (y,x), v, ori, p, l) a b c)) maze 
    = (corridor)!!(piece)
    where piece = snd(newc)
          corridor = maze!!fst(newc)
          newc = incrementCoord move (y,x)
getPiece move@(Move id o) (Ghost (GhoState (id2, (y,x), v, o2, p, l) s)) maze 
    = (corridor)!!(piece)
    where piece = snd(newc)
          corridor = maze!!fst(newc)
          newc = incrementCoord move (y,x)

-- Próxima ação

{- | Decide o que fazer quando certas peças são encontradas.
     Por exemplo, se uma peça Wall for encontrada, a lista de jogadores permanece inalterada.
     Se uma peça Empty for encontrada, o jogador ou se move para essa peça ou entra para um túnel. -}
checkMove :: Play -> State -> [Player]
checkMove move@(Move id o) state@(State maze players@(x:y) l)
    = case np of Wall -> if isPacMan move players
                         then players
                         else ghostWall move state 
                 Empty -> tunnelJump move players maze 
                 Food Little -> smallFood move up 
                 Food Big -> if isPacMan move players
                             then changeStateG $ bigFood move up
                             else bigFood move up 
    where np = checkPiece move players maze 
          up = (updateCoord move players)

{- | Verifica se o id da jogada a ser feita pertence a um Pacman.
     Caso pertença retorna True, senão retorna False.-}
isPacMan :: Play -> [Player] -> Bool
isPacMan (Move id o) [] = False
isPacMan (Move id o) ((Ghost (GhoState (id', (y,x), v, or, p, l) _) ):z) = if id == id' then False else isPacMan (Move id o) z
isPacMan (Move id o) ((Pacman (PacState (id', (y,x), v, ori, p, l) a b c)):z) = if id == id' then True else isPacMan (Move id o) z

-- Tarefa 5

-- | Altera a orientação do jogador ,quando este atinge uma parede, dependendo do seu estado: 
-- | Estado : 
--
-- * Alive => a nova orientação é calculada através do conjunto de funções *compareDist $ filterWalls $ distancia*.
-- * Dead => a nova orientação é dada tendo em conta a orientação atual do fantasma, neste caso altera para a direção à direita da orientação atual.
ghostWall :: Play -> State -> [Player]
ghostWall (Move id o) (State maze (x:y) level) =
    if checkGID (Move id o) (x) 
    then case x of (Ghost(GhoState (id', (y',x'), v, o', p, l) Alive)) -> (aliveWall (State maze (x:y) level) x):(y)
                   (Ghost(GhoState (id', (y',x'), v, o', p, l) Dead)) -> (deadWall x):(y)
    else (x):(ghostWall (Move id o) (State maze y level))

{- | Esta função é responsável por alterar a orientação do fantasma quando este está morto.
     Muda a orientação para a orientação à direita da orientação atual.-}   
deadWall :: Player -> Player
deadWall (Ghost(GhoState (id, (y,x), v, R, p, l) m)) = (Ghost(GhoState (id, (y,x), v, D, p, l) m))
deadWall (Ghost(GhoState (id, (y,x), v, L, p, l) m)) = (Ghost(GhoState (id, (y,x), v, U, p, l) m))
deadWall (Ghost(GhoState (id, (y,x), v, U, p, l) m)) = (Ghost(GhoState (id, (y,x), v, R, p, l) m))
deadWall (Ghost(GhoState (id, (y,x), v, D, p, l) m)) = (Ghost(GhoState (id, (y,x), v, L, p, l) m))

{- | Esta função é responsável por alterar a orientação do fantasma quando este está vivo.
     Esta, é substituida pela orientação calculada na função *compareDist*. -}
aliveWall :: State -> Player -> Player
aliveWall state g@(Ghost(GhoState (id, (y,x), v, o, p, l) m)) = (Ghost(GhoState (id, (y,x), v, new_orientation, p, l) m))
    where new_orientation = (compareDist $ filterWalls $ distancia state g)

{- | Quando dada um número (pontos) a função adiciona os pontos ao jogador. 
     @addPoint n player@ adiciona @n@ pontos ao jogador @player@. -}
addPoint :: Int -> Player -> Player
addPoint pt (Pacman (PacState (id, (y,x), v, ori, p, l) a b c))
    = (Pacman (PacState (id, (y,x), v, ori, p+pt, l) a b c))

{- | O que deverá acontecer ao Pacman quando este comer a peça Small Food?   
     Esta função usa *addPoint* para adicionar um ponto ao correto jogador após o escolher usando *checkID*. -}
smallFood :: Play -> [Player] -> [Player]
smallFood move [] = []
smallFood move@(Move id o) players@(x:y) 
    = case x of Pacman a -> if checkID move x
                            then (addPoint 1 x):y
                            else x:smallFood move y
                otherwise -> if checkGID move x 
                             then x:y                
                             else x:smallFood move y

{- | O que deverá acontecer ao Pacman quando este comer a peça Big Food?   
     Esta função faz 3 coisas, adiciona 5 pontos ao jogador, muda o seu estado para Mega
     e muda o estado de todos os fantasmas para Dead. Tudo isto usando *changeStageG* e *changeStateP*. -}
bigFood :: Play -> [Player] -> [Player]
bigFood move [] = [] 
bigFood move@(Move id o) players@(x:y)
    = case x of Pacman a -> if checkID move x 
                            then ((changeStateP x):(bigFood move y))
                            else x:(bigFood move y)
                otherwise -> if checkGID move x
                             then (x:y)         
                             else x:(bigFood move y)

-- | Muda o estado dos fantasmas para Dead e reduz as suas velocidades para metade.
changeStateG :: [Player] -> [Player] 
changeStateG [] = []
changeStateG ((Ghost (GhoState (id, (y,x), v, o, p, l) _) ):z)
    = Ghost (GhoState (id, (y,x), (v/2), o, p, l) Dead):changeStateG z
changeStateG ((Pacman n):z) = (Pacman n):changeStateG z

-- | Muda o estado do jogador para Mega.
changeStateP :: Player -> Player 
changeStateP (Pacman (PacState (id, (y,x), v, ori, p, l) a b _))
    = (Pacman (PacState (id, (y,x), v, ori, p+5, l) 20 b Mega))

{- | O que devera acontecer ao Pacman quando este se movimenta para uma peça Empty?
     Primeiro, a função seleciona o jogador e, depois, usando *jump* decide se o jogador
     se deve movimentar pelo túnel ou não. -}
tunnelJump :: Play -> [Player] -> Maze -> [Player]
tunnelJump move@(Move id o) players@(x:y) maze 
    = case x of Pacman a -> if checkID move x
                            then (jump move x maze):y 
                            else (x):(tunnelJump move y maze)
                otherwise -> if checkGID move x
                             then (changeGhostCoord move x):y
                             else (x):(tunnelJump move y maze)

{- | Esta função é chamada quando se procura por um túnel. 
     A *jump* compara as próximas coordenadas do jogador e se o valor de x é quer a primeira ou última peças
     do corredor, então as coordenadas do jogador são atualizadas correspondentemente.
     Por exemplo, @(2,0) -- (2,30)@, atendendo que o corredor tem comprimento 31. -}
jump :: Play -> Player -> Maze -> Player 
jump move@(Move id o) player@(Pacman (PacState (id1, (y,x), v, ori, p, l) a b c)) (a1:b1)
    | (snd(next)) == 0 = (Pacman (PacState (id1, (y,last), v, ori, p, l) a b c))
    | (snd(next)) == last = (Pacman (PacState (id1, (y,0), v, ori, p, l) a b c))
    | otherwise = changeCoord move player 
    where next = incrementCoord move (y,x) 
          last = (length a1 - 1)


--  Ghost vs Pacman 

{- | A *paGhost* é uma função que verifica se há colisão entre um jogador e um fantasma.
     Compara as as coordenadas do jogador e do fantasma e, se forem iguais, verifica qual o estado do fantasma.
     Se o o estado do fantasma for Dead, então o jogador come o fantasma, se não, o jogador perde uma vida.
     É também responsável por garantir que quando um fantasma é comido, este é teletransportado para a casa dos fantasmas com o estado Alive e com a velocidade normal. -}
paGhost :: Player -> [Player] -> Maze -> [Player]
paGhost x [] maze = []
paGhost pac@(Pacman (PacState (id1, (y,x), v, ori, p, l) a b c)) players@(x1:y1) (k1:k2)
    = case x1 of Pacman a -> x1:paGhost pac y1 (k1:k2)
                 otherwise -> if coord pac x1 
                              then case x1 of (Ghost (GhoState (id, (y2,x2), v1, o, p1, l1) Dead)) -> incPlayer pac (Ghost (GhoState (id, (newy,newx), v1*2, new_orientation, p1, l1) Alive):(paGhost pac y1 (k1:k2)))
                                              otherwise -> decPlayer pac (x1:(paGhost pac y1 (k1:k2)))                 
                              else x1:paGhost pac y1 (k1:k2)
    where newx = (length k1) `div` 2
          newy = length(k1:k2) `div` 2
          new_orientation = invertOri x1
paGhost g@(Ghost (GhoState (id2, (y,x), v, o2, p, l) s)) players@(x1:y1) (k1:k2)
    = players

-- | Esta função quando dado um jogador retorna a sua orientação inversa.
invertOri :: Player -> Orientation
invertOri (Ghost (GhoState (id, (y2,x2), v1, o, p1, l1) x))
    | o == R = L
    | o == L = R
    | o == U = D
    | o == D = U
    | o == Null = U

-- | Esta função compara dois conjuntos de coordenadas e retorna True ou False caso estas sejam iguais ou diferentes, respetivamente. 
coord :: Player -> Player -> Bool 
coord (Pacman (PacState (id1, (y,x), v, ori, p, l) a b c)) (Ghost (GhoState (id, (y1,x1), v1, o, p1, l1) s) )
    | (x == x1) && (y == y1) = True
    | otherwise = False


-- | Esta função é responsável por atualizar o estado do jogador, adicionando 10 pontos.
incPlayer :: Player -> [Player] -> [Player]
incPlayer x [] = []
incPlayer pac@(Pacman (PacState (id1, (y,x), v, ori, p, l) a b c)) players@(x1:y1)
    | pac == x1 = (addPoint 10 x1):y1
    | otherwise = x1:incPlayer pac y1 

{- | Esta função é responsável por atualizar o estado do jogador, diminuindo o seu número de vidas.
     Se o jogador tiver 0 vidas, o estado do mesmo é mudado para Dying. -}
decPlayer :: Player -> [Player] -> [Player]
decPlayer x [] = []
decPlayer pac@(Pacman (PacState (id1, (y,x), v, ori, p, l) a b c)) players@(x1:y1)
   | pac == x1 = 
       if (l == 0) 
       then (Pacman (PacState (id1, (y,x), v, ori, p, l) a b Dying)):y1
       else (Pacman (PacState (id1, (y,x), v, ori, p, l-1) a b c)):y1
   | otherwise = x1:decPlayer pac y1

-- Atualização do labirinto 

-- | Esta função retira duma lista de jogadores, o jogador cujo ID é o mesmo que o da jogada, com o objetivo de extrair as suas coordenadas.
getPlayer :: Play -> [Player] -> Player 
getPlayer move@(Move id o) players@(x:y) 
    = case x of Ghost a -> if checkGID move x
                           then x                 
                           else getPlayer move y
                otherwise -> if checkID move x 
                             then x  
                             else getPlayer move y

{- | Esta função muda uma peça comida pela peç Empty.
     Esta muda o labirinto de acordo com as coordenadas do jogador. -}
getMaze :: Play -> [Player] -> Maze -> Maze 
getMaze move@(Move id o) players@(x:y) (a:b) 
    = updateMaze (a:b) player 
    where player = getPlayer move players 

-- | A *updateMaze* repõe um corredor num labirinto, insere o novo corredor no corredor y e junta o resto do labirinto.
updateMaze :: Maze -> Player -> Maze 
updateMaze maze@(x1:y1) pac@(Pacman (PacState (id1, (y,x), v, ori, p, l) a b c))
    = take y maze ++ [(updatePiece corridor (y,x))] ++ drop (y+1) maze
    where corridor = maze!!y
updateMaze maze@(x1:y1) (Ghost (GhoState (id2, (y,x), v, o2, p, l) s))
    = maze 
   
-- | Esta função repõe uma peça do labirinto pela peça Empty no elemento x.  
updatePiece :: Corridor -> Coords -> Corridor 
updatePiece (x:y) (y1,x1) 
    = take (x1) (x:y) ++ [Empty] ++ drop (x1+1) (x:y)

-- Execução de jogadas

{- | A função *play* é responsável por juntar todas as funções acima de modo a fazer uma jogada que cubra todos os casos possíveis.
     Tem duas partes: atualização do labirinto e atualização do estado. -}
play :: Play -> State -> State 
play move state@(State maze [] a) = state
play move@(Move id o) state@(State maze jr a) 
    = State (getMaze move jr maze) (paGhost player updated maze) a
    where player = getPlayer move updated
          updated = checkMove move state 

