= Introdução

Esta tarefa foi o primeiro contacto com o projeto e é extremamente importante para o bom funcionamento do projeto final, uma vez que é a base de tudo: é responsável pela criação de mapas semi-aleatórios (labirintos) que, sem eles, seria impossível jogar.

= Objetivos

O principal objetivo desta tarefa foi gerar labirintos que fossem jogáveis, de onde surgiram alguns desafios:

 * Arranjar uma maneira de fazer com que todo o seu contorno fossem paredes (Wall), tal como no jogo original, de forma a limitar o espaço onde os players podem jogar.

 * Criar os túneis laterais por onde o Pacman pode ser "teletransportado" do lado direito do mapa para o lado esquerdo ou vice-versa. Um dos obstáculos neste passo foi fazer com que as peças adjacentes ao túnel não fossem paredes, de modo ao Pacman não ficar preso no próprio túnel e ser obrigado a voltar para o outro lado.

 * Criar a casa dos fantasmas, desafio este que nos trouxe vários problemas em deixar a casa no centro do mapa, uma vez que ficava sempre desalinhada conforme a altura e a largura do mapa fossem par ou ímpar.

= Conclusão

Para primeira impressão acerca do projeto, foi uma tarefa que nos causou stress em alguns dos problemas encontrados, problemas estes que foram todos ultrapassados. 
Após a resolução dos mesmos, sentimos que afinal o projeto era algo exequível (pelo menos para já).

-}



-- | Gera uma lista de números aleatórios de tamanho largura * altura.
generateRandoms :: Int -> Int -> [Int]
generateRandoms n seed = let gen = mkStdGen seed -- cria um gerador aleatório
                        in take n $ randomRs (0,99) gen -- lê os primeiros n elementos duma série infinita de números aleatórios entre 0 e 9

-- Construção de corredores 

-- | Esta função converte inteiros em peças de jogo. Por exemplo: /converPiece 76/ retorna Wall (#).
convertPiece :: Int -> Piece
convertPiece x 
            | x == 3 = Food Big
            | x >= 0 && x < 70 = Food Little
            | x >= 70 && x <= 99 = Wall
            | otherwise = Empty

-- | Constrói os corredores usando convertPiece quando é dada uma lista de inteiros.
convertCorridor :: [Int] -> Corridor
convertCorridor [] = []
convertCorridor (x:y) = (convertPiece x : convertCorridor y) 

-- | Parte o corredor principal de comprimento largura * altura em corredores de comprimento menor.
convertMaze :: Corridor -> Int -> Maze
convertMaze [] _ = []
convertMaze (x:y) width = (n : convertMaze r width)
    where (n,r) = splitAt width (x:y)

-- Construção de paredes 

{- | Esta função gera uma lista de peças Wall. 
     Estas listas irão ser usadas em *topBotWall*.-}
wallGenerator :: Int -> Corridor 
wallGenerator x 
    | x <= 0 = []
    | otherwise = Wall:wallGenerator(x-1)

{- | Adiciona as paredes laterais ao resto do labirinto. 
     Itera por todos os corredores do labirinto e adicona uma peça Wall quer no início quer no fim de cada corredor. -}
makeMaze :: Maze -> Maze
makeMaze [] = []
makeMaze (x:y) = (wall ++ x ++ wall):makeMaze y
    where wall = [convertPiece 99]

-- | Adiciona as paredes geradas em *wallGenerator* ao resto do labirinto. 
topBotWall :: Corridor -> Int -> Maze
topBotWall [] n = []
topBotWall (x:y) width = [wall] ++ convertMaze (x:y) width ++ [wall]
    where wall = wallGenerator width

-- | Diz-nos o meio do labirinto em relação à altura do mesmo.
getMid :: Maze -> Int
getMid [] = 0
getMid maze = length(maze) `div` 2

-- Construção dos túneis 

{- | Repõe as primeira e última peça dum corredor pela peça Empty. 
     Esta função apenas vai ser usada nos corredores do meio. -}
replace :: Corridor -> Corridor
replace [] = []
replace (x:y) = [Empty] ++ tail(init(x:y)) ++ [Empty]

{- | Repõe o corredor do meio pelo novo corredor já construído com túnel.
     Esta função é usada apenas em labirintos ímpares. -}
tunnelOdd :: Maze -> Int -> Maze
tunnelOdd (x:y) mid = take (mid) (x:y) ++ replace ((x:y)!!(mid)) : drop (mid+1) (x:y)

{- | Repõe os corredor dos meio pelos novos corredores já construídos com túneis. 
     Esta função é usada apenas em labirintos pares. -}
tunnelEven :: Maze -> Int -> Maze
tunnelEven (x:y) mid =  do { 
    tunnelOdd l (mid-1)}
    where l = tunnelOdd (x:y) (mid)

{- | Verifica se o labirinto é par ou ímpar e aplica as funções acima consoante seja par ou ímpar. -}
addTunnel :: Maze -> Maze 
addTunnel (x:y)
    | length(x:y) `mod` 2 == 0 = tunnelEven (x:y) mid
    | otherwise = tunnelOdd (x:y) mid
    where mid = getMid (x:y)

-- Casa dos fantasmas  

-- | Modelo da casa em labirinto ímpar.
oddModel = [[Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty],
            [Empty,Wall,Wall,Wall,Empty,Empty,Wall,Wall,Wall,Empty],
            [Empty,Wall,Empty,Empty,Empty,Empty,Empty,Empty,Wall,Empty],
            [Empty,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Empty],
            [Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty]]

-- | Modelo da casa em labirinto par.
evenModel = [[Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty],
             [Empty,Wall,Wall,Wall,Empty,Empty,Empty,Wall,Wall,Wall,Empty],
             [Empty,Wall,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Wall,Empty],
             [Empty,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Empty],
             [Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty]]

{- | Repõe uma parte do corredor pela correspondente alteração do corredor que já contém uma parte da casa dos fantasmas do modelo ímpar. -}
replaceHouse :: Corridor -> Int -> Corridor 
replaceHouse (x:y) n = take mid (x:y) ++ part ++ drop (mid+10) (x:y)
    where part = oddModel!!n 
          mid = (length(x:y) `div` 2 )-5

{- | Repõe uma parte do corredor pela correspondente alteração do corredor que já contém uma parte da casa dos fantasmas do modelo par. 
     Basicamente, uma *replaceHouse* para labirintos pares. -}
replaceHouseEven :: Corridor -> Int -> Corridor
replaceHouseEven (x:y) n = take mid (x:y) ++ part ++ drop (mid +11) (x:y)
    where part = evenModel!!n 
          mid = (length(x:y) `div` 2 )-5

-- | Repõe o novo corredor alterado (que contém parte da casa de fantasmas) num labirinto ímpar.
replaceCorridor :: Maze -> Int -> Int -> Maze
replaceCorridor (x:y) pos piece = take (pos) (x:y) ++ (replaceHouse ((x:y)!!(pos)) piece) : (drop (pos+1) (x:y))

-- | Repõe o novo corredor alterado (que contém parte da casa de fantasmas) num labirinto par.
replaceCorridorEven :: Maze -> Int -> Int -> Maze
replaceCorridorEven (x:y) pos piece = take (pos) (x:y) ++ (replaceHouseEven ((x:y)!!(pos)) piece) : (drop (pos+1) (x:y)) 

{- | Usando as funções acima, esta função repõe todos os corredores necessários para a construção total da casa de fantasmas no labirinto.
     A construção dá-se por primeiro substituir o corredor que contém a parte de cima da casa de fantasmas e posteriormente a substituição dos outros corredores que contêm a casa.
     Devido a esta abordagem, precisamos de quatro funções, uma para cada caso: 2 números ímpares; 2 números pares; 1 número ímpar e 1 número par ou 1 número par e 1 número ímpar. -}
buildHouseOdd1 :: Maze -> Maze 
buildHouseOdd1 (x:y) = do {
    replaceCorridor h4 (mid+1 ) 4 
}
    where h4 = replaceCorridor h3 (mid ) 3
          h3 = replaceCorridor h2 (mid -1) 2
          h2 = replaceCorridor h1 (mid - 2) 1
          h1 = replaceCorridor (x:y) (mid -3) 0
          mid = getMid (x:y)

{- | Esta função faz o mesmo que a *buildHouseOdd1* mas em vez de usar o modelo par da casa de fantasmas, usa o modelo par.
     Apenas funciona para 2 números pares. -}
buildHouseEven1 :: Maze -> Maze
buildHouseEven1 (x:y) = do {
    replaceCorridorEven h4 (mid + 2) 4 
}
    where h4 = replaceCorridorEven h3 (mid+1) 3
          h3 = replaceCorridorEven h2 (mid) 2
          h2 = replaceCorridorEven h1 (mid-1) 1
          h1 = replaceCorridorEven (x:y) (mid-2) 0
          mid = getMid (x:y)

{- | Esta função faz o mesmo que a *buildHouseOdd1* mas em vez de usar o modelo par da casa de fantasmas, usa o modelo par.
     Apenas funciona para 1 número par e 1 número ímpar. -}
buildHouseEven2 :: Maze -> Maze
buildHouseEven2 (x:y) = do {
    replaceCorridorEven h4 (mid+1) 4 
}
    where h4 = replaceCorridorEven h3 (mid) 3
          h3 = replaceCorridorEven h2 (mid-1) 2
          h2 = replaceCorridorEven h1 (mid-2) 1
          h1 = replaceCorridorEven (x:y) (mid-3) 0
          mid = getMid (x:y)

{- | Esta função faz o mesmo que a *buildHouseOdd1* mas em vez de usar o modelo par da casa de fantasmas, usa o modelo par.
     Apenas funciona para 1 número ímpar e 1 número par. -}
buildHouseOdd2 :: Maze -> Maze 
buildHouseOdd2 (x:y) = do {
    replaceCorridor h4 (mid+2 ) 4 
}
    where h4 = replaceCorridor h3 (mid + 1) 3
          h3 = replaceCorridor h2 (mid) 2
          h2 = replaceCorridor h1 (mid - 1) 1
          h1 = replaceCorridor (x:y) (mid -2) 0
          mid = getMid (x:y)

{- | Adiciona a casa dos fantasmas ao resto do labirinto usando todas as funções *buildHouse* dependendo na paridade do imput. -}
chooseHouse :: Maze -> Maze
chooseHouse [] = []
chooseHouse (x:y) 
    | (length(x:y) `mod` 2 == 0) && (length(x) `mod` 2 == 0) = buildHouseOdd1 (x:y)
    | (length(x:y) `mod` 2 /= 0) && (length(x) `mod` 2 /= 0) = buildHouseEven1 (x:y)
    | (length(x:y) `mod` 2 /= 0) && (length(x) `mod` 2 == 0) = buildHouseOdd2 (x:y)
    | otherwise = buildHouseEven2 (x:y)

-- Labirinto -> IO() 

{- | Converte um corredor numa string. 
     Todas as funções até *generateMaze* são utilizadas apenas para propósitos de vizualização. -}
showCorridor :: Corridor -> String 
showCorridor [] = []
showCorridor (x:y) = show x ++ showCorridor y 

-- | Converte um labirinto numa string adicionando \n para separar os corredores. 
showMaze :: Maze -> String 
showMaze [] = []
showMaze (x:y) = (showCorridor x ++ "\n" ++ showMaze y)

-- Construção do labirinto completo

{- | Gera o labirinto inteiro apartir de todas as funções acima.
     É retirado 2 ao valor de de largura e altura na linha 232 para compensar a adição das paredes, uma vez que se não houvesse tal diminuição, o labirinto excederia o tamanho suposto. -}
generateMaze :: Int -> Int -> Int -> Maze
generateMaze w h seed = if w <= 14 || h <= 9 then error "Must be at least 15x10!" else maze
    where nr = generateRandoms ((w-2)*(h-2)) seed
          pieces = convertCorridor nr
          wall = topBotWall pieces (w-2)
          noTunnel = makeMaze wall 
          tunnel = addTunnel noTunnel 
          maze = chooseHouse tunnel

-- | Gera um labirinto do tipo IO() para propósitos de vizualização.
generateMaze' :: Int -> Int -> Int -> IO()
generateMaze' w h seed = if w <= 14 || h <= 9 then error "Must be at least 15x10!" else putStrLn $ showMaze (maze)
    where nr = generateRandoms ((w-2)*(h-2)) seed
          pieces = convertCorridor nr
          wall = topBotWall pieces (w-2)
          noTunnel = makeMaze wall 
          tunnel = addTunnel noTunnel 
          maze = chooseHouse tunnel

-- 100% on Codeboard. 
{- | 

= Introdução

Nesta tarefa não tivemos de alterar muita coisa pois grande parte já estava feita pelos professores. No entanto as funções que vão atualizar o frame do jogo tiveram de ser feitas por nós. Este módulo implementa o NCurses no jogo para que este seja jogável.

= Objetivos

Criar as funções que permitem que o estado do jogo mude com o passar do tempo foi o objetivo principal desta tarefa. 
A passagem do tempo foi implementada de modo a ser modular, no nosso caso a função executa a função 'passTime' da "Tarefa4" a cada 250 ms, dando exatamente quatro jogadas (do Pacman) por segundo.

Nesta tarefa surgiu um novo /data type/ o /manager/ este, contém o estado do jogo, o /id/ correspondente ao Pacman, o /step/ (número de iterações já feitas), o valor /before/ (instante de tempo em que foi feita a última jogada), /delta/ (tempo decorrido em ms desde a última jogada) e o /delay/ (intervalo de tempo entre jogadas (250ms)). Para que o delay seja de 250 milissegundos tivemos de criar certas funções como a /updateTime/, /resetTime/ e /nextFrame/ para garantir que o estado é atualizado sempre que o valor do /delta/ seja maior do que o do /delay/, ou seja, (before - delta) > 250 implica que o estado do jogo seja atualizado.

A função loop é responsável por "executar o manager" a cada 250 milissegundos. Adicionalmente, esta verifica a cada iteração se ainda existem peças por comer, caso existam o jogo continua, caso contrário o jogo acaba e se a tecla "q" é pressionada que, caso seja, também acaba o jogo.

= Conclusão

Esta tarefa, apesar de ter sido menos explorada do que as restantes, adiciona muito conteúdo novo em relação a como simular a passagem do tempo num ambiente virtual. 

-}



{- |
data Manager = Manager
{
   state :: State, [State do player]
   pid :: Int, [Player ID]
   step :: Int, [Número de iterações já feitas]
   before :: Integer, [Instante de tempo em que foi feita a última jogada]
   delta :: Integer, [Tempo decorrido em ms desde a última jogada]
   delay :: Integer [Intervalo de tempo entre jogadas (250ms)]
}
-}

-- | Função para carregar o estado de jogo através de um mapa.
loadManager :: Manager
loadManager = ( Manager (loadMaze "1.txt") 0 0 0 0 defaultDelayTime )

{- | Esta função é responsável pela mudança na orientatção do jogador quando premida uma das teclas chave.-}
-- | Teclas :
--
-- * KeyUpArrow	 <-> U
-- * KeyDownArrow <-> D
-- * KeyLeftArrow <-> L
-- * KeyRightArrow <-> R

updateControlledPlayer :: Key -> Manager -> Manager
updateControlledPlayer k m@(Manager state p step b delta delay) 
  = case k of KeyUpArrow -> (Manager up p step b delta delay) 
              KeyDownArrow -> (Manager down p step b delta delay) 
              KeyLeftArrow -> (Manager left p step b delta delay) 
              KeyRightArrow -> (Manager right p step b delta delay) 
  where up = changeOrientation m U 
        down = changeOrientation m D 
        left = changeOrientation m L 
        right = changeOrientation m R 


{- | Esta função trata da projeção do mapa;pacman;jogo no terminal. 
     É executada a cada iteração, ou seja, a cada 250ms. -}        
updateScreen :: Window  -> ColorID -> Manager -> Curses ()
updateScreen w a man =
                  do
                    updateWindow w $ do
                      -- clear 
                      setColor a
                      moveCursor 0 0 
                      drawString $ show (state man)
                    render

{- | Função responsável por obter o tempo atual.-}
currentTime :: IO Integer
currentTime = fmap ( round . (* 1000) ) getPOSIXTime

-- O estado tem de ser atualizado sempre que delta > delay, isto garante os intervalos de 250ms ou 4 jogadas por segundo. 
-- Ou seja sempre que (before - delta) > 250 o jogo é atualizado. 
-- Acho que isto já está definido na Main em loop.

updateTime :: Integer -> Manager -> Manager
updateTime now man = man {delta = (now - before man)} 

resetTimer :: Integer -> Manager -> Manager
resetTimer now man = man {delta = 0, before = now}

nextFrame :: Integer -> Manager -> Manager
nextFrame now man =  let update = (resetTimer now man) 
                     in update { state= (passTime (step man) (state man)), step = (step man) +1 } 

loop :: Window -> Manager -> Curses ()
loop w man@(Manager s pid step bf delt del ) = do 
  color_schema <- newColorID ColorWhite ColorBlack 16
  now <- liftIO  currentTime
  updateScreen w  color_schema man
  if ((verifyGame s) == False)
   then if ( delt > del )
         then loop w $ nextFrame now man
         else do
               ev <- getEvent w $ Just 0
               case ev of
                     Nothing -> loop w (updateTime now man)
                     Just (EventSpecialKey arrow ) -> loop w $ updateControlledPlayer arrow (updateTime now man)
                     Just ev' ->
                       if (ev' == EventCharacter 'q')
                         then return ()
                         else loop w (updateTime now man)
   else return ()
   
main :: IO ()
main =
  runCurses $ do
    setEcho False
    setCursorMode CursorInvisible
    w <- defaultWindow
    loop w loadManager




loadMaze :: String -> State
loadMaze filepath = unsafePerformIO $ readStateFromFile filepath


readStateFromFile :: String -> IO State
readStateFromFile f = do
                content <- readFile f
                let llines = lines content 
                    (new_map,pl) = convertLinesToPiece llines 0 []
                return (State new_map pl 1)



convertLinesToPiece :: [String] -> Int -> [Player] -> (Maze,[Player])
convertLinesToPiece [] _ l = ([],l)
convertLinesToPiece (x:xs) n l  = let (a,b) = convertLineToPiece x n 0 l 
                                      (a1,b1) = convertLinesToPiece xs (n+1) b
                                  in (a:a1,b1)

convertLineToPiece :: String -> Int -> Int -> [Player] -> ([Piece],[Player])
convertLineToPiece [] _ _ l = ([],l)
convertLineToPiece (z:zs) x y l = let (a,b ) = charToPiece z x y l
                                      (a1,b1) = convertLineToPiece zs x (y+1) b 
                                  in (a:a1,b1)


charToPiece :: Char -> Int -> Int -> [Player] -> (Piece,[Player])
charToPiece c x y l
    | c == '{' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Normal ))   :l) )
    | c == '<' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Closed Normal )) :l) )
    | c == '}' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Open Normal ))   :l) )
    | c == '>' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Closed Normal )) :l) )
    | c == 'V' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Open Normal ))   :l) )
    | c == 'v' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Closed Normal )) :l) )
    | c == '^' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Open Normal ))   :l) )
    | c == '|' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Closed Normal )) :l) )
    | c == 'X' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Dying ))    :l) )
    | c == '8' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Mega ))     :l) )
    | c == 'M' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Alive))            :l) )
    | c == '?' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Dead))             :l) )
    | c == 'o' =  (Food Big,l)
    | c == '.' =  (Food Little,l)
    | c == '#' =  (Wall,l)
    | otherwise = (Empty,l)


data State = State 
    {
        maze :: Maze
    ,   playersState :: [Player]
    ,   level :: Int
    }

type Maze = [Corridor]
type Corridor = [Piece]
data Piece =  Food FoodType | PacPlayer Player| Empty | Wall deriving (Eq)
data Player =  Pacman PacState | Ghost GhoState deriving (Eq)

data Orientation = L | R | U | D | Null deriving (Eq,Show)
data PacState= PacState 
    {   
        pacState :: PlayerState
    ,   timeMega :: Double
    ,   openClosed :: Mouth
    ,   pacmanMode :: PacMode
    
    } deriving Eq

data GhoState= GhoState 
    {
        ghostState :: PlayerState
    ,   ghostMode :: GhostMode
    } deriving Eq

type Coords = (Int,Int)
type PlayerState = (Int, Coords, Double , Orientation, Int, Int)
--                 (ID,  (x,y), velocity, orientation, points, lives) 
data Mouth = Open | Closed deriving (Eq,Show)
data PacMode = Dying | Mega | Normal deriving (Eq,Show)
data GhostMode = Dead  | Alive deriving (Eq,Show)
data FoodType = Big | Little deriving (Eq)
data Color = Blue | Green | Purple | Red | Yellow | None deriving Eq 

data Play = Move Int Orientation deriving (Eq,Show)

type Instructions = [Instruction]

data Instruction = Instruct [(Int, Piece)]
                 | Repeat Int deriving (Show, Eq)



instance Show State where
  show (State m ps p) = printMaze mz ++ "Level: " ++ show p ++ "\nPlayers: \n" ++ (foldr (++) "\n" (map (\y-> printPlayerStats y) ps))
                          where mz = placePlayersOnMap ps m

instance Show PacState where
   show ( PacState s o m Dying  ) =  "X"
   show ( PacState (a,b,c,R,i,l) _ Open m  ) =  "{"
   show ( PacState (a,b,c,R,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,L,i,l) _ Open m  ) =  "}"
   show ( PacState (a,b,c,L,i,l) _ Closed m  ) =  ">"
   show ( PacState (a,b,c,U,i,l) _ Open m  ) =  "V"
   show ( PacState (a,b,c,U,i,l) _ Closed m  ) =  "v"
   show ( PacState (a,b,c,D,i,l) _ Open m  ) =  "^"
   show ( PacState (a,b,c,D,i,l) _ Closed m  ) =  "|"
   show ( PacState (a,b,c,Null,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,Null,i,l) _ Open m  ) =  "{"

instance Show Player where
   show (Pacman x ) =  show x
   show ( Ghost x ) =   show x

instance Show GhoState where
   show (GhoState x Dead ) =  "?"
   show (GhoState x Alive ) =  "M"

instance Show FoodType where
   show ( Big ) =  "o"
   show ( Little ) =  "."

instance Show Piece where
   show (  Wall ) = coloredString "#" None
   show (  Empty ) = coloredString " " None
   show (  Food z ) = coloredString (show z )   Green
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Normal ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Normal)  ) Yellow
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Mega   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Mega)  ) Blue
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Dying   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Dying)  ) Red
   show ( PacPlayer (Ghost z) ) = coloredString (show z)  Purple


coloredString :: String -> Color -> String
coloredString x y
    | y == Blue ="\x1b[36m" ++  x ++ "\x1b[0m"
    | y == Red = "\x1b[31m" ++ x ++ "\x1b[0m"
    | y == Green = "\x1b[32m" ++ x ++ "\x1b[0m"
    | y == Purple ="\x1b[35m" ++ x ++ "\x1b[0m"
    | y == Yellow ="\x1b[33m" ++ x ++ "\x1b[0m"
    | otherwise =  "\x1b[0m" ++ x 


placePlayersOnMap :: [Player] -> Maze -> Maze
placePlayersOnMap [] x = x
placePlayersOnMap (x:xs) m = placePlayersOnMap xs ( replaceElemInMaze (getPlayerCoords x) (PacPlayer x) m )


printMaze :: Maze -> String
printMaze []  =  ""
printMaze (x:xs) = foldr (++) "" ( map (\y -> show y) x )  ++ "\n" ++ printMaze ( xs )

printPlayerStats :: Player -> String
printPlayerStats p = let (a,b,c,d,e,l) = getPlayerState p
                     in "ID:" ++ show a ++  " Points:" ++ show e ++ " Lives:" ++ show l ++"\n"

getPlayerID :: Player -> Int
getPlayerID (Pacman (PacState (x,y,z,t,h,l) q c d )) = x
getPlayerID  (Ghost (GhoState (x,y,z,t,h,l) q )) = x
 
getPlayerPoints :: Player -> Int
getPlayerPoints (Pacman (PacState (x,y,z,t,h,l) q c d )) = h
getPlayerPoints (Ghost (GhoState (x,y,z,t,h,l) q )) = h

setPlayerCoords :: Player -> Coords -> Player
setPlayerCoords (Pacman (PacState (x,y,z,t,h,l) q c d )) (a,b) = Pacman (PacState (x,(a,b),z,t,h,l) q c d )
setPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) q )) (a,b) = Ghost (GhoState (x,(a,b),z,t,h,l) q )


getPieceOrientation :: Piece -> Orientation
getPieceOrientation (PacPlayer p) =  getPlayerOrientation p
getPieceOrientation _ = Null

getPacmanMode :: Player -> PacMode
getPacmanMode (Pacman (PacState a b c d)) = d
  
getPlayerState :: Player -> PlayerState
getPlayerState (Pacman (PacState a b c d )) = a
getPlayerState (Ghost (GhoState a b )) = a

getPlayerOrientation :: Player -> Orientation
getPlayerOrientation (Pacman (PacState (x,y,z,t,h,l) q c d )) = t
getPlayerOrientation  (Ghost (GhoState (x,y,z,t,h,l) q )) = t

replaceElemInMaze :: Coords -> Piece -> Maze -> Maze
replaceElemInMaze (a,b) _ [] = []
replaceElemInMaze (a,b) p (x:xs) 
  | a == 0 = replaceNElem b p x : xs 
  | otherwise = x : replaceElemInMaze (a-1,b) p xs


replaceNElem :: Int -> a -> [a] -> [a]
replaceNElem i _ [] = [] 
replaceNElem i el (x:xs)
  |  i == 0 = el : xs 
  | otherwise =  x : replaceNElem (i-1) el xs

getPlayerCoords :: Player -> Coords
getPlayerCoords (Pacman (PacState (x,y,z,t,h,l) b c d )) = y
getPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) b )) = y
getPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) b )) = y
