-- | Faz jogadas para os fantasmas
ghostPlay :: State -> [Play]
ghostPlay (State m (Pacman (PacState (a,(y,x),c,d,e,f) g h i):Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l) = if i == Normal && g1 == Alive && abs (y-y1) > abs (x-x1) && signum (y-y1) == (-1)       then (Move a1 U) : ghostPlay (State m t l)
                                                                                                                else if i == Normal && g1 == Alive && abs (y-y1) > abs (x-x1) && signum (y-y1) == 1         then (Move a1 D) : ghostPlay (State m t l) 
                                                                                                                else if i == Normal && g1 == Alive && abs (y-y1) < abs (x-x1) && signum (x-x1) == (-1)      then (Move a1 L) : ghostPlay (State m t l) 
                                                                                                                else if i == Normal && g1 == Alive && abs (y-y1) < abs (x-x1) && signum (x-x1) == 1         then (Move a1 R) : ghostPlay (State m t l)
                                                                                                                else if i == Mega && g1 == Dead                                                             then (Move a1 R) : ghostPlay (State m t l)
                                                                                                                else ghostPlay (State m ((Pacman (PacState(a,(y,x),c,d,e,f) g h i)): t) l) 
                                                                                                               


