-- | Um exemplo de um labirinto simples sem quaisquer restrições associadas:
--
sampleMaze :: Maze
sampleMaze = [
                [Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall],
                [Empty, Food Little, Food Little, Food Big, Food Little, Food Big, Food Little, Empty],
                [Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall]
             ]

-- | Gera um número aleatório entre 0 e 99
--
genRandom :: Int -> Int -> [Int]
genRandom n seed = let gen = mkStdGen seed -- creates a random generator
                        in take n $ randomRs (0,99) gen -- takes the first n elements from an infinite series of random numbers between 0-9


-- | Dada uma certa seed devolve um número inteiro aleatório:
--
nrRandom :: Int -> Int
nrRandom seed = head $ genRandom 1 seed


-- | Converte uma lista numa lista de listas de tamanho n
-- 
subList :: Int -> [a] -> [[a]]
subList _ [] = []
subList n l = take n l: subList n (drop n l)


{- | Converte um número inteiro numa peça (Piece)
3 <=> Food Big
0 <= n < 70 <=> Food Little
70 < n <= 99 <=> Wall -}
--
convertPiece :: Int -> Piece
convertPiece x
    | x == 3 = Food Big
    | x >= 0 && x < 70 = Food Little
    | otherwise = Wall


-- | Converte um corredor numa string
--
printCorridor :: Corridor -> String
printCorridor [] = "\n"
printCorridor (x:xs) = show x ++ printCorridor xs


-- | Converte uma lista de inteiros num corredor
--
convertCorridor :: [Int] -> Corridor
convertCorridor [] = []
convertCorridor (x:xs) = convertPiece x : convertCorridor xs


-- | Converte uma lista de uma lista de inteiros num labirinto  
--
convertMaze :: [[Int]] -> Maze
convertMaze [] = []
convertMaze (x:xs) = convertCorridor x : convertMaze xs


-- | Converte um labirinto em forma de string
--
printMaze :: Maze -> String
printMaze []  =  ""
printMaze (x:xs) = foldr (++) "" ( map (\y -> show y) x )  ++ "\n" ++ printMaze ( xs ) 


-- | Coloca o Maze (convertido em string)
--
placeMaze :: Maze -> IO()
placeMaze x = do putStrLn (printMaze (x))

-- | Coloca uma lista de jogadores num labirinto
--
placePlayersOnMap :: [Player] -> Maze -> Maze
placePlayersOnMap [] x = x
placePlayersOnMap (x:xs) m = placePlayersOnMap xs ( replaceElemInMaze (getPlayerCoords x) (PacPlayer x) m )


-- | Converte as estatísticas de um jogador numa string
--
printPlayerStats :: Player -> String
printPlayerStats p = let (a,b,c,d,e,l) = getPlayerState p
                     in "ID:" ++ show a ++  " Points:" ++ show e ++ " Lives:" ++ show l ++"\n"


-- | Devolve o estado de jogo (PlayerState) de um jogador 
--
getPlayerState :: Player -> PlayerState
getPlayerState (Pacman (PacState a b c d )) = a
getPlayerState (Ghost (GhoState a b )) = a


-- | Devolve o ID de um jogador
--
getPlayerID :: Player -> Int
getPlayerID (Pacman (PacState (x,y,z,t,h,l) q c d )) = x
getPlayerID  (Ghost (GhoState (x,y,z,t,h,l) q )) = x


-- | Devolve as coordenadas de um jogador
--
getPlayerCoords :: Player -> Coords
getPlayerCoords (Pacman (PacState (x,y,z,t,h,l) b c d )) = y
getPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) b )) = y


-- | Devolve a orientação de um jogador
--
getPlayerOrientation :: Player -> Orientation
getPlayerOrientation (Pacman (PacState (x,y,z,t,h,l) q c d )) = t
getPlayerOrientation (Ghost (GhoState (x,y,z,t,h,l) q )) = t

-- |
--
getPlayerVelocity:: Player -> Double
getPlayerVelocity (Pacman (PacState (x,y,z,t,h,l) q c d )) = z
getPlayerVelocity (Ghost (GhoState (x,y,z,t,h,l) q )) = z

-- |
--
getPlayerMouth:: Player -> Mouth
getPlayerMouth (Pacman (PacState (x,y,z,t,h,l) q c d )) = c


-- | Devolve os pontos de um jogador
--
getPlayerPoints :: Player -> Int
getPlayerPoints (Pacman (PacState (x,y,z,t,h,l) q c d )) = h
getPlayerPoints (Ghost (GhoState (x,y,z,t,h,l) q )) = h


-- | Devolve o número de vidas de um jogador
--
getPlayerLives :: Player -> Int
getPlayerLives (Pacman (PacState (x,y,z,t,h,l) q c d )) = l
getPlayerLives (Ghost (GhoState (x,y,z,t,h,l) q )) = l


-- | Devolve o modo do jogador pacman 
--
getPacmanMode :: Player -> PacMode
getPacmanMode (Pacman (PacState a b c d)) = d

-- |
--
getTimeMega :: Player -> Double
getTimeMega (Pacman (PacState a b c d)) = b
getTimeMega x = 0 

-- | Devolve o modo do jogador fantasma
--
getGhostMode :: Player -> GhostMode
getGhostMode (Ghost (GhoState a d)) = d

-- | Coloca as coordenadas de um player
--
setPlayerCoords :: Player -> Coords -> Player
setPlayerCoords (Pacman (PacState (x,y,z,t,h,l) q c d )) (a,b) = Pacman (PacState (x,(a,b),z,t,h,l) q c d )
setPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) q )) (a,b) = Ghost (GhoState (x,(a,b),z,t,h,l) q )


-- | Devolve a orientação de uma peça 
--
getPieceOrientation :: Piece -> Orientation
getPieceOrientation (PacPlayer p) =  getPlayerOrientation p
getPieceOrientation _ = Null


-- | Subsitui uma peça que está numas certas coordenadas do labirinto por outra peça, devolvendo o labirinto atualizado
--
replaceElemInMaze :: Coords -> Piece -> Maze -> Maze
replaceElemInMaze (a,b) _ [] = []
replaceElemInMaze (a,b) p (x:xs) 
  | a == 0 = replaceNElem b p x : xs 
  | otherwise = x : replaceElemInMaze (a-1,b) p xs

getPacman :: [Player] -> Player
getPacman (Pacman ps : xs) = Pacman ps
getPacman (x:xs) = getPacman xs

-- | Recebe um índice, um elemento de uma lista e uma lista. Devolve a lista atualizada cujo elemento no índice indicado foi substituído pelo elemento dado
--
replaceNElem :: Int -> a -> [a] -> [a]
replaceNElem i _ [] = [] 
replaceNElem i el (x:xs)
  |  i == 0 = el : xs 
  | otherwise =  x : replaceNElem (i-1) el xs

checkPacman :: Player -> Bool
checkPacman (Pacman (PacState (id, (x,y), v, ort, p, l) t o m)) = True
checkPacman (Ghost (GhoState (id, (x,y), v, ort, p, l) m)) = False

checkGhostDead :: Player -> Bool
checkGhostDead (Ghost (GhoState (id, (x,y), v, ort, p, l) Dead)) = True
checkGhostDead (Ghost (GhoState (id, (x,y), v, ort, p, l) Alive)) = False
checkGhostDead (Pacman (PacState (id, (x,y), v, ort, p, l) t o m)) = False

{- |

= Introdução

Nesta tarefa 6 desenvolvemos as táticas e as jogadas que o bot (pacman) deve tomar de modo a agir corretamente no jogo.

= Desenvolvimento

Na realização desta tarefa criamos funções que permitem ao pacman jogar de acordo com o estado de jogo atual.

Para implementar estas reações por parte do bot, criamos funções que permitem: ver se ha algum fantasma perto do pacman num determinado raio e identifiçá-lo; ver quais as condições a que o bot está sujeito, nomeadamente (e por ordem de prioridade), se tem algum fantasma vivo a persegui-lo num raio de 5 unidades; se tem algum fantasma morto que deve perseguir; se tem uma comida grande à sua volta; se tem uma comida pequena à sua volta; calcular a melhor orientação que o bot deve tomar (quer esteja a ser perseguido, a perseguir, ou simplesmente a comer comida para somar pontos)

= Conclusão

Ficamos mais satisfeitos com o funcionamento da movimentação bot do que com o funcionamento da movimentação dos fantasmas, visto que o bot recalcula para onde deve ir de acordo com as peças que tem à sua volta e num determinado raio.
No entanto, o bot apresenta alguns problemas evidentes, como por exemplo o facto de, por dar prioridade a fugir dos fantasmas, tomar uma orientação que o leva a tentar movimentar-se contra uma parede infinitamente.
-}



{- | Condição que define a prioridade de jogada para comer uma comida pequena se não houver nenhuma comida grande à volta e o pacman não estiver a ser perseguido ou a perseguir algum fantasma -}
--
checkFoodLittle :: Maze -> Int -> [Player] -> Orientation -> Coords -> (Bool, Play)
checkFoodLittle maze id pls ort (x,y) 
    | getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id pls)) ort) == Just (Food Little) = (True, Move id ort)
    | getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id pls)) U) == Just (Food Little) = (True, Move id U)
    | getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id pls)) D) == Just (Food Little) = (True, Move id D)
    | getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id pls)) R) == Just (Food Little) = (True, Move id R)
    | getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id pls)) L) == Just (Food Little) = (True, Move id L)
    | otherwise = (False, Move id ort)

-- | Condição que define a prioridade de jogada para comer uma comida grande se se o pacman não estiver a ser perseguido ou estiver a perseguir alguém
--
checkFoodBig :: Maze -> Int -> [Player] -> Orientation -> Coords -> (Bool, Play)
checkFoodBig maze id pls ort (x,y) 
    | getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id pls)) ort) == Just (Food Big) = (True, Move id ort)
    | getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id pls)) U) == Just (Food Big) = (True, Move id U)
    | getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id pls)) D) == Just (Food Big) = (True, Move id D)
    | getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id pls)) R) == Just (Food Big) = (True, Move id R)
    | getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id pls)) L) == Just (Food Big) = (True, Move id L)
    | otherwise = (False, Move id ort)

-- | Vai buscar as coordenadas do fantasma mais próximo ao pacman de uma lista de jogadores
--
getNearestGhostCoords :: [Player] -> Coords
getNearestGhostCoords (j:js) = head (sortOn (distance (getPlayerCoords (getPacman (j:js)))) (map (getPlayerCoords) (getGhosts (j:js))))

-- | Verifica se existe algum fantasma num determinado raio
--
checkGhostClose :: [Player] -> Bool
checkGhostClose pls
    | distance (getPlayerCoords (getPacman pls)) (getNearestGhostCoords pls) <= 5 = True
    | otherwise = False

-- | Vai buscar o fantasma com as coordenadas do fantasma mais próximo ao pacman
--
getNearestGhostFromCoords :: [Player] -> Coords -> Player
getNearestGhostFromCoords (j:js) (x,y)
    | (not (checkPacman j)) && (getPlayerCoords j) == (x,y) = j
    | otherwise = getNearestGhostFromCoords js (x,y)
    
-- | Vai buscar o fantasma mais próximo do pacman a partir de uma lista de jogadores
--
getNearestGhost :: [Player] -> Player
getNearestGhost pls = getNearestGhostFromCoords pls (getNearestGhostCoords pls)

-- | Devolve a melhor orientação de modo a que a distância do pacman ao fantasma mais próximo seja maior
--
getEscapeOrt :: [Player] -> Orientation
getEscapeOrt pls = snd (head (sortOn (fst) (getBestOrt (getNearestGhostCoords pls) (getPlayerCoords (getPacman pls)))))

-- | Devolve a melhor orientação de modo a que a distância do pacman ao fantasma mais próximo seja menor
--
getChaseOrt :: [Player] -> Orientation
getChaseOrt pls = snd (head (reverse (sortOn (fst) (getBestOrt (getNearestGhostCoords pls) (getPlayerCoords (getPacman pls))))))

-- | Permite que o pacman jogue sozinho atribuíndo-lhe jogadas que obedecem a determinadas condições
--
bot :: Int -> State -> Maybe Play
bot id s@(State maze pls lvl)
    | (getPacmanMode (getPacman pls) == Normal) && (checkGhostClose pls) && ((getGhostMode (getNearestGhost pls)) == Alive) = Just (Move id (getEscapeOrt pls))
    | (getPacmanMode (getPacman pls) == Mega) && (checkGhostClose pls) && ((getGhostMode (getNearestGhost pls)) == Alive) = Just (Move id (getEscapeOrt pls)) 
    | (getPacmanMode (getPacman pls) == Mega) && ((getGhostMode (getNearestGhost pls)) == Dead) = Just (Move id (getChaseOrt pls))
    | fst (checkFoodBig maze id pls (getPlayerOrientation (getPacman pls)) (getPlayerCoords (getPacman pls))) = Just (snd (checkFoodBig maze id pls (getPlayerOrientation (getPacman pls)) (getPlayerCoords (getPacman pls))))
    | fst (checkFoodLittle maze id pls (getPlayerOrientation (getPacman pls)) (getPlayerCoords (getPacman pls))) = Just (snd (checkFoodLittle maze id pls (getPlayerOrientation (getPacman pls)) (getPlayerCoords (getPacman pls))))
    | otherwise = Just (Move id (getPlayerOrientation (getPacman pls)))
    where id = getPlayerID (getPacman pls)

{-
not (fst (getNewOrt maze id pls (getPlayerOrientation (getPacman pls)) (getPlayerCoords (getPacman pls)))) = Just (snd (getNewOrt maze id pls (getPlayerOrientation (getPacman pls)) (getPlayerCoords (getPacman pls))))
 
checkWallU :: Maze -> Int -> [Player] -> Orientation -> Coords -> Bool
checkWallU maze id pls U (x,y) 
    | (getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id pls)) U)) == Just Wall = True
    | otherwise = False

checkWallR :: Maze -> Int -> [Player] -> Orientation -> Coords -> Bool
checkWallR maze id pls R (x,y) 
    | (getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id pls)) R)) == Just Wall = True
    | otherwise = False

checkWallD :: Maze -> Int -> [Player] -> Orientation -> Coords -> Bool
checkWallD maze id pls D (x,y) 
    | (getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id pls)) D)) == Just Wall = True
    | otherwise = False

checkWallL :: Maze -> Int -> [Player] -> Orientation -> Coords -> Bool
checkWallL maze id pls L (x,y) 
    | (getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id pls)) L)) == Just Wall = True
    | otherwise = False


getNewOrt :: Maze -> Int -> [Player] -> Orientation -> Coords -> (Bool, Play)
getNewOrt maze id pls ort (x,y) 
    | not (checkWallU maze id pls U (x,y)) = (False, Move id U)
    | (checkWallU maze id pls U (x,y)) = ((checkWallD maze id pls D (x,y)), Move id D)
    | (checkWallD maze id pls D (x,y)) = ((checkWallR maze id pls L (x,y)), Move id L)
    | (checkWallR maze id pls R (x,y)) = ((checkWallR maze id pls R (x,y)), Move id R)
    | otherwise = (True, Move id ort) -}


{- | 

= Introdução

Nesta tarefa 5 desenvolvemos as táticas e as jogadas que os fantasmas devem tomar de modo a agir corretamente no jogo.

= Desenvolvimento

Na realização desta tarefa criamos dois tipos de jogadas que os fantasmas podiam tomar.
Caso os fantasmas estejam vivos, estes devem perseguir o pacman, recalculando (cada vez que batem numa parede) qual a orientação que devem tomar de modo a que a sua distância à do pacman seja a menor.
Caso os fantasmas estejam mortos, estes devem fugir do pacman, mudando a sua orientação 90º para a direita cada vez que batem numa parede.

Para implementar estas reações por parte dos fantasmas, criamos funções que permitem: calcular a distância entre dois jogadores; calcular a melhor orientação que o fantasma deve tomar; mudar a orientação do fantasma 90º para direita.

= Conclusão

Apesar de termos cumprido os parâmetros que foram indicados para a realização desta tarefa, reconhecemos que a movimentação dos fantasmas tem algumas falhas que advém do facto de este só recalcular qual deve ser a sua próxima orientação ao bater numa parede.
-}



-- | Calcula a distância entre dois pontos
--
distance :: Coords -> Coords -> Double
distance (x,y) (a,b) = sqrt (((fromIntegral a)-(fromIntegral x))^2 + ((fromIntegral b)-(fromIntegral y))^2)

-- | Vai buscar a melhor orientação que um jogador deve tomar para chegar mais perto de outro jogador
--  
getBestOrt :: Coords -> Coords -> [(Double, Orientation)]
getBestOrt (x,y) (a,b) = [(distance (x-1,y) (a,b), U), (distance (x+1,y) (a,b), D), (distance (x,y-1) (a,b), L), (distance (x,y+1) (a,b), R)] 

-- | Define as jogadas de perseguição (fantasma a perseguir pacman)
--
chaseMode :: State -> Int -> Play
chaseMode s@(State maze pls lvl) id 
    | getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id pls)) (getPlayerOrientation (getPlayerFromID id pls))) == Just Wall = Move id (snd (head (sortOn (fst) (getBestOrt (getPlayerCoords (getPlayerFromID id pls)) (getPlayerCoords (getPacman pls))))))
    | otherwise = (Move id (getPlayerOrientation (getPlayerFromID id pls)))

-- | Muda a orientação a 90º no sentido do ponteiro dos relógios
--
changeOrientation :: Orientation -> Orientation
changeOrientation U = R
changeOrientation R = D
changeOrientation D = L
changeOrientation L = U

-- | Define as jogadas para escapar (fantasmas escapar do pacman)
--
scatterMode :: State -> Int -> Play
scatterMode s@(State maze pls lvl) id 
    | getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id pls)) (getPlayerOrientation (getPlayerFromID id pls))) == Just Wall = Move id (changeOrientation (getPlayerOrientation (getPlayerFromID id pls)))
    | otherwise = (Move id (getPlayerOrientation (getPlayerFromID id pls)))

-- | Calcula a lista de jogadas para os fantasmas a partir de um estado de jogo
--
ghostPlay :: State -> [Play]
ghostPlay s@(State maze (j:js) lvl) 
    | (not (checkPacman j)) && (getGhostMode j) == Alive = (chaseMode s (getPlayerID j)):ghostPlay (State maze js lvl) 
    | (not (checkPacman j)) && (getGhostMode j) == Dead = (scatterMode s (getPlayerID j)):ghostPlay (State maze js lvl) 
    | otherwise = ghostPlay (State maze (js++[j]) lvl)





{- | 

= Introdução

De acordo com o jogo do Pac-Man, os jogadores (fantasmas e Pac-Man) tomam uma determinada orientação e, a partir daí, andam sozinhos com a passagem do tempo até mudarem de orientação novamente e repetirem o mesmo processo.
É nesta tarefa 4 que definimos as funções que permitem aos jogadores do nosso projeto movimentarem-se com a passagem do tempo, tal como no jogo original.

= Desenvolvimento

Tal como foi referido na introdução, o principal objetivo desta tarefa é implementar o efeito da passagem do tempo no estado de jogo.

Para isto foram tomadas as seguintes medidas: considerou-se que o tempo que passa entre cada iteração é 250 milisegundos. Isto significa que a cada segundo, se o jogador estiver com uma velocidade normal, move-se quatro vezes; foram implementadas funções adicionais na tarefa 2 que permitem ao pacman abrir e fechar a sua boca a cada jogada (dando uma animação mais similar à do jogo clássico) e que fazem com que o pacman perca tempo em modo mega, obedecendo às condições impostas previamente; foi feita uma função passTime (com a ajuda de uma função auxilixar) que, de acordo com o estado de jogo atual, devolve o estado de jogo uma iteração (ou iterações) depois; mais tarde, os argumentos usados na função auxiliar da passTime foram alterados de modo a que as jogadas dos fantasmas e do pacman correspondessem, respetivamente, às jogadas definidas na tarefa 5 e tarefa 6.

= Conclusão

Concluímos, com gosto, esta tarefa, visto que conseguimos cumprir os requisitos indicados pelos docentes e ficamos muito satisfeitos com o resultado final e o seu funcionamento.
 -}



-- | Tempo regular de cada iteração
--
defaultDelayTime = 250 -- 250 ms

-- | Permite atualizações no estado de jogo com a passagem do tempo
--
passTime :: Int -> State -> State
passTime n s@(State maze (x:xs) lvl) = passTimeAux (x:xs) n s

-- | Função auxiliar à passTime
--
passTimeAux :: [Player] -> Int -> State -> State
passTimeAux [] n s = s
passTimeAux (x:xs) n s 
    | (checkPacman x) && (getPacmanMode x == Mega) = passTimeAux xs n (play (getBotPlay (bot (getPlayerID x) s)) s)
    | (checkPacman x) && ((getTimeMega x) <= 0) = passTimeAux xs n (play (getBotPlay (bot (getPlayerID x) s)) s)
    | not (checkGhostDead x) = passTimeAux xs n (play (getPlay (ghostPlay s) (getPlayerID x)) s)
    | (even n) && (checkGhostDead x) = passTimeAux xs n (play (getPlay (ghostPlay s) (getPlayerID x)) s)
    | (odd n) && (checkGhostDead x) = passTimeAux xs n s
    | otherwise = passTimeAux xs n s  
  
-- | Vai buscar a jogada relativa a um ID dado a uma lista de jogadas
--  
getPlay :: [Play] -> Int -> Play
getPlay ((Move id ort):xs) id'
    | id == id' = Move id ort
    | otherwise = getPlay xs id'

-- | Transforma uma Maybe Play numa jogada
--
getBotPlay :: Maybe Play -> Play
getBotPlay (Just (Move id ort)) = Move id ort

{- | Função para jogar sem bot

passTimeAux :: [Player] -> Int -> State -> State
passTimeAux [] n s = s
passTimeAux (x:xs) n s 
    | (checkPacman x) && (getPacmanMode x == Mega) = passTimeAux xs n (play (Move (getPlayerID x) (getPlayerOrientation x)) s)
    | (checkPacman x) && ((getTimeMega x) <= 0) = passTimeAux xs n (play (Move (getPlayerID x) (getPlayerOrientation x)) s)
    | not (checkGhostDead x) = passTimeAux xs n (play (getPlay (ghostPlay s) (getPlayerID x)) s)
    | (even n) && (checkGhostDead x) = passTimeAux xs n (play (getPlay (ghostPlay s) (getPlayerID x)) s)
    | (odd n) && (checkGhostDead x) = passTimeAux xs n s
    | otherwise = passTimeAux xs n s
-}

    

{- | Para a realização desta tarefa vamos primeiro fazer uma função que devolve os padrões horizontais, e a partir daí vamos construir os padrões verticais até termos a função compactMaze. -}



-- | Divide o corredor numa lista de corredores cujos elementos correspondem aos elemtos iguais consecutivos do corredor original
--
splitCorridor :: Corridor -> [Corridor] -- length ((splitCorridor l) !! 0) dá o numero de vezes repetido .... (length (x:xs) - length (tail (x:xs)))
splitCorridor  [] = []
splitCorridor (x:xs) = (x:takeWhile(== x) xs):splitCorridor (dropWhile(==x) xs)

-- | Devolve a lista [(Int,Piece)] de uma determinada instrução
--
getIntPiece :: Instruction -> [(Int,Piece)]
getIntPiece (Instruct ((i,p):xs)) = (i,p):xs

-- | Devolve o padrão horizontal de um corredor em forma de instrução
--
horPattern :: Corridor -> Instruction
horPattern [] = Instruct []
horPattern [x] = Instruct [(1,x)]
horPattern (x:xs:[]) = if (x == xs) then Instruct [(2,x)] else Instruct [(1,x),(1,xs)]
horPattern (x:xs) 
    | (length (splitCorridor (x:xs))) > 1 = Instruct ((length ((splitCorridor (x:xs)) !! 0), x):getIntPiece (horPattern (drop (length ((splitCorridor (x:xs)) !! 0)) (x:xs))))
    | otherwise = Instruct [(length ((splitCorridor (x:xs)) !! 0), x)]

-- | Transforma um labirinto numa lista de instruções em que cada instrução corresponde ao padrão horizontal em instrução de cada corredor do labirinto 
--
horPatternMaze :: Maze -> Instructions
horPatternMaze [] = []
horPatternMaze (x:xs) = (horPattern x):horPatternMaze xs

-- | Devolve o índice da primeira ocorrência de um elemento numa determinada lista 
--
getIndex :: Eq a => a -> [a] -> Int
getIndex a [x] = 0
getIndex a (x:xs) 
    | a == x = 0
    | otherwise = 1+getIndex a xs

-- | Devolve a lista de índices correspondestes às ocorrências de um determinado elemento numa lista
--
getCorridorIndex :: Eq a => a -> [a] -> [Int]
getCorridorIndex _ [] = [] 
getCorridorIndex n l
        | n == last l = getCorridorIndex n (init l)++[(length l)-1]
        | otherwise = getCorridorIndex n (init l)

-- | Substitui numa determinada lista de instruções uma instrução na posição correspondente ao índice dado 
--
replaceInstructRepeatInt :: [Instruction] -> Int -> Instruction -> [Instruction]
replaceInstructRepeatInt xs i x = before ++ (x : after)
  where before = take i xs
        after = drop (i+1) xs

-- | Substitui numa determinada lista de instruções uma instrução nas posições correspondentes aos elementos da lista de índices dada
--
replaceInstructRepeatInts :: [Instruction] -> [Int] -> Instruction -> [Instruction]
replaceInstructRepeatInts xs [] x = xs 
replaceInstructRepeatInts xs (i:is) x = replaceInstructRepeatInts (replaceInstructRepeatInt xs i x) is x

-- | Função auxiliar da compactMaze que atualiza uma lista de instruções para uma lista de instruções com os respetivos "Repeat" necessários
--
compactMaze' :: Instructions -> Int -> Instructions
compactMaze' ((Repeat y):ys) i = (Repeat y):compactMaze' ys i
compactMaze' [] i = []
compactMaze' (x:xs) i
    | elem x xs = compactMaze' (replaceInstructRepeatInts (x:xs) (tail (getCorridorIndex x (x:xs))) (Repeat (getIndex x (x:xs)+i))) i
    | otherwise = x:compactMaze' xs (i+1)

-- | Recebe um labirinto e transforma-o numa lista de instruções válida
--
compactMaze :: Maze -> Instructions
compactMaze [] = []
compactMaze (x:xs) = compactMaze' (horPatternMaze (x:xs)) 0

-- | Dada uma instrução devolve-a em forma de corredor
--
unzipCorridor :: Instruction -> Corridor
unzipCorridor (Instruct []) = []
unzipCorridor (Instruct ((i,p):xs)) = (replicate i p) ++ unzipCorridor (Instruct xs)

-- | Dada uma lista de instruções, descompacta-a num labirinto constituídos pelas instruções do tipo Instruct [(Int,Piece)]
--
unzipMaze :: Instructions -> Maze
unzipMaze [] = []
unzipMaze (x:xs) = (unzipCorridor x):(unzipMaze xs) 

-- | Dada uma lista de instruções, devolve a mesma com os repeats substituídos pelos respetivos (Instruct [(Int,Piece)])
--
deleteRepeats :: Instructions -> Instructions -> Instructions
deleteRepeats [] (y:ys) = []
deleteRepeats (Repeat x:xs) (y:ys) =  ((y:ys) !! x):deleteRepeats xs (y:ys)
deleteRepeats (x:xs) (y:ys) = x:deleteRepeats xs (y:ys)

-- | Testa se as instruções descompactadas em forma de labirinto correspondem ao labirinto correto
--
testCompactMaze :: Instructions -> Maze -> Bool
testCompactMaze (x:xs) m = m == unzipMaze (deleteRepeats (x:xs) (x:xs)) 


{- | Nesta tarefa, de modo a definir a função play, vamos escrever funções auxiliares que ajudem no cumprimento das jogadas, quer estas sejam simples mudanças de orientação, ou mudanças na posição do jogador, obedecendo às respetivas condições e restrições associadas. -}



-- | Dado um ID e uma lista de jogadores, devolve o jogador com esse ID único
--
getPlayerFromID :: Int -> [Player] -> Player
getPlayerFromID id (j:js) 
    | id == (getPlayerID j) = j
    | otherwise = getPlayerFromID id js

-- | Dado um ID e uma lista de jogadores, devolve a lista de jogadores sem o jogador com esse ID único
--
getPlayerFromNotID :: Int -> [Player] -> [Player]
getPlayerFromNotID id (j:js) 
    | id == (getPlayerID j) = js
    | otherwise = j: getPlayerFromNotID id js

-- | Dado um jogador, devolve o jogador com a orientação alterada para a que foi dada
--
changePlayerOrientation :: Orientation -> Player -> Player
changePlayerOrientation ort2 (Pacman (PacState (id , (x,y), v, ort1, p, l) t o m )) = (Pacman (PacState (id , (x,y), v, ort2, p, l) t o m ))
changePlayerOrientation ort2 (Ghost (GhoState (id , (x,y), v, ort1, p, l) m )) = (Ghost (GhoState (id , (x,y), v, ort2, p, l) m ))

-- | Dada uma lista de jogadores, devolve o jogador escolhido a partir do seu ID único com a sua orientação alterada para a que foi dada
--
changePlayerOrientationFromID :: Orientation -> Int -> [Player] -> Player
changePlayerOrientationFromID ort2 id (j:js)
    | id == getPlayerID j = changePlayerOrientation ort2 j
    | otherwise = changePlayerOrientationFromID ort2 id js 

-- | Dadas umas coordenadas e uma orientação, devolve as coordenadas atualizadas da possível próxima posição
--
nextPosition :: Coords -> Orientation -> Coords
nextPosition (x,y) ort = case ort of L -> (x,y-1)
                                     R -> (x,y+1)                                    
                                     U -> (x-1,y)
                                     D -> (x+1,y)
                                     Null -> (x,y)

-- | Dado um labirinto e umas coordenadas, calcula a peça que aí se encontra (podendo não ser dadas coordenadas válidas e, nesse caso, não devolve nenhuma peça)
--
getPiece :: Maze -> Coords -> Maybe Piece 
getPiece maze (x,y) 
  | y<0 || y>=(length (maze !! 0)) = Nothing
  | otherwise = Just ((maze !! x) !! y)
  
-- | Dadas umas coordenadas e um jogador, devolve o jogador com as suas coordenadas alteradas para as que foram dadas
--
changePlayerCoords :: Coords -> Player -> Player 
changePlayerCoords (x,y) (Pacman (PacState (id, (x',y'), v, ort, p, l) t o m)) = (Pacman (PacState (id, (x,y), v, ort, p, l) t o m))
changePlayerCoords (x,y) (Ghost (GhoState (id, (x',y'), v, ort, p, l) m)) = (Ghost (GhoState (id, (x,y), v, ort, p, l) m))

-- | Dado um jogador, atualiza as suas coordenadas para para as coordenadas da posição seguinte, de acordo com a orientação atual que tem
--
updatePlayerCoords :: Player -> Player
updatePlayerCoords (Pacman (PacState (id, (x,y), v, ort, p, l) t o m)) = (Pacman (PacState (id, (nextPosition (x,y) ort), v, ort, p, l) t o m)) 
updatePlayerCoords (Ghost (GhoState (id, (x,y), v, ort, p, l) m)) = (Ghost (GhoState (id, (nextPosition (x,y) ort), v, ort, p, l) m))

-- | Atualiza os pontos de um jogador de acordo com a peça dada
--
updatePlayerPoints :: Player -> Piece -> Player
updatePlayerPoints (Pacman (PacState (id , (x,y), v, ort, p, l) t o m )) (Food Little) = (Pacman (PacState (id , (x,y), v, ort, p+1, l) t o m ))
updatePlayerPoints (Pacman (PacState (id , (x,y), v, ort, p, l) t o m )) (Food Big) = (Pacman (PacState (id , (x,y), v, ort, p+5, l) t o m ))
updatePlayerPoints (Pacman (PacState (id , (x,y), v, ort, p, l) t o m )) (PacPlayer (Ghost  (GhoState a Dead ))) = (Pacman (PacState (id , (x,y), v, ort, p+10, l) t o m ))
updatePlayerPoints x p = x

-- | Atualiza as vidas de um jogador, tirando uma vida ao seu número de vidas atuais
--
updatePlayerLives :: Player -> Player
updatePlayerLives (Pacman (PacState (x,y,z,t,h,l) q c d )) = (Pacman (PacState (x,y,z,t,h,(l-1)) q c d ))
updatePlayerLives x = x

-- Dado um jogador pacman e um modo (PacMode), altera o modo desse jogador pacman para o modo dado
--
changePacMode :: Player -> PacMode -> Player
changePacMode (Pacman (PacState (id , (x,y), v, ort, p, l) t o m )) m' = (Pacman (PacState (id , (x,y), v, ort, p, l) t o m'))
changePacMode x m = x

-- | Dado um  jogador fantasma e um modo (GhostMode), altera o modo desse jogador fantasma para o modo dado
--
changeGhostMode :: Player -> GhostMode -> Player
changeGhostMode (Ghost (GhoState (id , (x,y), v, ort, p, l) m )) m' = (Ghost (GhoState (id , (x,y), v, ort, p, l) m'))

-- | Dada uma lista de jogadores, altera o modo de todos os fantasmas vivos para morto (Dead)
--
changeGhostsForDead :: [Player] -> [Player]
changeGhostsForDead [] = []
changeGhostsForDead ((Ghost (GhoState (id, (x,y), v, ort, p, l) Alive)):js) = (Ghost (GhoState (id, (x,y), v/2 , ort, p, l) Dead)):changeGhostsForDead js
changeGhostsForDead ((Ghost (GhoState (id, (x,y), v , ort, p, l) Dead)):js) = (Ghost (GhoState (id, (x,y), v , ort, p, l) Dead):changeGhostsForDead js)
changeGhostsForDead ((Pacman (PacState (id, (x,y), v, ort, p, l) t o m)):js) = ((Pacman (PacState (id, (x,y), v, ort, p, l) t o m)):changeGhostsForDead js) 

-- | Dada uma lista de jogadores, altera o modo de todos os fantasmas mortos para vivo (Alive)
--
changeGhostsForAlive :: [Player] -> [Player]
changeGhostsForAlive [] = []
changeGhostsForAlive ((Ghost (GhoState (id, (x,y), v, ort, p, l) Alive)):js) = (Ghost (GhoState (id, (x,y), v , ort, p, l) Alive)):changeGhostsForAlive js
changeGhostsForAlive ((Ghost (GhoState (id, (x,y), v , ort, p, l) Dead)):js) = (Ghost (GhoState (id, (x,y), 2*v , ort, p, l) Alive)):changeGhostsForAlive js
changeGhostsForAlive ((Pacman (PacState (id, (x,y), v, ort, p, l) t o m)):js) = (Pacman (PacState (id, (x,y), v, ort, p, l) t o m)):changeGhostsForAlive js 

-- | Dado um jogador fantasma morto, altera o seu modo para vivo
--
changeGhostForAlive :: Player -> Player
changeGhostForAlive ((Ghost (GhoState (id, (x,y), v, ort, p, l) Dead))) = ((Ghost (GhoState (id, (x,y), 2*v, ort, p, l) Alive)))
changeGhostForAlive x = x

-- | Dado um labirinto devolve as coordenadas centrais onde os fantasmas devem renascer, conforme o labirinto é par ou ímpar
--
getMiddleCoords :: Maze -> Coords
getMiddleCoords m 
  | even (length m) = (((div (length m) 2)-1), (div (length (m !! 0)) 2))
  | otherwise = ((div (length m) 2), (div (length (m !! 0)) 2))

-- | Dada uma lista de jogadores, devolve a lista dos jogadores dessa lista que são fantasmas
--
getGhosts :: [Player] -> [Player]
getGhosts [] = []
getGhosts (j:js) = case j of
  (Ghost (GhoState _ _)) -> j:getGhosts js
  otherwise -> getGhosts js

-- | Dada uma lista de jogadores e um ID, verifica se o jogador da lista com esse ID único tem as mesmas coordenadas de outro jogador
--
checkCoordsPlayerGhosts :: [Player] -> Int -> [Player] -> Bool
checkCoordsPlayerGhosts (j:js) id [] = False
checkCoordsPlayerGhosts (j:js) id (g:gs) 
  | getPlayerCoords (getPlayerFromID id (j:js)) == getPlayerCoords g = True
  | otherwise = checkCoordsPlayerGhosts (j:js) id gs 

-- | Devolve o jogador fantasma com as mesmas coordenadas do jogador cujo ID foi dado, de uma determinada lista de jogadores
--
getGhostSameCoords :: [Player] -> Int -> [Player] -> Player
getGhostSameCoords js id (g:gs)
  | getPlayerCoords (getPlayerFromID id js) == getPlayerCoords g = g
  | otherwise = getGhostSameCoords js id gs

-- | Devolve a lista de jogadores sem um determinado jogador dessa lista
--
deleteGhost :: [Player] -> Player -> [Player]
deleteGhost [] g = []
deleteGhost (j:js) g 
  | getPlayerID j == getPlayerID g = js
  | otherwise = j: (deleteGhost js g)

-- |
--
setTimeMega :: Player -> Player
setTimeMega (Pacman (PacState (id, (x,y), v, ort, p, l) t o m)) = (Pacman (PacState (id, (x,y), v, ort, p, l) 10000 o m))
setTimeMega x = x

-- | Altera o estado do pacman para normal a partir de um state
--
changePacModeFromState :: Int -> State -> State
changePacModeFromState id s@(State maze js lvl)
  | (checkPacman (getPlayerFromID id js)) && ((getPacmanMode (getPlayerFromID id js)) == Dying) = s
  | (checkPacman (getPlayerFromID id js)) && ((getTimeMega (getPlayerFromID id js))) <= 0 = State maze ((changePacMode (getPlayerFromID id js) Normal):(changeGhostsForAlive (getPlayerFromNotID id js))) lvl 
  | otherwise = s

-- | Abre e fecha a boca do pacman
--
changePlayerMouth :: Player -> Player
changePlayerMouth (Pacman (PacState (id, (x,y), v, ort, p, l) t Open m)) = (Pacman (PacState (id, (x,y), v, ort, p, l) t Closed m))
changePlayerMouth (Pacman (PacState (id, (x,y), v, ort, p, l) t Closed m)) = (Pacman (PacState (id, (x,y), v, ort, p, l) t Open m))

-- | Abre e fecha a boca do pacman na lista de jogadores
--
changePlayerMouthList :: [Player] -> [Player]
changePlayerMouthList [] = []
changePlayerMouthList (j:js)
    | checkPacman j = (changePlayerMouth j):js
    | otherwise = j:changePlayerMouthList js
 
{- | Dado um labirinto, um ID, uma lista de jogadores e uma orientação, atualiza o labirinto conforme a ação concebida ao jogador cujo ID único foi recebido -} 
--
updateMaze :: Maze -> Int -> [Player] -> Orientation -> Maze
updateMaze maze id js ort = if checkPacman (getPlayerFromID id js) then case getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id js)) ort) of
   Just Wall -> maze
   Just Empty -> maze
   Just (Food Little) -> replaceElemInMaze (nextPosition (getPlayerCoords (getPlayerFromID id js)) ort) Empty maze
   Just (Food Big) -> replaceElemInMaze (nextPosition (getPlayerCoords (getPlayerFromID id js)) ort) Empty maze
   Nothing -> maze
   else maze 

{- | Dado um labirinto, um ID, uma lista de jogadores e uma orientação, atualiza a lista de jogadores conforme a ação concebida ao jogador cujo ID único foi recebido, no labirinto em questão -}
--
updatePlayer :: Maze -> Int -> [Player] -> Orientation -> [Player]
updatePlayer maze id js ort = if (checkPacman (getPlayerFromID id js)) && (getPacmanMode (getPlayerFromID id js) /= Dying) then case getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id js)) ort) of 
  Just Wall -> js
  Just Empty -> (updatePlayerCoords (getPlayerFromID id js):getPlayerFromNotID id js)
  Just (Food Little) -> (updatePlayerCoords (updatePlayerPoints (getPlayerFromID id js) (Food Little))):(getPlayerFromNotID id js)
  Just (Food Big) -> (updatePlayerCoords (setTimeMega (changePacMode (updatePlayerPoints (getPlayerFromID id js) (Food Big)) Mega))): (changeGhostsForDead (getPlayerFromNotID id js))
  Nothing -> if (snd(getPlayerCoords (getPlayerFromID id js)) == 0) && (ort == L) then (changePlayerCoords ((fst(getPlayerCoords (getPlayerFromID id js))),((length (maze !! 0))-1)) (getPlayerFromID id js)):(getPlayerFromNotID id js) else (changePlayerCoords (fst(getPlayerCoords (getPlayerFromID id js)),0) ((getPlayerFromID id js))):getPlayerFromNotID id js
  else if (checkPacman (getPlayerFromID id js)) && (getPacmanMode (getPlayerFromID id js) == Dying) then js else
  case getPiece maze (nextPosition (getPlayerCoords (getPlayerFromID id js)) ort) of 
  Just Wall -> js
  Just Empty -> (updatePlayerCoords (getPlayerFromID id js):getPlayerFromNotID id js)
  Just (Food Little) -> (updatePlayerCoords (getPlayerFromID id js):getPlayerFromNotID id js)
  Just (Food Big) -> (updatePlayerCoords (getPlayerFromID id js):getPlayerFromNotID id js)
  Nothing -> js

{- | Dado um labirinto, a lista de jogadores atualizada de acordo com a peça que vinha a seguir e um ID, devolve a lista de jogadores atualizada conforme o jogador com o ID único dado tem coordenadas iguais às de um fantasma pertencente à lista de jogadores -}
--
updatePlayerByGhost :: Maze -> [Player] -> Int -> [Player] -- devolve a lista c os jogadores atualizados, o do ID com os pontos e os fantasmas no sitio e modo alterado
updatePlayerByGhost m js id 
    | checkPacman (getPlayerFromID id js) && (checkCoordsPlayerGhosts js id (getGhosts js)) && (getGhostMode (getGhostSameCoords js id (getGhosts js))) == Alive = if ((getPlayerLives (getPlayerFromID id js)) > 0 ) then (updatePlayerLives (getPlayerFromID id js)):(getPlayerFromNotID id js) else (changePacMode (getPlayerFromID id js) Dying):(getPlayerFromNotID id js)
    | checkPacman (getPlayerFromID id js) && (checkCoordsPlayerGhosts js id (getGhosts js)) && (getGhostMode (getGhostSameCoords js id (getGhosts js))) == Dead =  (updatePlayerPoints (getPlayerFromID id js) (PacPlayer (getGhostSameCoords js id (getGhosts js)))):(changeGhostForAlive (changePlayerCoords (getMiddleCoords m) (getGhostSameCoords js id (getGhosts js)))):(deleteGhost (getPlayerFromNotID id js) ((changeGhostMode (changePlayerCoords (getMiddleCoords m) (getGhostSameCoords js id (getGhosts js))) Alive)))
    | otherwise = js
    
-- | Recebe uma jogada e um determinado estado e devolve o estado atualizado após a realização da jogada
--
play :: Play -> State -> State
play (Move id ort) s@(State maze js lvl) 
  | (getPlayerOrientation (getPlayerFromID id js)) /= ort = changePacModeFromState id (State maze (sortOn (getPlayerID) (changePlayerMouthList ((changePlayerOrientationFromID ort id js):getPlayerFromNotID id js))) lvl)
  | otherwise = changePacModeFromState id (State (updateMaze maze id js ort) (sortOn (getPlayerID) (changePlayerMouthList (updatePlayerByGhost maze (updatePlayer maze id js ort) id))) lvl)

{- | Nesta tarefa vamos construindo e gerando labirintos cada vez mais completos até termos um labirinto válido.

Um labirinto válido segue as seguintes regras:
1. O labirinto é rodeado por peças Wall (exceto túnel);
2. A faixa mais central forma um túnel;
3. Todos os corredores têm o mesmo comprimento;
4. A “casa dos fantasmas” está localizada no centro do labirinto;
5. Deve ter as dimenões mínimas de 15x10.

Para isto, vamos definir várias funções que nos vão ajudar a  construir esses labirintos. -}



-- | Gera um labirinto aleatório sem quaisquer restrições associadas
--
genMaze :: Int -> Int -> Int -> Maze
genMaze x y s =
                 let random_nrs = genRandom (x*y) s
                 in convertMaze $ subList x random_nrs

-- | Cria um Corridor composto por n Walls 
--
createWall :: Int -> Corridor
createWall 0 = []
createWall n = Wall : createWall (n-1)

-- | Gera um labirinto com os limites superiores e inferiores (corredores de paredes) com a ajuda das funções createWall e genMaze
-- 
genUpDownExtremes :: Int -> Int -> Int -> Maze
genUpDownExtremes x y s = (createWall x):(genMaze x (y-2) s) ++ [createWall x]

-- | Troca uma certa Piece por outra Piece num certo Corridor de acordo com o índice "n" dado
--
replaceInList :: Int -> Piece -> Corridor -> Corridor
replaceInList n p [] = [] 
replaceInList 0 p (x:xs) = p:xs
replaceInList n p (x:xs) = x:(replaceInList (n-1) p xs)

-- | Troca a primeira e a última Piece de uma certa lista por uma Wall com a ajuda da função replaceInList
--
replaceFirstLastWall :: Maze -> Maze 
replaceFirstLastWall [] = []
replaceFirstLastWall (x:xs) = replaceInList ((length x) - 1) Wall (replaceInList 0 Wall x) : replaceFirstLastWall xs

-- | Gera um labirinto com todos os limites/extremos (rodeado por Wall) aplicando a função replaceFirstLastWall ao labirinto gerado pela função genUpDownExtremes
--
genAllExtremes :: Int -> Int -> Int -> Maze
genAllExtremes x y s = replaceFirstLastWall (genUpDownExtremes x y s)


-- | Devolve os corredores do meio de um labirinto, tendo em conta que se o labirinto tiver número de corredores par então o meio vai corresponder a dois corredores e se tiver número de corredores ímpar vai corresponder a apenas um corredor.
-- 
getMiddle :: Maze -> Maze
getMiddle [] = []
getMiddle x
    | even (length x) = [x !! ((div (length x) 2)-1), x !! (div (length x) 2)]
    | otherwise = [x !!  (div (length x) 2)]
    
-- | Devolve os pares de corredores que não são os que corredores do meio (corredores antes do meio, corredores depois do meio)
--
getNotMiddle :: Maze -> (Maze, Maze) 
getNotMiddle [] = ([], [])
getNotMiddle x
    | even (length x) = (take (((length x) `div` 2)-1) x, drop (((length x) `div` 2)+1) x)
    | otherwise = (take ((length x) `div` 2) x, drop (((length x) `div` 2)+1) x)

-- | Substitui as primeiras e últimas peças dos corredores (ou corredor) do meio
--
replaceFirstLastEmpty :: Maze -> Maze
replaceFirstLastEmpty x
    | even (length x) = replaceInList ((length ((getMiddle x) !! 0)) - 1) Empty (replaceInList 0 Empty ((getMiddle x) !! 0)): [replaceInList ((length ((getMiddle x) !! 1)) - 1) Empty (replaceInList 0 Empty ((getMiddle x) !! 1))]
    | otherwise = [replaceInList ((length ((getMiddle x) !! 0)) - 1) Empty (replaceInList 0 Empty ((getMiddle x) !! 0))]
      

-- | Gera um labirinto com os limites todos e os túneis incluídos a partir das funções getNotMiddle, replaceFirstLastEmpty e genAllExtremes e através da tática de junção mencionada acima
--
genTunnel :: Int -> Int -> Int -> Maze
genTunnel x y s = (fst (getNotMiddle (genAllExtremes x y s))) ++ (replaceFirstLastEmpty (genAllExtremes x y s)) ++ (snd (getNotMiddle (genAllExtremes x y s)))


-- | Cria a casa dos fantasmas de acordo com se o comprimento do labirinto é par ou ímpar (se for par a casa tem comprimento 8, se for ímpar tem comprimento 9)
--
createGhostHouse :: Int -> Maze -- ^ (adicionamos Empty antes e depois de cada corredor da casa dos fantasmas, visto que posteriormente a casa dos fantasmas tem de estar rodeada por Empty)
createGhostHouse x 
    | even x = [
            [Empty, Wall, Wall, Wall, Empty, Empty, Wall, Wall, Wall, Empty],
            [Empty, Wall, Empty, Empty, Empty, Empty, Empty, Empty, Wall, Empty],
            [Empty, Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall, Empty]
                ]

    | otherwise = [
            [Empty, Wall, Wall, Wall, Empty, Empty, Empty, Wall, Wall, Wall, Empty],
            [Empty, Wall, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Wall, Empty],
            [Empty, Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall, Empty]
                  ]
-- | Coloca um corredor dentro de outro corredor a partir do índice n que recebe como argumento
--
replaceCorridor :: Int -> Corridor -> Corridor -> Corridor
replaceCorridor n [] c2 = c2
replaceCorridor 0 (x:xs) (y:ys) = x:replaceCorridor 0 xs ys
replaceCorridor n (x:xs) (y:ys) = y:replaceCorridor (n-1) (x:xs) ys

-- | Devolve os corredores nos quais não vai ser substituído a casa fantasmas (corredores antes da casa fantasma, corredores depois da casa fantasma)
--
getNotGhostHouse :: Maze -> (Maze, Maze) 
getNotGhostHouse [] = ([], [])
getNotGhostHouse x
    | even (length x) = (take (((length x) `div` 2)-2) x, drop (((length x) `div` 2)+1) x)
    | otherwise = (take (((length x) `div` 2)-1) x, drop (((length x) `div` 2)+2) x)   

-- | Devolve os corredores do meio que vão ser substítuidos pelos corredores com a casa fantasmas
--
getMiddleGhostHouse :: Maze -> Maze
getMiddleGhostHouse [] = []
getMiddleGhostHouse x
    | even (length x) = [x !! ((div (length x) 2)-2),x !! ((div (length x) 2)-1), x !! (div (length x) 2)]
    | otherwise = [x !! ((div (length x) 2)-1),x !! (div (length x) 2),x !! ((div (length x) 2)+1)]

-- | Gera um labirinto com todos os limites, com os túneis, e com a casa fantasmas colocada no centro (falta rodear a casa por Empty)
--
genGhostHouse :: Int -> Int -> Int -> Maze
genGhostHouse x y s =  (fst (getNotGhostHouse (genTunnel x y s)))
                    ++ [(replaceCorridor n ((createGhostHouse x) !! 0) ((getMiddleGhostHouse (genTunnel x y s)) !! 0))]
                    ++ [(replaceCorridor n ((createGhostHouse x) !! 1) ((getMiddleGhostHouse (genTunnel x y s)) !! 1))]
                    ++ [(replaceCorridor n ((createGhostHouse x) !! 2) ((getMiddleGhostHouse (genTunnel x y s)) !! 2))]
                    ++ (snd (getNotGhostHouse (genTunnel x y s)))
            where n = (div x 2)-5 


-- | Devolve os corredores nos quais não vai ser substituído a casa fantasmas e os Empty que a rodeiam
--
getNotGhostHouseEmptys :: Maze -> (Maze, Maze) 
getNotGhostHouseEmptys [] = ([], [])
getNotGhostHouseEmptys x
    | even (length x) = (take (((length x) `div` 2)-3) x, drop (((length x) `div` 2)+2) x)
    | otherwise = (take (((length x) `div` 2)-2) x, drop (((length x) `div` 2)+3) x)  

-- | Devolve os corredores cujos primeiro e último têm de ser substituídos por Empty à volta da casa fantasmas
--
getMiddleGhostHouseEmptys :: Maze -> Maze
getMiddleGhostHouseEmptys [] = []
getMiddleGhostHouseEmptys x
    | even (length x) = [x !! ((div (length x) 2)-3),x !! ((div (length x) 2)-2),x !! ((div (length x) 2)-1), x !! (div (length x) 2),x !! ((div (length x) 2)+1)]
    | otherwise = [x !! ((div (length x) 2)-2),x !! ((div (length x) 2)-1),x !! (div (length x) 2),x !! ((div (length x) 2)+1),x !! ((div (length x) 2)+2)]
 
-- | Cria um corredor de vazio (Empty) para colocar em cima e em baixo da casa fantasmas de acordo com se o comprimento do labirinto é par ou ímpar
--
createEmptys :: Int -> Corridor
createEmptys x 
    | even x = [Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty]
    | otherwise = [Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty]

-- | Gera um labirinto válido
--
generateMaze :: Int -> Int -> Int -> Maze
generateMaze x y s = if x>=15 && y>=10 then (fst (getNotGhostHouseEmptys (genTunnel x y s)))
                    ++ [(replaceCorridor n (createEmptys x) ((getMiddleGhostHouseEmptys (genTunnel x y s)) !! 0))]
                    ++ [(replaceCorridor n ((createGhostHouse x) !! 0) ((getMiddleGhostHouse (genTunnel x y s)) !! 0))]
                    ++ [(replaceCorridor n ((createGhostHouse x) !! 1) ((getMiddleGhostHouse (genTunnel x y s)) !! 1))]
                    ++ [(replaceCorridor n ((createGhostHouse x) !! 2) ((getMiddleGhostHouse (genTunnel x y s)) !! 2))]
                    ++ [(replaceCorridor n (createEmptys x) ((getMiddleGhostHouseEmptys (genTunnel x y s)) !! 4))] 
                    ++ (snd (getNotGhostHouseEmptys (genTunnel x y s)))
                    else []
            where n = (div x 2)-5 


-- | Gera um labirinto válido em forma de string
--
placeGenerateMaze :: Int -> Int -> Int -> IO()
placeGenerateMaze x y s = placeMaze (generateMaze x y s)

    

-- | Testa se um labirinto tem a altura que foi dada
--
testMazeHeight :: Int -> Int -> Int -> Bool
testMazeHeight x y s 
    | (length (generateMaze x y s)) == y = True
    | otherwise = False

-- | Testa se todos os corredores do labirinto têm o comprimento dado
--
testCorridorsLength :: Maze -> Int -> Bool
testCorridorsLength [] x = True
testCorridorsLength (c:cs) x = (length c) == x && testCorridorsLength cs x

-- | Testa se um corredor tem como primeiro e último elemento uma parede
--
testCorridorWall :: Corridor -> Bool
testCorridorWall (x:xs) = x == Wall && (last (x:xs)) == Wall

-- | Testa se todos os corredores de um labirinto têm como primeiro e último elemento uma parede
--
testReplaceFirstLastWall :: Maze -> Bool
testReplaceFirstLastWall [] = True
testReplaceFirstLastWall (c:cs) = testCorridorWall c && testReplaceFirstLastWall cs

-- | Testa se um corredor tem como primeiro e último elemento um vazio 
--
testCorridorEmpty :: Corridor -> Bool
testCorridorEmpty (x:xs) = x == Empty && (last (x:xs)) == Empty

-- | Testa a colocação do(s) túnel/túneis conforme os labirintos são pares ou ímpares
--
testTunnelPlacement :: Maze -> Bool
testTunnelPlacement m
    | even (length m) = (testCorridorEmpty (m !! (div (length m) 2))) && (testCorridorEmpty (m !! ((div (length m) 2)-1)))
    | otherwise = testCorridorEmpty (m !! (div (length m) 2))



data Manager = Manager 
    {   
        state   :: State
    ,    pid    :: Int
    ,    step   :: Int
    ,    before :: Integer
    ,    delta  :: Integer
    ,    delay  :: Integer
    } 


loadManager :: Manager
loadManager = ( Manager (loadMaze "maps/1.txt") 0 0 0 0 defaultDelayTime )

rotatePlayerWithID :: Key -> [Player] -> Int -> [Player]
rotatePlayerWithID KeyUpArrow (j:js) id = if getPlayerID j == id then (changePlayerOrientation U j):js else j:(rotatePlayerWithID KeyUpArrow js id)
rotatePlayerWithID KeyDownArrow (j:js) id = if getPlayerID j == id then (changePlayerOrientation D j):js else j:(rotatePlayerWithID KeyDownArrow js id)
rotatePlayerWithID KeyLeftArrow (j:js) id = if getPlayerID j == id then (changePlayerOrientation L j):js else j:(rotatePlayerWithID KeyLeftArrow js id)
rotatePlayerWithID KeyRightArrow (j:js) id = if getPlayerID j == id then (changePlayerOrientation R j):js else j:(rotatePlayerWithID KeyRightArrow js id)

updateControlledPlayer :: Key -> Manager -> Manager
updateControlledPlayer KeyUpArrow (Manager (State m (j:js) lvl) pid step bf delt del) = Manager (State m (rotatePlayerWithID KeyUpArrow (j:js) pid) lvl) pid step bf delt del
updateControlledPlayer KeyDownArrow (Manager (State m (j:js) lvl) pid step bf delt del) = Manager (State m (rotatePlayerWithID KeyDownArrow (j:js) pid) lvl) pid step bf delt del
updateControlledPlayer KeyLeftArrow (Manager (State m (j:js) lvl) pid step bf delt del) = Manager (State m (rotatePlayerWithID KeyLeftArrow (j:js) pid) lvl) pid step bf delt del
updateControlledPlayer KeyRightArrow (Manager (State m (j:js) lvl) pid step bf delt del) = Manager (State m (rotatePlayerWithID KeyRightArrow (j:js) pid) lvl) pid step bf delt del

updateTimeMega :: [Player] -> [Player]
updateTimeMega [] = []
updateTimeMega ((Pacman (PacState (id, (x,y), v, ort, p, l) t o m)):xs) = (Pacman (PacState (id, (x,y), v, ort, p, l) (t-250) o m)):xs
updateTimeMega (x:xs) = x:updateTimeMega xs

updateScreen :: Window  -> ColorID -> Manager -> Curses ()
updateScreen w a man =
                  do
                    updateWindow w $ do
                      clear
                      setColor a
                      moveCursor 0 0 
                      drawString $ show (state man)
                    render
     
currentTime :: IO Integer
currentTime = fmap ( round . (* 1000) ) getPOSIXTime

updateTime :: Integer -> Manager -> Manager 
updateTime now man = man {delta = (now - before man)}

resetTimer :: Integer -> Manager -> Manager 
resetTimer now man = man {delta = 0, before = now}

nextFrame :: Integer -> Manager -> Manager 
nextFrame now man@(Manager (State maze pls lvl) pid s b d e) = Manager (passTime s (State maze (updateTimeMega pls) lvl)) pid (s+1) now 0 e

loop :: Window -> Manager -> Curses ()
loop w man@(Manager s pid step bf delt del ) = do 
  color_schema <- newColorID ColorWhite ColorDefault  10
  now <- liftIO  currentTime
  updateScreen w  color_schema man
  if ( delt > del )
    then loop w $ nextFrame now man
    else do
          ev <- getEvent w $ Just 0
          case ev of
                Nothing -> loop w (updateTime now man)
                Just (EventSpecialKey arrow ) -> loop w $ updateControlledPlayer arrow (updateTime now man)
                Just ev' ->
                  if (ev' == EventCharacter 'q')
                    then return ()
                    else loop w (updateTime now man)

main :: IO ()
main =
  runCurses $ do
    setEcho False
    setCursorMode CursorInvisible
    w <- defaultWindow
    loop w loadManager




loadMaze :: String -> State
loadMaze filepath = unsafePerformIO $ readStateFromFile filepath



readStateFromFile :: String -> IO State
readStateFromFile f = do
                content <- readFile f
                let llines = lines content 
                    (new_map,pl) = convertLinesToPiece llines 0 []
                return (State new_map pl 1)



convertLinesToPiece :: [String] -> Int -> [Player] -> (Maze,[Player])
convertLinesToPiece [] _ l = ([],l)
convertLinesToPiece (x:xs) n l  = let (a,b) = convertLineToPiece x n 0 l 
                                      (a1,b1) = convertLinesToPiece xs (n+1) b
                                  in (a:a1,b1)

convertLineToPiece :: String -> Int -> Int -> [Player] -> ([Piece],[Player])
convertLineToPiece [] _ _ l = ([],l)
convertLineToPiece (z:zs) x y l = let (a,b ) = charToPiece z x y l
                                      (a1,b1) = convertLineToPiece zs x (y+1) b 
                                  in (a:a1,b1)


charToPiece :: Char -> Int -> Int -> [Player] -> (Piece,[Player])
charToPiece c x y l
    | c == '{' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Normal ))   :l) )
    | c == '<' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Closed Normal )) :l) )
    | c == '}' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Open Normal ))   :l) )
    | c == '>' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Closed Normal )) :l) )
    | c == 'V' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Open Normal ))   :l) )
    | c == 'v' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Closed Normal )) :l) )
    | c == '^' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Open Normal ))   :l) )
    | c == '|' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Closed Normal )) :l) )
    | c == 'X' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Dying ))    :l) )
    | c == 'M' =  (Empty, ((Ghost (  GhoState (length l,(x,y),1,R,0,1 ) Alive))            :l) )
    | c == '?' =  (Empty, ((Ghost (  GhoState (length l,(x,y),1,R,0,1 ) Dead))             :l) )
    | c == 'o' =  (Food Big,l)
    | c == '.' =  (Food Little,l)
    | c == '#' =  (Wall,l)
    | otherwise = (Empty,l)

getMaze :: State -> Maze
getMaze (State m ps l) = m


data State = State
    {
        maze :: Maze
    ,   playersState :: [Player]
    ,   level :: Int
    }

type Maze = [Corridor]
type Corridor = [Piece]
data Piece =  Food FoodType | PacPlayer Player| Empty | Wall deriving (Eq)
data Player =  Pacman PacState | Ghost GhoState deriving (Eq)

data Orientation = L | R | U | D | Null deriving (Eq,Show)
data PacState= PacState
    {
        pacState :: PlayerState
    ,   timeMega :: Double
    ,   openClosed :: Mouth
    ,   pacmanMode :: PacMode

    } deriving Eq

data GhoState= GhoState
    {
        ghostState :: PlayerState
    ,   ghostMode :: GhostMode
    } deriving Eq

type Coords = (Int,Int)
type PlayerState = (Int, Coords, Double , Orientation, Int, Int)
--                 (ID,  (x,y), velocity, orientation, points, lives)
data Mouth = Open | Closed deriving (Eq,Show)
data PacMode = Dying | Mega | Normal deriving (Eq,Show)
data GhostMode = Dead  | Alive deriving (Eq,Show)
data FoodType = Big | Little deriving (Eq)
data Color = Blue | Green | Purple | Red | Yellow | None deriving Eq

data Play = Move Int Orientation deriving (Eq,Show)

type Instructions = [Instruction]

data Instruction = Instruct [(Int, Piece)]
                 | Repeat Int deriving (Show, Eq)



instance Show State where
  show (State m ps p) = printMaze mz ++ "Level: " ++ show p ++ "\nPlayers: \n" ++ (foldr (++) "\n" (map (\y-> printPlayerStats y) ps))
                          where mz = placePlayersOnMap ps m

instance Show PacState where
   show ( PacState s o m Dying  ) =  "X"
   show ( PacState (a,b,c,R,i,l) _ Open m  ) =  "{"
   show ( PacState (a,b,c,R,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,L,i,l) _ Open m  ) =  "}"
   show ( PacState (a,b,c,L,i,l) _ Closed m  ) =  ">"
   show ( PacState (a,b,c,U,i,l) _ Open m  ) =  "V"
   show ( PacState (a,b,c,U,i,l) _ Closed m  ) =  "v"
   show ( PacState (a,b,c,D,i,l) _ Open m  ) =  "^"
   show ( PacState (a,b,c,D,i,l) _ Closed m  ) =  "|"
   show ( PacState (a,b,c,Null,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,Null,i,l) _ Open m  ) =  "{"

instance Show Player where
   show (Pacman x ) =  show x
   show ( Ghost x ) =   show x

instance Show GhoState where
   show (GhoState x Dead ) =  "?"
   show (GhoState x Alive ) =  "M"

instance Show FoodType where
   show ( Big ) =  "o"
   show ( Little ) =  "."

instance Show Piece where
   show (  Wall ) = coloredString "#" None
   show (  Empty ) = coloredString " " None
   show (  Food z ) = coloredString (show z )   Green
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Normal ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Normal)  ) Yellow
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Mega   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Mega)  ) Blue
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Dying   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Dying)  ) Red
   show ( PacPlayer (Ghost z) ) = coloredString (show z)  Purple


coloredString :: String -> Color -> String
coloredString x y = x
--    | y == Blue ="\x1b[36m" ++  x ++ "\x1b[0m"
--    | y == Red = "\x1b[31m" ++ x ++ "\x1b[0m"
--    | y == Green = "\x1b[32m" ++ x ++ "\x1b[0m"
--    | y == Purple ="\x1b[35m" ++ x ++ "\x1b[0m"
--    | y == Yellow ="\x1b[33m" ++ x ++ "\x1b[0m"
--    | otherwise =  "\x1b[0m" ++ x


placePlayersOnMap :: [Player] -> Maze -> Maze
placePlayersOnMap [] x = x
placePlayersOnMap (x:xs) m = placePlayersOnMap xs ( replaceElemInMaze (getPlayerCoords x) (PacPlayer x) m )


printMaze :: Maze -> String
printMaze []  =  ""
printMaze (x:xs) = foldr (++) "" ( map (\y -> show y) x )  ++ "\n" ++ printMaze ( xs )

printPlayerStats :: Player -> String
printPlayerStats p = let (a,b,c,d,e,l) = getPlayerState p
                     in "ID:" ++ show a ++  " Points:" ++ show e ++ " Lives:" ++ show l ++"\n"

getPlayerID :: Player -> Int
getPlayerID (Pacman (PacState (x,y,z,t,h,l) q c d )) = x
getPlayerID  (Ghost (GhoState (x,y,z,t,h,l) q )) = x

getPlayerPoints :: Player -> Int
getPlayerPoints (Pacman (PacState (x,y,z,t,h,l) q c d )) = h
getPlayerPoints (Ghost (GhoState (x,y,z,t,h,l) q )) = h

setPlayerCoords :: Player -> Coords -> Player
setPlayerCoords (Pacman (PacState (x,y,z,t,h,l) q c d )) (a,b) = Pacman (PacState (x,(a,b),z,t,h,l) q c d )
setPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) q )) (a,b) = Ghost (GhoState (x,(a,b),z,t,h,l) q )


getPieceOrientation :: Piece -> Orientation
getPieceOrientation (PacPlayer p) =  getPlayerOrientation p
getPieceOrientation _ = Null

getPacmanMode :: Player -> PacMode
getPacmanMode (Pacman (PacState a b c d)) = d

getPlayerState :: Player -> PlayerState
getPlayerState (Pacman (PacState a b c d )) = a
getPlayerState (Ghost (GhoState a b )) = a

getPlayerOrientation :: Player -> Orientation
getPlayerOrientation (Pacman (PacState (x,y,z,t,h,l) q c d )) = t
getPlayerOrientation  (Ghost (GhoState (x,y,z,t,h,l) q )) = t

replaceElemInMaze :: Coords -> Piece -> Maze -> Maze
replaceElemInMaze (a,b) _ [] = []
replaceElemInMaze (a,b) p (x:xs)
  | a == 0 = replaceNElem b p x : xs
  | otherwise = x : replaceElemInMaze (a-1,b) p xs


replaceNElem :: Int -> a -> [a] -> [a]
replaceNElem i _ [] = []
replaceNElem i el (x:xs)
  |  i == 0 = el : xs
  | otherwise =  x : replaceNElem (i-1) el xs

getPlayerCoords :: Player -> Coords
getPlayerCoords (Pacman (PacState (x,y,z,t,h,l) b c d )) = y
getPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) b )) = y
{- |
=Introdução

Nesta Tarefa foi desenvolvido um Bot que assume a posicão de jogador. Assim sendo, o Bot tem de ser programado em forma de vencer o jogo.
Para isso adotamos uma estratégia que consistia na distância do jogador às peças do labirinto, e aos outros jogadores.

=Objetivos

O Objetivo desta Tarefa será, então, obter um Bot funcional.
A estratégia que implantamos recorre à utilização da função "distance :: Coords -> Coords -> Float".
Esta estratégia é muito identica à estratégia utilizada na Tarefa anterior (Tarefa 5 - Movimento dos Fantasmas).

Para a resolução desta tarefa ser o mais organizada possível temos de ter em consideração que o PacMan tem 2 (principais) modos.

-__Modo Mega__;
-__Modo Normal__.

Assim sendo, o desenvolvimento de um Bot nestas condições tem de ser dividido em duas partes distintas.
Quando o PacMan se encontra em estado Mega, e quando se encontra em estado Normal.

==Desenvolvimento da Função principal "bot :: Int -> State -> Maybe Play"

Como foi exposto em cima o Bot vai se movimentar consuante o modo do seu jogador (PacMan).
Portanto, a função principal vai estar também dividida em mais duas funções (do mesmo tipo da função principal).

-__Função botMega__;

-__Função botNormal__.

Mas como é que fariamos o Bot decidir qual das funções escolher?
Para isso criamos uma função __megaOrNormal__ que recebe uma lista de Jogadores e se existir algum Pacman em modo "Mega" devolve o Bool "True", caso contrário devolve o Bool __False__
Então se a função __megaOrNormal__ for _True_, a função __bot__ ativava a função auxiliar botMega. Por outro lado se a função __megaOrNormal__ devolver o Bool __False__ a função __botNormal__ é ativada.
Assim nasce a função bot,

bot :: Int -> State -> Maybe Play

bot x (State m pl lv)

| megaOrNormal pl = botMega x (State m pl lv)

| otherwise = botNormal x (State m pl lv)


==Funções "botMega" e "botNormal"

As duas funções vão, obrigatóriamente, ter diferentes prioridades. Enquanto o PacMan no modo Normal perde vidas se este bater contra um dos fantasmas, o PacMan no modo Mega ganha pontos e mata os fantasmas.
Por isso as funções estão feitas de maneiras diferentes.


===Função "botNormal"

Nós consideramos que o PacMan no modo Normal devia (por ordem de prioridade):

-__Fugir dos Fantasmas__ (Função escape);
-__Comer Food Bigs__     (Função goFoodBig).
-__Comer Food Littles__  (Função goFoodLittle);

===Função "botMega"

Nós consideramos que o PacMan no modo Normal devia (por ordem de prioridade):

-__Caçar os Fantasmas__ (Função hunt);
-__Comer Food Littles__  (Função goFoodLittle);
-__Comer Food Bigs__     (Função goFoodBig).

==Funcionamento das funções

Primeiramente temos de relembrar que a estratégia utilizada vai recorrer à função __distance__ que calcula a distância de uma coordenada a outra coordenada (ambas do labirinto).
A função __distance__ vai servir de indicador para o bot saber a distância que se encontra de certos elementos.

==Funções "escape" e "hunt"

As duas funções referentes ao comportamento do Pacman face ao aproximar de um Ghost são as "escape" e "hunt"
Caso o Pacman esteja em modo __Normal__ a função __escape__ é a função que vai ser ativada.

=== "escape"

A função __escape__ vai ser ativada quando o um Ghost no modo __Alive__ entra num raio de 3 unidades do Pacman.
Para isto acontecer, a função __detectGhost__ foi criada.

detectGhost :: State -> Bool

detectGhost (State m pl lv) = (distance (head (sortOn (distance (getPacCoords pl)) (coordGhosts pl))) (getPacCoords pl)) <= 3

Quando a função __detectGhost__ retornar um __True__, então a fução __escape__ vai ser ativada.

Mas como é que a função "escape" foi pensada?
Tal como na tarefa 5, __todas__ estas funções foram desenvolvidas para retornar uma lista de __Orientações__, que depois vão ser processadas para devolver a orientação mais favorável ao Pacman.

Para determinar esta [Orientation], temos de ver os vários possiveis cenários em que o Pacman se encontra, pois cada posição tem uma maneira diferente de reagir.
Assim sendo, foi criada a função __outcome__.

outcome :: State -> Int

outcome (State m pl lv) = aux (head (sortOn (distance (getPacCoords pl)) (coordGhosts pl))) (getPacCoords pl)

    where

      aux :: Coords -> Coords -> Int

      aux (x,y) (x1,y1) | x > x1  && y > y1  = 1 -- (Fantasma em baixo e à direita do Pacman)

                        | x < x1  && y < y1  = 2 -- (Fantasma em cima e à esquerda do Pacman)

                        | x == x1 && y < y1  = 3 -- (Fantasma à esquerda do Pacman)

                        | x == x1 && y > y1  = 4 -- (Fantasma à direita do Pacman)

                        | x < x1  && y == y1 = 5 -- (Fantasma em cima do Pacman)

                        | x > x1  && y == y1 = 6 -- (Fantasma em baixo do Pacman)

                        | x > x1  && y < y1  = 7 -- (Fantasma em baixo e à esquerda do Pacman)

                        | x < x1  && y > y1  = 8 -- (Fantasma em cima e à direita do Pacman)

Na função __outcome__ definimos 8 diferentes situações em que o Pacman se poderia encontrar. No entanto, sentimos que o Pacman se deveria comportar de diferentes maneiras
tendo em conta se este está na parte superior, ou inferior do labirinto.
Assim, inspirados pela função __upOrDown__ criamos a função exatamente igual __upOrDown1__.

upOrDown1 :: State -> Bool

upOrDown1 (State m (pl:pls) l)

| fst (getPacCoords (pl:pls)) > (div (length (m)) 2) = False

| otherwise = True/

Por fim, com as 16 diferentes diferentes situações, podemos definir a função __escape__

escape :: State -> [Orientation]

escape (State m pl lv)

| upOrDown1 (State m pl lv) && outcome (State m pl lv) == 1 = [L,U,D,R]

| upOrDown1 (State m pl lv) && outcome (State m pl lv) == 2 = [D,R,L,U]

| upOrDown1 (State m pl lv) && outcome (State m pl lv) == 3 = [R,D,U,L]

| upOrDown1 (State m pl lv) && outcome (State m pl lv) == 4 = [L,D,U,R]

| upOrDown1 (State m pl lv) && outcome (State m pl lv) == 5 = [D,L,R,U]

| upOrDown1 (State m pl lv) && outcome (State m pl lv) == 6 = [U,L,R,D]

| upOrDown1 (State m pl lv) && outcome (State m pl lv) == 7 = [R,U,L,D]

| upOrDown1 (State m pl lv) && outcome (State m pl lv) == 8 = [D,L,R,U]

| outcome (State m pl lv) == 1 = [U,L,R,D]

| outcome (State m pl lv) == 2 = [R,D,L,U]

| outcome (State m pl lv) == 3 = [R,U,D,L]

| outcome (State m pl lv) == 4 = [L,U,D,R]

| outcome (State m pl lv) == 5 = [D,L,R,U]

| outcome (State m pl lv) == 6 = [U,L,R,D]

| outcome (State m pl lv) == 7 = [U,R,L,D]

| outcome (State m pl lv) == 8 = [L,R,D,U]

=== "hunt"

A função __hunt__ é estruturada exatamente da mesma maneia que a __escape__, apenas com um promenor, em vez de o Pacman fugir dos fantasmas, o Pacman caça os fantasmas.
Tirando as funçoẽs __detectGhost__ e __detectGhostMega__ todas as restantes funções são exatamente as mesmas __mas com listas de orientações diferentes__.
Qual a diferença entre as funçẽs de deteção dos __Ghosts__?
A __detectGhostMega__ em vez de retornar "True" quando um fantasma está num raio de 3 unidades do Pacman, retorna __True__ quando o fantasma está num raio de __5 unidades__.

A função hunt e definida então pelas funções __outcome__ e __upOrDown1__

hunt :: State -> [Orientation]

hunt (State m pl lv)

 | upOrDown1 (State m pl lv) && outcome (State m pl lv) == 1 = [D,R,L,U]

                       | upOrDown1 (State m pl lv) && outcome (State m pl lv) == 2 = [U,L,R,D]

                       | upOrDown1 (State m pl lv) && outcome (State m pl lv) == 3 = [L,U,D,R]

                       | upOrDown1 (State m pl lv) && outcome (State m pl lv) == 4 = [R,U,D,L]

                       | upOrDown1 (State m pl lv) && outcome (State m pl lv) == 5 = [U,R,L,D]

                       | upOrDown1 (State m pl lv) && outcome (State m pl lv) == 6 = [D,R,L,U]

                       | upOrDown1 (State m pl lv) && outcome (State m pl lv) == 7 = [D,L,R,U]

                       | upOrDown1 (State m pl lv) && outcome (State m pl lv) == 8 = [R,U,D,L]

                       | outcome (State m pl lv) == 1 = [D,R,L,U]

                       | outcome (State m pl lv) == 2 = [U,L,R,D]

                       | outcome (State m pl lv) == 3 = [L,D,U,R]

                       | outcome (State m pl lv) == 4 = [R,D,U,L]

                       | outcome (State m pl lv) == 5 = [U,R,L,D]

                       | outcome (State m pl lv) == 6 = [D,R,L,U]

                       | outcome (State m pl lv) == 7 = [L,D,U,R]

                       | outcome (State m pl lv) == 8 = [U,R,L,D]

== Funções "goFoodBig" e "goFoodLittle"

=== "goFoodBig"

Chegamos agora as funções que são escolhidas pelo Bot caso este não se sinta ameaçado por um Ghost ou não esteja a ser perseguido.

Como é que o Bot decide qual das funções deve escolher?
A nossa ideia foi pensar no que seria mais benéfico para o Bot. Chegamos a conclusão então que o Pacman apenas deveria perseguir as comidas grandes quando fosse plausível, isto é,
definimos então que o Bot apenas devia ativar a função __goFoodBig__ se houvesse alguma Comida Grande num raio de 5 unidades do Pacman.
Para definir isto precisamos então de um __localizador__ das __comidas grandes__ de um labirinto.

Assim nasceu a função __coordsBig__.

coordsBig :: Maze -> [Coords]

coordsBig m = aux (0,0) m

      where

        aux :: Coords -> Maze -> [Coords]

        aux (a,b) [] = []

        aux (a,b) (x:xs) = aux1 (a,b) x ++ aux (a+1,b) (xs)

        aux1 :: Coords -> Corridor -> [Coords]

        aux1 (a,b) [] = []

        aux1 (a,b) (x:xs) | x == (Food Big) = (a,b) : aux1 (a,b+1) xs

                          | otherwise = aux1 (a,b+1) xs

Com a função __coordsBig__ podemos então ordenar as mesmas em função da distância das mesmas até ao Pacman, usando assim a função __sortOn__ da biblioteca __Data.List__.

Assim nasceu a função __ordCoordsBig__.

ordCoordsBig :: State -> [Coords]

ordCoordsBig (State m pl lv) = sortOn (distance (getPacCoords pl)) (coordsBig m)


Com isto podemos começar a pensar nas possiveis situações em que o Pacman se encontra em relação as Comidas Grandes, com a função __outcomeFoodBig__.

outcomeFoodBig :: State -> Int

outcomeFoodBig (State m pl lv) = aux (head (ordCoordsBig (State m pl lv))) (getPacCoords pl)

 where

   aux :: Coords -> Coords -> Int

   aux (x,y) (x1,y1)  | x < x1 = 1 -- (Comida Big em cima do pacman)

                      | x > x1 = 2 -- (Comida Big em baixo do pacman)

                      | y < y1 = 3 -- (Comida Big a esquerda do pacman)

                      | y > y1 = 4 -- (Comida Big a direita do pacman)

Tendo então a variedade de situações podemos criar a função __goFoodBig__ que nos retorna a __lista de orientações__ que precisamos.

goFoodBig :: State -> [Orientation]

goFoodBig (State m pl lv) | outcomeFoodBig (State m pl lv) == 1 = [U,R,L,D]

                          | outcomeFoodBig (State m pl lv) == 2 = [D,R,L,U]

                          | outcomeFoodBig (State m pl lv) == 3 = [L,U,D,R]

                          | outcomeFoodBig (State m pl lv) == 4 = [R,U,D,L]

== "goFoodLittle"

Exatamente o __mesmo__ que acontece com a Comida grande, acontece agora com a __Comida Pequena__, exceto no raio da distância, agora esse raio é de 100000.

detectLittle :: State -> Bool

detectLittle (State m pl lv) = (distance (head (ordCoordsLittle (State m pl lv))) (getPacCoords pl)) <= 100000

Assim com a função __outcomeLittle__,

outcomeLittle :: State -> Int

outcomeLittle (State m pl lv) = aux (head (ordCoordsLittle (State m pl lv))) (getPacCoords pl)

  where

    aux :: Coords -> Coords -> Int

    aux (x,y) (x1,y1) | x < x1 = 1 -- (Comida pequena em cima do pacman)

                      | x > x1 = 2 -- (Comida pequena em baixo do pacman)

                      | y < y1 = 3 -- (Comida pequena a esquerda do pacman)

                      | y > y1 = 4 -- (Comida pequena a direita do pacman)

criamos a função __goFoodLittle__.

goFoodLittle :: State -> [Orientation]

goFoodLittle (State m pl lv) | outcomeLittle (State m pl lv) == 1 = [U,R,L,D]

                             | outcomeLittle (State m pl lv) == 2 = [D,R,L,U]

                             | outcomeLittle (State m pl lv) == 3 = [L,U,D,R]

                             | outcomeLittle (State m pl lv) == 4 = [R,U,D,L]

=Função "bot"

Temos então tudo o necessário para criar as funções principais.

=="botMega"

botMega :: Int -> State -> Maybe Play

botMega x (State m pl lv) | detectGhostMega (State m pl lv)  = if getPacOrientation pl == (chooseOrientation (hunt (State m pl lv)) (notoList m (getPacCoords pl)))

                                                       then Nothing else Just (Move x (chooseOrientation (hunt (State m pl lv)) (notoList m (getPacCoords pl))))

                          | detectLittle (State m pl lv) = if getPacOrientation pl == (chooseOrientation (goFoodLittle (State m pl lv)) (notoList m (getPacCoords pl)))

                                                       then Nothing else Just (Move x (chooseOrientation (goFoodLittle (State m pl lv)) (notoList m (getPacCoords pl))))

                          | detectBig   (State m pl lv)  = if getPacOrientation pl == (chooseOrientation (goFoodBig (State m pl lv)) (notoList m (getPacCoords pl)))

                                                       then Nothing else Just (Move x (chooseOrientation (goFoodBig (State m pl lv)) (notoList m (getPacCoords pl))))

                          | otherwise = Nothing

=="botNormal"

botNormal :: Int -> State -> Maybe Play

botNormal x (State m pl lv) | detectGhost (State m pl lv)  = if getPacOrientation pl == (chooseOrientation (escape (State m pl lv)) (notoList m (getPacCoords pl)))

                                                       then Nothing else Just (Move x (chooseOrientation (escape (State m pl lv)) (notoList m (getPacCoords pl))))

                      | detectBig   (State m pl lv)  = if getPacOrientation pl == (chooseOrientation (goFoodBig (State m pl lv)) (notoList m (getPacCoords pl)))

                                                       then Nothing else Just (Move x (chooseOrientation (goFoodBig (State m pl lv)) (notoList m (getPacCoords pl))))

                      | detectLittle (State m pl lv) = if getPacOrientation pl == (chooseOrientation (goFoodLittle (State m pl lv)) (notoList m (getPacCoords pl)))

                                                       then Nothing else Just (Move x (chooseOrientation (goFoodLittle (State m pl lv)) (notoList m (getPacCoords pl))))

                      | otherwise = Nothing

Se reparmos, para estas funções serem aplicadas a função __bot__, precisam de retornar um __Maybe Play__.
Como fazemos isso?

Primeiramente precisamos de fazer com que as nossas orientações se transformem em plays.
Para isso recorremos as funções chooseOrientation e a notoList (explicadas nas outras tarefas)

Assim já é escolhida a orientação que mais vai favorecer o Pacman, e qual o Bot vai escolher.

Nasce assim a função final __bot__.

bot :: Int -> State -> Maybe Play

bot x (State m pl lv) | megaOrNormal pl = botMega x (State m pl lv)

                      | otherwise = botNormal x (State m pl lv)


=Discussão e conclusão

O Bot não foi adicionado ao ficheiro Main.hs, pois acreditamos que o ficheiro Main deve ser só utilizado para jogar o Pacman, e por isso, a Main só funciona se o jogador for um jogador real.

No fim de contas, o Bot não é o mais optimo, no entanto achamos que o pensamento é bastante sólido e o Bot é capaz de jogar PacMan sem problemas.
Mesmo com as dificuldades, ficamos felizes com o resultado final, já que conseguimos completar o desafio e usamos um pensamento bastante organizado.
-}





bot :: Int -> State -> Maybe Play
bot x (State m pl lv) | megaOrNormal pl = botMega x (State m pl lv)
                      | otherwise = botNormal x (State m pl lv)


botNormal :: Int -> State -> Maybe Play
botNormal x (State m pl lv) | detectGhost (State m pl lv)  = if getPacOrientation pl == (chooseOrientation (escape (State m pl lv)) (notoList m (getPacCoords pl)))
                                                       then Nothing else Just (Move x (chooseOrientation (escape (State m pl lv)) (notoList m (getPacCoords pl))))
                      | detectBig   (State m pl lv)  = if getPacOrientation pl == (chooseOrientation (goFoodBig (State m pl lv)) (notoList m (getPacCoords pl)))
                                                       then Nothing else Just (Move x (chooseOrientation (goFoodBig (State m pl lv)) (notoList m (getPacCoords pl))))
                      | detectLittle (State m pl lv) = if getPacOrientation pl == (chooseOrientation (goFoodLittle (State m pl lv)) (notoList m (getPacCoords pl)))
                                                       then Nothing else Just (Move x (chooseOrientation (goFoodLittle (State m pl lv)) (notoList m (getPacCoords pl))))
                      | otherwise = Nothing

botMega :: Int -> State -> Maybe Play
botMega x (State m pl lv) | detectGhostMega (State m pl lv)  = if getPacOrientation pl == (chooseOrientation (hunt (State m pl lv)) (notoList m (getPacCoords pl)))
                                                       then Nothing else Just (Move x (chooseOrientation (hunt (State m pl lv)) (notoList m (getPacCoords pl))))
                          | detectLittle (State m pl lv) = if getPacOrientation pl == (chooseOrientation (goFoodLittle (State m pl lv)) (notoList m (getPacCoords pl)))
                                                       then Nothing else Just (Move x (chooseOrientation (goFoodLittle (State m pl lv)) (notoList m (getPacCoords pl))))
                          | detectBig   (State m pl lv)  = if getPacOrientation pl == (chooseOrientation (goFoodBig (State m pl lv)) (notoList m (getPacCoords pl)))
                                                       then Nothing else Just (Move x (chooseOrientation (goFoodBig (State m pl lv)) (notoList m (getPacCoords pl))))
                          | otherwise = Nothing

megaOrNormal :: [Player] -> Bool
megaOrNormal (Pacman (PacState (i,(a,b),s,o,p,v) t m Mega):xs) = True
megaOrNormal (Pacman (PacState (i,(a,b),s,o,p,v) t m e):xs) = False
megaOrNormal (x:xs) = megaOrNormal (xs)

getPacOrientation :: [Player] -> Orientation
getPacOrientation (Pacman (PacState (i,(a,b),s,o,p,v) t m e):xs) = o
getPacOrientation (x:xs) = getPacOrientation (xs)

