-- | Grupo de funções que facilitaram os testes referentes a esta Tarefa
charToPiece :: Char -> Int -> Int -> [Player] -> (Piece,[Player])
charToPiece c x y l
    | c == '{' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Normal ))   :l) )
    | c == '<' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Closed Normal )) :l) )
    | c == '}' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Open Normal ))   :l) )
    | c == '>' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Closed Normal )) :l) )
    | c == 'V' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Open Normal ))   :l) )
    | c == 'v' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Closed Normal )) :l) )
    | c == '^' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Open Normal ))   :l) )
    | c == '|' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Closed Normal )) :l) )
    | c == 'X' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Dying ))    :l) )
    | c == 'M' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Alive))            :l) )
    | c == '?' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Dead))             :l) )
    | c == 'o' =  (Food Big,l)
    | c == '.' =  (Food Little,l)
    | c == '#' =  (Wall,l)
    | otherwise = (Empty,l)


-- | Função que mostra as coords do pacman
getPacCoords :: [Player] -> Coords
getPacCoords (Pacman (PacState (i,(a,b),s,o,p,v) t m e):xs) = (a,b)
getPacCoords (Ghost (GhoState (i,(x,y),ve,o,p,v) e):xs) = getPacCoords (xs)


-- | Função que mostra coords dos Players Ghosts

coordGhosts :: [Player] -> [Coords]
coordGhosts [] = []
coordGhosts (Ghost (GhoState (i,(x,y),ve,o,p,v) e):xs) = (x,y) : coordGhosts (xs)
coordGhosts (Pacman (PacState (i,(a,b),s,o,p,v) t m e):xs) = coordGhosts (xs)

-- | Função que mostra qual peça que está na posição indicada
whichPiece :: Coords -> Maze -> Piece
whichPiece (a,b) x = head (drop b (head(drop a x)))
-- | Função que verifica se uma certa peça é um Fantasma e informa isso através de um Booleano (True, False)
isGhost :: Piece -> Bool
isGhost  (PacPlayer (Ghost _)) = True
isGhost _ = False
-- | Função que quando invocada transforma todos os fantasmas vivos em fantasmas mortos
killGhost :: [Player] -> [Player]
killGhost [] =[]
killGhost ((Ghost (GhoState (i,(x,y),ve,o,p,v) Alive)):xs) = (rotate180 (Ghost (GhoState (i,(x,y),ve/2,o,p,v) Dead))): killGhost xs
killGhost (pl:pls) = pl : killGhost pls

rotate180 :: Player -> Player
rotate180 (Ghost (GhoState (i,(x,y),ve,D,p,v) e)) = (Ghost (GhoState (i,(x,y),ve,U,p,v) e))
rotate180 (Ghost (GhoState (i,(x,y),ve,U,p,v) e)) = (Ghost (GhoState (i,(x,y),ve,D,p,v) e))
rotate180 (Ghost (GhoState (i,(x,y),ve,L,p,v) e)) = (Ghost (GhoState (i,(x,y),ve,R,p,v) e))
rotate180 (Ghost (GhoState (i,(x,y),ve,R,p,v) e)) = (Ghost (GhoState (i,(x,y),ve,L,p,v) e))
rotate180 x = x

isPacMan :: Piece -> Bool
isPacMan (PacPlayer (Pacman _)) = True
isPacMan _                      = False

killPacman :: State -> State
killPacman (State maze (((Pacman (PacState (i,(a,b),s,o,p,v) t m e))):xs) l) = if v-1 == 0 then (State maze (((Pacman (PacState (i,(a,b),s,o,p,0) t m Dying))):xs) l) else (State maze (((Pacman (PacState (i,(a,b),s,o,p,v-1) t m e))):xs) l)
killPacman (State maze (p:pl) l) = addPlayer [p] (killPacman (State maze pl l))

resGhost :: [Player] -> [Player]
resGhost [] = []
resGhost ((Ghost (GhoState (i,(x,y),ve,o,p,v) Dead)):xs) = ((Ghost (GhoState (i,(x,y),ve*2,o,p,v) Alive)):xs)
resGhost (pl:pls) = pl : resGhost pls

-- | Função que adiciona uma lista de jogadores à cabeça da lista de Jogadores do State
addPlayer :: [Player] -> State -> State
addPlayer a (State m [] lv) = (State m a lv)
addPlayer [] (State m (x:xs) lv) = (State m (x:xs) lv)
addPlayer a (State m (x:xs) lv) = (State m (a ++ x:xs) lv)
-- | Função que mete uma lista de jogadores na parte final da lista de jogadores do "State"
addPlayerHead :: [Player] -> State -> State
addPlayerHead a (State m [] lv) = (State m a lv)
addPlayerHead [] (State m (x:xs) lv) = (State m (x:xs) lv)
addPlayerHead a (State m (x:xs) lv) = (State m (x:xs ++ a) lv)
-- | Função que mete o jogador com o mesmo Id da Jogada na cabeça da lista de jogadores do "State"
idEmHead ::Play -> State -> State
idEmHead (Move i a) (State m (p:t) lv) | i == getPlayerID p = (State m (p:t) lv)
                                       | i /= getPlayerID p = addPlayerHead [p] (State m (t) lv)
-- | Função que remove as peças por onde o Pacman passa
eatenFood :: Play -> State -> State
eatenFood m s = aux m s
  where
    aux :: Play -> State -> State
    aux (Move x _) (State maze ((Pacman (PacState (i,(a,b),s,o,p,v) t m e)):pl) lv)
      | x == i = (State (replaceElemInMaze (a,b) Empty maze) ((Pacman (PacState (i,(a,b),s,o,p,v) t m e)):pl) lv )
      | otherwise = addPlayer [(Pacman (PacState (i,(a,b),s,o,p,v) t m e))] (State maze pl lv )
-- | Função que adiciona os jogadores de um estado ao seu labirinto (Para estes serem considerados peças)
converte :: State -> State
converte (State maze (x:xs) l) = (State (placePlayersOnMap (tirajog (State maze (x:xs) l)) maze) [x] l)
-- | Função que retira a lista de Jogadores presente no "State"
tirajog :: State -> [Player]
tirajog (State maze ((Pacman (PacState (i,(a,b),s,o,p,v) t m e)):xs) l) = ((Pacman (PacState (i,(a,b),s,o,p,v) t m e)):xs)
tirajog (State maze ((Ghost (GhoState (i,(x,y),ve,o,p,v) Alive)):pls) l) = ((Ghost (GhoState (i,(x,y),ve,o,p,v) Alive)):pls)
tirajog (State maze ((Ghost (GhoState (i,(x,y),ve,o,p,v) Dead)):pls) l) = ((Ghost (GhoState (i,(x,y),ve,o,p,v) Dead)):pls)

-- | Função que adiciona um jogador a uma lista de jogadores (E passa a ser a Head da lista)
addPlayerList :: Player -> [Player] -> [Player]
addPlayerList p [] = [p]
addPlayerList p (x:xs) = (p:x:xs)
-- | Função usada para quando um fantasma em estado morto e comido, este ser levado para a casa dos fantasmas
ghostToHouse :: Play -> State -> State
ghostToHouse play (State maze [] lv) = (State maze [] lv)
ghostToHouse play (State maze [x] lv) = (State maze [x] lv)
ghostToHouse play (State maze ((Pacman (PacState (i1,y1,s1,o1,p1,v1) t1 m1 e1 )):(Ghost (GhoState (i2,y2,s2,o2,p2,v2) e2 )):pl) lv)
    | y2 == getCoordsFromId (getMoveId play) ((Pacman (PacState (i1,y1,s1,o1,p1,v1) t1 m1 e1 )):(Ghost (GhoState (i2,y2,s2,o2,p2,v2) e2 )):pl) =
      if even (length maze)
        then addPlayerHead [(setPlayerCoords (Ghost (GhoState (i2,y2,s2,o2,p2,v2) Alive )) ((div (length maze) 2)-1,(div (length (head maze)) 2)))] (State maze ((Pacman (PacState (i1,y1,s1,o1,p1,v1) t1 m1 e1 )):pl) lv)
        else addPlayerHead [(setPlayerCoords (Ghost (GhoState (i2,y2,s2,o2,p2,v2) Alive )) ((div (length maze) 2),(div (length (head maze)) 2)))] (State maze ((Pacman (PacState (i1,y1,s1,o1,p1,v1) t1 m1 e1 )):pl) lv)
    | otherwise = addPlayerHead [(Ghost (GhoState (i2,y2,s2,o2,p2,v2) e2 ))] (ghostToHouse play (State maze ((Pacman (PacState (i1,y1,s1,o1,p1,v1) t1 m1 e1 )):pl) lv))
-- | Função usada para a partir do Id e do Jogador obter as suas coordernadas
getCoordsFromId :: Int -> [Player] -> Coords
getCoordsFromId x ((Ghost (GhoState (i,y,s,o,p,v) e )):pl) = getCoordsFromId x pl
getCoordsFromId x ((Pacman (PacState (i,y,s,o,p,v) t m e )):pls)
    | x == i = y
    | otherwise = getCoordsFromId x pls
-- | Função usada numa Play para obter o Id do jogador a qual essa move vai ser aplicada
getMoveId :: Play -> Int
getMoveId (Move x D) = x
getMoveId (Move x U) = x
getMoveId (Move x L) = x
getMoveId (Move x R) = x
-- | Verifa se o jogador esta na direçao da jogada e-- (Processa a jogada, tal como o nome indica)
--depois decide se muda direçao ou move o jogador-- (Se a direção da jogada for a mesma do jogador então aplica a função Move, que tem várias possibilidades D = Down, U= Up, L= Left, R=Right)
processPlay :: Play -> State -> State
processPlay (Move x D) (State maze ((Ghost (GhoState (i2,y2,s2,o2,p2,v2) Alive )):xs) l) = (moveD (Move x D) (idEmHead (Move x D) (State maze (Ghost (GhoState (i2,y2,s2,D,p2,v2) Alive):xs) l)))
processPlay (Move x D) (State maze ((Ghost (GhoState (i2,y2,s2,o2,p2,v2) Dead )):xs) l) = (moveD (Move x D) (idEmHead (Move x D) (State maze (Ghost (GhoState (i2,y2,s2,D,p2,v2) Dead):xs) l)))
processPlay (Move x R) (State maze ((Ghost (GhoState (i2,y2,s2,o2,p2,v2) Alive )):xs) l) = (moveR (Move x R) (idEmHead (Move x R) (State maze (Ghost (GhoState (i2,y2,s2,R,p2,v2) Alive):xs) l)))
processPlay (Move x R) (State maze ((Ghost (GhoState (i2,y2,s2,o2,p2,v2) Dead )):xs) l) =  (moveR (Move x R) (idEmHead (Move x R) (State maze (Ghost (GhoState (i2,y2,s2,R,p2,v2) Dead):xs) l)))
processPlay (Move x L) (State maze ((Ghost (GhoState (i2,y2,s2,o2,p2,v2) Alive )):xs) l) = (moveL (Move x L) (idEmHead (Move x L) (State maze (Ghost (GhoState (i2,y2,s2,L,p2,v2) Alive):xs) l)))
processPlay (Move x L) (State maze ((Ghost (GhoState (i2,y2,s2,o2,p2,v2) Dead )):xs) l) = (moveL (Move x L) (idEmHead (Move x L) (State maze (Ghost (GhoState (i2,y2,s2,L,p2,v2) Dead):xs) l)))
processPlay (Move x U) (State maze ((Ghost (GhoState (i2,y2,s2,o2,p2,v2) Alive )):xs) l) = (moveU (Move x U) (idEmHead (Move x U) (State maze (Ghost (GhoState (i2,y2,s2,U,p2,v2) Alive):xs) l)))
processPlay (Move x U) (State maze ((Ghost (GhoState (i2,y2,s2,o2,p2,v2) Dead )):xs) l) = (moveU (Move x U) (idEmHead (Move x U) (State maze (Ghost (GhoState (i2,y2,s2,U,p2,v2) Dead):xs) l)))

processPlay (Move x y) (State maze (Pacman (PacState (i ,(a,b),s,o,p,v) t m Dying):xs) l) = (State maze (Pacman (PacState (i ,(a,b),s,o,p,v) t m Dying):xs) l)
processPlay (Move x D) (State maze (Pacman (PacState (i ,(a,b),s,o,p,v) t m e):xs) l)
    | D == o = eatenFood (Move x D) (moveD (Move x D) (idEmHead (Move x D) (State maze (Pacman (PacState (i ,(a,b),s,o,p,v) t m e):xs) l)))
    | D /= o = addPlayerHead xs (idEmHead (Move x D) (State maze [Pacman (PacState (i ,(a,b),s,D,p,v) t m e)] l))
processPlay (Move x L) (State maze (Pacman (PacState (i ,(a,b),s,o,p,v) t m e):xs) l)
    | L == o = eatenFood (Move x L) (moveL (Move x L) (idEmHead (Move x D) (State maze (Pacman (PacState (i ,(a,b),s,o,p,v) t m e):xs) l)))
    | L /= o = addPlayerHead xs (idEmHead (Move x D) (State maze [(Pacman (PacState (i ,(a,b),s,L,p,v) t m e))] l))
processPlay (Move x R) (State maze (Pacman (PacState (i ,(a,b),s,o,p,v) t m e):xs) l)
    | R == o = eatenFood (Move x R) (moveR (Move x R) (idEmHead (Move x D) (State maze (Pacman (PacState (i ,(a,b),s,o,p,v) t m e):xs) l)))
    | R /= o = addPlayerHead xs (idEmHead (Move x D) (State maze [Pacman (PacState (i ,(a,b),s,R,p,v) t m e)] l))
processPlay (Move x U) (State maze (Pacman (PacState (i ,(a,b),s,o,p,v) t m e):xs) l)
    | U == o = eatenFood (Move x U) (moveU (Move x U) (idEmHead (Move x D) (State maze (Pacman (PacState (i ,(a,b),s,o,p,v) t m e):xs) l)))
    | U /= o = addPlayerHead xs (idEmHead (Move x D) (State maze [Pacman (PacState (i ,(a,b),s,U,p,v) t m e)] l))
-- | Move Down-- Função que considera todas as possibilidades quando o pacman se move para Baixo (Down)
moveD :: Play -> State -> State
-- | Fantasmas
moveD (Move x D) (State maze ((Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e)):pm) lv)
    | x == i && getPacCoords (((Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e)):pm)) == (a+1,b) = if e == Dead
                                                                                            then (State maze (((Ghost (GhoState (i,((div (length maze) 2)-1,(div (length (head maze)) 2)),s2,o2,p2,v2) Alive)) : pm)) lv)
                                                                                            else killPacman (State maze ((Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e )) : pm) lv)
    | x == i && whichPiece (a+1,b) maze == Wall        = (State maze ((Ghost (GhoState (i,(a,b),s2,D,p2,v2) e )) : pm) lv)
    | x == i && whichPiece (a+1,b) maze == Empty       = (State maze (moveGhost (Move x D) ((Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e )) : pm)) lv)
    | x == i && whichPiece (a+1,b) maze == Food Little = (State maze (moveGhost (Move x D) ((Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e )) : pm)) lv)
    | x == i && whichPiece (a+1,b) maze == Food Big    = (State maze (moveGhost (Move x D) ((Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e )) : pm)) lv)
    | otherwise =  addPlayer [(Ghost (GhoState (i,(a,b),s2,o2,p2,v2) Alive ))] (moveD (Move x D) (State maze pm lv))
-- | PacmanNormal
moveD (Move x D) (State maze ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm) lv)
    | x == i && elem (a+1,b) (coordGhosts ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):pm)) = (State maze (moveNormalToGhost (Move x D) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && whichPiece (a+1,b) maze == Wall        = (State maze (moveNormalToWall (Move x D) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && whichPiece (a+1,b) maze == Empty       = (State maze (moveNormalToEmpty (Move x D) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && whichPiece (a+1,b) maze == Food Little = (State maze (moveNormalToLittle (Move x D) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && whichPiece (a+1,b) maze == Food Big    = (State maze (moveNormalToBig (Move x D) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | otherwise =  addPlayer [(Pacman(PacState(i,(a,b),s,o,p,v) t m Normal))] (moveD (Move x D) (State maze pm lv))
-- | Pacman Mega
moveD (Move x D) (State maze ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm) lv)
    | x == i && elem (a+1,b) (coordGhosts ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):pm)) = ghostToHouse (Move x D) (State maze (moveMegaToGhost (Move x D) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && whichPiece (a+1,b) maze == Wall        = (State maze (megatoWall (Move x D) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm)) lv)
    | x == i && whichPiece (a+1,b) maze == Empty       = (State maze (moveMegaToEmpty (Move x D) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm)) lv)
    | x == i && whichPiece (a+1,b) maze == Food Little = (State maze (moveMegaToLittle (Move x D) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm)) lv)
    | x == i && whichPiece (a+1,b) maze == Food Big    = (State maze (moveMegaToBig (Move x D) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm)) lv)
    | otherwise =  addPlayer [(Pacman(PacState(i,(a,b),s,o,p,v) t m Mega))] (moveD (Move x D) (State maze pm lv))
-- | Move Up-- Função que considera todas as possibilidades quando o pacman se move para Cima (Up)
moveU :: Play -> State -> State
-- | Fantasmas
moveU (Move x U) (State maze ((Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e )) : pm) lv)
    | x == i && getPacCoords (((Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e)):pm)) == (a-1,b) = if e == Dead
                                                                                            then (State maze (((Ghost (GhoState (i,((div (length maze) 2)-1,(div (length (head maze)) 2)),s2,o2,p2,v2) Alive )) : pm)) lv)
                                                                                            else killPacman (State maze ((Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e )) : pm) lv)
    | x == i && whichPiece (a-1,b) maze == Wall        = (State maze ((Ghost (GhoState (i,(a,b),s2,U,p2,v2) e )) : pm) lv)
    | x == i && whichPiece (a-1,b) maze == Empty       = (State maze (moveGhost (Move x U) ((Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e )) : pm)) lv)
    | x == i && whichPiece (a-1,b) maze == Food Little = (State maze (moveGhost (Move x U) ((Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e )) : pm)) lv)
    | x == i && whichPiece (a-1,b) maze == Food Big    = (State maze (moveGhost (Move x U) ((Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e )) : pm)) lv)
    | otherwise =  addPlayer [(Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e ))] (moveU (Move x U) (State maze pm lv))

-- | Pacman Normal
moveU (Move x U) (State maze ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm) lv)
    | x == i && elem (a-1,b) (coordGhosts ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):pm)) = (State maze (moveNormalToGhost (Move x U) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && whichPiece (a-1,b) maze == Wall        = State maze  (moveNormalToWall (Move x U) ((Pacman (PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv
    | x == i && whichPiece (a-1,b) maze == Empty       = (State maze (moveNormalToEmpty (Move x U) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && whichPiece (a-1,b) maze == Food Little = (State maze (moveNormalToLittle (Move x U) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && whichPiece (a-1,b) maze == Food Big    = (State maze (moveNormalToBig (Move x U) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | otherwise =  addPlayer [(Pacman(PacState(i,(a,b),s,o,p,v) t m Normal))] (moveU (Move x U) (State maze pm lv))
-- | Pacman Mega
moveU (Move x U) (State maze ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm) lv)
    | x == i && elem (a-1,b) (coordGhosts ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):pm)) = ghostToHouse (Move x U) (State maze (moveMegaToGhost (Move x U) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && whichPiece (a-1,b) maze == Wall        = (State maze (megatoWall (Move x U) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm)) lv)
    | x == i && whichPiece (a-1,b) maze == Empty       = (State maze (moveMegaToEmpty (Move x U) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm)) lv)
    | x == i && whichPiece (a-1,b) maze == Food Little = (State maze (moveMegaToLittle (Move x U) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm)) lv)
    | x == i && whichPiece (a-1,b) maze == Food Big    = (State maze (moveMegaToBig (Move x U) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm)) lv)
    | otherwise =  addPlayer [(Pacman(PacState(i,(a,b),s,o,p,v) t m Mega))] (moveU (Move x U) (State maze pm lv))
-- | Move Right-- Função que considera todas as possibilidades quando o pacman se move para a Direita (Right)
moveR :: Play -> State -> State

-- | Fantasmas
moveR (Move x R) (State maze ((Ghost (GhoState (i,(a,b),s,o,p,v) e )) : pm) lv)
    | x == i && getPacCoords (((Ghost (GhoState (i,(a,b),s,o,p,v) e)):pm)) == (a,b+1) = if e == Dead
                                                                                            then (State maze (((Ghost (GhoState (i,((div (length maze) 2)-1,(div (length (head maze)) 2)),s,o,p,v) Alive )) : pm)) lv)
                                                                                            else killPacman (State maze ((Ghost (GhoState (i,(a,b),s,o,p,v) e )) : pm) lv)
    | x == i && b == (length ((!!) maze 6))-1 = (State maze ((Ghost (GhoState (i,(a,0),s,o,p,v) e )) : pm) lv)
    | x == i && whichPiece (a,b+1) maze == Wall        = (State maze ((Ghost (GhoState (i,(a,b),s,R,p,v) e )) : pm) lv)
    | x == i && whichPiece (a,b+1) maze == Empty       = (State maze (moveGhost (Move x R) ((Ghost (GhoState (i,(a,b),s,o,p,v) e )) : pm)) lv)
    | x == i && whichPiece (a,b+1) maze == Food Little = (State maze (moveGhost (Move x R) ((Ghost (GhoState (i,(a,b),s,o,p,v) e )) : pm)) lv)
    | x == i && whichPiece (a,b+1) maze == Food Big    = (State maze (moveGhost (Move x R) ((Ghost (GhoState (i,(a,b),s,o,p,v) e )) : pm)) lv)
    | otherwise =  addPlayer [(Ghost (GhoState (i,(a,b),s,o,p,v) Alive ))] (moveD (Move x R) (State maze pm lv))

-- | Pacman Normal
moveR (Move x R) (State maze ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm) lv)
    | x == i && elem (a,b+1) (coordGhosts ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):pm)) = (State maze (moveNormalToGhost (Move x R) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i &&  b == (length (head maze))-1           = (State maze (moveNormalToEmpty (Move x R) ((Pacman(PacState(i,(a,-1),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && whichPiece (a,b+1) maze == Wall        = (State maze (moveNormalToWall (Move x R) ((Pacman (PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && whichPiece (a,b+1) maze == Empty       = (State maze (moveNormalToEmpty (Move x R) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && whichPiece (a,b+1) maze == Food Little = (State maze (moveNormalToLittle (Move x R) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && whichPiece (a,b+1) maze == Food Big    = (State maze (moveNormalToBig (Move x R) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | otherwise =  addPlayer [(Pacman(PacState(i,(a,b),s,o,p,v) t m Normal))] (moveR (Move x R) (State maze pm lv))
-- | Pacman Mega
moveR (Move x R) (State maze ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm) lv)
    | x == i && elem (a,b+1) (coordGhosts ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):pm)) = ghostToHouse (Move x R) (State maze (moveMegaToGhost (Move x R) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && b == length (head maze)-1 = (State maze (moveMegaToEmpty (Move x R) ((Pacman(PacState(i,(a,-1),s,o,p,v) t m Mega)) : pm)) lv)
    | x == i && whichPiece (a,b+1) maze == Wall        = (State maze (megatoWall (Move x R) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm)) lv)
    | x == i && whichPiece (a,b+1) maze == Empty       = (State maze (moveMegaToEmpty (Move x R) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm)) lv)
    | x == i && whichPiece (a,b+1) maze == Food Little = (State maze (moveMegaToLittle (Move x R) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm)) lv)
    | x == i && whichPiece (a,b+1) maze == Food Big    = (State maze (moveMegaToBig (Move x R) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm)) lv)
    | otherwise =  addPlayer [(Pacman(PacState(i,(a,b),s,o,p,v) t m Mega))] (moveR (Move x R) (State maze pm lv))
-- | Move Left-- Função que considera todas as possibilidades quando o pacman se move para a Esquerda (Left)
moveL :: Play -> State -> State
-- | Fantasmas
moveL (Move x L) (State maze ((Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e )) : pm) lv)
    | x == i && getPacCoords (((Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e)):pm)) == (a,b-1) = if e == Dead
                                                                                            then (State maze (((Ghost (GhoState (i,((div (length maze) 2)-1,(div (length (head maze)) 2)),s2,o2,p2,v2) Alive )) : pm)) lv)
                                                                                            else killPacman (State maze ((Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e )) : pm) lv)
    | x == i && b == 0 = (State maze (moveGhost (Move x L) ((Ghost (GhoState (i,(a,(length (head maze))),s2,o2,p2,v2) e )) : pm)) lv)
    | x == i && whichPiece (a,b-1) maze == Wall        = (State maze ((Ghost (GhoState (i,(a,b),s2,L,p2,v2) e )) : pm) lv)
    | x == i && whichPiece (a,b-1) maze == Empty       = (State maze (moveGhost (Move x L) ((Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e )) : pm)) lv)
    | x == i && whichPiece (a,b-1) maze == Food Little = (State maze (moveGhost (Move x L) ((Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e )) : pm)) lv)
    | x == i && whichPiece (a,b-1) maze == Food Big    = (State maze (moveGhost (Move x L) ((Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e )) : pm)) lv)
    | otherwise =  addPlayer [(Ghost (GhoState (i,(a,b),s2,o2,p2,v2) e ))] (moveD (Move x L) (State maze pm lv))

-- | Pacman Normal
moveL (Move x L) (State maze ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm) lv)
    | x == i && elem (a,b-1) (coordGhosts ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):pm)) = (State maze (moveNormalToGhost (Move x L) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && b == 0 = (State maze (moveNormalToEmpty (Move x L) ((Pacman(PacState(i,(a,(length (head maze))),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && whichPiece (a,b-1) maze == Wall        = (State maze (moveNormalToWall (Move x L) ((Pacman (PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && whichPiece (a,b-1) maze == Empty       = (State maze (moveNormalToEmpty (Move x L) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && whichPiece (a,b-1) maze == Food Little = (State maze (moveNormalToLittle (Move x L) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && whichPiece (a,b-1) maze == Food Big    = (State maze (moveNormalToBig (Move x L) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | otherwise =  addPlayer [(Pacman(PacState(i,(a,b),s,o,p,v) t m Normal))] (moveL (Move x L) (State maze pm lv))
-- | Pacman Mega
moveL (Move x L) (State maze ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm) lv)
    | x == i && elem (a,b-1) (coordGhosts ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):pm)) = ghostToHouse (Move x L) (State maze (moveMegaToGhost (Move x L) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : pm)) lv)
    | x == i && b == 0 = (State maze (moveMegaToEmpty (Move x L) ((Pacman(PacState(i,(a,(length (head maze))),s,o,p,v) t m Mega)) : pm)) lv)
    | x == i && whichPiece (a,b-1) maze == Wall        = (State maze (megatoWall (Move x L) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm)) lv)
    | x == i && whichPiece (a,b-1) maze == Empty       = (State maze (moveMegaToEmpty (Move x L) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm)) lv)
    | x == i && whichPiece (a,b-1) maze == Food Little = (State maze (moveMegaToLittle (Move x L) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm)) lv)
    | x == i && whichPiece (a,b-1) maze == Food Big    = (State maze (moveMegaToBig (Move x L) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Mega)) : pm)) lv)
    | otherwise =  addPlayer [(Pacman(PacState(i,(a,b),s,o,p,v) t m Mega))] (moveL (Move x L) (State maze pm lv))
-- | Funções chamadas pelos moves que modificam o estado dos jogadores após cada tipo de jogada
-- | Pacman em estado normal anda para uma posição vazia
moveNormalToEmpty :: Play -> [Player] -> [Player]
moveNormalToEmpty _ [] = []
moveNormalToEmpty (Move x D) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):otherplayers)
    | x == i = resGhost((Pacman(PacState(i,(a+1,b),s,o,p,v) t m Normal)) : otherplayers)
    | otherwise = resGhost((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)): (moveNormalToEmpty (Move x D) otherplayers))
moveNormalToEmpty (Move x U) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):otherplayers)
    | x == i = resGhost((Pacman(PacState(i,(a-1,b),s,o,p,v) t m Normal)) : otherplayers)
    | otherwise = resGhost((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)): (moveNormalToEmpty (Move x U) otherplayers))
moveNormalToEmpty (Move x L) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):otherplayers)
    | x == i = resGhost((Pacman(PacState(i,(a,b-1),s,o,p,v) t m Normal)) : otherplayers)
    | otherwise = resGhost((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)): (moveNormalToEmpty (Move x L) otherplayers))
moveNormalToEmpty (Move x R) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):otherplayers)
    | x == i = resGhost((Pacman(PacState(i,(a,b+1),s,o,p,v) t m Normal)) : otherplayers)
    | otherwise = resGhost((Pacman(PacState(i,(a,b+1),s,o,p,v) t m Normal)): (moveNormalToEmpty (Move x R) otherplayers))

moveNormalToWall :: Play -> [Player] -> [Player]
moveNormalToWall _ [] = []
moveNormalToWall (Move x D) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : otherplayers)
    | x == i = resGhost((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : otherplayers)
    | otherwise = resGhost((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)): (moveNormalToWall (Move x D) otherplayers))
moveNormalToWall (Move x U) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : otherplayers)
    | x == i = resGhost((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : otherplayers)
    | otherwise = resGhost((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)): (moveNormalToWall (Move x U) otherplayers))
moveNormalToWall (Move x L) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : otherplayers)
    | x == i = resGhost((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : otherplayers)
    | otherwise = resGhost((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)): (moveNormalToWall (Move x L) otherplayers))
moveNormalToWall (Move x R) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : otherplayers)
    | x == i = resGhost((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : otherplayers)
    | otherwise = resGhost((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)): (moveNormalToWall (Move x R) otherplayers))

-- | Pacman em estado normal anda para uma posição com uma comida pequena
moveNormalToLittle :: Play -> [Player] -> [Player]
moveNormalToLittle _ [] = []
moveNormalToLittle (Move x D) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)) : otherplayers)
    | x == i = resGhost((Pacman(PacState(i,(a+1,b),s,o,(p+1),v) t m Normal)) : otherplayers)
