-- | Pacman em estado normal anda para uma posição com uma comida grande
moveNormalToBig :: Play -> [Player] -> [Player]
moveNormalToBig _ [] = []
moveNormalToBig (Move x D) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):otherplayers)
    | x == i = killGhost ((Pacman(PacState(i,(a+1,b),s,o,(p+5),v) 40 m Mega)) : otherplayers)
    | otherwise = ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)): (moveNormalToBig (Move x D) otherplayers))
moveNormalToBig (Move x U) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):otherplayers)
    | x == i = killGhost ((Pacman(PacState(i,(a-1,b),s,o,(p+5),v) 40 m Mega)) : otherplayers)
    | otherwise = (Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)): (moveNormalToBig (Move x U) otherplayers)
moveNormalToBig (Move x L) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):otherplayers)
    | x == i = killGhost ((Pacman(PacState(i,(a,b-1),s,o,(p+5),v) 40 m Mega)) : otherplayers)
    | otherwise = (Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)): (moveNormalToBig (Move x L) otherplayers)
moveNormalToBig (Move x R) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):otherplayers)
    | x == i = killGhost ((Pacman(PacState(i,(a,b+1),s,o,(p+5),v) 40 m Mega)) : otherplayers)
    | otherwise = (Pacman(PacState(i,(a,b+1),s,o,p,v) t m Normal)): (moveNormalToBig (Move x R) otherplayers)
-- | Pacman em estado normal anda para uma posição com um fantasma em estado vivo
moveNormalToGhost :: Play -> [Player] -> [Player]
moveNormalToGhost _ [] = []
moveNormalToGhost (Move x D) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):otherplayers)
    | x == i = if (v-1) == 0
               then (Pacman(PacState(i,(a,b),s,o,p,0) t m Dying)):otherplayers
               else (Pacman(PacState(i,(a+1,b),(s),o,p,v-1) t m Normal)):otherplayers
    | otherwise = (Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)): (moveNormalToGhost (Move x D) otherplayers)
moveNormalToGhost (Move x U) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):otherplayers)
    | x == i = if (v-1) == 0
               then (Pacman(PacState(i,(a,b),s,o,p,v) t m Dying)):otherplayers
               else (Pacman(PacState(i,(a-1,b),(s),o,p,v-1) t m Normal)):otherplayers
    | otherwise = (Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)): (moveNormalToGhost (Move x U) otherplayers)
moveNormalToGhost (Move x L) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):otherplayers)
    | x == i = if (v-1) == 0
               then (Pacman(PacState(i,(a,b),s,o,p,0) t m Dying)):otherplayers
               else (Pacman(PacState(i,(a,b-1),(s),o,p,(v-1)) t m Normal)):otherplayers
    | otherwise = (Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)): (moveNormalToGhost (Move x L) otherplayers)
moveNormalToGhost (Move x R) ((Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)):otherplayers)
    | x == i = if (v-1) == 0
               then (Pacman(PacState(i,(a,b),s,o,p,0) t m Dying)):otherplayers
               else (Pacman(PacState(i,(a,b+1),(s),o,p,(v-1)) t m Normal)):otherplayers
    | otherwise = (Pacman(PacState(i,(a,b),s,o,p,v) t m Normal)): (moveNormalToGhost (Move x R) otherplayers)
-- | Pacman em estado Mega anda para uma posição vazia
moveMegaToEmpty :: Play -> [Player] -> [Player]
moveMegaToEmpty _ [] = []
moveMegaToEmpty (Move x D) ((Pacman(PacState(i,(a,b),s,o,p,v) t m e)) : otherplayers)
    | x == i = (Pacman (PacState (i, (a+1,b),s,o,p,v) (t-1) m Mega)) : otherplayers
    | otherwise = (Pacman(PacState(i,(a,b),s,o,p,v) (t-1) m e)) : (moveMegaToEmpty (Move x D) otherplayers)
moveMegaToEmpty (Move x U) ((Pacman(PacState(i,(a,b),s,o,p,v) t m e)) : otherplayers)
    | x == i = (Pacman (PacState (i, (a-1,b),s,o,p,v) (t-1) m Mega)) : otherplayers
    | otherwise = (Pacman(PacState(i,(a,b),s,o,p,v) (t-1) m e)) : (moveMegaToEmpty (Move x U) otherplayers)
moveMegaToEmpty (Move x L) ((Pacman(PacState(i,(a,b),s,o,p,v) t m e)) : otherplayers)
    | x == i = (Pacman (PacState (i, (a,b-1),s,o,p,v) (t-1) m Mega)) : otherplayers
    | otherwise = (Pacman(PacState(i,(a,b),s,o,p,v) (t-1) m e)) : (moveMegaToEmpty (Move x L) otherplayers)
moveMegaToEmpty (Move x R) ((Pacman(PacState(i,(a,b),s,o,p,v) t m e)) : otherplayers)
    | x == i = (Pacman (PacState (i, (a,b+1),s,o,p,v) (t-1) m Mega)) : otherplayers
    | otherwise = (Pacman(PacState(i,(a,b),s,o,p,v) (t-1) m e)) : (moveMegaToEmpty (Move x R) otherplayers)
