megatoWall :: Play -> [Player] -> [Player]
megatoWall (Move x l) ((Pacman(PacState(i,(a,b),s,o,p,v) t m e)) : otherplayers)
    | x == i = megaToNormal(Pacman (PacState (i,(a,b),s,o,p,v) (t-1) m e) : otherplayers)
    | otherwise = (Pacman(PacState(i,(a,b),s,o,p,v) t m e)) : (megatoWall (Move x l) otherplayers)


megaToNormal :: [Player] -> [Player]
megaToNormal [] = []
megaToNormal ((Pacman(PacState (i,c,s,o,p,v) t m Mega)):pls)
    | t <= 0 = ((Pacman(PacState (i,c,s,o,p,v) t m Normal)): megaToNormal pls)
    | otherwise = (Pacman(PacState (i,c,s,o,p,v) t m Mega)): megaToNormal pls
megaToNormal (pl:pls) = pl : megaToNormal pls


moveGhost :: Play -> [Player] -> [Player]
moveGhost _ [] = []
moveGhost (Move x D) ((Ghost (GhoState (i,(a,b),ve,o,p,v) e)):otherplayers)
    | x == i = ((Ghost (GhoState (i,(a+1,b),ve,D,p,v) e)) : otherplayers)
    | otherwise = ((Ghost (GhoState (i,(a,b),ve,o,p,v) e)): (moveGhost (Move x D) otherplayers))
moveGhost (Move x U) ((Ghost (GhoState (i,(a,b),ve,o,p,v) e)):otherplayers)
    | x == i = ((Ghost (GhoState (i,(a-1,b),ve,U,p,v) e)) : otherplayers)
    | otherwise = ((Ghost (GhoState (i,(a,b),ve,o,p,v) e)): (moveGhost (Move x U) otherplayers))
moveGhost (Move x L) ((Ghost (GhoState (i,(a,b),ve,o,p,v) e)):otherplayers)
    | x == i = ((Ghost (GhoState (i,(a,b-1),ve,L,p,v) e)) : otherplayers)
    | otherwise = ((Ghost (GhoState (i,(a,b),ve,o,p,v) e)): (moveGhost (Move x L) otherplayers))
moveGhost (Move x R) ((Ghost (GhoState (i,(a,b),ve,o,p,v) e)):otherplayers)
    | x == i = ((Ghost (GhoState (i,(a,b+1),ve,R,p,v) e)) : otherplayers)
    | otherwise = ((Ghost (GhoState (i,(a,b),ve,o,p,v) e)): (moveGhost (Move x R) otherplayers))


changeMouth :: [Player] -> [Player]
changeMouth [] = []
changeMouth ((Pacman (PacState (i,c,s,o,p,v) t m Dying)):pls) = ((Pacman (PacState (i,c,s,o,p,v) t m Dying)):pls)
changeMouth ((Pacman (PacState (i,c,s,o,p,v) t m e)):pls)
    | m == Open = megaToNormal [(Pacman(PacState (i,c,s,o,p,v) t Closed e))] ++ changeMouth (megaToNormal pls)
    | otherwise = megaToNormal [(Pacman(PacState (i,c,s,o,p,v) t Open e))] ++ changeMouth (megaToNormal pls)
changeMouth ((Ghost(GhoState (i,c,s,o,p,v) e)):pls) = megaToNormal [(Ghost(GhoState (i,c,s,o,p,v) e))] ++ changeMouth (megaToNormal pls)


-- | Função Final que recebe um "Move" um "State" e apresenta esse mesmo "State" modificado tendo em conta o "Move" apresentado
play :: Play -> State -> State
play (Move x D) (State m pl l) = (processPlay (Move x D) (idEmHead (Move x D) (State (m) (changeMouth pl) l)))
play (Move x R) (State m pl l) = (processPlay (Move x R) (idEmHead (Move x R) (State (m) (changeMouth pl) l)))
play (Move x L) (State m pl l) = (processPlay (Move x L) (idEmHead (Move x L) (State (m) (changeMouth pl) l)))
play (Move x U) (State m pl l) = (processPlay (Move x U) (idEmHead (Move x U) (State (m) (changeMouth pl) l)))
{- |
=Introdução

Nesta tarefa foi desenvolvido um código que automaticamente gera um labirinto onde o pacman pode ser jogado.

=Objetivos

O grande objetivo na tarefa foi gerar um labirinto aleatorio usando as funcionalidades que o Haskell oferecia.
No entanto, nada foi muito direto. Inicialmente foi necessário ter com conta vários promenores.
Cada labirinto e constituido de de 4 tipos de peças diferentes.
- Walls        - Paredes
- Food Littles - Comidas pequenas
- Food Bigs    - Comidas grandes
- Emptys       - Espaços vazios

==Procedimento

Inicialmete tivemos de ter em atenção a algumas regras.

 * O labirinto tem de estar rodeado de peças - Walls
 * A existencia de tuneis no meio do Labirinto
 * A existencia de uma "Casa dos fantasmas"
  * A casa dos fantasmas tem de estar rodeada de peças Emptys

=Discução e Conclusão

No fim desta tarefa conseguimos desenvolver a função "generateMaze :: Int -> Int -> Int ->  Maze" que, tal como o nome sugere, gera um labirinto aleatorio,
tendo em conta um valor para a largura, comprimento e um número aleatorio que vai servir de /randomizer/.
-}




-- | Função que gera numeros aleatorios (Para depois serem substituidos por peças)
geraAleatorios :: Int -> Int -> [Int]
geraAleatorios n seed = let gen = mkStdGen seed -- creates a random generator
                       in take n $ randomRs (0,99) gen -- takes the first n elements from an infinite series of random numbers between 0-9


-- | Função para separar listas n em n elementos
subList :: Int  -- ^ Numero de elementos na lista nova
            -> [a] -> [[a]]
subList _ [] = []
subList n l = take n l: subList n (drop n l)


-- | Converte os números aleatoriamente criados em peças
convertePiece :: Int -> Piece
convertePiece a | a == 3 = Food Big
                | a < 70 && a >= 0 = Food Little
                | a >= 70 && a <= 99 = Wall

-- | Função que converte o corredor em "String"
printCorridor :: Corridor -> String
printCorridor [] = "\n"
printCorridor (x:xs) = show x ++ printCorridor xs

-- | Função que converte uma lista de números numa lista de peças (Corredor)
converteCorridor :: [Int] -> [Piece]
converteCorridor [] = []
converteCorridor (h:hs) = (convertePiece h : converteCorridor hs)

-- | Função que converte uma lista de listas de números numa lista de corredores (Labirinto)
converteMaze :: [[Int]] -> Maze
converteMaze [] = []
converteMaze (h:hs) = converteCorridor h : converteMaze hs

-- | Função que cria uma linha só com paredes
onlyWall :: Int -> Corridor
onlyWall 0 = []
onlyWall a = [Wall] ++ onlyWall (a-1)

-- | Função que cria um labirinto com numeros aleatorios
generateRandomMaze :: Int -> Int -> Int -> Maze
generateRandomMaze x y s =
                 let random_nrs = geraAleatorios (x*y) s
                 in converteMaze $ subList x random_nrs


-- | Função que posiciona paredes a volta do labirinto de altura "y" e largura "x" com uma seed "s"
generateWalledMaze :: Int -> Int -> Int -> Maze
generateWalledMaze x y s = [onlyWall x] ++ (addWalls (generateRandomMaze (x-2) (y-2) s)) ++ [onlyWall x]

-- | Função auxiliar da função "generateWalledMaze", que cria paredes à esquerda e à direita do labirinto
addWalls :: Maze -> Maze
addWalls [] = []
addWalls (x:xs) = ([Wall]++x++[Wall]) : addWalls xs


-- | Função que adiciona tuneis ao labirinto (Chama 2 funções diferentes, caso o labirinto seja par ou impar)
addTunnels :: Int -> Int -> Int -> Maze
addTunnels x y s | even y = addTunnelsEven x y s
                 | otherwise = addTunnelsOdd x y s

-- | Função que adiciona tuneis ao labirinto quando este é Par
addTunnelsEven :: Int -> Int -> Int -> Maze
addTunnelsEven x y s = take ((div y 2)-1) (generateWalledMaze x y s) ++
                       auxAddTunnels(drop ((div y 2)-1) (take ((div y 2)+1) (generateWalledMaze x y s))) ++
                       drop ((div y 2)+1) (generateWalledMaze x y s)

-- | Função que adiciona tuneis ao labirinto quando este é Impar
addTunnelsOdd :: Int -> Int -> Int -> Maze
addTunnelsOdd x y s = take (div y 2) (generateWalledMaze x y s) ++
                      auxAddTunnels (drop (div y 2) (take ((div y 2)+1) (generateWalledMaze x y s))) ++
                      drop ((div y 2)+1) (generateWalledMaze x y s)

-- | Função que pega num labirinto e remove as paredes da esquerda e direita (Utilizada no addTunnelsOdd/Even para remover as paredes dos respectivos corredores)
auxAddTunnels :: Maze -> Maze
auxAddTunnels [] = []
auxAddTunnels (x:xs) = ([Empty] ++ (init (tail x)) ++ [Empty]) : (auxAddTunnels xs)


-- | Função que constroi a casa dos fantasmas
buildHouse :: Int  -> Int -> Maze
buildHouse x s = if even x
               then buildEvenHouse x s
               else buildOddHouse x s

-- | Constroi a casa quando o labirinto é par
buildEvenHouse :: Int -> Int -> Maze
buildEvenHouse x s = [
                      take 10 (repeat Empty),
                      [Empty] ++ take 3 (repeat Wall) ++ [Empty ,Empty] ++ take 3 (repeat Wall) ++ [Empty],
                      [Empty,Wall] ++ take 6 (repeat Empty) ++ [Wall,Empty],
                      [Empty] ++ take 8 (repeat Wall) ++ [Empty],
                      take 10 (repeat Empty)
                     ]
-- | Constroi a casa quando o labirinto é impar
buildOddHouse :: Int -> Int -> Maze
buildOddHouse x s = [
                     take 11 (repeat Empty),
                     [Empty] ++ take 3 (repeat Wall) ++ [Empty, Empty ,Empty] ++ take 3 (repeat Wall) ++ [Empty],
                     [Empty,Wall] ++ take 7 (repeat Empty) ++ [Wall,Empty],
                     [Empty] ++ take 9 (repeat Wall) ++ [Empty],
                     take 11 (repeat Empty)
                    ]


-- | Constroi a parte central do Maze
addHouse :: Int -> Int -> Int -> Maze
addHouse x y s = connect (left(center x y s)) (buildHouse x s) (right (center x y s))

-- | Conecta 3 Mazes para juntar a parte central do maze
connect :: Maze -> Maze -> Maze -> Maze
connect [] [] [] = []
connect x y z = (head x ++ head y ++ head z) : connect (tail x) (tail y) (tail z)

-- | Cria lista do que esta à esquerda da casa
left :: Maze -> Maze
left [] = []
left (x:xs) | even (length x) = take ((div (length x) 2)-5) x : left xs
            | odd (length x) = take ((div (length x) 2)-5) x : left xs

-- | Cria lista do que esta à direita da casa
right :: Maze -> Maze
right [] = []
right (x:xs) | even (length x) = drop ((div (length x) 2)+5) x : right xs
             | odd (length x) = drop ((div (length x) 2)+6) x : right xs

-- | Pega num maze e seleciona a zona da casa
center :: Int -> Int -> Int -> Maze
center x y s | even y = drop ((div y 2)-3) (take ((div y 2)+2) (addTunnels x y s))
             | otherwise = drop ((div y 2)-2) (take ((div y 2)+3) (addTunnels x y s))


-- | Gera um maze completo
auxgenerateMaze :: Int -> Int -> Int -> Maze
auxgenerateMaze x y s | even y = take ((div y 2)-3) (addTunnels x y s) ++ (addHouse x y s) ++ drop ((div y 2)+2) (addTunnels x y s)
                      | otherwise = take ((div y 2)-2) (addTunnels x y s) ++ (addHouse x y s) ++ drop ((div y 2)+3) (addTunnels x y s)

-- | Função final que constroi o labirinto ("x" largura do labirinto, "y" altura, "s" seed aleatoria de forma a criar valores para as peças)
generateMaze :: Int -> Int -> Int -> Maze
generateMaze x y s | x < 15 && y>=10 = auxgenerateMaze 15 y s
                   | y < 10 && x>= 15 = auxgenerateMaze x 10 s
                   | x < 15 && y < 10 = auxgenerateMaze 15 10 s
                   | otherwise = auxgenerateMaze x y s

-- | Função que apenas server para visualizar de maneira mais explicita o labirinto
generateMazeVisualizer :: Int -> Int -> Int -> IO()
generateMazeVisualizer x y s = putStr (printMaze(generateMaze x y s))



data Manager = Manager
    {
        state   :: State
    ,    pid    :: Int
    ,    step   :: Int
    ,    before :: Integer
    ,    delta  :: Integer
    ,    delay  :: Integer
    }


loadManager :: Manager
loadManager = ( Manager (loadMaze "maps/1.txt") 0 0 0 0 defaultDelayTime )

changeDir :: Orientation -> State -> State
changeDir x (State maze [] l) = State maze [] l
changeDir x (State maze ((Pacman (PacState(i,(a,b),s,o,p,v) t m e)) :pl) lv) | o == x = (State maze ((Pacman (PacState(i,(a,b),s,o,p,v) t m e)) :pl) lv)
                                                                             | otherwise = (State maze ((Pacman (PacState(i,(a,b),s,x,p,v) t m e)) :pl) lv)
changeDir x (State maze (p:pl) l) = addPlayerHead [p] (changeDir x (State maze (pl) l))


updateControlledPlayer :: Key -> Manager -> Manager
updateControlledPlayer KeyLeftArrow  (Manager st pid step b d delay) = Manager (changeDir L st) pid step b d delay
updateControlledPlayer KeyRightArrow (Manager st pid step b d delay) = Manager (changeDir R st) pid step b d delay
updateControlledPlayer KeyDownArrow  (Manager st pid step b d delay) = Manager (changeDir D st) pid step b d delay
updateControlledPlayer KeyUpArrow    (Manager st pid step b d delay) = Manager (changeDir U st) pid step b d delay


updateScreen :: Window  -> ColorID -> Manager -> Curses ()
updateScreen w a man =
                  do
                    updateWindow w $ do
                      --clear
                      setColor a
                      moveCursor 0 0
                      drawString $ show (state man)
                    render

currentTime :: IO Integer
currentTime = fmap ( round . (* 1000) ) getPOSIXTime

updateTime :: Integer -> Manager -> Manager
updateTime now (Manager st pid step b d delay) = (Manager st pid step now (d + (now - b)) delay)

resetTimer :: Integer -> Manager -> Manager
resetTimer now (Manager st pid step b d delay) = (Manager st pid step now 0 delay)

nextFrame :: Integer -> Manager -> Manager
nextFrame now (Manager st pid step b d delay) = resetTimer now (Manager (passTime step st) pid step b d delay)


loop :: Window -> Manager -> Curses ()
loop w man@(Manager s pid step bf delt del ) = do
  color_schema <- newColorID ColorBlue ColorWhite  10
  now <- liftIO  currentTime
  updateScreen w  color_schema man
  if ( delt > del )
    then loop w $ nextFrame now man
    else do
          ev <- getEvent w $ Just 0
          case ev of
                Nothing -> loop w $ updateTime now man
                Just (EventSpecialKey arrow ) -> loop w $ updateControlledPlayer arrow $ updateTime now man
                Just ev' ->
                  if (ev' == EventCharacter 'q')
                    then return ()
                    else loop w $ updateTime now man

main :: IO ()
main =
  runCurses $ do
    setEcho False
    setCursorMode CursorInvisible
    w <- defaultWindow
    loop w loadManager



loadMaze :: String -> State
loadMaze filepath = unsafePerformIO $ readStateFromFile filepath



readStateFromFile :: String -> IO State
readStateFromFile f = do
                content <- readFile f
                let llines = lines content
                    (new_map,pl) = convertLinesToPiece llines 0 []
                return (State new_map pl 1)



convertLinesToPiece :: [String] -> Int -> [Player] -> (Maze,[Player])
convertLinesToPiece [] _ l = ([],l)
convertLinesToPiece (x:xs) n l  = let (a,b) = convertLineToPiece x n 0 l
                                      (a1,b1) = convertLinesToPiece xs (n+1) b
                                  in (a:a1,b1)

convertLineToPiece :: String -> Int -> Int -> [Player] -> ([Piece],[Player])
convertLineToPiece [] _ _ l = ([],l)
convertLineToPiece (z:zs) x y l = let (a,b ) = charToPiece z x y l
                                      (a1,b1) = convertLineToPiece zs x (y+1) b
                                  in (a:a1,b1)


charToPiece :: Char -> Int -> Int -> [Player] -> (Piece,[Player])
charToPiece c x y l
    | c == '{' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Normal ))   :l) )
    | c == '<' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Closed Normal )) :l) )
    | c == '}' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Open Normal ))   :l) )
    | c == '>' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Closed Normal )) :l) )
    | c == 'V' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Open Normal ))   :l) )
    | c == 'v' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Closed Normal )) :l) )
    | c == '^' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Open Normal ))   :l) )
    | c == '|' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Closed Normal )) :l) )
    | c == 'X' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Dying ))    :l) )
    | c == 'M' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Alive))            :l) )
    | c == '?' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Dead))             :l) )
    | c == 'o' =  (Food Big,l)
    | c == '.' =  (Food Little,l)
    | c == '#' =  (Wall,l)
    | otherwise = (Empty,l)


data State = State 
    {
        maze :: Maze
    ,   playersState :: [Player]
    ,   level :: Int
    }

type Maze = [Corridor]
type Corridor = [Piece]
data Piece =  Food FoodType | PacPlayer Player| Empty | Wall deriving (Eq)
data Player =  Pacman PacState | Ghost GhoState deriving (Eq)

data Orientation = L | R | U | D | Null deriving (Eq,Show)
data PacState= PacState 
    {   
        pacState :: PlayerState
    ,   timeMega :: Double
    ,   openClosed :: Mouth
    ,   pacmanMode :: PacMode
    
    } deriving Eq

data GhoState= GhoState 
    {
        ghostState :: PlayerState
    ,   ghostMode :: GhostMode
    } deriving Eq

type Coords = (Int,Int)
type PlayerState = (Int, Coords, Double , Orientation, Int, Int)
--                 (ID,  (x,y), velocity, orientation, points, lives) 
data Mouth = Open | Closed deriving (Eq,Show)
data PacMode = Dying | Mega | Normal deriving (Eq,Show)
data GhostMode = Dead  | Alive deriving (Eq,Show)
data FoodType = Big | Little deriving (Eq)
data Color = Blue | Green | Purple | Red | Yellow | None deriving Eq 

data Play = Move Int Orientation deriving (Eq,Show)

type Instructions = [Instruction]

data Instruction = Instruct [(Int, Piece)]
                 | Repeat Int deriving (Show, Eq)


data Manager = Manager 
    {   
        state   :: State
    ,    pid    :: Int
    ,    step   :: Int
    ,    before :: Integer
    ,    delta  :: Integer
    ,    delay  :: Integer
    } 



instance Show State where
  show (State m ps p) = printMaze mz ++ "Level: " ++ show p ++ "\nPlayers: \n" ++ (foldr (++) "\n" (map (\y-> printPlayerStats y) ps))
                          where mz = placePlayersOnMap ps m

instance Show PacState where
   show ( PacState s o m Dying  ) =  "X"
   show ( PacState (a,b,c,R,i,l) _ Open m  ) =  "{"
   show ( PacState (a,b,c,R,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,L,i,l) _ Open m  ) =  "}"
   show ( PacState (a,b,c,L,i,l) _ Closed m  ) =  ">"
   show ( PacState (a,b,c,U,i,l) _ Open m  ) =  "V"
   show ( PacState (a,b,c,U,i,l) _ Closed m  ) =  "v"
   show ( PacState (a,b,c,D,i,l) _ Open m  ) =  "^"
   show ( PacState (a,b,c,D,i,l) _ Closed m  ) =  "|"
   show ( PacState (a,b,c,Null,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,Null,i,l) _ Open m  ) =  "{"

instance Show Player where
   show (Pacman x ) =  show x
   show ( Ghost x ) =   show x

instance Show GhoState where
   show (GhoState x Dead ) =  "?"
   show (GhoState x Alive ) =  "M"

instance Show FoodType where
   show ( Big ) =  "o"
   show ( Little ) =  "."

instance Show Piece where
   show (  Wall ) = coloredString "#" None
   show (  Empty ) = coloredString " " None
   show (  Food z ) = coloredString (show z )   Green
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Normal ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Normal)  ) Yellow
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Mega   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Mega)  ) Blue
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Dying   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Dying)  ) Red
   show ( PacPlayer (Ghost z) ) = coloredString (show z)  Purple


coloredString :: String -> Color -> String
coloredString x y = x
{-    | y == Blue ="\x1b[36m" ++  x ++ "\x1b[0m"
