-- | função que define os moviemntos possiveis 
getAvailableMoves :: Player -> Maze -> Int
getAvailableMoves p maze = sum (map (\x -> if x == Wall then 0 else 1) [proximaPecaOrientacao R coords maze,proximaPecaOrientacao L coords maze,proximaPecaOrientacao U coords maze ,proximaPecaOrientacao D coords maze])
                     where coords = getPlayerCoords p
-- | função que retorna os movimentos possiveis 
returnAvailableMove :: Player -> Maze -> Play
returnAvailableMove p maze 
 | proximaPecaOrientacao U coords maze /= Wall = Move id U
 | proximaPecaOrientacao D coords maze /= Wall = Move id D
 | proximaPecaOrientacao L coords maze /= Wall = Move id L
 | proximaPecaOrientacao R coords maze /= Wall = Move id R
 where id = getPlayerID p
       coords = getPlayerCoords p
-- |
start :: [Player] -> State -> [Play]
start [] s = []
start (x:xs) s@(State m pl a)
 | not (isPacman x) && getGhostMode x == Alive = (start xs s) ++ [chaseMode s (getPlayerID x)]   
 | not (isPacman x) && getGhostMode x == Dead  = (start xs s) ++ [scatterMode s (getPlayerID x)]
 | otherwise = start xs s
-- | função que define a perseguição do fantasma ao Pacman
chaseMode :: State -> Int -> Play
chaseMode s@(State maze pl a) id 
 | getAvailableMoves ghost maze <= 1 = returnAvailableMove ghost maze
 | otherwise = if (elem (getPlayerOrientation pacman) [R,L]) then (chaseVertical ghost maze pacman) else (chaseHorizontal ghost maze pacman) 
 where ghost = getPlayer id pl
       pacman = lookForPacman pl
-- | função que define quando os fantasmas fogem do Pacman em modo Mega
scatterMode :: State -> Int -> Play
scatterMode s@(State maze pl a) id 
 | dir == R = Move id L
 | dir == L = Move id R
 | dir == U = Move id D
 | dir == D = Move id U
 where (Move idx dir) = chaseMode s id

-- | comportamento vertical do fantasma quando se encontra a perseguir o Pacman
chaseVertical :: Player -> Maze -> Player -> Play
chaseVertical p1 maze p2 
 | isPacman p1 = (Move (getPlayerID p1) Null)
 | y1 > y2 = if proximaPecaOrientacao U (y1,x1) maze /= Wall then (Move idp1 U) else chaseHorizontal p1 maze p2
 | y1 < y2 = if proximaPecaOrientacao D (y1,x1) maze /= Wall then (Move idp1 D) else chaseHorizontal p1 maze p2
 | y1 == y2 && x1 > x2 = if proximaPecaOrientacao L (y1,x1) maze /= Wall then (Move idp1 L) 
                         else if (getPlayerOrientation p2) == U then (Move idp1 D) else (Move idp1 U)
 | y1 == y2 && x1 < x2 = if proximaPecaOrientacao R (y1,x1) maze /= Wall then (Move idp1 R)
                         else if (getPlayerOrientation p2) == D then (Move idp1 D) else (Move idp1 U)
 where (y1,x1) = getPlayerCoords p1
       (y2,x2) = getPlayerCoords p2
       idp1 = getPlayerID p1
-- | comportamento horizontal do fantasma quando se encontrar a perseguir o Pacman
chaseHorizontal :: Player -> Maze -> Player -> Play
chaseHorizontal p1 maze p2 
 | isPacman p1 = (Move (getPlayerID p1) Null)
 | x1 > x2 = if proximaPecaOrientacao L (y1,x1) maze /= Wall then (Move idp1 L) else chaseVertical p1 maze p2
 | x1 < x2 = if proximaPecaOrientacao R (y1,x1) maze /= Wall then (Move idp1 R) else chaseVertical p1 maze p2
 | x1 == x2 && y1 > y2 = if proximaPecaOrientacao U (y1,x1) maze /= Wall then (Move idp1 U) 
                         else if (getPlayerOrientation p2) == R then (Move idp1 L) else (Move idp1 R)
 | x1 == x2 && y1 < y2 = if proximaPecaOrientacao D (y1,x1) maze /= Wall then (Move idp1 D)
                         else if (getPlayerOrientation p2) == R then (Move idp1 L) else (Move idp1 R)
 where (y1,x1) = getPlayerCoords p1
       (y2,x2) = getPlayerCoords p2
       idp1 = getPlayerID p1

proximaPecaOrientacao :: Orientation -> Coords -> Maze -> Piece
proximaPecaOrientacao orientation (x,y) m
 | orientation == R  = if y < ( length (head m)) - 1 then (m !! x) !! (y+1) else Empty
 | orientation == L  = if y > 0 then (m !! x) !! (y-1) else Empty
 | orientation == U  = if x > 0 then (m !! (x-1)) !! y else Empty
 | otherwise = if x < (length m) -1 then (m !! (x+1)) !! y else Empty


ghostPlay :: State -> [Play]
ghostPlay s@(State maze pl a) = start pl s




-- | Função que controi o Labirinto
constroiMSet5 :: Int -> Corridor -> [(Int, Piece)]
constroiMSet5 e [] = []
constroiMSet5 e [x] = [(e,x)]
constroiMSet5 e (x:y:t) | x == y = constroiMSet5 (e + 1) (y:t)
                        | otherwise = (e,x) : constroiMSet5 1 (y:t) 

-- | Função que decide se o tipo do corredor vai ser do tipo repeat ou instruct
repeatoun :: Int -> Maze -> Maze -> Instructions
repeatoun e m [] = []
repeatoun e m (h:t) | e == seraigual m h = Instruct (constroiMSet5 1 h) : repeatoun (e + 1) m t
                    | otherwise = Repeat (seraigual m h) : repeatoun (e + 1) m t

-- | Encontra o indice da primeira vez que um determinado corredor aparece no labirinto 
seraigual :: Maze -> Corridor -> Int
seraigual (h:t) c | h == c = 0
                  | otherwise = 1 + seraigual t c 

-- | Função que compila o Labirinto
compactMaze :: Maze -> Instructions
compactMaze l = repeatoun 0 l l 




players :: [Player]
players =  [jogador1,jogador2]

jogador1 :: Player
jogador1=(Pacman (PacState (1,(7,11),1,R,1,1) 0 Open Normal))

jogador2 :: Player
jogador2=(Ghost (GhoState (0,(5,12),1,R,0,1) Alive ))

-- | Função que nos permite obter uma determinada peça com umas certas coordenadas pertencente ao labirinto 
getPieceFromMaze :: Maze -> Coords ->  Piece
getPieceFromMaze ((h:t):x) (0,0) = h
getPieceFromMaze ((h:t):x) (0,row) = getPieceFromMaze (t:x) (0,row-1)
getPieceFromMaze (x:xs) (col, row) = getPieceFromMaze xs (col-1, row)


-- Função que define o que acontece ao Player caso se encontre com uma Wall
pacnawall :: Player -> Orientation -> Maze -> Player
pacnawall (Pacman(PacState (id, (x,y), a, s, p, d) e r t)) k m | s == L && k == L && y == 0 = (Pacman (PacState (id, (x,(length(head m)-1)), a, L, p, d) e r t))
                                                               | s == R && k == R && y == (length(head m)-1) = (Pacman (PacState (id, (x,0), a, R, p, d) e r t))
                                                               | s == R && k == R = if getPieceFromMaze m (x,y+1) == Wall then (Pacman(PacState (id, (x,y), a, s, p, d) e r t))
                                                                                    else (Pacman (PacState (id, (x,y+1), a, R, p, d) e r t)) 
                                                               | s == L && k == L = if getPieceFromMaze m (x,y-1) == Wall then (Pacman(PacState (id, (x,y), a, s, p, d) e r t))
                                                                                    else (Pacman (PacState (id, (x,y-1), a, L, p, d) e r t))
                                                               | s == U && k == U = if getPieceFromMaze m (x-1,y) == Wall then (Pacman(PacState (id, (x,y), a, s, p, d) e r t))
                                                                                    else (Pacman (PacState (id, (x-1,y), a, U, p, d) e r t))
                                                               | s == D && k == D = if getPieceFromMaze m (x+1,y) == Wall then (Pacman(PacState (id, (x,y), a, s, p, d) e r t))
                                                                                    else (Pacman (PacState (id, (x+1,y), a, D, p, d) e r t)) 
                                                               | otherwise = (Pacman (PacState (id, (x,y), a, k, p, d) e r t))

-- | Função que atualiza os dados do jogadores no labirinto 
atualiza :: Maze -> Player -> Maze
atualiza l (Pacman(PacState (id, (x,y), a, s, p, d) e r t)) = replaceElemInMaze (x,y) Empty l 

-- | Função que nos dá a pontuação do Player
score :: Player -> [Player] -> Maze -> (Player, [Player])
score   (Pacman (PacState (id, (x,y), a, s, p, d) e r t)) ghosts m
           | getPieceFromMaze m (x,y) == Food Big = ((Pacman (PacState (id, (x,y), a, s, p+5, d) e r Mega)), map (\ (Ghost (GhoState (id, coords, vel, orient, pontos, vidas) _))  -> Ghost (GhoState (id, coords, vel/2, orient, pontos, vidas) Dead)) ghosts)
           | getPieceFromMaze m (x,y) == Food Little = ((Pacman (PacState (id, (x,y), a, s, p+1, d) e r t)), ghosts)
           | otherwise = ((Pacman (PacState (id, (x,y), a, s, p, d) e r t)), ghosts)

-- | Função que atualiza o estado do Ghost  
ghostmood :: [Player] -> [Player]
ghostmood [] = []
ghostmood ((Ghost (GhoState (id1, (x1,y1), a1, s1, p1, d1) t1)) : xs) = (Ghost (GhoState (id1, (x1,y1), a1, s1, p1, d1) Dead) : ghostmood xs)


-- | Função que define o que acontece quando um Ghost morre
pacvsghost :: Player -> [Player] -> Maze -> [Player]
pacvsghost (Pacman (PacState (id, (x,y), a, s, p, d) e r t)) [] m = []
pacvsghost (Pacman (PacState (id, (x,y), a, s, p, d) e r t)) ((Ghost (GhoState (id1, (x1,y1), a1, s1, p1, d1) t1)) : xs) m 
              | t == Mega && t1 == Alive = pacvsghost (Pacman (PacState (id, (x,y), a, s, p, d) e r t)) (ghostmood ((Ghost (GhoState (id1, (x1,y1), a1, s1, p1, d1) t1)) : xs)) m 
              | x == x1 && y == y1 && t == Mega && t1 == Dead = (Ghost (GhoState (id1, (div (length m) 2, div (length (head m)) 2), a1, s1, p1, d1) Alive)) : pacvsghost (Pacman (PacState (id, (x,y), a, s, p, d) e r t)) xs m
              | otherwise = (Ghost (GhoState (id1, (x1,y1), a1, s1, p1, d1) t1)) : pacvsghost (Pacman (PacState (id, (x,y), a, s, p, d) e r t)) xs m

-- | Função que de uma lista de Players nos diz os dados do jogador Pacman
findpac :: [Player] -> Player
findpac [] = error "no pacman"
findpac ((Pacman(PacState (id, (x,y), a, s, p, d) e r t)) : t1) = (Pacman(PacState (id, (x,y), a, s, p, d) e r t))
findpac ((Ghost (GhoState (id1, (x1,y1), a1, s1, p1, d1) t1)) : t) = findpac t

-- | Função que de uma lista de Players nos diz quais são Ghosts
findghost :: [Player] -> [Player]
findghost [] = []
findghost ((Pacman(PacState (id, (x,y), a, s, p, d) e r t1)) : t) = findghost t
findghost ((Ghost (GhoState (id1, (x1,y1), a1, s1, p1, d1) t1)) : t) = (Ghost (GhoState (id1, (x1,y1), a1, s1, p1, d1) t1)) : findghost t

-- | Função que define o que acontece ao Pacman quando este encontra um Ghost na mesma Piece
ghostvspac :: Player -> [Player] -> Maze -> Player
ghostvspac (Pacman (PacState (id, (x,y), a, s, p, d) e r t)) [] m = (Pacman (PacState (id, (x,y), a, s, p, d) e r t))
ghostvspac (Pacman (PacState (id, (x,y), a, s, p, d) e r t)) ((Ghost (GhoState (id1, (x1,y1), a1, s1, p1, d1) t1)) : xs) m 
           | x == x1 && y == y1 && t == Mega = ghostvspac (Pacman (PacState (id, (x,y), a, s, p + 10, d) e r t)) xs m
           | x == x1 && y == y1 && t == Normal && t1 == Alive = ghostvspac (Pacman (PacState (id, (x,y), a, s, p, d - 1) e r t)) xs m
           | x == x1 && y == y1 && t == Normal && t1 == Alive && d == 0 = (Pacman (PacState (id, (x,y), a, s, p, d) e r Dying))
           | otherwise = ghostvspac (Pacman (PacState (id, (x,y), a, s, p, d) e r t)) xs m

-- | Esta função junta os fantasmas e o pacman numa lista de Players
todos :: Player -> [Player] -> [Player]
todos (Pacman (PacState (id, (x,y), a, s, p, d) e r t)) [] = [(Pacman (PacState (id, (x,y), a, s, p, d) e r t))]
todos (Pacman (PacState (id, (x,y), a, s, p, d) e r t)) ((Ghost (GhoState (id1, (x1,y1), a1, s1, p1, d1) t1)) : xs) = (Ghost (GhoState (id1, (x1,y1), a1, s1, p1, d1) t1)) : todos (Pacman (PacState (id, (x,y), a, s, p, d) e r t)) xs

-- | a função dá uma jogada e move o pacman no labirinto
play :: Play -> State -> State 
play (Move b o ) (State l j y) = (State (atualiza l (pacnawall pacman o l)) (todos (ghostvspac pacman' ghosts' l)  (pacvsghost pacman' ghosts' l)) y)
        where (pacman', ghosts') = score (pacnawall pacman o l) ghosts l
              pacman = findpac j
              ghosts = findghost j




-- | Gerar a casa dos fantasmas 
ghostHouse :: Int -> Maze
ghostHouse i 
  | even i = [
                  [Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Empty],
                  [Empty,   Wall, Wall, Wall, Empty,   Empty,   Wall, Wall, Wall, Empty],
                  [Empty,   Wall, Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Wall, Empty],
                  [Empty,   Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall, Empty],
                  [Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Empty]
             ]
  | otherwise = [
                  [Empty, Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Empty],
                  [Empty, Wall, Wall, Wall, Empty,   Empty,   Empty,   Wall, Wall, Wall, Empty],
                  [Empty, Wall, Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Wall, Empty],
                  [Empty, Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall, Empty],
                  [Empty, Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Empty,   Empty]
                 ]

-- | Esta função gera as paredes do labirinto com um certo numero de linhas e de colunas  
generateExteriorWalls :: Int -> Int -> Int -> [Int] -> Maze
generateExteriorWalls linha linhas colunas pecas
    | linha == linhas = []
    | linha == 0 || linha == linhas-1 = replicate colunas Wall : generateExteriorWalls (linha+1) linhas colunas pecas
    | odd linhas && linha == div linhas 2 = ([Empty] ++ (map convertePiece (take (colunas-2) pecas)) ++ [Empty]): generateExteriorWalls (linha+1) linhas colunas (drop (colunas-2) pecas)
    | even linhas && (linha == div linhas 2 || linha == div linhas 2 - 1) = ([Empty] ++ (map convertePiece (take (colunas-2) pecas)) ++ [Empty]): generateExteriorWalls (linha+1) linhas colunas (drop (colunas-2) pecas)
    | otherwise = ([Wall] ++ (map convertePiece (take (colunas-2) pecas)) ++ [Wall]): generateExteriorWalls (linha+1) linhas colunas (drop (colunas-2) pecas)

-- | posiciona a casa dos fantasmas no labirinto ja criado utilizando a funçao addGhostHouseCorridor
addGhostHouse :: Int-> Int -> Int -> Maze -> Maze -> Maze
addGhostHouse _ _ _ l [] = l
addGhostHouse linhas colunas linha (c:cs) (g:gs)
    | even linhas && linha <= (div (linhas - 3) 2) - 2 = c : addGhostHouse linhas colunas (linha+1) cs (g:gs)
    | odd linhas && linha < (div (linhas - 3) 2) - 1 = c : addGhostHouse linhas colunas (linha+1) cs (g:gs)
    | otherwise = addGhostHouseCorridor colunas 0 c g : addGhostHouse linhas colunas (linha+1) cs gs

-- | funçao auxiliar da funçao addGhostHouse, esta função é utilizada para auxiliar na colocaçao da casa dos fantasmas no labirinto pois posiciona a casa no labirinto consoante o numero de colunas 
addGhostHouseCorridor :: Int -> Int -> Corridor -> Corridor -> Corridor
addGhostHouseCorridor _ _ l [] = l
addGhostHouseCorridor colunas coluna (x:xs) (y:ys)
    | even colunas && coluna <= (div (colunas - 9) 2) - 1= x : addGhostHouseCorridor colunas (coluna + 1) xs (y:ys)
    | odd colunas && coluna < (div (colunas - 8) 2) - 1 = x : addGhostHouseCorridor colunas (coluna + 1) xs (y:ys)
    | otherwise = y : addGhostHouseCorridor colunas (coluna+1) xs ys

-- Gerar um labirinto com uma dada largura, altura e semente.
generateMaze :: Int -> Int -> Int -> Maze
generateMaze colunas linhas semente = ghosthouse
    where walls = generateExteriorWalls 0 linhas colunas (geraAleatorios (linhas * colunas - 2 * linhas - 2 * (colunas -2)) semente)
          ghosthouse = addGhostHouse linhas colunas 0 walls (ghostHouse colunas)


data Manager = Manager 
    {   
        state   :: State
    ,    pid    :: Int
    ,    step   :: Int
    ,    before :: Integer
    ,    delta  :: Integer
    ,    delay  :: Integer
    } 


loadManager :: Manager
loadManager = ( Manager (loadMaze "maps/1.txt") 0 0 0 0 defaultDelayTime )

updateControlledPlayer :: Key -> Manager -> Manager
updateControlledPlayer k m@(Manager (State lab ps l) pid step before delta delay)
                      | k == KeyUpArrow = (Manager (State lab (y : (apanhaFantasma ps)) l) pid step before delta delay)
                      | k == KeyLeftArrow = (Manager (State lab (y : (apanhaFantasma ps)) l) pid step before delta delay)
                      | k == KeyRightArrow = (Manager (State lab (y : (apanhaFantasma ps)) l) pid step before delta delay)
                      | k == KeyDownArrow = (Manager (State lab (y : (apanhaFantasma ps)) l) pid step before delta delay)
                  where pac = (findpac ps)
                        y = oriByKey k pac

                        
oriByKey :: Key -> Player -> Player 
oriByKey k (Pacman (PacState (id,(x,y),vel,ori,point,life) t b d))
        | k == KeyUpArrow = (Pacman (PacState (id,(x,y),vel,U,point,life) t b d))
        | k == KeyDownArrow = (Pacman (PacState (id,(x,y),vel,D,point,life) t b d))
        | k == KeyLeftArrow = (Pacman (PacState (id,(x,y),vel,L,point,life) t b d))
        | k == KeyRightArrow = (Pacman (PacState (id,(x,y),vel,R,point,life) t b d)) 

updateScreen :: Window  -> ColorID -> Manager -> Curses ()
updateScreen w a man =
                  do
                    updateWindow w $ do
                      clear
                      setColor a
                      moveCursor 0 0 
                      drawString $ show (state man)
                    render
     
currentTime :: IO Integer
currentTime = fmap ( round . (* 1000) ) getPOSIXTime

updateTime :: Integer -> Manager -> Manager
updateTime now man = man {delta = (now - before man)} 

resetTimer :: Integer -> Manager -> Manager
resetTimer now man = man {delta = 0, before = now} 

nextFrame :: Integer -> Manager -> Manager
nextFrame now man =  let update = (resetTimer now man) 
                     in update { state= (passTime (step man) (state man)), step = (step man) +1 } 

loop :: Window -> Manager -> Curses ()
loop w man@(Manager s pid step bf delt del ) = do 
  color_schema <- newColorID ColorBlue ColorWhite  10
  now <- liftIO  currentTime
  updateScreen w  color_schema man
  if ( delt > del )
    then loop w $ nextFrame now man
    else do
          ev <- getEvent w $ Just 0
          case ev of
                Nothing -> loop w (updateTime now man)
                Just (EventSpecialKey arrow ) -> loop w $ updateControlledPlayer arrow (updateTime now man)
                Just ev' ->
                  if (ev' == EventCharacter 'q')
                    then return ()
                    else loop w (updateTime now man)

main :: IO ()
main =
  runCurses $ do
    setEcho False
    setCursorMode CursorInvisible
    w <- defaultWindow
    loop w loadManager



type Maze = [Corridor]
type Corridor = [Piece]
data Piece = Food FoodType | Wall | Empty
data FoodType = Big | Little

instance Show Piece where
    show (Food Big) = "o"
    show (Food Little) = "."
    show (Wall) = "#"
    show (Empty) = " "

