                [Empty, Food Little, Food Little, Food Big, Food Little, Food Big, Food Little, Empty],
                [Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall]
            ]


-- | Given a seed returns a list of n integer randomly generated
--
geraAleatorios :: Int -> Int -> [Int]
geraAleatorios n seed = let gen = mkStdGen seed -- creates a random generator
                        in take n $ randomRs (0,9) gen -- takes the first n elements from an infinite series of random numbers between 0-9


-- | Given a seed returns an integer randomly generated
--
nrAleatorio :: Int -> Int
nrAleatorio seed = head $ geraAleatorios 1 seed


-- Converssta list into a list of list of size n
--
subLista :: Int -> [a] -> [[a]]
subLista _ [] = []
subLista n l = take n l: subLista n (drop n l)


-- | Converts an integer number into a Piece
-- 3 <=> Food Granfre
-- 0 <= n < 7 <=> Food Little
-- 7 < n <= 9 <=> Wall
--
convertePiece :: Int -> Piece
convertePiece = undefined


-- | Converts a Corridor to a string
--
printCorridor :: Corridor -> String
printCorridor = undefined


-- | Converts a Maze to a string
--
printMaze :: Maze -> String
printMaze = undefined


-- | Converts a list of integers into a Corridor
--
converteCorridor :: [Int] -> Corridor
converteCorridor = undefined


-- | Converts a list of lists of integers into a Maze
--
converteMaze :: [[Int]] -> Maze
converteMaze = undefined


geraMaze :: Int -> Int -> Int -> IO ()
geraMaze x y s =
                 let random_nrs = geraAleatorios (x*y) s
                 in putStrLn $ printMaze $ converteMaze $ subLista x random_nrs




loadMaze :: String -> State
loadMaze filepath = unsafePerformIO $ readStateFromFile filepath



readStateFromFile :: String -> IO State
readStateFromFile f = do
                content <- readFile f
                let llines = lines content 
                    (new_map,pl) = convertLinesToPiece llines 0 []
                return (State new_map pl 1)



convertLinesToPiece :: [String] -> Int -> [Player] -> (Maze,[Player])
convertLinesToPiece [] _ l = ([],l)
convertLinesToPiece (x:xs) n l  = let (a,b) = convertLineToPiece x n 0 l 
                                      (a1,b1) = convertLinesToPiece xs (n+1) b
                                  in (a:a1,b1)

convertLineToPiece :: String -> Int -> Int -> [Player] -> ([Piece],[Player])
convertLineToPiece [] _ _ l = ([],l)
convertLineToPiece (z:zs) x y l = let (a,b ) = charToPiece z x y l
                                      (a1,b1) = convertLineToPiece zs x (y+1) b 
                                  in (a:a1,b1)


charToPiece :: Char -> Int -> Int -> [Player] -> (Piece,[Player])
charToPiece c x y l
    | c == '{' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Normal ))   :l) )
    | c == '<' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Closed Normal )) :l) )
    | c == '}' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Open Normal ))   :l) )
    | c == '>' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Closed Normal )) :l) )
    | c == 'V' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Open Normal ))   :l) )
    | c == 'v' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Closed Normal )) :l) )
    | c == '^' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Open Normal ))   :l) )
    | c == '|' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Closed Normal )) :l) )
    | c == 'X' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Dying ))    :l) )
    | c == 'M' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Alive))            :l) )
    | c == '?' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Dead))             :l) )
    | c == 'o' =  (Food Big,l)
    | c == '.' =  (Food Little,l)
    | c == '#' =  (Wall,l)
    | otherwise = (Empty,l)



data State = State 
    {
        maze :: Maze
    ,   playersState :: [Player]
    ,   level :: Int
    }

type Maze = [Corridor]
type Corridor = [Piece]
data Piece =  Food FoodType | PacPlayer Player| Empty | Wall deriving (Eq)
data Player =  Pacman PacState | Ghost GhoState deriving (Eq)

data Orientation = L | R | U | D | Null deriving (Eq,Show)
data PacState= PacState 
    {   
        pacState :: PlayerState
    ,   timeMega :: Double
    ,   openClosed :: Mouth
    ,   pacmanMode :: PacMode
    
    } deriving Eq

data GhoState= GhoState 
    {
        ghostState :: PlayerState
    ,   ghostMode :: GhostMode
    } deriving Eq

type Coords = (Int,Int)
type PlayerState = (Int, Coords, Double , Orientation, Int, Int)
--                 (ID,  (x,y), velocity, orientation, points, lives) 
data Mouth = Open | Closed deriving (Eq,Show)
data PacMode = Dying | Mega | Normal deriving (Eq,Show)
data GhostMode = Dead  | Alive deriving (Eq,Show)
data FoodType = Big | Little deriving (Eq)
data Color = Blue | Green | Purple | Red | Yellow | None deriving Eq 

data Play = Move Int Orientation deriving (Eq,Show)

type Instructions = [Instruction]

-- | data Instruction é o que uma Instruction é 
--

data Instruction = Instruct [(Int, Piece)]
                 | Repeat Int deriving (Show, Eq)

-- | Mostrar os niveis e o players do jogo
--
instance Show State where
  show (State m ps p) = printMaze mz ++ "Level: " ++ show p ++ "\nPlayers: \n" ++ (foldr (++) "\n" (map (\y-> printPlayerStats y) ps))
                          where mz = placePlayersOnMap ps m

-- | mostrar os vários "aspetos" que um Pac tem
--

instance Show PacState where
   show ( PacState s o m Dying  ) =  "X"
   show ( PacState (a,b,c,R,i,l) _ Open m  ) =  "{"
   show ( PacState (a,b,c,R,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,L,i,l) _ Open m  ) =  "}"
   show ( PacState (a,b,c,L,i,l) _ Closed m  ) =  ">"
   show ( PacState (a,b,c,U,i,l) _ Open m  ) =  "V"
   show ( PacState (a,b,c,U,i,l) _ Closed m  ) =  "v"
   show ( PacState (a,b,c,D,i,l) _ Open m  ) =  "^"
   show ( PacState (a,b,c,D,i,l) _ Closed m  ) =  "|"
   show ( PacState (a,b,c,Null,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,Null,i,l) _ Open m  ) =  "{"

-- | mostrar o player
--


instance Show Player where
   show (Pacman x ) =  show x
   show ( Ghost x ) =   show x

-- | mostrar a imagem de uma player
--

instance Show GhoState where
   show (GhoState x Dead ) =  "?"
   show (GhoState x Alive ) =  "M"

-- | mostrar uma piece
--

instance Show FoodType where
   show ( Big ) =  "o"
   show ( Little ) =  "."

-- | mostrar a piece associada ao player
--

instance Show Piece where
   show (  Wall ) = coloredString "#" None
   show (  Empty ) = coloredString " " None
   show (  Food z ) = coloredString (show z )   Green
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Normal ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Normal)  ) Yellow
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Mega   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Mega)  ) Blue
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Dying   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Dying)  ) Red
   show ( PacPlayer (Ghost z) ) = coloredString (show z)  Purple

-- | coloredString
--


coloredString :: String -> Color -> String
coloredString x y
    | y == Blue ="\x1b[36m" ++  x ++ "\x1b[0m"
    | y == Red = "\x1b[31m" ++ x ++ "\x1b[0m"
    | y == Green = "\x1b[32m" ++ x ++ "\x1b[0m"
    | y == Purple ="\x1b[35m" ++ x ++ "\x1b[0m"
    | y == Yellow ="\x1b[33m" ++ x ++ "\x1b[0m"
    | otherwise =  "\x1b[0m" ++ x 

-- | placePlayersOnMap é para colocar o player num Maze
--

placePlayersOnMap :: [Player] -> Maze -> Maze
placePlayersOnMap [] x = x
placePlayersOnMap (x:xs) m = placePlayersOnMap xs ( replaceElemInMaze (getPlayerCoords x) (PacPlayer x) m )


-- | printMaze é para imprimir o Maze
--


printMaze :: Maze -> String
printMaze []  =  ""
printMaze (x:xs) = foldr (++) "" ( map (\y -> show y) x )  ++ "\n" ++ printMaze ( xs )

-- |printPlayerStats é para imprimir os Stats do player
--

printPlayerStats :: Player -> String
printPlayerStats p = let (a,b,c,d,e,l) = getPlayerState p
                     in "ID:" ++ show a ++  " Points:" ++ show e ++ " Lives:" ++ show l ++"\n"

-- | getPlayerId é para me dar o ID de um player
--

getPlayerID :: Player -> Int
getPlayerID (Pacman (PacState (x,y,z,t,h,l) q c d )) = x
getPlayerID  (Ghost (GhoState (x,y,z,t,h,l) q )) = x
 
-- | getPlayerPoints é para me dar os pontos que um player possui 
--

getPlayerPoints :: Player -> Int
getPlayerPoints (Pacman (PacState (x,y,z,t,h,l) q c d )) = h
getPlayerPoints (Ghost (GhoState (x,y,z,t,h,l) q )) = h

-- | setPlayerCoords serve para dar uma nova orientação de um player
--

setPlayerCoords :: Player -> Coords -> Player
setPlayerCoords (Pacman (PacState (x,y,z,t,h,l) q c d )) (a,b) = Pacman (PacState (x,(a,b),z,t,h,l) q c d )
setPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) q )) (a,b) = Ghost (GhoState (x,(a,b),z,t,h,l) q )

-- |getPieceOrientation serve para me dar a orientação de uma piece
--

getPieceOrientation :: Piece -> Orientation
getPieceOrientation (PacPlayer p) =  getPlayerOrientation p
getPieceOrientation _ = Null


-- | getPacmanMode ser para me dar o Mode do player pacman
--

getPacmanMode :: Player -> PacMode
getPacmanMode (Pacman (PacState a b c d)) = d


-- | getPlayerState serve para me dar um estado em que um player está
--
  
getPlayerState :: Player -> PlayerState
getPlayerState (Pacman (PacState a b c d )) = a
getPlayerState (Ghost (GhoState a b )) = a

-- | getPlayerOrientation serve para dar me a orientação de um player
--

getPlayerOrientation :: Player -> Orientation
getPlayerOrientation (Pacman (PacState (x,y,z,t,h,l) q c d )) = t
getPlayerOrientation  (Ghost (GhoState (x,y,z,t,h,l) q )) = t

-- |replaceElemInMaze serve para substituir umaa Piece num Maze
--

replaceElemInMaze :: Coords -> Piece -> Maze -> Maze
replaceElemInMaze (a,b) _ [] = []
replaceElemInMaze (a,b) p (x:xs) 
  | a == 0 = replaceNElem b p x : xs 
  | otherwise = x : replaceElemInMaze (a-1,b) p xs


-- | replaceNElem serve para fazer replace de um Int num maze
--

replaceNElem :: Int -> a -> [a] -> [a]
replaceNElem i _ [] = [] 
replaceNElem i el (x:xs)
  |  i == 0 = el : xs 
  | otherwise =  x : replaceNElem (i-1) el xs

-- |getPlayerCoords serve para dar as coords de um player 
--

getPlayerCoords :: Player -> Coords
getPlayerCoords (Pacman (PacState (x,y,z,t,h,l) b c d )) = y
getPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) b )) = y



--bot :: Int -> State -> Maybe Play
--bot id (State maze [(Ghost (GhoState (x1,y1,z1,t1,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level) | 

getStateFromManager :: Manager -> State 
getStateFromManager (Manager state pid step before delta delay) = state

seeIfStepChanged :: Manager -> Manager -> Bool 
seeIfStepChanged (Manager state pid step before delta delay) (Manager state1 pid1 step1 before1 delta1 delay1) | step1 == step + 1 = True 
                                                                                                               | otherwise = False 



{- |
= Introdução

A tarefa 5 foi uma tarefa na qual definimos o código para a realização do jogo PacMan, mais precisamente a movimentação dos Ghosts
no maze e as suas caracteristicas.

= Objetivos

O nosso principal objetivo era criar uma jogo em que os fantasmas também fizessem movimentações
como o Pacman, usando Play's 

Para isso definimos várias funções em que conseguisse-mos retirar de um state, os seus players e os seus ID's para depois 
fazer-mos jogadas com os fantasmas.

Começamos por ver se aparecia uma parede á frente do Ghost, para quando isso aconter ele determinar as coordenadas 
do Pacman no maze.(foundWall)
Seguindo tentamos determinar qual seria o caminho mais curto para chegar até ao Pacman (ghostTriesBestOrientation)
depois de definir essa função junta-mos ao chaseMode para quando o Ghost estiver Alive possa perseguir o Pacman

Depois fizemos para quando o Ghost estiver Dead, ele "fugir" do Pacman, que para isto acontecer o Pacman teria de 
estar no modo Mega.Para isso criamos uma função que quando o Ghost está Dead e bate contra uma parede este
muda a sua Orientação para a sua direita (ghostTurnsToTheRight).

Também usámos

Para além de quando o Pacman entra em estado Mega, todos os ghosts passam para o modo Dead, que tá tinhamos definido
na Tarefa2 da primeira Fase.


= Discussão e conclusão

Com isto conseguimos fazer jogadas para os fantasmas, faze-los "correr" atrás dos Pac's quando isso lhes
permitir e "fugir" dos Pac's, tanto quanto possivel 



-}







-- | ghostPlay serve para fazer uma série de jogadas dos ghosts
--

ghostPlay :: State -> [Play]
ghostPlay (State maze [(Ghost (GhoState (x1,y1,z1,t1,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level) = [(chaseMode (State maze [(Ghost (GhoState (x1,y1,z1,t1,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level) x1), scatterMode (State maze [(Ghost (GhoState (x1,y1,z1,t1,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level) x1 ]
                                                                                                                                                                   
 
-- | oppositeOrientationOfGhost criei para mudar a orientação do fantasma para uma nova orientação 
-- 

oppositeOrientationOfGhost :: Player -> Player 
oppositeOrientationOfGhost (Ghost (GhoState (x,y,z,U,h,l) q )) = setPlayerOrientation (Ghost (GhoState (x,y,z,U,h,l) q )) D 
oppositeOrientationOfGhost (Ghost (GhoState (x,y,z,D,h,l) q )) = setPlayerOrientation (Ghost (GhoState (x,y,z,D,h,l) q )) U 
oppositeOrientationOfGhost (Ghost (GhoState (x,y,z,R,h,l) q )) = setPlayerOrientation (Ghost (GhoState (x,y,z,R,h,l) q )) L
oppositeOrientationOfGhost (Ghost (GhoState (x,y,z,L,h,l) q )) = setPlayerOrientation (Ghost (GhoState (x,y,z,L,h,l) q )) R


-- | ghostRunsAwayFromPac criei para quando o Ghost está Dead muda para a Orientação oposta á que tinha
--

ghostTurnsToTheRight ::  State -> Play 
ghostTurnsToTheRight (State maze [(Ghost (GhoState (idGhost,y1,z1,t1,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level)| getPlayerOrientation (Ghost (GhoState (idGhost,y1,z1,t1,h1,l1) q1 )) == U && getGhostMode (Ghost (GhoState (idGhost,y1,z1,t1,h1,l1) q1 )) == Dead = (Move idGhost R) 
                                                                                                                                  | getPlayerOrientation (Ghost (GhoState (idGhost,y1,z1,t1,h1,l1) q1 )) == R && getGhostMode (Ghost (GhoState (idGhost,y1,z1,t1,h1,l1) q1 )) == Dead = (Move idGhost D)
                                                                                                                                  | getPlayerOrientation (Ghost (GhoState (idGhost,y1,z1,t1,h1,l1) q1 )) == D && getGhostMode (Ghost (GhoState (idGhost,y1,z1,t1,h1,l1) q1 )) == Dead = (Move idGhost L)
                                                                                                                                  | getPlayerOrientation (Ghost (GhoState (idGhost,y1,z1,t1,h1,l1) q1 )) == L && getGhostMode (Ghost (GhoState (idGhost,y1,z1,t1,h1,l1) q1 )) == Dead = (Move idGhost U)
  

-- | getGhostId esta função serve para me dar o ID do ghost
--

getGhostId :: Player -> State  -> Int 
getGhostId (Ghost (GhoState (x,y,z,t,h,l) q )) state = x 


-- | ghostTriesBestOrientation fiz para o ghost achar a orientação mais adequada á posição do pac
--

ghostTriesBestOrientation :: Coords -> State -> Orientation 
ghostTriesBestOrientation coord (State maze [(Ghost (GhoState (x,(abcissa,ordenada),z,t,h,l) q ))] level) | getGhostMode (Ghost (GhoState (x,(abcissa,ordenada),z,t,h,l) q )) == Alive && abs (abcissa-fst coord) == abs (ordenada-snd coord) && (abcissa-fst coord) < 0 = U 
                                                                                             | getGhostMode (Ghost (GhoState (x,(abcissa,ordenada),z,t,h,l) q )) == Alive && abs (abcissa-fst coord) == abs (ordenada-snd coord) && (abcissa-fst coord) > 0 = D 
                                                                                             | getGhostMode (Ghost (GhoState (x,(abcissa,ordenada),z,t,h,l) q )) == Alive && abs (abcissa-fst coord) > abs (ordenada-snd coord) && (abcissa-fst coord) < 0 = R
                                                                                             | getGhostMode (Ghost (GhoState (x,(abcissa,ordenada),z,t,h,l) q )) == Alive && abs (abcissa-fst coord) > abs (ordenada-snd coord) && (abcissa-fst coord) > 0 = L 
                                                                                             | getGhostMode (Ghost (GhoState (x,(abcissa,ordenada),z,t,h,l) q )) == Alive && abs (abcissa-fst coord) < abs (ordenada-snd coord) && (abcissa-fst coord) < 0 = U
                                                                                             | getGhostMode (Ghost (GhoState (x,(abcissa,ordenada),z,t,h,l) q )) == Alive && abs (abcissa-fst coord) < abs (ordenada-snd coord) && (abcissa-fst coord) > 0 = D 
                                                                                             | getGhostMode (Ghost (GhoState (x,(abcissa,ordenada),z,t,h,l) q )) == Alive && snd coord == ordenada && (fst coord-abcissa) < 0 = L
                                                                                             | getGhostMode (Ghost (GhoState (x,(abcissa,ordenada),z,t,h,l) q )) == Alive && fst coord == abcissa && (snd coord-ordenada) < 0 = D 
                                                                                             | getGhostMode (Ghost (GhoState (x,(abcissa,ordenada),z,t,h,l) q )) == Alive && fst coord == abcissa && (snd coord-ordenada) > 0 = U 
                                                                                             | getGhostMode (Ghost (GhoState (x,(abcissa,ordenada),z,t,h,l) q )) == Alive && snd coord == ordenada && (fst coord-abcissa) > 0 = R  


-- | foundWall serve para ver se o Ghost encontrou uma parede
--


foundWall :: State -> Int -> State 
foundWall (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,D,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level) id | id == idGhost && getPieceOnCoord maze (abcissa,ordenada-1) == Wall = (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,D,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level)
foundWall (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,U,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level) id | id == idGhost && getPieceOnCoord maze (abcissa,ordenada+1) == Wall = (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,U,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level)
foundWall (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,L,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level) id | id == idGhost && getPieceOnCoord maze (abcissa-1,ordenada) == Wall = (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,L,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level)
foundWall (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,R,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level) id | id == idGhost && getPieceOnCoord maze (abcissa+1,ordenada) == Wall = (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,R,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level)

-- | getPacCoordsFromState serve para me dar as coordenadas do pac através de um state
-- 

getPacCoordsFromState :: State -> Coords
getPacCoordsFromState (State maze [(Ghost (GhoState (x,y,z,t,h,l) q )),(Pacman (PacState (x',y',z',t',h',l') q' c1' d' )) ] level ) = y'   

-- | givePacCoordsWhenGhostInWall serve para dar as coords do pac quando o ghost bate numa parede
--

givePacCoordsWhenGhostInWall :: State -> Int -> Coords 
givePacCoordsWhenGhostInWall (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level) id = getPacCoordsFromState ( foundWall (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level) id)

-- | chaseMode para fazer a perseguição ao pac
-- 

chaseMode :: State -> Int -> Play  
chaseMode (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level) id 
                                                                                                                                        | id == idGhost && getPieceOnCoord maze (abcissa-1,ordenada) == Wall && getGhostMode (Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 )) == Alive && t1 == U = (Move id (ghostTriesBestOrientation  (givePacCoordsWhenGhostInWall (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level) id) (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 ))] level)))
                                                                                                                                        | id == idGhost && getPieceOnCoord maze (abcissa+1,ordenada) == Wall && getGhostMode (Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 )) == Alive && t1 == D = (Move id (ghostTriesBestOrientation  (givePacCoordsWhenGhostInWall (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level) id) (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 ))] level)))
                                                                                                                                        | id == idGhost && getPieceOnCoord maze (abcissa,ordenada+1) == Wall && getGhostMode (Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 )) == Alive && t1 == R = (Move id (ghostTriesBestOrientation  (givePacCoordsWhenGhostInWall (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level) id) (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 ))] level)))
                                                                                                                                        | id == idGhost && getPieceOnCoord maze (abcissa,ordenada-1) == Wall && getGhostMode (Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 )) == Alive && t1 == L = (Move id (ghostTriesBestOrientation  (givePacCoordsWhenGhostInWall (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level) id) (State maze [(Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 ))] level)))
                                                                                                                                        | id == idGhost && getGhostMode (Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 )) == Alive && t1 == D = (Move idGhost D)
                                                                                                                                        | id == idGhost && getGhostMode (Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 )) == Alive && t1 == L = (Move idGhost L)
                                                                                                                                        | id == idGhost && getGhostMode (Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 )) == Alive && t1 == R = (Move idGhost R)
                                                                                                                                        | id == idGhost && getGhostMode (Ghost (GhoState (idGhost,(abcissa,ordenada),z1,t1,h1,l1) q1 )) == Alive && t1 == U = (Move idGhost U)



-- | scatterMode para o ghost fugir do pac quando o ghost está Dead
--

scatterMode :: State -> Int -> Play
scatterMode (State maze [(Ghost (GhoState (x,y,z,t,h,l) q )), (Pacman (PacState (x1,y1,z1,t1,h1,l1) q1 c1 d1 ))] level) id | getGhostMode (Ghost (GhoState (x,y,z,t,h,l) q )) == Dead  && id == x && getPacmanMode (Pacman (PacState (x1,y1,z1,t1,h1,l1) q1 c1 d1 )) == Mega = (ghostTurnsToTheRight (foundWall (State maze [(Ghost (GhoState (x,y,z,t,h,l) q ))] level) id)) 
                                                                                                                           | id == x = (Move id t)
                                                                                                                             








