defaultDelayTime = 250 -- 250 ms
defaultBeforeTime = 62.5 -- 62.5 ms tempo que demora 1 jogada 


data Manager = Manager 
    {   
         state :: State
    ,    pid    :: Int                              -- ID do jogador 
    ,    step :: Int                                -- número que indica por quantas iterações o jogo já passou
    ,    before :: Integer                          -- instante de tempo de tempo em que foi efetuada a última jogada
    ,    delta :: Integer                           -- tempo decorrido em milissegundos desde a última jogada
    ,    delay :: Integer                           -- representa o intervalo de tempo entre jogadas (em milissegundos)
    } 

-- | passTime serve para a partir de um step fazer uma iteração
--

passTime :: Int -> State -> State
passTime step (State maze [(Ghost (GhoState (x1,y1,z1,t1,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level) = play (Move x t) (State maze [(Ghost (GhoState (x1,y1,z1,t1,h1,l1) q1 )),(Pacman (PacState (x,y,z,t,h,l) q c d ))] level)

-- | giveAllPlayersFromState criei com o intuito de dar me a lista de todos os jogadores do State
--

giveAllPlayersFromState :: State -> [Player]
giveAllPlayersFromState (State maze playersState level) = playersState 

-- | getStepFromManager serve para retirar o step de um Manager
--

getStepFromManager :: Manager -> Int 
getStepFromManager (Manager state pid step before delta delay) = step

-- | checkIfPacmanIsInMega serve para ver se num State o Pac está em mode Mega
--

checkIfPacmanIsInMega :: Player -> State -> Bool 
checkIfPacmanIsInMega (Pacman (PacState a b c d)) state | d == Mega = True 
                                                        | otherwise  = False  

-- | timeInMega criei para me dar o tempo que o pacMan está em estado Mega
--

timeInMega :: Player -> Double 
timeInMega (Pacman (PacState (x,y,z,t,h,l) q c d )) = q    

-- | getStateFromManager serve para retirar o state a partir de um manager 
--

getStateFromManager :: Manager -> State 
getStateFromManager (Manager state pid step before delta delay) = state 


-- | pacmanGoesToNormalMode criei para retornar o pacMan para Normal mode quando o tempo Mega == 0 
-- 

pacmanGoesToNormalMode :: Player -> Manager -> Player 
pacmanGoesToNormalMode (Pacman (PacState (x,y,z,t,h,l) q c d )) man | timeInMega (Pacman (PacState (x,y,z,t,h,l) q c d )) == 0 = setPacManMode (Pacman (PacState (x,y,z,t,h,l) q c d )) Normal  
                                                                     
-- | setPacManMode criei para mudar o estado do pacMan p 
--

setPacManMode :: Player -> PacMode  -> Player 
setPacManMode (Pacman (PacState (x,y,z,t,h,l) q c d )) pacMode = Pacman (PacState (x,y,z,t,h,l) q c pacMode ) 

-- | decreaseTimeInMega serve para diminuir o tempo que o pacMan está em estado Mega
-- 

decreaseTimeInMega :: Player -> Manager -> Player 
decreaseTimeInMega (Pacman (PacState (x,y,z,t,h,l) q c d )) (Manager state pid step before delta delay ) = (Pacman (PacState (x,y,z,t,h,l) (q - defaultBeforeTime) c d )) 
 
-- | ghostGoesToAliveMode serve para colocar o Ghost em modo Alive depois do pacMan perder o estado Mega
--

ghostGoesToAliveMode :: Player -> Player -> State -> Player 
ghostGoesToAliveMode (Ghost (GhoState a b )) (Pacman (PacState (x,y,z,t,h,l) q c d )) state | timeInMega (Pacman (PacState (x,y,z,t,h,l) q c d )) == 0 = setGhostMode (Ghost (GhoState a b )) Alive

-- | getPacManMouth criei com o intuito de dar-me a "boca" do pacMan
--

getPacManMouth :: Player -> Mouth 
getPacManMouth ( Pacman ( PacState (i, c, x, y,z,l) o m d ) ) = m 


-- | setPacMouth serve para mudar a boca do Pac
--

setPacMouth :: Player -> Mouth -> Player 
setPacMouth (Pacman (PacState (x,y,z,t,h,l) q c d )) newMouth = (Pacman (PacState (x,y,z,t,h,l) q newMouth d ))









{- |
= Introdução

Nesta tarefa o objetivo foi converter um labirinto válido numa sequencia de instruções
que torna a leitura mais fácil

= Objetivos

Começamos por definir uma função chamada convertHorizontal com o intuito de verificar se existiam peças 
iguais seguidas e junta-las.

Depois foi a função convertVertical que dá um conjunto de Instruções na vertical

No final foi juntar essas funções compactMaze, para no final dar a lista de instruções
de um labirinto inteiro


= Discussão e conclusão

Conseguimos obter os resultados esperados, dando instruções certas de 
um labirinto

-}





-- | compactMaze serve para a partir de uma maze devolver uma lista de Instructions
--

compactMaze m = reverse  (
     convertVertical (
        reverse ((map convertHorizontal ( map convertCorridor  m )))))

-- |convertPiecetoInstructions criei com o intuito de converter uma peça numa instrução
--

convertPiecetoInstructions :: Piece -> (Int, Piece)
convertPiecetoInstructions piece = (1,piece)

-- | convertCorridor criei com o intuito de a partir de um corredor dár-me uma lista de Int e pieces
--

convertCorridor:: Corridor -> [(Int, Piece)]
convertCorridor c = map convertPiecetoInstructions c

-- | convertHorizontal criei com o intuito de verificar se existiam peças iguais seguidas e junta-las
--

convertHorizontal :: [(Int, Piece)] -> [(Int, Piece)]
convertHorizontal [] = []
convertHorizontal ( p : ps) = if (length ps > 0) && (snd p) == ( snd (ps!!0)) then convertHorizontal (((fst p) +1, snd p) : drop 1 ps)
    else p : convertHorizontal ps


-- | convertVertical serve para me dar Instruções na vertical
--

convertVertical :: [[(Int, Piece)]] -> Instructions 
convertVertical [] = []
convertVertical (p : ps ) = let idx = findIndex (==p) (reverse ps)
                            in if idx == Nothing then (Instruct p) : convertVertical ps else 
                                (Repeat (fromMaybe 0 idx)) : convertVertical ps






{- |
= Introdução

Nesta tarefa o objetivo foi efetuar jogadas com os players do State, e com isto também 
atribuir-lhe algumas caracteristicas

= Objetivos

Começamos por verificar se seria possivel com uma jogada mudar de posição, pos os players
podiam apanhar uma parede.

Depois começamos por atribuir as "caracteristicas" que tinham que ter para quando fizessem
jogadas, como a função updatePlayerByPiece, sendPlayerToOthersideOfTunnel e outras funções.

Depois juntá-mos todas essas funções na função play, para que no final possam efetuar jogadas


= Discussão e conclusão

Conseguimos o resultado que queriamos, fazer jogadas com o Pac ou até mesmo os Ghosts e com 
as suas "caracteristicas" a funcionar como quando comem uma comida ganham um ponto, juntamente com
outras.


-}



-- | o getPlayerById criei com o intuito de obter um player consuante o seu ID
--

getPlayerById :: Int -> State -> Player
getPlayerById id state = filter (\p -> getPlayerID p == id) (playersState state )!!0


-- | a função play foi para fazer uma jogada de um player dando uma nova orientação
--

play :: Play -> State -> State
play (Move playerId newOrientation) state = if checkIfOrientationChanged (Move playerId newOrientation) state then 
                        updatePlayerInState (setPlayerOrientation (getPlayerById playerId state) newOrientation ) state   
                    else (if canPositionChange (Move playerId newOrientation) state 
                        then let player = getPlayerById playerId state
                            in processAction player (playerTargetCoords player (maze state) newOrientation) state
                    else state
                     )


-- | a função canPositionChange criei com o intuito de verificar se com uma jogada posso mudar de posição
--

canPositionChange:: Play -> State -> Bool
canPositionChange _play state = getPieceOnCoord (maze state) (playerTargetCoords (getPlayerById (getIdFromPlay _play) state) (maze state) (getOrientationFromPlay _play) ) /= Wall -- Esta função diz-me se é possivel mover o jogador
                                                                                                                                                                      -- se na posição seguinte estiver uma parede retorna um Bool

-- | criei com o intuito de fazer um novo state
-- 

processAction:: Player -> Coords -> State -> State
processAction player targetCoords state = let piece = getPieceOnCoord (maze state) targetCoords
                                          in updatePlayerByPiece (setPlayerCoords player targetCoords) piece state


-- |  a playerTargetCoords foi para dar um player uma nova coordenada consoante o seu movimento 
--

playerTargetCoords :: Player -> Maze -> Orientation -> Coords
playerTargetCoords player maze L = fixCoords maze (fst (getPlayerCoords player), (snd (getPlayerCoords player) -1))
playerTargetCoords player maze R = fixCoords maze (fst (getPlayerCoords player), (snd (getPlayerCoords player) +1))
playerTargetCoords player  maze U = fixCoords maze ((fst (getPlayerCoords player)-1), snd (getPlayerCoords player))
playerTargetCoords player maze D = fixCoords maze ((fst (getPlayerCoords player)+1), snd (getPlayerCoords player))
playerTargetCoords player _ _ = getPlayerCoords player


-- | fixCoords foi para dar uma nova coordenada no maze 
--

fixCoords :: Maze -> Coords -> Coords
fixCoords maze (y, x)
    | x < 0 = (y, (length (maze!!0)) -1)
    | x >= length (maze!!0) = (y, 0)
    | otherwise = (y, x)



-- | getPieceOnCoord criei com o intuito de dar-me uma peça existente numa certa coordenada
--


getPieceOnCoord:: Maze -> Coords -> Piece
getPieceOnCoord maze coord = (maze!!(fst coord))!!(snd coord) 

-- | getPlayerOnCoord criei com o intuito de dar-me um player caso exista numa coordenada de um maze
--

getPlayerOnCoord :: State -> Coords -> Maybe Player
getPlayerOnCoord (State maze playersState level) coords = let players = filter (\p -> coords == getPlayerCoords p ) playersState
                                                         in if length players == 0 then Nothing
                                                         else Just (players!!0)


-- | checkIfOrientationChanged serve para me dizer se um jogador mudou de posição ou não
--

checkIfOrientationChanged :: Play -> State -> Bool
checkIfOrientationChanged _play state = getPlayerOrientation (getPlayerById (getIdFromPlay _play) state) /= getOrientationFromPlay _play

-- | getIdFromPLay é para me dar o  ID da jogada
--

getIdFromPlay:: Play -> Int
getIdFromPlay (Move id orientation) = id

-- | getOrientationFromPlay serve para me dar a orientação da jogada
--

getOrientationFromPlay:: Play -> Orientation
getOrientationFromPlay (Move id orientation) = orientation

-- | setPlayerOrientation criei com o intuito de dar ao player uma nova orientação
--

setPlayerOrientation:: Player -> Orientation -> Player
setPlayerOrientation (Pacman (PacState (x,y,z,t,h,l) q c d )) newOrientation = Pacman (PacState (x,y,z,newOrientation,h,l) q c d )
setPlayerOrientation (Ghost (GhoState (x,y,z,t,h,l) q )) newOrientation = Ghost (GhoState (x,y,z, newOrientation,h,l) q )

-- | addPlayerPoints serve para adicionar pontos a um player
--

addPlayerPoints :: Player -> Int -> Player 
addPlayerPoints (Pacman (PacState (x,y,z,t,h,l) q c d )) n = (Pacman (PacState (x,y,z,t,h+n,l) q c d ))


-- | updatePacmanMode serve para atualizar o estado de um player
--

updatePacmanMode :: Player -> PacMode -> Player
updatePacmanMode player _ = player


-- | setPlayerVelocity serve para dar uma nova velocidade a um player 
--

setPlayerVelocity :: Player -> Double -> Player
setPlayerVelocity (Pacman (PacState (x,y,z,t,h,l) q c d )) velocity = Pacman (PacState (x,y,velocity,t,h,l) q c d )
setPlayerVelocity (Ghost (GhoState (x,y,z,t,h,l) q )) velocity = Ghost (GhoState (x,y,velocity,t,h,l) q )


-- | getPlayerVelocity dá-me a velocidade de um player
--

getPlayerVelocity :: Player -> Double
getPlayerVelocity (Pacman (PacState (x,y,z,t,h,l) q c d )) = z

 
-- | isPlayerInTunnel diz-me se um player está no tunel ou não
--

isPlayerInTunnel :: Player -> Maze -> Bool
isPlayerInTunnel _player maze = ( snd( getPlayerCoords _player) == 0 || snd( getPlayerCoords _player) ==  (length (maze!!0)) - 1)


-- | sendPlayerToOthersideOfTunnel serve para levar um player para o outro lado do tunel
-- 

sendPlayerToOthersideOfTunnel :: Player -> Maze -> Player
sendPlayerToOthersideOfTunnel _player maze = if snd (getPlayerCoords _player) == -1 then 
    setPlayerCoords _player ((fst (getPlayerCoords _player)), (length (maze!!0)-1)) 
    else 
        if (snd (getPlayerCoords _player) == (length (maze!!0))) 
          then setPlayerCoords _player ((fst (getPlayerCoords _player)), 0) 
        else _player



-- | a função updatePlayerByPiece criei com o intuito de atualizar um player num state consuante o tipo de Piece
--

updatePlayerByPiece :: Player -> Piece -> State -> State 
updatePlayerByPiece player Empty state = updatePlayerInState (player) state
updatePlayerByPiece (Ghost (s)) (Food (f)) state = updatePlayerInState ((Ghost (s))) state
updatePlayerByPiece (Pacman (s)) (Food (Little)) state = removeFood (getPlayerCoords (Pacman (s)) ) (updatePlayerInState  (addPlayerPoints (Pacman (s)) 1 ) state)
updatePlayerByPiece (Pacman (s)) (Food (Big)) state = removeFood (getPlayerCoords (Pacman (s)) ) (setGhostsToDeadStateAndDecreaseVelocity (updatePlayerInState (updatePacmanMode (addPlayerPoints (Pacman (s)) 5) Mega) state))
-- falta meter o fantasma na casa dos fantasmas
updatePlayerByPiece (Pacman (s)) (PacPlayer ( Ghost ( GhoState gs Dead))) state = updatePlayerInState  ( Ghost ( GhoState gs Alive)) (updatePlayerInState (addPlayerPoints (Pacman (s)) 10) state) 

updatePlayerByPiece (Pacman (s)) (PacPlayer ( Ghost ( GhoState gs Alive))) state = if (getPlayerLives (Pacman (s))) == 0 then updatePlayerInState (updatePacmanMode (Pacman (s)) Dying) state     --se a vida == 0 muda player state para Dying
                                                                             else updatePlayerInState (decreasePlayerLives (Pacman (s))) state        -- caso contrario o jogado rperde uma vida


-- | removeFood serve para substituir uma Piece qualquer naquela coordenada por um Empty 
--

removeFood :: Coords -> State -> State
removeFood coords (State m pl l) = (State (replaceElemInMaze coords Empty m) pl l) 

-- | getPlayerLives da-me o numero de vidas do Pacman no state
--

getPlayerLives :: Player -> Int
getPlayerLives (Pacman (PacState (x,y,z,t,h,l) q c d )) = l 


-- | decreasePlayerLives serve para Diminuir o numero de vidas do player
--

decreasePlayerLives :: Player -> Player
decreasePlayerLives (Pacman (PacState (x,y,z,t,h,l) q c d )) = (Pacman (PacState (x,y,z,t,h,l-1) q c d ))

-- |setGhostsToDeadStateAndDecreaseVelocity criei com o intuito de transformar todos os ghosts para Dead e diminuir a sua velocidade 
--

setGhostsToDeadStateAndDecreaseVelocity :: State -> State
setGhostsToDeadStateAndDecreaseVelocity (State m playersState l) = State m (map setGhostToDeadStateAndDecreaseVelocity playersState) l

-- | getGhostMode serve para me dar o estado do ghost existente no state 
--

getGhostMode :: Player -> GhostMode 
getGhostMode (Ghost (GhoState a b )) = b

-- | setGhostMode serve para lhe passar um novo GhostMode do ghost
--

setGhostMode :: Player -> GhostMode -> Player
setGhostMode (Ghost (GhoState a b )) newMode = (Ghost (GhoState a newMode ))

-- | setGhostToDeadStateAndDecreaseVelocity criei com o intuito de passar apenas um ghost para o estado Dead e diminuir a sua velocidade


setGhostToDeadStateAndDecreaseVelocity :: Player -> Player
setGhostToDeadStateAndDecreaseVelocity (Ghost (GhoState (x,y,z,t,h,l) gm )) = (Ghost (GhoState (x,y,(z/2),t,h,l) Dead ))
setGhostToDeadStateAndDecreaseVelocity _player = _player



{- | A função updatePlayerInState serve para me dar o updade de um player num state
.-}

updatePlayerInState :: Player -> State -> State
updatePlayerInState _player (State maze playersState level) = State maze (map (\p -> (if getPlayerID p /= getPlayerID _player then p 
                                                                                 else _player)) playersState) level





{- |
= Introdução

Na tarefa 1 o objetivo foi gerar labirintos aleatorios utilizando código e dando as medidas do maze 
no terminal

= Objetivos

Para começar, fizemos uma função para colocar Walls nas paredes laterais do labirinto (paredesLaterais)  e 
juntamos á função rodearParedes, para que á volta do labirinto esteja sempre com Walls.

Depois começamos por criar uma função tunelCorridor para substituir uma peça por uma wall, e depois juntar 
 a essa função tunel. Com isto já formá-mos um labrinto que contem um tunel a meio do labirinto.

Depois começamos a fazer a casa dos fantasmas, fazendo a primeira função, geraCasaFantasmas que gera uma casa
dos fantasmas. De seguida fizemos a função criaCasaFantasmas, que coloca a casa no meio do labirinto.

No final juntamos essas funções todas numa só função, generateMaze, que faz um labirinto já com as condições 
que queriamos


= Discussão e conclusão

Com isto, conseguimos obter um labirinto esperado, rodeado de paredes, com um tunel e uma casa dos fantasmas
no meio

-}


-- | type Maze é o tipo de maze, ou seja. uma lista de corridor
--

type Maze = [Corridor]

-- | type Corridor é uma lista de Piece
--

type Corridor = [Piece]

-- | Piece pode ser uma Food Wall ou Empty
--

data Piece = Food FoodType | Wall | Empty

-- | uma Food pode ser Big ou Little
--
data FoodType = Big | Little


-- | mostra a figura que uma Piece tem 
-- 
instance Show Piece where
    show (Food Big) = "o"
    show (Food Little) = "."
    show (Wall) = "#"
    show (Empty) = " "


-- | sampleMaze é um exemplo de uma lista
--

sampleMaze :: Maze
sampleMaze = [
                [Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall],
                [Empty, Food Little, Food Little, Food Big, Food Little, Food Big, Food Little, Empty],
                [Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall]
            ]



-- | Given a seed returns a list of n integer randomly generated
--
geraAleatorios :: Int -> Int -> [Int]
geraAleatorios n seed = let gen = mkStdGen seed -- creates a random generator
                        in take n $ randomRs (0,99) gen -- takes the first n elements from an infinite series of random numbers between 0-9


-- | Given a seed returns an integer randomly generated
--
nrAleatorio :: Int -> Int
nrAleatorio seed = head $ geraAleatorios 1 seed


-- | Converssta list into a list of list of size n
--
subLista :: Int -> [a] -> [[a]]
subLista _ [] = []
subLista n l = take n l: subLista n (drop n l)


-- | Converts an integer number into a Peca
-- 3 <=> Comida Granfre
-- 0 <= n < 7 <=> Little
-- 7 < n <= 9 <=> Wall
--
convertePiece :: Int -> Piece
convertePiece x
   | x == 3 = Food Big
   | x >= 0 && x < 70 = Food Little
   | x >= 70 && x <= 99 = Wall


-- | Converts a Corredor to a string
--
printCorridor :: Corridor -> String
printCorridor [] = "\n"
printCorridor (h:t) = show h ++ printCorridor t


-- | Converts a Labirinto to a string
--
printMaze :: Maze -> String
printMaze [] = ""
printMaze (h:t)= printCorridor h ++ printMaze t


-- | Converts a list of integers into a Corredor
--
converteCorridor :: [Int] -> Corridor
converteCorridor l = map convertePiece l


-- | Converts a list of lists of integers into a Labirinto
--
converteMaze :: [[Int]] -> Maze
converteMaze l = map  converteCorridor l  


-- | geraMaze foi para gerar um labirinto aleatorio
--


geraMaze :: Int -> Int -> Int -> Maze
geraMaze x y s =
                 let random_nrs = geraAleatorios (x*y) s
                 in converteMaze $ subLista x random_nrs


{- | a função rodeadoParedes foi para rodear o labrinto todo com Walls
.-}

rodeadoParedes :: Maze -> Maze
rodeadoParedes (h:t) = 
    let crs = map paredesLaterais (take (length t -1) t)
    in (replicate (length h) Wall) : crs ++  [(replicate (length h) Wall)]



{- | Criei a função paredesLaterais com o intuito de colocar Walls nas paredes laterais do maze  
.-}

paredesLaterais :: Corridor -> Corridor
paredesLaterais (h:t) = Wall : (take (length t - 1) t ++ [Wall])   


{- | Criei a função generateMaze com o intuito de criar um maze já completo (com a casa dos fantasmas e o tunel) 
.-}

generateMaze :: Int -> Int -> Int -> Maze 
generateMaze x y s = criaCasaFantasmas (tunel (rodeadoParedes (geraMaze x y s) )) (geraCasaFantasmas x) x y (length ((geraCasaFantasmas x )!!0))         



{- | Criei a função tunel com o intuito de atualizar o maze, já com o tunel no meio 
.-}

tunel :: Maze -> Maze
tunel z | mod (length z) 2 == 0 = (take (length z `div` 2 -1) z) ++ [tunelCorridor( z!!(length z `div` 2 -1))] ++ [tunelCorridor (z !! (length z `div` 2))] ++ drop (length z `div` 2 +1) z
        | otherwise = (take (length z `div` 2 ) z) ++ [tunelCorridor( z!!(length z `div` 2 ))] ++ drop (length z `div` 2+1) z


{- | Criei a função tunelCorridor para substituir a peça por um Empty
.-}

tunelCorridor :: [Piece] -> [Piece]
tunelCorridor (h:t) = Empty : (take(length t -1) t ++ [Empty]) 


{- | Criei a função CriaCasaFantasmas com o intuito de juntar uma casa de fantasmas a meio de um labirinto  
.-}

criaCasaFantasmas :: Maze ->  Maze -> Int -> Int -> Int -> Maze
criaCasaFantasmas maze casaFantasma largura altura larguraCasa
                     = take ((altura-5) `quot` 2) maze ++ 
                    [take ((largura - larguraCasa) `quot` 2)  (maze!!(((altura-5) `quot` 2))) ++ casaFantasma!!0 ++ drop (larguraCasa +((largura - larguraCasa) `quot` 2)  ) (maze!!(((altura-5) `quot` 2))) ] ++
                    [take ((largura - larguraCasa) `quot` 2)  (maze!!(((altura-5) `quot` 2)+1)) ++ casaFantasma!!1 ++ drop (larguraCasa +((largura - larguraCasa) `quot` 2)  ) (maze!!(((altura-5) `quot` 2)+1)) ] ++
                    [ take ((largura - larguraCasa) `quot` 2)  (maze!!(((altura-5) `quot` 2)+2)) ++ casaFantasma!!2 ++ drop (larguraCasa +((largura - larguraCasa) `quot` 2)  ) (maze!!(((altura-5) `quot` 2)+2)) ] ++
                    [take ((largura - larguraCasa) `quot` 2)  (maze!!(((altura-5) `quot` 2)+3)) ++ casaFantasma!!3 ++ drop (larguraCasa +((largura - larguraCasa) `quot` 2)  ) (maze!!(((altura-5) `quot` 2)+3))  ] ++
                    [ take ((largura - larguraCasa) `quot` 2)  (maze!!(((altura-5) `quot` 2)+4)) ++ casaFantasma!!4 ++ drop (larguraCasa +((largura - larguraCasa) `quot` 2)  ) (maze!!(((altura-5) `quot` 2)+4)) ] ++
                    (drop (((altura-5) `quot` 2)+5) maze)
                        

{- | Criei a função geraCasaFantasmas com o intuito de gerar uma casa de fantasmas consoante a largura do maze 
.-}

geraCasaFantasmas :: Int -> Maze
geraCasaFantasmas largura | mod (largura) 2 == 1 = [
    (replicate 11 Empty),
    (concat [[Empty] , replicate 3 Wall , replicate 3 Empty , replicate 3 Wall , [Empty]]),
    (concat [[Empty, Wall] , replicate 7 Empty, [Wall, Empty]]),
    (concat [[Empty], replicate 9 Wall , [Empty]]),
    (replicate 11 Empty)
    ]
                          | otherwise = [
    (replicate 10 Empty),
    (concat [[Empty] , replicate 3 Wall , replicate 2 Empty , replicate 3 Wall , [Empty]]),
    (concat [[Empty, Wall] , replicate 6 Empty, [Wall, Empty]]),
    (concat [[Empty], replicate 8 Wall , [Empty]]),
    (replicate 10 Empty) ]


-- | a função imprime é para imprimir o labirinto no terminal


imprime :: Maze -> IO ()
imprime m = putStrLn $ printMaze m



-- data Manager = Manager 
--     {   
--         state   :: State
--     ,    pid    :: Int
--     ,    step   :: Int
--     ,    before :: Integer
--     ,    delta  :: Integer
--     ,    delay  :: Integer
--     } 

-- | loadManager serve para mostrar o Manager no terminal
--

loadManager :: Manager
loadManager = ( Manager (loadMaze "mapsFase1/1.txt") 0 0 0 0 defaultDelayTime )

-- | updateControlledPlayer serve para a partir de "pressionar" teclas fazer os players fazerem movimentos
--

updateControlledPlayer :: Key -> Manager -> Manager
updateControlledPlayer KeyUpArrow (Manager (State m [(Pacman (PacState (x,y,z,t,h,l) q c d )),(Ghost (GhoState (x1,y1,z1,t1,h1,l1) q1 ))] level) pid step before delta delay)  = (Manager (State m [(Pacman (PacState (x,y,z,U,h,l) q c d ))] level) pid step before delta delay)
updateControlledPlayer KeyDownArrow (Manager (State m [(Pacman (PacState (x,y,z,t,h,l) q c d )),(Ghost (GhoState (x1,y1,z1,t1,h1,l1) q1 ))] level) pid step before delta delay)  = (Manager (State m [(Pacman (PacState (x,y,z,D,h,l) q c d ))] level) pid step before delta delay)
updateControlledPlayer KeyLeftArrow (Manager (State m [(Pacman (PacState (x,y,z,t,h,l) q c d )),(Ghost (GhoState (x1,y1,z1,t1,h1,l1) q1 ))] level) pid step before delta delay)  = (Manager (State m [(Pacman (PacState (x,y,z,L,h,l) q c d ))] level) pid step before delta delay)
updateControlledPlayer KeyRightArrow (Manager (State m [(Pacman (PacState (x,y,z,t,h,l) q c d )),(Ghost (GhoState (x1,y1,z1,t1,h1,l1) q1 ))] level) pid step before delta delay)  = (Manager (State m [(Pacman (PacState (x,y,z,R,h,l) q c d ))] level) pid step before delta delay)


updateScreen :: Window  -> ColorID -> Manager -> Curses ()
updateScreen w a man =
                  do
                    updateWindow w $ do
                      clear
                      setColor a
                      moveCursor 0 0 
                      drawString $ show (state man)
                    render
     
currentTime :: IO Integer
currentTime = fmap ( round . (* 1000) ) getPOSIXTime

-- | updateTime serve para fazer update dos tempos
--

updateTime :: Integer -> Manager -> Manager
updateTime now (Manager state p step b delta delay) = Manager state p step now (delta+(now-b)) delay

-- | resetTimer serve para fazer "reset" ao tempo
--

resetTimer :: Integer -> Manager -> Manager
resetTimer now (Manager state p step b d delay) = (Manager state p step now 0 delay)

-- | nextFrame serve para mostrar o manager seguinte ou por outras palavras mostrar um manager diferente do anterior
--

nextFrame :: Integer -> Manager -> Manager
nextFrame now (Manager state id step before delta delay) = let newState = passTime step state 
                    in resetTimer now (Manager newState id (step+1) before delta delay)

loop :: Window -> Manager -> Curses ()
loop w man@(Manager s pid step bf delt del ) = do 
  color_schema <- newColorID ColorBlue ColorWhite  10
  now <- liftIO  currentTime
  updateScreen w  color_schema man
  if ( delt > del )
    then loop w $ nextFrame now man
    else do
          ev <- getEvent w $ Just 0
          case ev of
                Nothing -> loop w (updateTime now man)
                Just (EventSpecialKey arrow ) -> loop w $ updateControlledPlayer arrow (updateTime now man)
                Just ev' ->
                  if (ev' == EventCharacter 'q')
                    then return ()
                    else loop w (updateTime now man)

main :: IO ()
main =
  runCurses $ do
    setEcho False
    setCursorMode CursorInvisible
    w <- defaultWindow
    loop w loadManager







loadMaze :: String -> State
loadMaze filepath = unsafePerformIO $ readStateFromFile filepath



readStateFromFile :: String -> IO State
readStateFromFile f = do
                content <- readFile f
                let llines = lines content 
                    (new_map,pl) = convertLinesToPiece llines 0 []
                return (State new_map pl 1)



convertLinesToPiece :: [String] -> Int -> [Player] -> (Maze,[Player])
convertLinesToPiece [] _ l = ([],l)
convertLinesToPiece (x:xs) n l  = let (a,b) = convertLineToPiece x n 0 l 
                                      (a1,b1) = convertLinesToPiece xs (n+1) b
                                  in (a:a1,b1)

convertLineToPiece :: String -> Int -> Int -> [Player] -> ([Piece],[Player])
convertLineToPiece [] _ _ l = ([],l)
convertLineToPiece (z:zs) x y l = let (a,b ) = charToPiece z x y l
                                      (a1,b1) = convertLineToPiece zs x (y+1) b 
                                  in (a:a1,b1)


charToPiece :: Char -> Int -> Int -> [Player] -> (Piece,[Player])
charToPiece c x y l
    | c == '{' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Normal ))   :l) )
    | c == '<' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Closed Normal )) :l) )
    | c == '}' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Open Normal ))   :l) )
    | c == '>' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Closed Normal )) :l) )
    | c == 'V' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Open Normal ))   :l) )
    | c == 'v' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Closed Normal )) :l) )
    | c == '^' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Open Normal ))   :l) )
    | c == '|' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Closed Normal )) :l) )
    | c == 'X' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Dying ))    :l) )
    | c == 'M' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Alive))            :l) )
    | c == '?' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Dead))             :l) )
    | c == 'o' =  (Food Big,l)
    | c == '.' =  (Food Little,l)
    | c == '#' =  (Wall,l)
    | otherwise = (Empty,l)



data State = State 
    {
        maze :: Maze
    ,   playersState :: [Player]
    ,   level :: Int
    }

type Maze = [Corridor]
type Corridor = [Piece]
data Piece =  Food FoodType | PacPlayer Player| Empty | Wall deriving (Eq)
data Player =  Pacman PacState | Ghost GhoState deriving (Eq)

data Orientation = L | R | U | D | Null deriving (Eq,Show)
data PacState= PacState 
    {   
        pacState :: PlayerState
    ,   timeMega :: Double
    ,   openClosed :: Mouth
    ,   pacmanMode :: PacMode
    
    } deriving Eq

data GhoState= GhoState 
    {
        ghostState :: PlayerState
    ,   ghostMode :: GhostMode
    } deriving Eq

type Coords = (Int,Int)
type PlayerState = (Int, Coords, Double , Orientation, Int, Int)
--                 (ID,  (x,y), velocity, orientation, points, lives) 
data Mouth = Open | Closed deriving (Eq,Show)
data PacMode = Dying | Mega | Normal deriving (Eq,Show)
data GhostMode = Dead  | Alive deriving (Eq,Show)
data FoodType = Big | Little deriving (Eq)
data Color = Blue | Green | Purple | Red | Yellow | None deriving Eq 

data Play = Move Int Orientation deriving (Eq,Show)

type Instructions = [Instruction]

data Instruction = Instruct [(Int, Piece)]
                 | Repeat Int deriving (Show, Eq)

instance Show State where
  show (State m ps p) = printMaze mz ++ "Level: " ++ show p ++ "\nPlayers: \n" ++ (foldr (++) "\n" (map (\y-> printPlayerStats y) ps))
                          where mz = placePlayersOnMap ps m

instance Show PacState where
   show ( PacState s o m Dying  ) =  "X"
   show ( PacState (a,b,c,R,i,l) _ Open m  ) =  "{"
   show ( PacState (a,b,c,R,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,L,i,l) _ Open m  ) =  "}"
   show ( PacState (a,b,c,L,i,l) _ Closed m  ) =  ">"
   show ( PacState (a,b,c,U,i,l) _ Open m  ) =  "V"
   show ( PacState (a,b,c,U,i,l) _ Closed m  ) =  "v"
   show ( PacState (a,b,c,D,i,l) _ Open m  ) =  "^"
   show ( PacState (a,b,c,D,i,l) _ Closed m  ) =  "|"
   show ( PacState (a,b,c,Null,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,Null,i,l) _ Open m  ) =  "{"

instance Show Player where
   show (Pacman x ) =  show x
   show ( Ghost x ) =   show x

instance Show GhoState where
   show (GhoState x Dead ) =  "?"
   show (GhoState x Alive ) =  "M"

instance Show FoodType where
   show ( Big ) =  "o"
   show ( Little ) =  "."

instance Show Piece where
   show (  Wall ) = coloredString "#" None
   show (  Empty ) = coloredString " " None
   show (  Food z ) = coloredString (show z )   Green
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Normal ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Normal)  ) Yellow
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Mega   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Mega)  ) Blue
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Dying   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Dying)  ) Red
   show ( PacPlayer (Ghost z) ) = coloredString (show z)  Purple


coloredString :: String -> Color -> String
coloredString x y = x
{-- 
    | y == Blue ="\x1b[36m" ++  x ++ "\x1b[0m"
    | y == Red = "\x1b[31m" ++ x ++ "\x1b[0m"
