getPacmans :: [Player] -> [Player]
getPacmans [] = []
getPacmans ((Pacman (PacState ps t oc m)):xs) = (Pacman (PacState ps t oc m)):getPacmans xs
getPacmans ((Ghost (GhoState ps m)):xs) = getPacmans xs
                

getGhostPlay :: [Play] -> Int -> Play
getGhostPlay [Move id o] _ = Move id o
getGhostPlay ((Move id o):ps) id2 | id == id2 = Move id o
                                  | otherwise = getGhostPlay ps id2


isDead :: Player -> Bool
isDead (Ghost (GhoState ps Dead)) = True
isDead p = False 


aux :: Int -> State -> [Player] -> State
aux step state [] = state
aux step (State m (h:t) l) (p:ps) | elem p gl && mod step 2 == 0 = aux step (play ghplay iState) ps
                                  | elem p gl && mod step 2 == 1 && isDead p = aux step iState ps
                                  | elem p gl && mod step 2 == 1 && isDead p == False = aux step (play ghplay iState) ps
                                  | otherwise = aux step (play (Move id o) iState) ps
                                 where ghplay = Move id o -- getGhostPlay (ghostPlay iState) id
                                       gl = getGhosts (p:ps)
                                       iState = (State m (h:t) l)
                                       id = getPlayerID p
                                       o = getPlayerOrientation p
                          
                                       
passTime :: Int -> State -> State -- int é o step
passTime step (State m ps l) = aux step (State m ps l) ps

















