-- | transforma um corridor numa lista de pares (int,Piece)
pieceToPair :: Corridor -> [(Int, Piece)]
pieceToPair [] = []
pieceToPair (p:ps) = (1, p) : pieceToPair ps

-- | Verifica se duas peças são iguais
comparePiece :: Piece -> Piece -> Bool
comparePiece Wall Wall = True
comparePiece Empty Empty = True
comparePiece (Food Big) (Food Big) = True
comparePiece (Food Little) (Food Little) = True
comparePiece _ _ = False

compareInt :: Eq a => a -> a -> Bool
compareInt x y = if x==y then True else False


-- | reduz uma lista de pares (int, piece) de maneira a juntar peças iguais no mesmo par
reduceIntPiece :: [(Int, Piece)] -> [(Int, Piece)]
reduceIntPiece [] = []
reduceIntPiece l | length l == 1 = l
reduceIntPiece ((n1, p1) : (n2, p2) :t) = if comparePiece p1 p2 then (reduceIntPiece ((n1+n2 ,p2) : t))
                                          else (n1, p1) : reduceIntPiece ((n2, p2) :t)


-- | transforma os corredores em intruções reduzidas
reduceinstructionHz :: Corridor -> Instruction
reduceinstructionHz (p:ps) = Instruct (reduceIntPiece (pieceToPair (p:ps)))

-- | reduz um Maze em instruções
reducedMazeHz :: Maze -> Instructions 
reducedMazeHz [] = []
reducedMazeHz (cr:crs) = reduceinstructionHz cr : reducedMazeHz crs




------------------------------------
-- | ve se duas instruções são iguais--
equalInstr :: Instruction -> Instruction -> Bool
equalInstr (Instruct []) (Instruct []) = True
equalInstr (Instruct []) _ = False 
equalInstr _ (Instruct []) = False
equalInstr (Instruct ((n1, p1) : t)) (Instruct ((n2 , p2) : ts)) | compareInt n1 n2 && comparePiece p1 p2 = equalInstr (Instruct t) (Instruct ts)
                                           | otherwise = False
                                           
-- | ve se uma instrução faz parte de uma lista de instruções                                       
elemlist :: Instruction -> Instructions -> Bool
elemlist _ [] = False 
elemlist (l1) (l2:ts) = if equalInstr l1 l2 then True
                                else elemlist l1 ts       
                                                                     
-- | ve as posições de um elemento numa lista            
positions :: Eq a => a -> [a] -> [Int]
positions a xs = indexed a (zip xs [0..])
    where indexed _ [] = []
          indexed a ((x,i):xs)
            | x == a = i:indexed a xs
            | otherwise = indexed a xs                                                

-- | tira uma instrução de uma lista de instruções
removeInstruction :: Instruction -> Instructions -> Instructions
removeInstruction _ [] = []
removeInstruction i (h:t) = if equalInstr i h then removeInstruction i t
                            else h : removeInstruction i t 

-- | devolve a lista com instruções que se repetem
extractEquals :: Instructions -> Instructions
extractEquals [] = []
extractEquals (h:t) | length (h:t) == 1 = []
extractEquals (h:t:ts) = if elemlist h (t:ts) then h : extractEquals (removeInstruction h (t:ts))
                         else extractEquals (t:ts)

-- | devolve as posições de instruções numa lista de instruções
posEqualI :: Instructions -> Instructions -> [[Int]]
posEqualI _ [] = []
posEqualI [] _ = []
posEqualI (p:q) (h:t) = tail (positions p (h:t)) : posEqualI q (h:t) 

-- | devolve as posições onde os Repeats tem que ser inseridos
posEqualInstr :: Instructions -> [[Int]]
posEqualInstr (h:t) = posEqualI (extractEquals (h:t)) (h:t) 

-- | devolve as posições da instrução a ser repetida
equalRepeatPos :: Instructions -> Instructions -> [Int]
equalRepeatPos _ [] = []
equalRepeatPos [] _ = []
equalRepeatPos (p:q) (h:t) = head (positions p (h:t)) : equalRepeatPos q (h:t)

-- | valor do int a colocar nos repeats
intRepeat :: Instructions -> [Int]
intRepeat (h:t) = equalRepeatPos (extractEquals (h:t)) (h:t)


-- | cria uma lista com os repeats prontos a inserir 
createRepeats :: [Int] -> Instructions
createRepeats [] = []
createRepeats (h:t) = (Repeat h) : createRepeats t 
 
-- | recebe a lista de instruções e devolve a lista de repeats a adicionar nessas instruções 
listRepeats :: Instructions -> Instructions
listRepeats (h:t:ts) = createRepeats (intRepeat (h:t:ts))

-- | função que junta e ordena a posEqualInstr
ordPosInt :: [[Int]] -> [Int]
ordPosInt (h:t) = sort (concat (h:t))

-- | recebe a lista de repeats, e replica os para inserir nas instruções
replicateRepeats :: Instructions -> [[Int]] -> [Instructions]
replicateRepeats l [] = []
replicateRepeats [] _ = []
replicateRepeats (r:rs) (l:ls) = take (length l) (repeat r) : replicateRepeats rs ls

-- | devolve os repeats para ordenar
replicateFinal :: Instructions -> [Instructions]
replicateFinal l = replicateRepeats (listRepeats l) (posEqualInstr l)

-- | substitui as instructions por repeats 
insertRepeats :: Instructions -> [Int] -> Instructions -> Instructions 
insertRepeats [] _ l = l
insertRepeats _ [] l = l
insertRepeats _ _ [] = [] 
insertRepeats (r:rs) (n:ns) (h:t) = if n==0 then r : insertRepeats rs (map ((+)(-1)) (ns)) (t)
                                    else h : insertRepeats (r:rs) (map ((+) (-1)) (n:ns)) t

-- | substitui lista de instructions por repeats
replaceInstructions :: [Instructions] -> [[Int]] -> Instructions -> [Instructions]
replaceInstructions (r:rs) (n:ns) (h:t) = insertRepeats r n (h:t) : replaceInstructions rs ns (h:t)


-- | faz pares com os repeats e as respetivas posições
pairs :: [Instruction] -> [Int]  -> [(Instruction, Int)]
pairs [] _ = []
pairs _ [] = []
pairs (r:rs) (n:ns) = (r, n) : (pairs rs ns)

-- | ordena os pares (repeat Int, Int)
mySort :: Ord b => [(a, b)] -> [(a, b)]
mySort = sortBy (compare `on` snd)

-- | volta a transformar os pares em repeats mas desta vez ordenados
pairsToReps :: [(Instruction, Int)] -> Instructions
pairsToReps [] = []
pairsToReps ((r,n):t) = r : pairsToReps t

pairReps :: [Instructions] -> [[Int]]-> [[(Instruction, Int)]]
pairReps [] _ = []
pairReps _ [] = []
pairReps (h:t) (n:ns) = pairs h n : pairReps t ns

-- | daqui sai uma lista de repeats ordenados
sortRepeats :: [[(Instruction, Int)]] -> Instructions
sortRepeats l = pairsToReps (mySort (concat  l))

-- | devolve a lista de repeats prontos a serem colocados nas instructios
repeatsFinal :: Instructions -> Instructions
repeatsFinal l = sortRepeats (pairReps (replicateFinal l) (posEqualInstr l))

-- | reduz as instruções verticalmente, colocando repeats
reduceMazeVt :: Instructions -> Instructions 
reduceMazeVt l = insertRepeats (repeatsFinal l) (ordPosInt (posEqualInstr l)) l

-- | transforma um maze em instruções reduzidas
compactMaze :: Maze -> Instructions
compactMaze m = reduceMazeVt (reducedMazeHz m)

--------------------------------------------------------------------------
sizeInstructions :: Instructions -> Int
sizeInstructions (h:t) = length (h:t) 
