-- | Function which in the main one will allow us to obtain the player related to the play which was made
--
getByID :: Int -> [Player] -> Player
getByID i (p:ps) | i == getPlayerID p = p
                 | otherwise = (getByID i ps)
                 
                            
-- | Function which will allow us to change the player's orientation whenever the play's orientation isn't the same as his
--
changeOrientation :: Player -> Orientation -> Player
changeOrientation (Pacman (PacState (id, (x,y), v, o, p, l) t oc m)) o1 = (Pacman (PacState (id, (x,y), v, o1, p, l) t oc m))
changeOrientation (Ghost (GhoState (id, (x,y), v, o, p, l) m)) o1 = (Ghost (GhoState (id, (x,y), v, o1, p, l) m))


-- | Functions which will allow us to replace a player by another one with the same id in the players list
--
remByID :: Int -> [Player] -> [Player]
remByID _ [] = []
remByID i (p:ps) | i == getPlayerID p = ps
                 | otherwise = p:(remByID i ps)
                 

-- | See previous comment
--
repPlayer :: State -> Player -> State
repPlayer (State maze ps n) (Pacman (PacState (i, (x,y), v, o, p, l) t oc m)) = State maze ((Pacman (PacState (i, (x,y), v, o, p, l) t oc m)) : (remByID i ps)) n
repPlayer (State maze ps n) (Ghost (GhoState (i, (x,y), v, o, p, l) m)) = State maze ((Ghost (GhoState (i, (x,y), v, o, p, l) m)) : (remByID i ps)) n


-- | Function which will allow us to get a player's new coords after a play in a certain direction
--
newCoords :: Player -> Orientation -> Coords
newCoords (Pacman (PacState (id, (x,y), v, o, p, l) t oc m)) o1 | o1 == L = (x,y-1)
                                                                | o1 == U = (x-1,y)
                                                                | o1 == R = (x,y+1)
                                                                | o1 == D = (x+1,y)
newCoords (Ghost (GhoState (id, (x,y), v, o, p, l) m)) o1 | o1 == L = (x,y-1)
                                                          | o1 == U = (x-1,y)
                                                          | o1 == R = (x,y+1)
                                                          | o1 == D = (x+1,y)


-- | Function which will allow us to make the player gain a point whenever he eats a small food
--
gainPoint :: Player -> Player
gainPoint (Pacman (PacState (i, (x,y), v, o, p, l) t oc m)) = (Pacman (PacState (i, (x,y), v, o, p+1, l) t oc m))


-- | Function which will allow us to make pacman loose a life whenever he collides with an alive ghost
--
looseLife :: Player -> Player
looseLife (Pacman (PacState (id, (x,y), v, o, p, l) t oc m)) = Pacman (PacState (id, (x,y), v, o, p, l-1) t oc m)



-- | Functions which will allow ys to put all players in the maze for some considerations
--
placePlayer :: Player -> Maze -> Maze
placePlayer p (c:cs) = (take x (c:cs)) ++ cwp ++ (drop (x+1) (c:cs))
                    where (x,y) = (getPlayerCoords p)
                          pc    = (c:cs)!!x -- pc player's corridor
                          cwp   = [(take y pc) ++ [PacPlayer p] ++ (drop (y+1) pc)] -- cwp corridor with the player


-- | Read previous comment
--
placePlayers :: [Player] -> Maze -> Maze
placePlayers [] maze = maze
placePlayers (p:ps) maze = placePlayers ps (placePlayer p maze)


-- | Function which will allow us to remove all ghosts from a list of players, so that we later on add them but with half the velocity and dead
--
removeGhosts :: [Player] -> [Player]
removeGhosts [] = []
removeGhosts ((Pacman (PacState (id, (x,y), v, o, p, l) t oc m)) : xs) = (Pacman (PacState (id, (x,y), v, o, p, l) t oc m)):(removeGhosts xs)
removeGhosts ((Ghost (GhoState (id, (x,y), v, o, p, l) m)) : xs) = removeGhosts xs


-- | Function which, with the following one, will allow us to half the velocity of a ghost
--
getPlayerVelocity :: Player -> Double
getPlayerVelocity (Pacman (PacState (id, (x,y), v, o, p, l) t oc m)) = v
getPlayerVelocity (Ghost (GhoState (id, (x,y), v, o, p, l) m)) = v


-- | Changes a player's velocity to the one we indicate
--
setPlayerVelocity :: Player -> Double -> Player
setPlayerVelocity (Pacman (PacState (id, (x,y), v, o, p, l) t oc m)) v1 = (Pacman (PacState (id, (x,y), v1, o, p, l) t oc m))
setPlayerVelocity (Ghost (GhoState (id, (x,y), v, o, p, l) m)) v1 = (Ghost (GhoState (id, (x,y), v1, o, p, l) m))


-- | Function which, in the final function, will allow us to reduce the velocity of the ghosts to half
--
slowGhosts :: [Player] -> [Player]
slowGhosts [] = []
slowGhosts (p:ps) = (setPlayerVelocity p ((getPlayerVelocity p)/2)) : slowGhosts ps


-- | Functions which, in setGhostsMode, will allow us to change all ghost players into dead ghosts
--
getGhosts :: [Player] -> [Player]
getGhosts [] = []
getGhosts ((Pacman (PacState ps t oc m)):xs) = getGhosts xs
getGhosts ((Ghost (GhoState ps m)):xs) = (Ghost (GhoState ps m)):(getGhosts xs)

-- | Read previous comment
--
setGhostsMode :: [Player] -> GhostMode -> [Player]
setGhostsMode [] _ = []
setGhostsMode (p:ps) Dead = (setGhostModee p Dead):(setGhostsMode ps Dead)
setGhostsMode (p:ps) Alive = (setGhostModee p Alive):(setGhostsMode ps Alive)


-- | Function which will allow us to change the ghost's mode whenever pacman eats a big food or a dead ghost
--
setGhostModee :: Player -> GhostMode -> Player
setGhostModee (Ghost (GhoState (id, (x,y), v, o, p, l) m)) Dead = (Ghost (GhoState (id, (x,y), v, o, p, l) Dead))
setGhostModee (Ghost (GhoState (id, (x,y), v, o, p, l) m)) Alive = (Ghost (GhoState (id, (x,y), v, o, p, l) Alive))


-- | Function which will allow us to change pacman's state whenever he either collides with an alive ghost and looses a life or eats a big food
--
setPacmanMode :: Player -> PacMode -> Player
setPacmanMode (Pacman (PacState (id, (x,y), v, o, p1, l) t oc m)) Dying = Pacman (PacState (id, (x,y), v, o, p1, l) t oc Dying)
setPacmanMode (Pacman (PacState (id, (x,y), v, o, p1, l) t oc m)) Mega = Pacman (PacState (id, (x,y), v, o, p1, l) t oc Mega)
setPacmanMode (Pacman (PacState (id, (x,y), v, o, p1, l) t oc m)) Normal = Pacman (PacState (id, (x,y), v, o, p1, l) t oc Normal)


-- | Function which will allow us to obtain the list of players related to a state so that we remove the ghosts from it's players list and further on we add them but changed
--
getPlayersFromState :: State -> [Player]
getPlayersFromState (State m ps l) = ps


-- | Function which, in the final function, will allow the player to win five points once he eats a big food
--
gainFivePoints :: Player -> Player
gainFivePoints (Pacman (PacState (id, (x,y), v, o, p, l) t oc m)) = (Pacman (PacState (id, (x,y), v, o, p+5, l) t oc m))


-- | Function which will allow us to establish two cases once pacman collides with an alive ghost
--
getPLives :: Player -> Int
getPLives (Pacman (PacState (id, (x,y), v, o, p, l) t oc m)) = l
getPLives (Ghost (GhoState (id, (x,y), v, o, p, l) m)) = l


-- | Function which will allow us to put pacman in the initial position once he collides with an alive ghost
--
initialCoord :: Maze -> Coords
initialCoord maze | even (length maze) = (div (length maze) 2 + 1, div (length (head maze)) 2)
                  | otherwise = (div (length maze) 2 + 2, div (length (head maze)) 2)


-- | Function which will allow us to put eaten ghosts in the ghost house
--
centerCoord :: Maze -> Coords
centerCoord maze = (div (length maze) 2, div (length (head maze)) 2)


-- | Function which will allow us to obtain the ghost in the coords to which pacman will move, in order to change that ghost's coords and make it alive
--
getGhostIn :: Coords -> [Player] -> Player
getGhostIn (xg,yg) ((Pacman (PacState (id, (x,y), v, o, p, l) t oc m)) : xs) = getGhostIn (xg,yg) xs
getGhostIn (xg,yg) ((Ghost (GhoState (id, (x,y), v, o, p, l) m)) : xs) | (xg == x) && (yg == y) = (Ghost (GhoState (id, (x,y), v, o, p, l) m))
                                                                       | otherwise = getGhostIn (xg,yg) xs


-- | Function which in the final function will allow the player to gain ten points whenever he eats a dead ghost
--
gainTenPoints :: Player -> Player
gainTenPoints (Pacman (PacState (id, (x,y), v, o, p, l) t oc m)) = (Pacman (PacState (id, (x,y), v, o, p+10, l) t oc m))


-- | Function which in the final function will change the player's coords when he enters the tunnel
--
tunnelAction :: Player -> Maze -> Player
tunnelAction (Pacman (PacState (id, (x,y), v, o, p, l) t oc m)) (c:cs) | y == 0 = (Pacman (PacState (id, (x, (length c) - 1), v, o, p, l) t oc m))
                                                                       | y == (length c) - 1 = (Pacman (PacState (id, (x,0), v, o, p, l) t oc m))


-- | Function which will allow us to replace the initial maze by another one but with an empty piece in pacman's previous coords
--
emptyPosition :: Coords -> Maze -> Maze
emptyPosition (a,b) m = replaceElemInMaze (a,b) Empty m


-- | Main function which will allow to move a player in a certain direction and update the effect of that play in the initial maze
--
play :: Play -> State -> State
play (Move i o) (State maze ps l) 
  | (((xp,yp) == (xp,0)) && o == L) || (((xp,yp) == (xp, length (head maze) - 1)) && o == R) = repPlayer iState (tunnelAction player maze)
  | (o /= (getPlayerOrientation player) || (p == Wall)) = repPlayer iState (changeOrientation player o)
  | otherwise = case p of (Empty)                                 -> repPlayer iState pnc
                          (Food Little)                           -> repPlayer iState pncfl
                          (Food Big)                              -> State maze sapfb l
                          (PacPlayer (Ghost (GhoState gs Alive))) -> if ln > 0 then repPlayer iState (setPlayerCoords (looseLife player) (initialCoord maze))
                                                                     else repPlayer iState (setPlayerCoords spcd (initialCoord maze))
                          (PacPlayer (Ghost (GhoState gs Dead)))  -> case pc of (Empty)       -> repPlayer (repPlayer iState gta) pncdg
                                                                                (Food Little) -> repPlayer (repPlayer iState gta) (gainPoint pncdg)
                                                                                (Food Big)    -> repPlayer (repPlayer (State maze sapfb l) gta) (gainFivePoints pncdg)
                                                                                otherwise     -> repPlayer (repPlayer iState gta) (gainTenPoints pncdg)
 where  player  = getByID i ps
        (xp,yp) = getPlayerCoords player
        mppe    = emptyPosition (xp,yp) maze -- maze (with pacman's) previous position emptied
        iState  = State mppe ps l
        p       = case o of U -> (mwp!!(xp-1))!!yp
                            R -> (mwp!!xp)!!(yp+1)
                            D -> (mwp!!(xp+1))!!yp
                            L -> (mwp!!xp)!!(yp-1)
        pc      = case o of U -> (maze!!(xp-1))!!yp
                            R -> (maze!!xp)!!(yp+1)
                            D -> (maze!!(xp+1))!!yp
                            L -> (maze!!xp)!!(yp-1)
        pnc     = setPlayerCoords player (newCoords player o) -- player (in) new coords
        pncfl   = gainPoint pnc -- player (in) new coords (which had a) food little
        spm     = setPacmanMode player Mega -- set pacman mega
        sapfb   = removeGhosts (getPlayersFromState (repPlayer iState (gainFivePoints (setPacmanMode pnc Mega)))) ++ (slowGhosts (setGhostsMode (getGhosts ps) Dead)) -- (players) state after pacman (in new coords eats a) big food
        ln      = getPLives player
        spcd    = setPacmanMode pnc Dying -- set pacman (in new) coords dying
        gin     = getGhostIn (newCoords player o) ps -- ghost in (pacman's about to be) new (coords)
        gta     = setGhostModee (setPlayerCoords gin (centerCoord maze)) Alive -- ghost (in) house (after being eaten and) alive
        pncdg   = gainTenPoints pnc -- player (in) new coords (which had a) dead ghost
        mwp     = placePlayers ps maze -- maze with players
