-- | Esta função gera aleatoriamente uma lista de números inteiros, e permitir-nos-á gerar aleatoriamente a zona interior do labirinto
--
geraListaAleatoria :: Int -> Int -> [Int]
geraListaAleatoria n seed = let gen = mkStdGen seed -- Cria um gerador aleatório.
                        in take n $ randomRs (0,99) gen -- Seleciona os primeiros n elementos de uma série infinita de números entre 0 e 99.


-- | Função que nos permite gerar um número aleatório
--
nrAleatorio :: Int -> Int
nrAleatorio seed = head $ geraListaAleatoria 1 seed


-- | Função que nos permitirá dividir a lista aleatória de números inteiros gerada em listas de comprimento n, de modo a separá-las, visto que corresponderão aos corredores do labirinto
--
parteLista :: Int -> [Int] -> [[Int]]
parteLista _ [] = []
parteLista n l = take n l: parteLista n (drop n l)


-- | Converte um número inteiro num valor do tipo indutivo Peca
--
converteNumaPeca :: Int -> Piece
converteNumaPeca n | n == 3 = Food Big
                   | n >= 0 && n < 70 = Food Little
                   | n >= 70 && n <= 99 = Wall


-- | Converte uma lista de números inteiros numa lista de valores do tipo indutivo Peca, de modo a definir a função seguinte
--           
converteNumCorredor :: [Int] -> [Piece]
converteNumCorredor [] = []
converteNumCorredor (h:t) = converteNumaPeca h : converteNumCorredor t


-- | Adiciona um valor do tipo Parede ao início e ao fim de cada corredor de modo a ficarmos com os limites laterais esquerdo e direito do Labirinto
--
converteNumLabirinto :: [[Int]] -> Maze
converteNumLabirinto [] = []
converteNumLabirinto (y:ys) = ([Wall] ++ (converteNumCorredor y) ++ [Wall]):converteNumLabirinto ys


-- | Gera o labirinto sem limites superior e inferior, sem túnel e sem casa
--
geraZonaInterior :: Int -> Int -> Int -> Maze
geraZonaInterior c a seed = converteNumLabirinto (parteLista c (geraListaAleatoria (c*a) seed))


-- | Função que nos permitirá criar os limites superior e inferior do labirinto
--
soParedes :: Int -> Corridor
soParedes 0 = []
soParedes n = Wall : soParedes (n-1)


-- | Função que nos permitirá fazer considerações nas funções seguintes
--
meioDaAltura :: Maze -> Int 
meioDaAltura lab = div (length lab) 2


-- | Função que nos permite obter os corredores onde o túnel será colocado para os alterarmos recorrendo à função parteParedesLat
--
corredoresDoMeio :: Maze -> [Corridor]          
corredoresDoMeio lab | even (length lab) = take 2 (drop (meioDaAltura lab - 1) lab)
                     | otherwise = take 1 (drop (meioDaAltura lab) lab) 


-- | Função que torna as peças inicial e final de um ou mais corredores numa peça do tipo Empty, que será aplicada ao valor devolvido pela função corredoresDoMeio, para obtermos os corredores onde o túnel irá ser colocado mas alterados
--
parteParedesLat :: [Corridor] -> [Corridor]
parteParedesLat [] = []
parteParedesLat (c:cs) = (Empty :(init (tail c)) ++ [Empty]) : parteParedesLat cs


-- | Função que nos permite gerar um labirinto com o túnel, labirinto esse ao qual será aplicada uma função que coloca a casa dos fantasmas no labirinto
--
geraTunel :: Maze -> Maze
geraTunel lab | even (length lab) = (take (midH - 1) lab) ++ tunel ++ drop (midH + 1) lab
              | otherwise = (take midH lab) ++ tunel ++ drop (midH + 1) lab
              where midH = meioDaAltura lab
                    tunel = parteParedesLat (corredoresDoMeio lab)
               
-- | Função que nos permite visualizar um corredor de um modo mais claro e que será útil na definição da função seguinte
--     
imprimeCorredor :: Corridor -> String
imprimeCorredor [] = "\n"
imprimeCorredor (p:ps) = show p ++ imprimeCorredor ps


-- | Função que nos permite visualizar um labirinto de um modo mais claro
--
imprimeLab :: Maze -> String
imprimeLab [] = []
imprimeLab (c:cs) = imprimeCorredor c ++ imprimeLab cs


-- | Função à qual se aplicou a função imprimeLab no terminal para verificar se as funções até aqui definidas estão a desempenhar o papel pretendido
--
geraLabirintoSemCasa :: Int -> Int -> Int -> Maze
geraLabirintoSemCasa c a seed = geraTunel (soParedes c : (geraZonaInterior (c-2) (a-2) seed) ++[soParedes c])
                   
                    
-- CASA FANTASMAS --
          
          
-- | Função cujos corredores do labirinto que ela devolve serão usados para colocar a casa de fantasmas no labirinto, tendo em conta o comprimento dele  
--                             
casaFantasmasInv :: Int -> Maze
casaFantasmasInv c | even c = [[Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty],
                [Empty,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Empty],
                [Empty,Wall,Empty,Empty,Empty,Empty,Empty,Empty,Wall,Empty],
                [Empty,Wall,Wall,Wall,Empty,Empty,Wall,Wall,Wall,Empty],
                [Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty]]
                | otherwise = [[Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty],
                [Empty,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Empty],
                [Empty,Wall,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Wall,Empty],
                [Empty,Wall,Wall,Wall,Empty,Empty,Empty,Wall,Wall,Wall,Empty],
                [Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty]]
                             
                               
-- | Função que devolve os corredores acima de onde a casa dos fantasmas virá a ser colocada e que nos permitirá juntá-los aos corredores com a casa e aos corredores abaixo da casa
--
extraiCorredoresAcimaCasa :: Maze -> Maze
extraiCorredoresAcimaCasa lab | even (length lab) = take (meioDaAltura lab - 3) lab
                              | otherwise = take (meioDaAltura lab - 2) lab
                              

-- | Função que devolve os corredores onde a casa dos fantasmas virá a ser colocada, de modo que os possamos alterar
--
extraiCorredoresCasa :: Maze -> Maze
extraiCorredoresCasa lab | even (length lab) = take 5 (drop (meioDaAltura lab - 3) lab)
                         | otherwise = take 5 (drop (meioDaAltura lab - 2) lab)


-- | Função que coloca parte da casa dos fantasmas no corredor l sendo n uma posicao na lista com a casa dos fantasmas e que aplicada aos corredores onde a casa dos fantasmas virá a ficar os tornará nos pretendidos
--
colocaParte :: Int -> Int -> Corridor -> Corridor
colocaParte _ _ [] = []
colocaParte c n l | even c = take (div (c-10) 2) l ++ ((casaFantasmasInv c) !! n) ++ drop (c - div (c-10) 2) l
                  | otherwise = take (div (c-11) 2) l ++ ((casaFantasmasInv c) !! n) ++ drop (c - div (c-11) 2) l
                 
                  
-- | Função que nos permite substituir os corredores onde a casa dos fantasmas virá a ficar pelos corredores com a parte da casa dos fantasmas incorporada que lhes corresponde
colocaCasa :: Int -> Int -> Maze -> Maze
colocaCasa _ _ [] = []
colocaCasa c n (h:t) = (colocaParte c n h) : (colocaCasa c n t) where n = length (h:t) - 1


-- | Função que devolve os corredores abaixo de onde a casa dos fantasmas virá a ser colocada e que nos permitirá juntá-los aos corredores com a casa e aos corredores acima da casa
--
extraiCorredoresAbaixoCasa :: Maze -> Maze
extraiCorredoresAbaixoCasa lab | even (length lab) = drop (meioDaAltura lab + 2) lab
                               | otherwise = drop (meioDaAltura lab + 3) lab
             
-- | Função que coloca a casa dos fantasmas no labirinto, que virá a ser aplicada ao labirinto com o túnel 
--
colocaCasaLab :: Int -> Maze -> Maze
colocaCasaLab c [] = []
colocaCasaLab c lab = (extraiCorredoresAcimaCasa lab) ++ (colocaCasa c n (extraiCorredoresCasa lab)) ++ (extraiCorredoresAbaixoCasa lab) where n = length lab - 1
  
  
-- | Função que gera um labirinto válido e aleatório
--
generateMaze :: Int -> Int -> Int -> Maze
generateMaze c a seed | (c >= 15) && (a >= 10) = colocaCasaLab c (geraTunel (soParedes c : (geraZonaInterior (c-2) (a-2) seed) ++[soParedes c]))
                      | otherwise = error "O comprimento do labirinto deve ser maior ou igual a 15 e a altura maior ou igual a 10"


-- | Função que permite uma melhor visualização do labirinto aleatório e válido gerado
--
geraLabImp :: Int -> Int -> Int -> IO()
geraLabImp c a seed = putStrLn $ imprimeLab $ generateMaze c a seed
