-- Compare two Instructions
testCompactMaze :: Instructions -> Instructions -> Bool 
testCompactMaze (x:[]) (y:[]) | x == y    = True
                              | otherwise = False
testCompactMaze (x:xs) (y:ys) | x == y    = testCompactMaze xs ys
                              | otherwise = False

