{- | 
  - O objetivo desta Tarefa foi de implementar um bot que jogue como Player Pacman por nós. 

  - Primeiramente, começamos por fazer algumas funções auxiliares, tal como a idPlayer que dado um Id e uma lista de Players, escolhe um Player, a função removePac, que dado um id, e uma lista de Players, remove o Player Pacman que tem um id igual ao dado, 
    a função compareCoords que produz uma lista com as distâncias de Manhattan do Pacman para os restantes Ghosts, a funcao whatPlayer que escolhe um jogador de uma lista de Players dependendo do inteiro dado e a função whatPlay que dados dois Players, um Pacman e um Ghost e comparando as coordenadas dos dois, faz a melhor jogada possível para o Pacman.
    Por fim, a funcao auxBotPlay produz uma possível jogada para o bot e vai ser implementada na função bot.
    
  - Concluindo, os resultados mais importantes dados por estas Tarefas foram  a implementação de jogadas automáticas no jogo    -}




-- | Escolhe um Player Pacman de uma lista de Players, baseado no seu ID
--
idPlayer :: Int -> [Player] -> Player 
idPlayer id (p1@(Pacman (PacState (a,(x,y),b,c,d,e) f g h)):ys) | id == a = p1
                                                                | otherwise = idPlayer id ys  
idPlayer id (p1@(Ghost (GhoState (a,(x,y),b,c,d,e) f)):ys) = idPlayer id ys 

-- | Remove o Pacman de uma lista de Players
--
removePac :: Int -> [Player] -> [Player]
removePac id (p1@(Pacman (PacState (a,(x,y),b,c,d,e) f g h)):ys) | id == a = ys
                                                                 | otherwise = p1 : removePac id ys 
removePac id (p1@(Ghost (GhoState (a,(x,y),b,c,d,e) f)):ys) = p1 : removePac id ys 

-- | Lista das distâncias de Manhattan do Pacman a cada Ghost
--
compareCoords :: Player -> [Player] -> [Int] 
compareCoords p1@(Pacman (PacState (a1,(x1,y1),b1,c1,d1,e1) f1 g1 h1)) ((Ghost (GhoState (a,(x,y),b,c,d,e) Alive)):t) = (abs (x1-x) + abs (y1-y)) : compareCoords p1 t  
compareCoords p1@(Pacman (PacState (a1,(x1,y1),b1,c1,d1,e1) f1 g1 h1)) ((Ghost (GhoState (a,(x,y),b,c,d,e) Dead)):t)  = (abs (x1-x) + abs (y1-y)) : compareCoords p1 t

-- | Escolhe um Player de uma lista de Players dependendo no Inteiro dado
--                  
whatPlayer :: Int -> [Player] -> Player
whatPlayer a (y:ys) | a == 0 = y 
                    | otherwise = whatPlayer (a-1) ys 

-- | Realiza as jogadas para o Pacman 
--
whatPlay :: Player -> Player -> Maybe Play
whatPlay p1@(Pacman (PacState (a1,(x1,y1),b1,c1,d1,e1) f1 g1 h1)) p2@(Ghost (GhoState (a,(x,y),b,c,d,e) Alive)) | x1 == x && y1 >= y = Just (Move a1 R)
                                                                                                                | x1 == x && y1 <= y = Just (Move a1 L)
                                                                                                                | x1 <= x && y1 == y = Just (Move a1 U) 
                                                                                                                | x1 >= x && y1 == y = Just (Move a1 D) 
                                                                                                                | y1 <= y && x1 <= x = Just (Move a1 L)
                                                                                                                | y1 >= y && x1 >= x = Just (Move a1 R) 
                                                                                                                | y1 >= y && x1 <= x = Just (Move a1 R)
                                                                                                                | y1 <= y && x1 >= x = Just (Move a1 L)
whatPlay p1@(Pacman (PacState (a1,(x1,y1),b1,c1,d1,e1) f1 g1 h1)) p2@(Ghost (GhoState (a,(x,y),b,c,d,e) Dead)) | x1 == x && y1 >= y = Just (Move a1 L)
                                                                                                               | x1 == x && y1 <= y = Just (Move a1 R)
                                                                                                               | x1 <= x && y1 == y = Just (Move a1 D) 
                                                                                                               | x1 >= x && y1 == y = Just (Move a1 U) 
                                                                                                               | y1 <= y && x1 <= x = Just (Move a1 R)
                                                                                                               | y1 >= y && x1 >= x = Just (Move a1 L) 
                                                                                                               | y1 >= y && x1 <= x = Just (Move a1 L)
                                                                                                               | y1 <= y && x1 >= x = Just (Move a1 R)

-- | Função auxiliar para a função bot  
--
auxBotPlay :: Player -> [Player] -> Maybe Play 
auxBotPlay x (y:ys) = whatPlay x (whatPlayer (minimum (compareCoords x (y:ys))) (y:ys)) 

-- | Possível jogada a realizar pelo bot
bot :: Int -> State -> Maybe Play
bot x (State m (y:ys) l) = auxBotPlay (idPlayer x (y:ys)) (removePac x (y:ys)) 

{- | 
 - O objetivo desta Tarefa é fazer com que os fantasmas tenham um comportamento próprio no jogo, ou seja, que vão atrás do Pacman ou que fujam dele.

 - Em primeiro lugar, decidimos fazer uma função que retira as coordenadas do Pacman de uma lista de Players, para depois comparar com as coordenadas do Ghost.
   Retirando as coordenadas do Pacman, fizemos as funções scatterPac e chasePac, que dado um State, um Inteiro e coordenadas produz um Play. Com a função scatterPac, o objetivo é dar instruções para o Ghost fugir do Pacman, comparando as suas coordenadas e vendo se a Piece a seguir é Wall . 
   Se for Wall, então dependendo da sua orientação o Ghost vai se movimentar sempre para a sua direita para não ir contra a Wall. A função chasePac vai ter quase o mesmo mecanismo que a função scatterPac só que o objetivo nesta é dar instruções ao Ghost para ir atrás do Pacman.
   De seguida, criamos uma função chamada findGhosts1 que dado uma lista de Players, retorna outra lista sem o Pacman e só com Ghosts.
   A função chaseMode vai fazer uma jogada para o Ghost ir atrás do Pacman, e vai utilizar a função chasePac para esse efeito. Já a função scatterMode vai fazer uma jogada para o Ghost fugir do Pacman, utilizando a função scatterPac. 
   Para finalizar fizemos a função ghostPlay que dado um State, vai devolver as jogadas de todos os fantasmas presentes na lista de Players do State.

 - Concluindo, o resultado mais importante desta Tarefa foi a alteração do comportamento dos fantasmas -}





-- | Coloca o pacman no topo da lista 
pacEnd :: [Player] -> [Player]
pacEnd [] = [] 
pacEnd ((Pacman (PacState (a,(x,y),b,c,d,e) f g h)):xs) = (Pacman (PacState (a,(x,y),b,c,d,e) f g h)) : xs
pacEnd ((Ghost (GhoState (a,(x,y),b,c,d,e) f)):xs) = pacEnd xs ++ [(Ghost (GhoState (a,(x,y),b,c,d,e) f))]


-- | Transforma uma lista de Players com Pacmans e Ghosts em uma lista de Players só com Ghosts
--
findGhosts1 :: [Player] -> [Player]
findGhosts1 [] = []
findGhosts1 ((Pacman (PacState (a,(x,y),b,c,d,e) f g h)):t) = t
findGhosts1 (p1@(Ghost (GhoState (a,(x,y),b,c,d,e) f)):ys) = p1 : findGhosts1 ys

-- | Jogada para o Ghost ir atrás do Pacman
--
chaseMode :: State -> Int -> Play
chaseMode (State m w@((Ghost (GhoState (a,(x1,y1),b,c,d,e) Alive )):t) l) z = chasePac (State m (findGhosts1 w) l) z (x2,y2) 
                                   where (x2,y2) = coordPac (pacEnd w)
chaseMode (State m w@((Pacman (PacState (a,(x,y),b,c,d,e) f g h)):t) l) z = chasePac (State m (findGhosts1 w) l) z (x2,y2) 
                                   where (x2,y2) = coordPac (pacEnd w)



-- | Dado um State, o ID e as coordenadas do Pacman, esta função elabora jogadas para o Ghost ir atrás do Pacman
--

scatterMode :: State -> Int -> Play

scatterMode (State m w@((Ghost (GhoState (a,(x,y),b,c,d,e) Dead)):t) l) z = (scatterPac (State m (findGhosts1  (((Ghost (GhoState (a,(x,y),b,c,d,e) Alive )):t))) l) z (x2,y2)) 
                                    where (x2,y2) = coordPac w
scatterMode (State m w@((Pacman (PacState (a,(x,y),b,c,d,e) f g h )):t) l) z = (scatterPac (State m (findGhosts1 w) l) z (x2,y2)) 
                                    where (x2,y2) = coordPac w

-- | Retira as coordenadas do Pacman presente na lista de Players
--
coordPac :: [Player] -> Coords
coordPac ((Pacman (PacState (a,(x,y),b,c,d,e) f g h)):t) = (x,y)
coordPac (_:t) = coordPac t
                                                                 
-- | Dá-nos a orientação do pacman de uma lista de players 
oriPac :: [Player] -> Orientation
oriPac ((Pacman (PacState (a,(x,y),b,c,d,e) f g h)):t) = c
oriPac (_:t) = oriPac t


-- | Dado um State, o ID e as coordenadas do Pacman, esta função elabora jogadas para o Ghost perseguir o Pacman
chasePac :: State -> Int -> Coords -> Play
chasePac (State m ((w@(r@(Ghost (GhoState (a,(x1,y1),b,c,d,e) Alive)):t))) l) z (x2,y2) | (x1>=x2) && (whosPiece m U r w == Wall) = Move z R
                                                                                        | (x1>=x2) && (whosPiece m R r w == Wall) = Move z U
                                                                                        | (x1>=x2) && (whosPiece m L r w == Wall) = Move z U
                                                                                        | (x1>=x2) && (whosPiece m D r w == Wall) = Move z U
                                                                                        | (x1<=x2) && (whosPiece m U r w == Wall) = Move z D
                                                                                        | (x1<=x2) && (whosPiece m R r w == Wall) = Move z D
                                                                                        | (x1<=x2) && (whosPiece m L r w == Wall) = Move z D
                                                                                        | (x1<=x2) && (whosPiece m D r w == Wall) = Move z L
                                                                                        | (y1>=y2) && (whosPiece m U r w == Wall) = Move z L
                                                                                        | (y1>=y2) && (whosPiece m R r w == Wall) = Move z L
                                                                                        | (y1>=y2) && (whosPiece m L r w == Wall) = Move z U
                                                                                        | (y1>=y2) && (whosPiece m D r w == Wall) = Move z L
                                                                                        | (y1<=y2) && (whosPiece m U r w == Wall) = Move z R
                                                                                        | (y1<=y2) && (whosPiece m R r w == Wall) = Move z D
                                                                                        | (y1<=y2) && (whosPiece m L r w == Wall) = Move z R
                                                                                        | (y1<=y2) && (whosPiece m D r w == Wall) = Move z R
                                                                                        | x1 == x2 && y1 >= y2 = (Move a L)
                                                                                        | x1 == x2 && y1 <= y2 = (Move a R)
                                                                                        | x1 <= x2 && y1 == y2 = (Move a D) 
                                                                                        | x1 >= x2 && y1 == y2 = (Move a U) 
                                                                                        | y1 <= y2 && x1 <= x2 = (Move a R)
                                                                                        | y1 >= y2 && x1 >= x2 = (Move a L) 
                                                                                        | y1 >= y2 && x1 <= x2 = (Move a L)
                                                                                        | y1 <= y2 && x1 >= x2 = (Move a R)
                                                                                        | otherwise = chasePac (State m t l) z (x2,y2)
chasePac (State m ((w@(x:t))) l) z (x2,y2) = chasePac (State m (t++[x]) l) z (x2,y2)

-- | Devolve um conjunto de jogadas para cada fantasma do labirinto
--
ghostPlay :: State -> [Play]
ghostPlay (State m [(Pacman(PacState (a,(x,y),b,c,d,e) f g h))] l) = []
ghostPlay s@(State m [(Ghost (GhoState (a,(x,y),b,c,d,e) Dead ))] l) = [scatterMode s a]  
ghostPlay s@(State m [(Ghost (GhoState (a,(x,y),b,c,d,e) Alive ))] l) = [chaseMode s a]  
ghostPlay (State m (w@(Ghost (GhoState (a,(x,y),b,c,d,e) Dead )):t) l) = (scatterMode (State m ((Ghost (GhoState (a,(x,y),b,c,d,e) Dead )):t) l) a) : ghostPlay (State m t l)
ghostPlay (State m (q@(Ghost (GhoState (a,(x,y),b,c,d,e) Alive)):t) l) = (chaseMode (State m ((Ghost (GhoState (a,(x,y),b,c,d,e) Alive)):t) l) a) : ghostPlay (State m t l)
ghostPlay (State m (p1@(Pacman(PacState (a,(x,y),b,c,d,e) f g h)):t) l) = ghostPlay (State m (t++[p1]) l)

-- | Dado um State, o ID e as coordenadas do Pacman, esta função elabora jogadas para o Ghost fugir do Pacman
--
scatterPac :: State -> Int -> Coords -> Play
scatterPac (State m ((w@(r@(Ghost (GhoState (a,(x1,y1),b,c,d,e) Dead)):t))) l) z (x2,y2) | (x1>=x2) && (whosPiece m U r w == Wall) = Move z L
                                                                                         | (x1>=x2) && (whosPiece m R r w == Wall) = Move z D
                                                                                         | (x1>=x2) && (whosPiece m L r w == Wall) = Move z D
                                                                                         | (x1>=x2) && (whosPiece m D r w == Wall) = Move z D
                                                                                         | (x1<=x2) && (whosPiece m U r w == Wall) = Move z U
                                                                                         | (x1<=x2) && (whosPiece m R r w == Wall) = Move z U
                                                                                         | (x1<=x2) && (whosPiece m L r w == Wall) = Move z U
                                                                                         | (x1<=x2) && (whosPiece m D r w == Wall) = Move z R                                                                                          | (y1>=y2) && (whosPiece m U r w == Wall) = Move z L
                                                                                         | (y1>=y2) && (whosPiece m R r w == Wall) = Move z R
                                                                                         | (y1>=y2) && (whosPiece m L r w == Wall) = Move z D
                                                                                         | (y1>=y2) && (whosPiece m D r w == Wall) = Move z R
                                                                                         | (y1<=y2) && (whosPiece m U r w == Wall) = Move z L
                                                                                         | (y1<=y2) && (whosPiece m R r w == Wall) = Move z U
                                                                                         | (y1<=y2) && (whosPiece m L r w == Wall) = Move z L
                                                                                         | (y1<=y2) && (whosPiece m D r w == Wall) = Move z L
                                                                                         | x1 == x2 && y1 >= y2 = (Move a L)
                                                                                         | x1 == x2 && y1 <= y2 = (Move a L)
                                                                                         | x1 <= x2 && y1 == y2 = (Move a U) 
                                                                                         | x1 >= x2 && y1 == y2 = (Move a D) 
                                                                                         | y1 <= y2 && x1 <= x2 = (Move a L)
                                                                                         | y1 >= y2 && x1 >= x2 = (Move a R) 
                                                                                         | y1 >= y2 && x1 <= x2 = (Move a R)
                                                                                         | y1 <= y2 && x1 >= x2 = (Move a L)
                                                                                         | otherwise = scatterPac (State m t l) z (x2,y2)
scatterPac (State m (x:t) l) z (x2,y2) = scatterPac (State m (t++[x]) l) z (x2,y2)

 

{- |
 - O objetivo da Tarefa 4 é reagir à passagem do tempo e para isso tivemos de definir a função passTime

 - Nesta tarefa, fizemos várias funções auxiliares. Primeiro, definimos uma função chasePac que faz alterar o estado da boca do Pacman, depois definimos outra função lostTime para o Pacman enquanto em Mega, perder tempo Mega. A função changeModeGhost faz alterar o State de entrada se não encontrar modo Mega em nenhum Pacman.
   Para a função encontraMega, se o Pacman presente numa lista de Players tiver em Mega, então a função irá dar False, por sua vez se não estiver em Mega irá dar True.
   A função changeModePac transforma o tempo Mega em zero e muda o Modo dos Pacmans presentes no State para Normal.
   Para a função encontraTempo, se numa lista de Players, o tempo Mega de um Pacman for menor ou igual a zero então dá True, e por sua vez se não encontar irá dar False.
   A função convertPac, transforma um State numa lista de jogadores.
   A encontraPac vai procurar o Pacman numa lista de jogadores.
   A função removePiece é usada para efeitos visuais no próprio jogo, pois quando o Pacman passa por cima das Food Big e Food Little, estas desaparecem.
   A função newPlay, vai ser uma nova função play com as novas caracteristicas.
   A função passTime, faz determinar as ações em cada instante por parte dos Players.
   A função pacTop coloca o PacMan no final da lista.

 - Em suma, o principal resultado obtido com esta tarefa foi a implementação da passagem do tempo nas jogadas -}








defaultDelayTime = 250 -- 250 ms

-- | Faz mudar o estado da boca do Player Pacman 
--
changeMouth :: State -> State
changeMouth (State m ((Pacman ((PacState (a,(x,y),b,c,d,e) f g h))):t) l) | g==Open = (State m ((Pacman ((PacState (a,(x,y),b,c,d,e) f Closed h))):t) l)
                                                                          | otherwise = (State m ((Pacman ((PacState (a,(x,y),b,c,d,e) f Open h))):t) l)
changeMouth (State m (x:t) l) = changeMouth (State m (t++[x]) l)

-- | Faz perder tempo Mega enquanto está em Mega
--
lostTime :: [Player] -> [Player]
lostTime [] = [] 
lostTime ((Pacman (PacState (a,(x,y),b,c,d,e) f g Mega)):t) = ((Pacman (PacState (a,(x,y),b,c,d,e) (f-0.25) g Mega)):t)
lostTime (x:t) = x : lostTime t

-- | Se não encontra modo Mega, então o State vai se alterar
--
changeModeGhost :: State -> State
changeModeGhost w@(State m lj l) | encontraMega lj = (State m (auxchangeModeGhost lj) l)
                                 | otherwise = w

-- | Dada uma lista de Players, muda a velocidade dos fantasmas para 1 e o Modo para Alive
--
auxchangeModeGhost :: [Player] -> [Player]
auxchangeModeGhost [] = []
auxchangeModeGhost ((Ghost (GhoState (a,(x,y),b,c,d,e) f)):t) = (Ghost (GhoState (a,(x,y),1,c,d,e) Alive)) : auxchangeModeGhost t 
auxchangeModeGhost ((Pacman (PacState (a,(x,y),b,c,d,e) f g h)):t) = (Pacman (PacState (a,(x,y),b,c,d,e) f g h)) : auxchangeModeGhost t 

-- | Se não encontrar nenhum Pacman com modo Mega dá True, se encontrar da False
encontraMega :: [Player] -> Bool
encontraMega [] = True
encontraMega ((Pacman (PacState (a,(x,y),b,c,d,e) f g h)) : xs) | h==Mega = False
                                                                | otherwise = True
encontraMega (_:t) = encontraMega t

-- | Muda o modo do Pacman para Normal
changeModePac :: State -> State
changeModePac w@(State m lj l) | encontraTempo lj = (State m (auxchangeModePac lj) l)
                               | otherwise = w

-- | Muda o tempo dos Pacmans na lista de Players para 0 e o seu modo para Normal
auxchangeModePac :: [Player] -> [Player]
auxchangeModePac [] = [] 
auxchangeModePac ((Pacman (PacState (a,(x,y),b,c,d,e) f g h)):t) = (Pacman (PacState (a,(x,y),b,c,d,e) 0 g Normal)) : auxchangeModePac t 
auxchangeModePac (h:t) = h : auxchangeModeGhost t  

-- | Se encontrar tempo Mega menor ou igual a 0 dá True, se não dá False
encontraTempo :: [Player] -> Bool
encontraTempo ((Pacman (PacState (a,(x,y),b,c,d,e) f g h)):t) | f<=0 = True
                                                              | otherwise = False
encontraTempo ((_:t)) = encontraTempo t

-- | Transforma o State na lista de jogadores que se encontra no State
convertPac :: State -> [Player]
convertPac (State m lj lv) = lj 

-- | Se encontra o Pacman retorna esse Pacman
encontraPac :: [Player] -> Player
encontraPac (w@(Pacman (PacState (a,(x,y),b,c,d,e) f g h)):t) = w
encontraPac (_:t) = encontraPac t 

-- | Remove as pieces quando o Pacman passa por elas
removePiece :: State -> State 
removePiece (State m lj lv) = (State (auxRemove m (encontraPac lj)) lj lv) 

-- | Determina a peça a remover e substitui por Empty
auxRemove :: Maze -> Player -> Maze
auxRemove m (Pacman (PacState (a,(x,y),b,c,d,e) f g h)) = take (x) m ++ [(take (y) l1) ++ [Empty] ++ (drop (y+1) l1)] ++ drop (x+1) m 
                                                        where l1 = head (drop (x) m)

-- | Nova função play
newPlay :: Play -> State -> State 
newPlay (Move id ori) (State m lj lv) = changeModeGhost $ changeModePac $ removePiece $ (changeMouth (State m1 (lostTime lj1) lv1))
                                 where (State m1 lj1 lv1) = play (Move id ori) (State m lj lv)  

-- | Altera o estado do jogo em uma iteração
passTime :: Int -> State -> State
passTime 0 s = s 
passTime i (State s lj lv) = auxPass i (pacEnd lj) (State s (pacEnd lj) lv)
 
-- | Função auxiliar para a passTime
auxPass :: Int -> [Player] -> State -> State 
auxPass _ [] s = s
auxPass i (p1@(Ghost (GhoState (a,(x,y),0.5,c,d,e) f)):xs) s | even i = auxPlays (ghostPlay s) s
                                                             | otherwise = s 
auxPass i (p1@(Ghost (GhoState (a,(x,y),1.0,c,d,e) f)):xs) s = auxPlays (ghostPlay s) s 
auxPass i (p1@(Pacman (PacState (a,(x,y),v,c,d,e) f g h)):xs) s = (newPlay (Move a c) (auxPlays (ghostPlay s) s))

-- | Coloca o Pacman no final da lista de Players
pacTop :: [Player] -> [Player]
pacTop [] = [] 
pacTop ((Pacman (PacState (a,(x,y),b,c,d,e) f g h)):xs) = xs ++ [(Pacman (PacState (a,(x,y),b,c,d,e) f g h))] 
pacTop ((Ghost (GhoState (a,(x,y),b,c,d,e) f)):xs) = (Ghost (GhoState (a,(x,y),b,c,d,e) f)) : pacTop xs

-- | Aplica uma lista de Plays num estado
auxPlays :: [Play] -> State -> State
auxPlays [] s = s 
auxPlays (x:xs) s = auxPlays xs (newPlay x s)




{- | 
 -   O principal objetivo desta Tarefa é converter um labirinto numa forma mais adequada para leitura, criando a função compactMaze.
    
 -   Começámos por definir a função chooseIndCorr que dado uma lista de corredores e um corredor, escolhe a posição onde um corredor se encontra, por exemplo se se encontrar na primeira posição retorna o valor 0.
     Seguidamente, definimos a função convertToInstruct que transforma um corredor numa Instruction e a função instructToInstruct que dado uma lista de pares Int e Piece, se para dois elementos consecutivos as Pieces são iguais, então vai se transformar num elemento em que a primeira componente vai ser composta pela Piece do primeiro par somado com um, e assim consecutivamente até percorrer a lista toda.
     Se os dois elementos consecutivos não tiverem as Pieces iguais, então esses elementos vão ficar iguais.
     Por fim, fizemos a função compactMaze que transforma um labirinto numa lista de instruções.

 -   Concluindo, o principal resultado obtido nesta tarefa foi a compactação do labirinto para uma forma mais fácil de se ler.
                                                                                                                         -}






-- | Creates Intructions given a Maze   

-- ^The function verify if the last element belong to the rest of the list, and to this recursively     

compactMaze :: Maze -> Instructions              
compactMaze []     = []                                                     
compactMaze l | elem (last l) (init l) = compactMaze (init l) ++  [Repeat (chooseIndCorr (init l) (last l))] 
              | otherwise = compactMaze (init l) ++ [convertToInstruct (last l)] 




-- | Calculates given a list of corridors and a corridor from that list, the position in which it is located, where the runner at the top of the list is in position 0 

chooseIndCorr :: [Corridor] -> Corridor -> Int  
chooseIndCorr (x:xs) a | a == x    = 0  
                       | otherwise = 1 + (chooseIndCorr xs a) 



-- | Given a corridor this function converts it to an Instruction
convertToInstruct :: Corridor -> Instruction 
convertToInstruct c = Instruct ( instructToInstruct (map (\x -> (1,x)) c)) 
 


-- | Given a list of pairs converts it into a list where the consecutive elements are equal, that is, where the Piece in the second element of the pair are the same in consecutives pairs of the list, come together 

-- ^If the consecutive elements are equal we add on one to the first element of the pair where the function retains the first pair with the changes otherwise the first pair go to the head of the final list and to this recursively
instructToInstruct :: [(Int, Piece)] -> [(Int, Piece)] 
instructToInstruct ((a,b):[])  = [(a,b)]
instructToInstruct ((a,b):(c,d):xs) | b == d    = instructToInstruct ((a+1,b):xs) 
                                    | otherwise = (a,b) : instructToInstruct ((c,d):xs) 
