-- | Movement of Pacman given one Orientation and one Player
movPlayer :: Orientation -> Player -> Player
movPlayer ori (Pacman (PacState (a,(x,y),g,h,b,c) d e f)) | h==U && ori == U = (Pacman (PacState (a,(x-1,y),g,U,b,c) d e f))       
                                                          | h==D && ori == D = (Pacman (PacState (a,(x+1,y),g,D,b,c) d e f))  
                                                          | h==L && ori == L = (Pacman (PacState (a,(x,y-1),g,L,b,c) d e f)) 
                                                          | h==R && ori == R = (Pacman (PacState (a,(x,y+1),g,R,b,c) d e f))  
                                                          | h==Null && ori == U = (Pacman (PacState (a,(x,y),g,U,b,c) d e f))
                                                          | h==Null && ori == D = (Pacman (PacState (a,(x,y),g,D,b,c) d e f))
                                                          | h==Null && ori == L = (Pacman (PacState (a,(x,y),g,L,b,c) d e f))
                                                          | h==Null && ori == R = (Pacman (PacState (a,(x,y),g,R,b,c) d e f)) 
                                                          | h/=U && ori == U = (Pacman (PacState (a,(x,y),g,U,b,c) d e f))
                                                          | h/=D && ori == D = (Pacman (PacState (a,(x,y),g,D,b,c) d e f))
                                                          | h/=L && ori == L = (Pacman (PacState (a,(x,y),g,L,b,c) d e f))
                                                          | h/=R && ori == R = (Pacman (PacState (a,(x,y),g,R,b,c) d e f))
                                                          | ori == Null = (Pacman (PacState (a,(x,y),g,Null,b,c) d e f))         
movPlayer ori (Ghost (GhoState (a,(x,y),g,h,b,c) d)) | h==U && ori == U = (Ghost (GhoState (a,(x-1,y),g,U,b,c) d))       
                                                     | h==D && ori == D = (Ghost (GhoState (a,(x+1,y),g,D,b,c) d))  
                                                     | h==L && ori == L = (Ghost (GhoState (a,(x,y-1),g,L,b,c) d)) 
                                                     | h==R && ori == R = (Ghost (GhoState (a,(x,y+1),g,R,b,c) d)) 
                                                     | h==Null && ori == U = (Ghost (GhoState (a,(x,y),g,U,b,c) d))       
                                                     | h==Null && ori == D = (Ghost (GhoState (a,(x,y),g,D,b,c) d))  
                                                     | h==Null && ori == L = (Ghost (GhoState (a,(x,y),g,L,b,c) d)) 
                                                     | h==Null && ori == R = (Ghost (GhoState (a,(x,y),g,R,b,c) d)) 
                                                     | h/=U && ori == U = (Ghost (GhoState (a,(x,y),g,U,b,c) d))
                                                     | h/=D && ori == D = (Ghost (GhoState (a,(x,y),g,D,b,c) d))
                                                     | h/=L && ori == L = (Ghost (GhoState (a,(x,y),g,L,b,c) d))
                                                     | h/=R && ori == R = (Ghost (GhoState (a,(x,y),g,R,b,c) d))
                                                     | ori == Null = (Ghost (GhoState (a,(x,y),g,Null,b,c) d))


-- | Verify if one ID corresponds to the ID of a Player
encontraID :: Int -> Player -> Bool
encontraID z (Pacman (PacState (a,(x,y),b,c,d,e) f g h)) | z == a    = True
                                                         | otherwise = False 
encontraID z (Ghost (GhoState (a,(x,y),b,c,d,e) f)) | z == a    = True
                                                    | otherwise = False       


-- | Verify if the ID correspond to a Player in a Player list, and move that Player
movPlayerId :: Int -> Orientation -> [Player] -> [Player] 
movPlayerId id ori (h:[]) | encontraID id h = [(movPlayer ori h)] 
                          | otherwise       = [h] 
movPlayerId id ori (h:t) | encontraID id h = (movPlayer ori h) : t 
                         | otherwise       = h : movPlayerId id ori t


-- | Identify the piece in a certain position of the Corridor
showPiece :: Maze -> Int -> Int -> Piece 
showPiece m a b = aux (aux m a) b                            
                where aux (x:[]) a = x
                      aux (x:xs) a | a == 0 = x
                                   | otherwise = aux xs (a-1)   


-- | Identify the next piece in the Maze, given a certain Orientation
whosPiece :: Maze -> Orientation -> Player -> [Player] -> Piece
whosPiece m ori (p1@(Pacman (PacState (a,(x,y),b,c,d,e) f g h))) (p2@(Ghost (GhoState (a1,(x1,y1),b1,c1,d1,e1) f1)):t) | ori == U && x1 == (x-1) && y == y1 = PacPlayer p2   
                                                                                                                       | ori == D && x1 == (x+1) && y == y1 = PacPlayer p2  
                                                                                                                       | ori == L && x == x1 && y1 == (y-1) = PacPlayer p2 
                                                                                                                       | ori == R && x == x1 && y1 == (y+1) = PacPlayer p2   
                                                                                                                       | otherwise                          = whosPiece m ori p1 t 
whosPiece m ori (p1@(Pacman (PacState (a,(x,y),b,c,d,e) f g h))) (p2@(Pacman (PacState (a1,(x1,y1),b1,c1,d1,e1) f1 g1 h1)):t) | ori == U && x1 == (x-1) && y == y1 = PacPlayer p2   
                                                                                                                              | ori == D && x1 == (x+1) && y == y1 = PacPlayer p2  
                                                                                                                              | ori == L && x == x1 && y1 == (y-1) = PacPlayer p2 
                                                                                                                              | ori == R && x == x1 && y1 == (y+1) = PacPlayer p2  
                                                                                                                              | otherwise                          = whosPiece m ori p1 t                                                                                                         
whosPiece m ori (Pacman (PacState (a,(x,y),b,c,d,e) f g h)) _ | ori == U = showPiece m (x-1) y 
                                                              | ori == D = showPiece m (x+1) y 
                                                              | ori == L = showPiece m x (y-1) 
                                                              | ori == R = showPiece m x (y+1)
                                                              | ori == Null = showPiece m x y 
whosPiece m ori (p1@(Ghost (GhoState (a,(x,y),b,c,d,e) f))) (p2@(Pacman (PacState (a1,(x1,y1),b1,c1,d1,e1) f1 g1 h1)):t) | ori == U && x1 == (x-1) && y == y1 = PacPlayer p2   
                                                                                                                         | ori == D && x1 == (x+1) && y == y1 = PacPlayer p2  
                                                                                                                         | ori == L && x == x1 && y1 == (y-1) = PacPlayer p2 
                                                                                                                         | ori == R && x == x1 && y1 == (y+1) = PacPlayer p2  
                                                                                                                         | otherwise                          = whosPiece m ori p1 t  
whosPiece m ori (p1@(Ghost (GhoState (a,(x,y),b,c,d,e) f))) (p2@(Ghost (GhoState (a1,(x1,y1),b1,c1,d1,e1) f1)):t) | ori == U && x1 == (x-1) && y == y1 = PacPlayer p2   
                                                                                                                  | ori == D && x1 == (x+1) && y == y1 = PacPlayer p2  
                                                                                                                  | ori == L && x == x1 && y1 == (y-1) = PacPlayer p2 
                                                                                                                  | ori == R && x == x1 && y1 == (y+1) = PacPlayer p2  
                                                                                                                  | otherwise                          = whosPiece m ori p1 t                                                                                            
whosPiece m ori (Ghost (GhoState (a,(x,y),b,c,d,e) f)) _ | ori == U = showPiece m (x-1) y   
                                                         | ori == D = showPiece m (x+1) y 
                                                         | ori == L = showPiece m x (y-1) 
                                                         | ori == R = showPiece m x (y+1)
                                                         | ori == Null = showPiece m x y 


-- | If the ID is found in one Player, that Player should gain one more point in the pontuation
eatLittle :: Int -> [Player] -> [Player]
eatLittle id [] = []
eatLittle id (h@(Pacman (PacState (a,(x,y),g,c,d,e) i m n)):t) | encontraID id h = (Pacman(PacState (a,(x,y),g,c,d+1,e) i m n)) : t
                                                               | otherwise       = h : eatLittle id t  
eatLittle id (h@(Ghost (GhoState (a,(x,y),g,c,d,e) i)):t) = h : eatLittle id t


-- | Changes the list of Players, depending on the Maze, the ID, the Orientation and a Piece 

movWhenEat :: Maze -> Int -> Orientation -> Piece -> [Player] -> [Player]
movWhenEat _ _ _ _ [] = []
movWhenEat _ _ Null _ s = s
movWhenEat m id ori Empty (p1@(Pacman (PacState (a,(x,y),g,c,d,e) i j n)):t) | encontraID id p1 = whenEmpty m ori (x,y) p1 : t 
                                                                             | otherwise        = p1 : movWhenEat m id ori Empty t 
movWhenEat m id ori Empty (p1@(Ghost (GhoState (a,(x,y),g,c,d,e) i)):t) | encontraID id p1 = whenEmpty m ori (x,y) p1 : t 
                                                                        | otherwise        = p1 : movWhenEat m id ori Empty t 
movWhenEat m id ori Wall (h:t) | encontraID id h = nextWall id ori (h:t) 
                               | otherwise       = h : movWhenEat m id ori Wall t   
movWhenEat m id ori (Food Little) (h:t) | encontraID id h = movPlayerId id ori (eatLittle id (h : t)) 
                                        | otherwise       = h : movWhenEat m id ori (Food Little) t
movWhenEat m id ori (Food Big) (h:t) | encontraID id h    = movPlayerId id ori (eatBig1 id (h:t))
                                     | otherwise          = movWhenEat m id ori (Food Big) (t++[h]) 
movWhenEat m id ori (PacPlayer x) (h:t) | encontraID id h    = nextPlayer ori m h x t
                                        | otherwise          = movWhenEat m id ori (PacPlayer x) (t++[h]) 


-- | If the ID is found in a Player of a list of Players, then its velocity should go to 0.0.

-- ^ Otherwise, the list of Players continue equal

nextWall :: Int -> Orientation -> [Player] -> [Player]
nextWall id ori [] = [] 
nextWall id ori (p1@(Pacman (PacState (a,(x,y),b,c,g,h) d e f)):t) | encontraID id p1 && ori == U = (Pacman (PacState (a,(x,y),b,U,g,h) d e f)) : t
                                                                   | encontraID id p1 && ori == D = (Pacman (PacState (a,(x,y),b,D,g,h) d e f)) : t
                                                                   | encontraID id p1 && ori == L = (Pacman (PacState (a,(x,y),b,L,g,h) d e f)) : t 
                                                                   | encontraID id p1 && ori == R = (Pacman (PacState (a,(x,y),b,R,g,h) d e f)) : t
                                                                   | encontraID id p1 && ori == Null = (Pacman (PacState (a,(x,y),b,Null,g,h) d e f)) : t
                                                                   | otherwise                    = p1 : nextWall id ori t 
nextWall id ori (p2@(Ghost (GhoState (a,(x,y),b,c,d,e) f)):t) | encontraID id p2 && ori == U = (Ghost (GhoState (a,(x,y),b,U,d,e) f)) :t
                                                              | encontraID id p2 && ori == D = (Ghost (GhoState (a,(x,y),b,D,d,e) f)) :t
                                                              | encontraID id p2 && ori == L = (Ghost (GhoState (a,(x,y),b,L,d,e) f)) :t
                                                              | encontraID id p2 && ori == R = (Ghost (GhoState (a,(x,y),b,R,d,e) f)) :t
                                                              | encontraID id p2 && ori == Null = ((Ghost (GhoState (a,(x,y),b,Null,d,e) f)):t)
                                                              | otherwise                    = p2 : nextWall id ori t

-- | Verify if the Player is in the right position to move to the next position depending on its Orientation
goeat :: Int -> Orientation -> [Player] -> Bool     
goeat id ori [] = False 
goeat id ori (h@(Ghost (GhoState (a,(x,y),v,d,b,c) n)):t) | ori == d && encontraID id h = True 
                                                          | otherwise                   = goeat id ori t 
goeat id ori (h@(Pacman (PacState (a,(x,y),g,c,d,e) i m n)):t) | ori == c && encontraID id h = True 
                                                               | otherwise                   = goeat id ori t                                                         


-- | The Player adds five to its pontuation
eatBig :: Player -> Player
eatBig (Pacman (PacState (a,(x,y),g,c,d,e) i m n)) = (Pacman (PacState (a,(x,y),1,c,d+5,e) (i+10) m Mega))


-- | The Player halves its velocity
movGhostDead :: Player -> Player
movGhostDead (Ghost (GhoState (a,(x,y),v,d,b,c) f)) = (Ghost (GhoState (a,(x,y),0.5,d,b,c) Dead))


-- | Given an ID and a list of Players, if the ID is found for a Pacman, that player should gain five points in its pontuation,
-- and the function ,movGhostDead should be applyed for all the Ghosts in the maze
eatBig1 :: Int -> [Player] -> [Player]
eatBig1 id [] = []
eatBig1 id (h@(Ghost (GhoState (a,(x,y),v,d,b,c) f)):t) = (movGhostDead h) : eatBig1 id t  
eatBig1 id (h@(Pacman (PacState (a,(x,y),g,c,d,e) i m n)):t) | encontraID id h = eatBig h : eatBig1 id t
                                                             | otherwise       = h : eatBig1 id t  


-- | The Player increases its pontuation by ten points
eatGhost :: Player -> Player
eatGhost (Pacman (PacState (a,(x,y),b,c,d,e) i m Mega)) = (Pacman (PacState (a,(x,y),1,c,d+10,e) i m Mega))


-- | If a Player Pacman encounters a Player Ghost, the list of Players will change
nextPlayer :: Orientation -> Maze -> Player -> Player -> [Player] -> [Player]
nextPlayer ori mz p1 p2 [] = [] 
nextPlayer ori mz ((p1@(Pacman (PacState (a,(x,y),b,c,d,e) f g Normal)))) ((p2@(Ghost (GhoState (k,(l,m),n,o,p,q) Alive)))) t | ori == c  = movPlayer ori (dyePac p1) : t
                                                                                                                              | otherwise = movPlayer ori p1 : t 
nextPlayer ori mz ((p1@(Pacman (PacState (a,(x,y),b,c,d,e) f g Mega)))) ((p2@(Ghost (GhoState (k,(l,m),n,o,p,q) Dead)))) t | ori == c  = movPlayer ori (eatGhost p1) : spawnGhost mz p2 t
                                                                                                                           | otherwise = movPlayer ori p1 : t 
nextPlayer ori mz ((p1@(Ghost (GhoState (a,(x,y),b,c,d,e) Alive)))) ((p2@(Pacman (PacState (k,(l,m),n,o,p,q) f g Normal)))) t = movPlayer ori p1 : t 
nextPlayer ori mz ((p1@(Ghost (GhoState (a,(x,y),b,c,d,e) Dead)))) ((p2@(Pacman (PacState (k,(l,m),n,o,p,q) f g Mega)))) t | ori == c  = (spawnGhost mz p1 t) ++ [movPlayer ori (eatGhost p1)]
                                                                                                                           | otherwise = movPlayer ori p1 : t 
nextPlayer ori mz (p1@(Ghost (GhoState (a,(x,y),b,c,d,e) f))) (p2@(Ghost (GhoState (a1,(x1,y1),b1,c1,d1,e1) f1)))  t = p1 : t
--nextPlayer ori mz ((p1@(Pacman (PacState (a,(x,y),b,c,d,e) f g h)))) _ t = movPlayer ori p1 : t 


-- | What happens to Pacman when he dies, if he has 0 lives or more
dyePac :: Player -> Player
dyePac (Pacman (PacState (a,(x,y),b,c,d,0) z f g)) = (Pacman (PacState (a,(x,y),b,c,d,0) z f Dying))
dyePac (Pacman (PacState (a,(x,y),b,c,d,e) z f g)) = (Pacman (PacState (a,(x,y),b,c,d,e-1) z f Normal))


-- | Choose the right Ghost of the list of Players to spawn in the Ghost house
spawnGhost :: Maze -> Player -> [Player] -> [Player] 
spawnGhost m p1 [] = []
spawnGhost m p1 (h:t) | p1 == h   = spawnGho m h : t 
                      | otherwise = h : spawnGhost m p1 t


-- | Defines the spawn of the Ghost when it is an even or odd heigth of the Maze
spawnGho :: Maze -> Player -> Player
spawnGho m (Ghost (GhoState (a,(x,y),b,c,d,q) z)) | even (length m) = Ghost (GhoState (a,((div (length m) 2) - 1 , (div (length (head m)) 2 ) - 1) ,1,c,d,1)  Alive)
                                                  | odd (length m)  = Ghost (GhoState (a,((div (length m) 2), (div (length (head m)) 2 )),1,c,d,1) Alive)  


-- | What happens to the Player when he moves to a Piece Empty
whenEmpty :: Maze -> Orientation -> Coords -> Player -> Player 
whenEmpty m ori (x,y) h | tunelEmpty ori m (x,y) = tunel m h 
                        | otherwise              = movPlayer ori h 


-- | Define if the piece Empty is the Tunnel or not and verifies if the Orientation is the correct
tunelEmpty :: Orientation -> Maze -> Coords -> Bool 
tunelEmpty ori m (x,y) | ori == L && y == 0 = True 
                       | ori == R && y == (length (head m)) - 1 && x == (div (length m) 2) = True 
                       | ori == R && y == (length (head m)) - 1 && x == (div (length m) 2) - 1 = True 
                       | ori == Null && y == 0 = False 
                       | ori == Null && y == (length (head m)) - 1 && x == (div (length m) 2) - 1 = False
                       | ori == Null && y == (length (head m)) - 1 && x == (div (length m) 2) = False 
                       | otherwise = False  


-- | Change the position of the player when he enters the Tunnel
tunel :: Maze -> Player -> Player
tunel m (Pacman (PacState (a,(x,0),b,c,d,e) f g h)) = (Pacman (PacState (a,(x,y-1),b,L,d,e) f g h))
                                                    where y = length (head m) 
tunel m (Pacman (PacState (a,(x,y),b,c,d,e) f g h)) = (Pacman (PacState (a,(x,0),b,R,d,e) f g h))
tunel m (Ghost (GhoState (a,(x,0),b,c,d,e) f)) = (Ghost (GhoState (a,(x,y-1),b,L,d,e) f))
                                                    where y = length (head m) 
tunel m (Ghost (GhoState (a,(x,y),b,c,d,e) f)) = (Ghost (GhoState (a,(x,0),b,R,d,e) f))                            


-- | Move the Player that corresponds to the ID, depending on the Orientation and on the Piece in the next position
playWith :: Maze -> Int -> Orientation -> [Player] -> [Player]
playWith m id ori [] = [] 
playWith m id ori (p1@(Pacman (PacState (a,(x,y),b,c,d,e) f g h)):t) | encontraID id p1 = movWhenEat m id ori (whosPiece m ori p1 t) (p1:t)
                                                                     | otherwise        = playWith m id ori (t++[p1]) 
playWith m id ori (p1@(Ghost (GhoState (a,(x,y),b,c,d,e) f)):t) | encontraID id p1 = movWhenEat m id ori (whosPiece m ori p1 t) (p1:t)
                                                                | otherwise        = playWith m id ori (t++[p1])                        



-- | Change the list of Players in the State, depending on the ID, on the Orientation and on the Maze 
play :: Play -> State -> State 
play (Move id ori) (State m lj lv) = (State m (playWith m id ori lj) lv) 



{- | 
-   Nesta tarefa, o principal objetivo é gerar um labirinto válido de acordo com o jogo original.
    Para alcançar esse objetivo, tivemos de definir a função generateMaze que dado a altura e o comprimento do labirinto e uma seed aleatória, produz um labirinto completamente válido.

-   Ao ler o enunciado do projeto, percebemos que tinhamos de realizar várias tarefas, tal como colocar a casa dos fantasmas no meio do labirinto, com algumas restrições caso o comprimento do labirinto fosse par, ou ímpar,
    como também colocar os tuneis, tanto no canto direito, como no canto esquerdo dependendo se a altura é ímpar ou se a altura é par.
    Em relação à casa dos fantasmas, para começar fizemos uma função oddHouse que representa a casa dos fantasmas quando o labirinto tem comprimento ímpar, e fizemos uma função evenHouse que representa a casa dos fantasmas quando o labirinto tem comprimento par.
    Logo a seguir, tivemos de escolher a lista de corredores onde ia ser implementada a casa dos fantasmas, e foi para isso que fizemos a função chooseCorrHouse que dado um maze produz essa lista de corredores. Ainda implementámos a putLine que escolhe um corredor de uma lista de corredores dependendo do numero inteiro dado.
    Por fim, fizemos a função putHouse onde alteramos a lista de corredores (que representa o labirinto) para colocar a casa dos fantasmas, utilizando as funções evenHouse, oddHouse e putLine.
    Quanto à implementação do tunel, criamos uma função denominada por linesTunnel que escolhe a linha do meio do labirinto, uma função putEmpty que coloca peças Emptys no ínicio e no final dos corredores de uma lista de corredores, a changeMidCorr que dado um Maze escolhe uma lista de corredores onde ficará o tunel, e por fim 
    a generateTunnel que utilizando as funções auxiliares anteriormente definidas para o tunel, gera os tuneis no labirinto.
    Para gerar um labirinto válido, também tivemos de fazer duas funções auxiliares : a buildWalls que coloca paredes na parte de cima e na parte de baixo do labirinto, e a putWalls que coloca paredes na parte direita e na parte esquerda do labirinto
    Por fim, fizemos a generateMaze, que utilizando as funções buildWalls, generateTunnel, putHouse, changeMidCorr e também tendo em conta se a altura do labirinto é impar ou par, gera um labirinto válido.

-   Em suma, os principais resultados obtidos nesta Tarefa foram a construção de um labirinto válido e a implementação do tunel e da casa dos fantasmas.  -}



-- | Given a seed returns a list of n integer randomly generated
--
geraAleatorios :: Int -> Int -> [Int]
geraAleatorios n seed = let gen = mkStdGen seed -- creates a random generator
                        in take n $ randomRs (0,90) gen -- takes the first n elements from an infinite series of random numbers between 0-9


-- | Given a seed returns an integer randomly generated
--
nrAleatorio :: Int -> Int
nrAleatorio seed = head $ geraAleatorios 1 seed


-- | Converts a list into a list of list of size n
--
subLista :: Int -> [a] -> [[a]]
subLista _ [] = []
subLista n l = take n l: subLista n (drop n l)


-- | Converts an integer number into a Piece
--
convertePiece  :: Int -> Piece 
convertePiece  x | x == 3 = Food Big
                 | x >= 0 && x < 70 = Food Little
                 | x >= 70 && x <= 90 = Wall

-- | Converts a Corridor to a string
--
printCorridor :: Corridor -> String
printCorridor [] = "\n"
printCorridor (h:t) = show h ++ printCorridor t

-- | Converts a list of integers into a Corridor
--
converteCorridor :: [Int] -> Corridor
converteCorridor l = map convertePiece  l

-- | Converts a list of lists of integers into a Maze
--
converteMaze :: [[Int]] -> Maze
converteMaze l = map converteCorridor l



--                               [CASA DOS FANTASMAS]

-- | Maze house for odd length
oddHouse :: [Corridor]
oddHouse = [[Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty],
             [Empty,Wall,Wall,Wall,Empty,Empty,Empty,Wall,Wall,Wall,Empty],
             [Empty,Wall,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Wall,Empty],
             [Empty,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Empty],
             [Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty]
            ]

-- | Maze house for even length
evenHouse :: [Corridor]
evenHouse = [[Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty],
           [Empty,Wall,Wall,Wall,Empty,Empty,Wall,Wall,Wall,Empty],
           [Empty,Wall,Empty,Empty,Empty,Empty,Empty,Empty,Wall,Empty],
           [Empty,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Wall,Empty],
           [Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty]
          ]

-- | Choose a list of corridors for the ghost house
chooseCorrHouse :: Maze -> [Corridor]
chooseCorrHouse m | even (length m) = take 5 (drop (metade-3) m)  
                  | otherwise       = take 5 (drop (metade-2) m) 
                  where metade = linesTunnel m  

-- | Choose the right corridor
putLine :: Int -> [Corridor] -> Corridor
putLine n (x:xs) | n==1 = x 
                 | otherwise = putLine (n-1) xs 

-- | Put the ghost house in the middle of the maze
putHouse :: [Corridor] -> [Corridor] 
putHouse (x:[]) | even (length x) = [(take (metade-5) x ++ (putLine 5 evenHouse) ++ drop (metade+5) x)] 
                | otherwise       = [(take (metade-5) x ++ (putLine 5 oddHouse) ++ drop (metade+6) x)]              
          where metade = div (length x) 2 
putHouse (x:xs) | even (length x) = let c = 5 - length xs in ((take (metade-5) x ++ (putLine c evenHouse) ++ drop (metade+5) x) : putHouse xs) 
                | otherwise       = let c = 5 - length xs in ((take (metade-5) x ++ (putLine c oddHouse) ++ drop (metade+6) x) : putHouse xs)                      
          where metade = div (length x) 2 

--                                      [TUNEL]

-- | Choose the middle line of the tunnel depending on the height of the maze
linesTunnel :: Maze -> Int 
linesTunnel m = div (length m) 2 
                 
-- | Generate Corridors with emptys in the beginning and in the end of the maze
putEmpty :: [Corridor] -> [Corridor] 
putEmpty [x]    = [[Empty] ++ (tail (init x)) ++ [Empty]] 
putEmpty (x:xs) = ([Empty] ++ (tail (init x)) ++ [Empty]) : putEmpty xs 

-- | Choose the right Corridors for the tunnel
changeMidCorr :: Maze -> [Corridor]
changeMidCorr m | even (length m) = take 2 (drop (n-1) m)  
                | otherwise       = take 1 (drop n m) 
              where n = linesTunnel m 

-- | Creates the tunnel in the maze
generateTunnel :: Maze -> Maze 
generateTunnel m | odd (length m) = putWalls (take metade m) ++ putEmpty (changeMidCorr m) ++ putWalls (drop (metade+1) m) 
                 | otherwise      = putWalls (take (metade-1) m) ++ putEmpty (changeMidCorr m) ++ putWalls (drop (metade+1) m) 
                 where metade = linesTunnel m 


--                              [LABIRINTO VÁLIDO]

-- | Creates a corridor only with Wall pieces, whereas the integer is non-negative
buildWalls :: Int -> Corridor 
buildWalls x | x == 0    = [] 
             | otherwise = Wall : buildWalls (x-1)   

-- | Put walls on the edge of the list of Corridors 
putWalls :: [Corridor] -> [Corridor]
putWalls [] = [] 
putWalls [x] = [[Wall] ++ tail (init x) ++ [Wall]] 
putWalls (x:xs) = ([Wall] ++ (tail (init x)) ++ [Wall]) : putWalls xs 

-- | Creates a valid maze
generateMaze :: Int -> Int -> Int -> Maze
generateMaze x y s | even y =  let m = [buildWalls x] ++ generateMaze1 ++ [buildWalls x] in generateTunnel (take (n-3) m ++ putHouse (chooseCorrHouse m) ++ drop (n+2) m) 
                   | otherwise = let m = [buildWalls x] ++ generateMaze1 ++ [buildWalls x] in generateTunnel (take (n-2) m ++ putHouse (chooseCorrHouse m) ++ drop (n+3) m) 
            where n = div y 2 
                  generateMaze1 = let random_nrs = geraAleatorios (x*(y-2)) s in converteMaze $ subLista x random_nrs 



loadManager :: Manager
loadManager = ( Manager (loadMaze "maps/1.txt") 0 0 0 0 defaultDelayTime )

updateControlledPlayer :: Key -> Manager -> Manager
updateControlledPlayer k w@(Manager s@(State m ljg l) pid step before delta delay) | k == KeyUpArrow    = Manager (State m (rodaPac s ljg k) l) pid (step+1) before delta delay
                                                                                   | k == KeyDownArrow  = Manager (State m (rodaPac s ljg k) l) pid (step+1) before delta delay
                                                                                   | k == KeyLeftArrow  = Manager (State m (rodaPac s ljg k) l) pid (step+1) before delta delay
                                                                                   | k == KeyRightArrow = Manager (State m (rodaPac s ljg k) l) pid (step+1) before delta delay
                                                                                   | otherwise          = w

rodaPac :: State -> [Player] -> Key -> [Player]
rodaPac _ [] _ = []
rodaPac s l k | k == KeyUpArrow = mudaCoordsU (encontraPac l) : findGhosts l
              | k == KeyDownArrow = mudaCoordsD (encontraPac l) : findGhosts l
              | k == KeyLeftArrow = mudaCoordsL (encontraPac l) : findGhosts l 
              | k == KeyRightArrow = mudaCoordsR (encontraPac l) : findGhosts l

findGhosts :: [Player] -> [Player]
findGhosts [] = []
findGhosts ((Pacman (PacState (a,(x,y),b,c,d,e) f g h)):t) = t
findGhosts (p1@(Ghost (GhoState (a,(x,y),b,c,d,e) f)):ys) = p1 : findGhosts ys 

mudaCoordsU :: Player -> Player
mudaCoordsU (Pacman (PacState (a,(x,y),b,c,d,e) f g h)) = (Pacman (PacState (a,(x,y),b,U,d,e) f g h))

mudaCoordsD :: Player -> Player
mudaCoordsD (Pacman (PacState (a,(x,y),b,c,d,e) f g h)) = (Pacman (PacState (a,(x,y),b,D,d,e) f g h))

mudaCoordsL :: Player -> Player
mudaCoordsL (Pacman (PacState (a,(x,y),b,c,d,e) f g h)) = (Pacman (PacState (a,(x,y),b,L,d,e) f g h))

mudaCoordsR :: Player -> Player
mudaCoordsR (Pacman (PacState (a,(x,y),b,c,d,e) f g h)) = (Pacman (PacState (a,(x,y),b,R,d,e) f g h))


updateScreen :: Window  -> ColorID -> Manager -> Curses ()
updateScreen w a man =
                  do
                    updateWindow w $ do
                      clear
                      setColor a
                      moveCursor 0 0 
                      drawString $ show (state man)
                    render
     
currentTime :: IO Integer
currentTime = fmap ( round . (* 1000) ) getPOSIXTime

nextFrame :: Integer -> Manager -> Manager
nextFrame now man =  let update = (resetTimer now man)
                     in update {state = (passTime (step man) (state man))}

updateTime :: Integer -> Manager -> Manager
updateTime now man = man {delta = (now - before man)} 

resetTimer :: Integer -> Manager -> Manager
resetTimer now man = man {delta = 0, before = now} 


loop :: Window -> Manager -> Curses ()
loop w man@(Manager s pid step bf delt del ) = do 
  color_schema <- newColorID ColorBlue ColorWhite  10
  now <- liftIO  currentTime
  updateScreen w  color_schema man
  if ( delt > del )
    then loop w $ nextFrame now man
    else do
          ev <- getEvent w $ Just 0
          case ev of
                Nothing -> loop w (updateTime now man)
                Just (EventSpecialKey arrow ) -> loop w $ updateControlledPlayer arrow (updateTime now man)
                Just ev' ->
                  if (ev' == EventCharacter 'q')
                    then return ()
                    else loop w (updateTime now man)

main :: IO ()
main =
  runCurses $ do
    setEcho False
    setCursorMode CursorInvisible
    w <- defaultWindow
    loop w loadManager





loadMaze :: String -> State
loadMaze filepath = unsafePerformIO $ readStateFromFile filepath



readStateFromFile :: String -> IO State
readStateFromFile f = do
                content <- readFile f
                let llines = lines content 
                    (new_map,pl) = convertLinesToPiece llines 0 []
                return (State new_map pl 1)



convertLinesToPiece :: [String] -> Int -> [Player] -> (Maze,[Player])
convertLinesToPiece [] _ l = ([],l)
convertLinesToPiece (x:xs) n l  = let (a,b) = convertLineToPiece x n 0 l 
                                      (a1,b1) = convertLinesToPiece xs (n+1) b
                                  in (a:a1,b1)

convertLineToPiece :: String -> Int -> Int -> [Player] -> ([Piece],[Player])
convertLineToPiece [] _ _ l = ([],l)
convertLineToPiece (z:zs) x y l = let (a,b ) = charToPiece z x y l
                                      (a1,b1) = convertLineToPiece zs x (y+1) b 
                                  in (a:a1,b1)


charToPiece :: Char -> Int -> Int -> [Player] -> (Piece,[Player])
charToPiece c x y l
    | c == '{' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Normal ))   :l) )
    | c == '<' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Closed Normal )) :l) )
    | c == '}' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Open Normal ))   :l) )
    | c == '>' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Closed Normal )) :l) )
    | c == 'V' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Open Normal ))   :l) )
    | c == 'v' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Closed Normal )) :l) )
    | c == '^' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Open Normal ))   :l) )
    | c == '|' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Closed Normal )) :l) )
    | c == 'X' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Dying ))    :l) )
    | c == 'M' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,R,0,1 ) Alive))            :l) )
    | c == '?' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,R,0,1 ) Dead))             :l) )
    | c == 'o' =  (Food Big,l)
    | c == '.' =  (Food Little,l)
    | c == '#' =  (Wall,l)
    | otherwise = (Empty,l)



data State = State 
    {
        maze :: Maze
    ,   playersState :: [Player]
    ,   level :: Int
    }

type Maze = [Corridor]
type Corridor = [Piece]
data Piece =  Food FoodType | PacPlayer Player| Empty | Wall deriving (Eq)
data Player =  Pacman PacState | Ghost GhoState deriving (Eq)

data Orientation = L | R | U | D | Null deriving (Eq,Show)
data PacState= PacState 
    {   
        pacState :: PlayerState
    ,   timeMega :: Double
    ,   openClosed :: Mouth
    ,   pacmanMode :: PacMode
    
    } deriving Eq

data GhoState= GhoState 
    {
        ghostState :: PlayerState
    ,   ghostMode :: GhostMode
    } deriving Eq

type Coords = (Int,Int)
type PlayerState = (Int, Coords, Double , Orientation, Int, Int)
--                 (ID,  (x,y), velocity, orientation, points, lives) 
data Mouth = Open | Closed deriving (Eq,Show)
data PacMode = Dying | Mega | Normal deriving (Eq,Show)
data GhostMode = Dead  | Alive deriving (Eq,Show)
data FoodType = Big | Little deriving (Eq)
data Color = Blue | Green | Purple | Red | Yellow | None deriving Eq 

data Play = Move Int Orientation deriving (Eq,Show)

type Instructions = [Instruction]

data Instruction = Instruct [(Int, Piece)]
                 | Repeat Int deriving (Show, Eq)

data Manager = Manager 
    {   
         state :: State
    ,    pid    :: Int
    ,    step :: Int
    ,    before :: Integer
    ,    delta :: Integer
    ,    delay :: Integer    
    } 


instance Show State where
  show (State m ps p) = printMaze mz ++ "Level: " ++ show p ++ "\nPlayers: \n" ++ (foldr (++) "\n" (map (\y-> printPlayerStats y) ps))
                          where mz = placePlayersOnMap ps m

instance Show PacState where
   show ( PacState s o m Dying  ) =  "X"
   show ( PacState (a,b,c,R,i,l) _ Open m  ) =  "{"
   show ( PacState (a,b,c,R,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,L,i,l) _ Open m  ) =  "}"
   show ( PacState (a,b,c,L,i,l) _ Closed m  ) =  ">"
   show ( PacState (a,b,c,U,i,l) _ Open m  ) =  "V"
   show ( PacState (a,b,c,U,i,l) _ Closed m  ) =  "v"
   show ( PacState (a,b,c,D,i,l) _ Open m  ) =  "^"
   show ( PacState (a,b,c,D,i,l) _ Closed m  ) =  "|"
   show ( PacState (a,b,c,Null,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,Null,i,l) _ Open m  ) =  "{"

instance Show Player where
   show (Pacman x ) =  show x
   show ( Ghost x ) =   show x

instance Show GhoState where
   show (GhoState x Dead ) =  "?"
   show (GhoState x Alive ) =  "M"

instance Show FoodType where
   show ( Big ) =  "o"
   show ( Little ) =  "."

instance Show Piece where
   show (  Wall ) = coloredString "#" None
   show (  Empty ) = coloredString " " None
   show (  Food z ) = coloredString (show z )   Green
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Normal ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Normal)  ) Yellow
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Mega   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Mega)  ) Blue
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Dying   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Dying)  ) Red
   show ( PacPlayer (Ghost z) ) = coloredString (show z)  Purple


coloredString :: String -> Color -> String
coloredString x y
    | True = x
    | y == Blue ="\x1b[36m" ++  x ++ "\x1b[0m"
    | y == Red = "\x1b[31m" ++ x ++ "\x1b[0m"
    | y == Green = "\x1b[32m" ++ x ++ "\x1b[0m"
    | y == Purple ="\x1b[35m" ++ x ++ "\x1b[0m"
    | y == Yellow ="\x1b[33m" ++ x ++ "\x1b[0m"
    | otherwise =  "\x1b[0m" ++ x 


placePlayersOnMap :: [Player] -> Maze -> Maze
placePlayersOnMap [] x = x
placePlayersOnMap (x:xs) m = placePlayersOnMap xs ( replaceElemInMaze (getPlayerCoords x) (PacPlayer x) m )


printMaze :: Maze -> String
printMaze []  =  ""
printMaze (x:xs) = foldr (++) "" ( map (\y -> show y) x )  ++ "\n" ++ printMaze ( xs )

printPlayerStats :: Player -> String
printPlayerStats p = let (a,b,c,d,e,l) = getPlayerState p
                     in "ID:" ++ show a ++  " Points:" ++ show e ++ " Lives:" ++ show l ++"\n"

getPlayerID :: Player -> Int
getPlayerID (Pacman (PacState (x,y,z,t,h,l) q c d )) = x
getPlayerID  (Ghost (GhoState (x,y,z,t,h,l) q )) = x
 
getPlayerPoints :: Player -> Int
getPlayerPoints (Pacman (PacState (x,y,z,t,h,l) q c d )) = h
getPlayerPoints (Ghost (GhoState (x,y,z,t,h,l) q )) = h

setPlayerCoords :: Player -> Coords -> Player
setPlayerCoords (Pacman (PacState (x,y,z,t,h,l) q c d )) (a,b) = Pacman (PacState (x,(a,b),z,t,h,l) q c d )
setPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) q )) (a,b) = Ghost (GhoState (x,(a,b),z,t,h,l) q )


getPieceOrientation :: Piece -> Orientation
getPieceOrientation (PacPlayer p) =  getPlayerOrientation p
getPieceOrientation _ = Null

getPacmanMode :: Player -> PacMode
getPacmanMode (Pacman (PacState a b c d)) = d
  
getGhostMode :: Player -> GhostMode
getGhostMode (Ghost (GhoState a b )) = b



getPlayerState :: Player -> PlayerState
getPlayerState (Pacman (PacState a b c d )) = a
getPlayerState (Ghost (GhoState a b )) = a

getPlayerOrientation :: Player -> Orientation
getPlayerOrientation (Pacman (PacState (x,y,z,t,h,l) q c d )) = t
getPlayerOrientation  (Ghost (GhoState (x,y,z,t,h,l) q )) = t

replaceElemInMaze :: Coords -> Piece -> Maze -> Maze
replaceElemInMaze (a,b) _ [] = []
replaceElemInMaze (a,b) p (x:xs) 
  | a == 0 = replaceNElem b p x : xs 
  | otherwise = x : replaceElemInMaze (a-1,b) p xs


replaceNElem :: Int -> a -> [a] -> [a]
replaceNElem i _ [] = [] 
replaceNElem i el (x:xs)
  |  i == 0 = el : xs 
  | otherwise =  x : replaceNElem (i-1) el xs

getPlayerCoords :: Player -> Coords
getPlayerCoords (Pacman (PacState (x,y,z,t,h,l) b c d )) = y
getPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) b )) = y




