--
mostraTestesTarefa1 :: Maze -> IO ()
mostraTestesTarefa1 m = putStrLn $ printMaze $ m

-- | Função que verifica os Labirintos
--
testeTarefa1 :: Maze -> [Char]
testeTarefa1 m | even (length m) == True && even(length (head m)) == True = "Labirinto com altura e largura par"
	       | even(length m) == True && odd(length (head m)) == True = "Labirinto com altura par e largura ímpar" 
	       | odd(length m) == True && odd(length (head m)) == True = "Labirinto com altura e largura ímpar"
	       | odd(length m) == True && even(length (head m)) == True = "Labirinto com altura ímpar e com largura par"
	       | otherwise = "Labirinto não aceite"

-- | Variável para testar a Tarefa3
--
testeTarefa3 = generateMaze 30 20 125

-- | Função que descompacta o Labirinto
--
demui3 :: Instructions -> Instructions
demui3 l = aux l []
    where aux l [] = l
          aux ((Repeat x):t) l = aux t (l ++ [(l !! x)])
          aux ((Instruct x):xs) l = aux xs (l ++ [Instruct x])

-- | Função que descompacta um Corredor
--
demui2 :: Instruction -> Corridor
demui2 (Instruct []) = []
demui2 (Instruct ((x,y):xs)) = (take x (repeat y)) ++ demui2 (Instruct xs)

-- | Função que descompacta um Labirinto
--
demuigeral :: Instructions -> Maze
demuigeral [] = []
demuigeral l = demui2 x: demuigeral xs
     where (x:xs) = demui3 l

-- | Função que testa a Tarefa3
--
testaTarefa3 :: Maze -> Bool
testaTarefa3 m | m == demuigeral (compactMaze m) = True
               | otherwise = False

mostraResultados :: Show a => [a] -> IO ()
mostraResultados m = mapM_ (\a -> putStr ("\nprintTestes >>>" ++ show a)) m
{-|
Module: Tarefa 6
Description : Módulo Haskell contendo todas as funções, /recursivas/, utilizadas para a implementação de um robot
Copyright   : Henrique Pereira <a97205@alunos.uminho.pt>;
              Andŕe Ye Sun <a96554@alunos.uminho.pt>.
= Introdução

Nesta tarefa foi nos pedido a criação de um bot que iria jogar como Pacman, escolhendo as melhores jogadas; bem como apresentar alguma competição no jogo.

= Desenvolvimento

Para a construção do bot, decidimo-nos focar em três aspetos que consideramos mais importantes, sendo o aspeto principal: o bot, quando tenta escapar ao fantasma que estiver mais proximo dele; e
comer os /Food Little/ e o /Food Big/; o pacman no estado /Mega/, que irá perseguir fantasmas.

Primeiramente, arranjar uma função que nos possa calcular a distância entre o Pacman e um Fantasma. A função que nós arranjámos para calcular as distâncias foi, a /calDistance/, 
pegando nas coordenadas do Pacman e nas coordenadas do ghost. De seguida, resolvemos criar uma função que nos permite reunir as coordenadas de todos os fantasmas numa lista, /allGhostCoords/.
Ao reunirmos todas as coordenadas dos ghost, possibilitou-nos a comparação entre as distâncias entre o Pacmnan com vários Ghosts para que nos possa proporcionar a distância mais curta ao Ghost mais próximo, usando recursivamente a função /calDistance/.
 
Em relação à comida, criámos uma função em que nos irá dar todo as coordenadas, dentro do labirinto, dos dois tipo de comida (/Food Big/ e /Food Little/); reunindo as coordenas numa lista de /Coords/.
 
Em seguida, criámos uma função que tem a mesma linha de pensamento da /nearGhost/, utilizando recursivamente a função /calDistance/ para ver a comida mais próxima ao Pacman.
Estas funções todas, foram utilizadas, recursivamente, na função /runFromGhost/ que tem como objetivo fugir dos Ghosts ou ir ter à comida mais próxima.

Finalizando, criámos uma função que, quando o Pacman come uma comida do tipo /Food Big/, esta função tem como objetivo, o bot ir atrás dos ghost que estiverem em /getGhostMode/
/Dead/ e mais pertos. Quando estiverem em /Alive/ o Pacman irá fugir sendo este a sua funçao default.

= Conclusão

Concluíndo, esta Tarefa foi-nos muito trabalhosa, exigindo muitas variáveis.
Daí ainda haver muitos bugs.
O bot não está de todo operacional, falhando em algumas variáveis mais gerais.    

-}


-- | Funçao que procura peça consoante uma coordenada
pieceMaze :: Coords -> Maze  -> Piece
pieceMaze  (x,y) m =  (m!!x)!!y 


-- | Funçao em que o pacaman fuge aos fantasmas
runFromGhost ::State -> Maybe Play
runFromGhost (State maze pl lvl)   
                | (dist > 4.0) && (y > d) && (pieceMaze (x,y-1) maze /= Wall) && (o == L) = Nothing
                | (dist > 4.0) && (y > d) && (pieceMaze (x,y-1) maze /= Wall) && (o /= L) = Just (Move i L)
                | (dist > 4.0) && (y > d) && (pieceMaze (x,y-1) maze == Wall) && (x >= c) && (pieceMaze (x-1,y) maze /= Wall) = Just (Move i U) 
                | (dist > 4.0) && (y > d) && (pieceMaze (x,y-1) maze == Wall) && (x >= c) && (pieceMaze (x-1,y) maze == Wall) = Just (Move i D)
                | (dist > 4.0) && (y > d) && (pieceMaze (x,y-1) maze == Wall) && (x <  c) && (pieceMaze (x+1,y) maze /= Wall) = Just (Move i D)
                | (dist > 4.0) && (y > d) && (pieceMaze (x,y-1) maze == Wall) && (x <  c) && (pieceMaze (x+1,y) maze == Wall) = Just (Move i U)
                | (dist > 4.0) && (y < d) && (pieceMaze (x,y+1) maze /= Wall) && (o == R) = Nothing
                | (dist > 4.0) && (y < d) && (pieceMaze (x,y+1) maze /= Wall) && (o /= R) = Just (Move i R)
                | (dist > 4.0) && (y < d) && (pieceMaze (x,y+1) maze == Wall) && (x >= c) && (pieceMaze (x-1,y) maze /= Wall) = Just (Move i U)
                | (dist > 4.0) && (y < d) && (pieceMaze (x,y+1) maze == Wall) && (x >= c) && (pieceMaze (x-1,y) maze == Wall) = Just (Move i D)
                | (dist > 4.0) && (y < d) && (pieceMaze (x,y+1) maze == Wall) && (x <  c) && (pieceMaze (x+1,y) maze /= Wall) = Just (Move i D)
                | (dist > 4.0) && (y < d) && (pieceMaze (x,y+1) maze == Wall) && (x <  c) && (pieceMaze (x+1,y) maze == Wall) = Just (Move i U)
                | (dist > 4.0) && (y == d) && (x > c) = Just (Move i U)
                | (dist > 4.0) && (y == d) && (x < c) = Just (Move i D)
                | (dist < 4.0) && (y > b) && (o == R) && (pieceMaze (x,y+1) maze /= Wall) = Nothing
                | (dist < 4.0) && (y > b) && (o /= R) && (pieceMaze (x,y+1) maze /= Wall) = Just (Move i R)
                | (dist < 4.0) && (y < b) && (o == L) && (pieceMaze (x,y-1) maze /= Wall) = Nothing
                | (dist < 4.0) && (y < b) && (o /= L) && (pieceMaze (x,y-1) maze /= Wall) = Just (Move i L)
                | (dist < 4.0) && (y == b) && (x > a) && (pieceMaze (x+1,y) maze /= Wall) = Just (Move i D)
                | (dist < 4.0) && (y == b) && (x < a) && (pieceMaze (x-1,y) maze /= Wall) = Just (Move i U) 
                | (dist < 4.0) && (o == L) && (pieceMaze (x,y-1) maze == Wall) && (pieceMaze (x-1,y) maze == Wall) = Just (Move i D)
                | (dist < 4.0) && (o == L) && (pieceMaze (x,y-1) maze == Wall) = Just (Move i U) 
                | (dist < 4.0) && (o == U) && (pieceMaze (x-1,y) maze == Wall) && (pieceMaze (x,y+1) maze == Wall) = Just (Move i L)
                | (dist < 4.0) && (o == U) && (pieceMaze (x-1,y) maze == Wall) = Just (Move i R)
                | (dist < 4.0) && (o == R) && (pieceMaze (x,y+1) maze == Wall) && (pieceMaze (x+1,y) maze == Wall) = Just (Move i U)
                | (dist < 4.0) && (o == R) && (pieceMaze (x,y+1) maze == Wall) = Just (Move i D)
                | (dist < 4.0) && (o == D) && (pieceMaze (x+1,y) maze == Wall) && (pieceMaze (x,y-1) maze == Wall) = Just (Move i R)
                | (dist < 4.0) && (o == D) && (pieceMaze (x+1,y) maze == Wall) = Just (Move i L)

                | otherwise = Nothing
    
    where pacman = separaPacman pl 
          (x,y) = getPlayerCoords pacman 
          i = getPlayerID pacman 
          o = getPlayerOrientation pacman
          g = separaFantasmas pl 
          ghost = nearGhost pacman g 
          (a,b) = getPlayerCoords ghost 
          listCoords = foodCords maze  
          (c,d) = nearFood pacman listCoords 
          dist =  calDistance (getPlayerCoords pacman) (a,b) 





-- | Funçao que me da as coordenadas das comidas dum labirinto 
foodCords :: Maze -> [Coords]
foodCords l = aux (0,0) l
       where aux :: Coords -> Maze -> [Coords]
             aux (x,y) ((Food Little:t):ls) = (x,y) : aux (x+1,y) (t:ls )    
             aux (x,y) (((Food Big):t):ls)  = (x,y) : aux (x+1,y) (t:ls )
             aux (x,y) ((_:t):ls)  = aux (x+1,y) (t:ls)
             aux (x,y) ([] : ls)   = aux (0,y+1) ls 
             aux _ [] = []

-- | Funçao que indica qual é a comida mais proxima ao pacman 
nearFood :: Player -> [Coords] -> Coords
nearFood p [x] = x 
nearFood (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) ((x3,y3):(x4,y4):t3) 
                        |(calDistance (x,y) (x3,y3)) <= (calDistance (x,y) (x4,y4)) = nearFood (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) ((x3,y3) : t3)
                        |otherwise = nearFood (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) ((x4,y4) :t3)



-- | Funçao que indica o fanstama mais proximo em relaçao ao pacman 
nearGhost :: Player -> [Player] -> Player
nearGhost p [x] = x 
nearGhost  (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) (((Ghost (GhoState (id1, (x1,y1), v1, o1, p1, l1) vm)):((Ghost (GhoState (id2, (x2,y2), v2, o2, p2, l2) vm2)): tail))) 
                                            | (calDistance (x,y) (x1,y1)) <= (calDistance (x,y) (x2,y2)) = nearGhost (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) ((Ghost (GhoState (id1, (x1,y1), v1, o1, p1, l1) vm)) : tail) 
                                            | otherwise =  nearGhost  (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) ((Ghost (GhoState (id2, (x2,y2), v2, o2, p2, l2) vm2)): tail)

-- | Funcao que calcula as distancias entre dois pontos
calDistance :: Coords -> Coords -> Float
calDistance (x1,x2) (y1,y2) = sqrt ((fromIntegral(x1)-fromIntegral(y1))^2 + (fromIntegral(x2)-fromIntegral(y2))^2)



-- | Funçao junta todas as coordenadas de um fantasma
ghostCoords :: [Player] -> [Coords]
ghostCoords [] = []
ghostCoords ((Ghost (GhoState (id1, (x1,y1), v1, o1, p1, l1) vm)): tail) = (x1,y1): ghostCoords tail 


-- | Funçao  que reunime numa lista as coordenadas de todos os fantasmas 
allghostCoords :: [Player] -> [Coords]
allghostCoords p = ghostCoords (separaFantasmas p)


