-- | __Funçao que finaliza a sexta tarefa__  junta todas as funcoes anteriormente definidas, de forma a completar o bot
bot :: Int -> State -> Maybe Play
bot id s@(State m pl lvl)
        | id == (getPlayerID (separaPacman pl)) && (getPacmanMode( separaPacman pl)) == Normal = runFromGhost s
        | id == (getPlayerID (separaPacman pl)) && (getPacmanMode( separaPacman pl)) == Mega = huntGhost s     
        |otherwise = Nothing
