bocaPacman :: Player -> Player
bocaPacman (Pacman(PacState (id, (x,y), v, o, p, l) t b e))
    | b == Closed = (Pacman(PacState (id, (x,y), v, o, p, l) t Open e))
    | otherwise = (Pacman(PacState (id, (x,y), v, o, p, l) t Closed e))

perdeMega :: Player -> Player
perdeMega (Pacman(PacState (id, (x,y), v, o, p, l) t b Mega))
    | t > 0 = (Pacman(PacState (id, (x,y), v, o, p, l) (t - 0.25) b Mega))
    | otherwise = (Pacman(PacState (id, (x,y), v, o, p, l) 0 b Normal))

fantAlive :: [Player] -> Player -> [Player]
fantAlive [] _ = []
fantAlive (Ghost (GhoState (id1, (x1,y1), v1, o1, p1, l1) vm):tail) (Pacman(PacState (id, (x,y), v, o, p, l) t b e))
    | e == Normal = (Ghost (GhoState (id1, (x1,y1), v1, o1, p1, l1) Alive)): fantAlive tail (Pacman(PacState (id, (x,y), v, o, p, l) t b e))
    | otherwise = (Ghost (GhoState (id1, (x1,y1), v1, o1, p1, l1) vm):tail)

