-- | Função auxiliar à última; que com funções anteriormente definidas, dá update ao jogo, em cada instância, com o bot do Pacman em controlo
proGresso :: [Player] -> State -> Int -> State


-- | Função que deixa o bot em controlo do Pacman
proGresso [] s _ = s
proGresso ((Pacman(PacState (id, (x,y), v, o, p, l) t b e)):tail) state step = proGresso tail (play movimento state) step
      where movimento = aux (bot id state)
            aux (Just x) = x
            aux Nothing = Move id Null
proGresso (Ghost (GhoState (id1, (x1,y1), v1, o1, p1, l1) vm):tail) state step
    | vm == Alive = proGresso tail (play ((Move id1 o1)) state) step
    | vm == Dead && even step = proGresso tail (play (Move id1 o1) state) step
    | vm == Dead && odd step = proGresso tail state step

{-
-- | Função alternativa que deixa o jogador usufruir do jogo
proGresso [] s _ = s
proGresso ((Pacman(PacState (id, (x,y), v, o, p, l) t b e)):tail) state step = proGresso tail (play (Move id o) state) step
proGresso (Ghost (GhoState (id1, (x1,y1), v1, o1, p1, l1) vm):tail) state step
    | vm == Alive = proGresso tail (play ((Move id1 o1)) state) step
    | vm == Dead && even step = proGresso tail (play (Move id1 o1) state) step
    | vm == Dead && odd step = proGresso tail state step
-}

-- | __ Função que finaliza a quarta tarefa__ dá update a todos os elementos do mapa em cada iteração
passTime :: Int  -> State -> State
passTime x (State m ps n) = proGresso ps (State m ps n) x
{-|
Module: Tarefa 3
Description : Módulo Haskell contendo todas as funções, /recursivas/, utilizadas para a implementação da compressao de labirintos aleatórios.
Copyright   : Henrique Pereira <a97205@alunos.uminho.pt>;
              Andŕe Ye Sun <a96554@alunos.uminho.pt>.

= Introdução
Nesta tarefa, o objetivo principal foi encontrar formas de comprimir os nossos labirintos. Por outras palavras, arranjar métodos para
podermos reduzir com que ocupasse o menor espaço possivel, nao perdendo nenhuma da informaçao.

= Desenvolvimento

Esta tarefa foi aquela que achamos mais acessível de fazer, o raciocínio para esta tarefa foi a criaçao duma funçao no qual irá permitir 
a junçao de peças iguais num tuplo em que as peças diferentes irao ser reagrupados numa outra lista. 
Depois desta funçao que nos compactava, fui preciso apenas arranjar uma funçao que nos premitisse transformar um Corridor em Instruction e, por fim,
chegar à função final do compactMaze em que transforma um Maze num conjunto de Instructions.

= Conclusão
Finalizando, os resultados desta tarefa foram sastisfatórios passando nos testes do Codeboard bem como nos nossos. 

-}



-- | Funcao que junta, num tuplo, todas as pecas iguais // as pecas diferentes, ficam separadas do resto. 
mui2 :: Maze -> Instructions
mui2 [] = []
mui2 (h:t) = Instruct (auxmui2 h 1) : mui2 t 

-- | Funcao, auxiliar, compacta um corredor.
auxmui2 :: Corridor -> Int -> [(Int,Piece)]
auxmui2 [] n = []
auxmui2 [x] n = [(n,x)]
auxmui2 (x:y:t) n | y == x =  auxmui2 (y:t) (n+1)
                  | otherwise = (n,x) : auxmui2 (y:t) 1 

-- | Funcao que compacta listas de corredores.
mui3 :: Instructions -> Instructions -> Instructions 
mui3 [] x = x
mui3 x l | elem (head x) l = mui3 (tail x) (l ++ [(Repeat (auxacuMui3 (head x) l))])
         | otherwise = mui3 (tail x) (l ++ [head x])

-- | Funcao, auxiliar, que retorna os indices dos corredores.
auxacuMui3::Eq a => a -> [a] -> Int
auxacuMui3 a l = length (takeWhile (/= a) l)

-- | __Funcao que finaliza a Tarefa3__. Codifica o labirinto como uma sequência de instruções que produzem o mesmo labirinto.
compactMaze :: Maze -> Instructions
compactMaze m = mui3 (mui2  m) []
