-- | Funcao que move Pacman
movimentoPacman :: Player -> Orientation -> Maze -> Player
movimentoPacman (Pacman(PacState (id, (x,y), v, o2, p, l) tMega af a)) o m | y == 0 && o2 == L && o == L = (Pacman(PacState (id, (x,length(head m) - 1), v, o, p, l) tMega af a))
                                                                           | y == (length(head m) - 1) && o2 == R && o == R = (Pacman(PacState (id, (x,0), v, o, p, l) tMega af a))
                                                                           | o == L && o2 == L = (Pacman(PacState (id, (x,y-1), v, o, p, l) tMega af a))
                                                                           | o == R && o2 == R = (Pacman(PacState (id, (x,y+1), v, o, p, l) tMega af a))
                                                                           | o == U && o2 == U = (Pacman(PacState (id, (x-1,y), v, o, p, l) tMega af a))
                                                                           | o == D && o2 == D = (Pacman(PacState (id, (x+1,y), v, o, p, l) tMega af a))
                                                                           | otherwise = (Pacman(PacState (id, (x,y), v, o, p, l) tMega af a))

movimentoFantasma :: [Player] -> Orientation -> Maze -> [Player]
movimentoFantasma [] o m = []
movimentoFantasma ((Ghost (GhoState (id, (x,y), v, o2, p, l) vm)): tail) o m | y == 0 && o2 == L && o == L = (Ghost(GhoState (id, (x,length(head m) - 1), v, o, p, l) vm)): movimentoFantasma tail o m
                                                                             | y == (length(head m) - 1) && o2 == R && o == R = (Ghost(GhoState (id, (x,0), v, o, p, l) vm)): movimentoFantasma tail o m
                                                                             | o == L && o2 == L = (Ghost(GhoState (id, (x,y-1), v, o, p, l) vm)): movimentoFantasma tail o m
                                                                             | o == R && o2 == R = (Ghost(GhoState (id, (x,y+1), v, o, p, l) vm)): movimentoFantasma tail o m
                                                                             | o == U && o2 == U = (Ghost(GhoState (id, (x-1,y), v, o, p, l) vm)): movimentoFantasma tail o m
                                                                             | o == D && o2 == D = (Ghost(GhoState (id, (x+1,y), v, o, p, l) vm)): movimentoFantasma tail o m
                                                                             | otherwise = (Ghost(GhoState (id, (x,y), v, o, p, l) vm)): movimentoFantasma tail o m

-- | Funcao que determina se tem uma parade, impossibilitando o movimento do Packman
pacSensor :: Player -> Orientation -> Maze -> Player
pacSensor (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) o1 m | y == 0 = if (o1 == L && o == L) then (Pacman(PacState (id, (x,length(head m) - 1), v, o, p, l) t b e)) else movimentoPacman (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) o1 m
                                                                | y == (length(head m) - 1) = if (o1 == R && o == R) then (Pacman(PacState (id, (x,0), v, o, p, l) t b e)) else movimentoPacman (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) o1 m
                                                                | o /= o1 = (Pacman(PacState (id, (x,y), v, o1, p, l) t b e))
                                                                | procuraPeca m (x,y-1) == Wall && o1 == L && o == L = (Pacman(PacState (id, (x,y), v, o, p, l) t b e))
                                                                | procuraPeca m (x,y+1) == Wall && o1 == R && o == R = (Pacman(PacState (id, (x,y), v, o, p, l) t b e))
                                                                | procuraPeca m (x-1,y) == Wall && o1 == U && o == U = (Pacman(PacState (id, (x,y), v, o, p, l) t b e))
                                                                | procuraPeca m (x+1,y) == Wall && o1 == D && o == D = (Pacman(PacState (id, (x,y), v, o, p, l) t b e))
                                                                | otherwise = movimentoPacman (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) o1 m

fantSensor :: [Player] -> Orientation -> Maze -> [Player]
fantSensor [] o1 m = []
fantSensor ((Ghost (GhoState (id, (x,y), v, o, p, l) vm)): tail) o1 m | y == 0 = if (o1 == L && o == L) then ((Ghost(GhoState (id, (x,length(head m) - 1), v, o, p, l) vm)):tail) else movimentoFantasma ((Ghost(GhoState (id, (x,y), v, o, p, l) vm)):tail) o1 m
                                                                      | y == (length(head m) - 1) = if (o1 == R && o == R) then ((Ghost(GhoState (id, (x,0), v, o, p, l) vm)):tail) else movimentoFantasma ((Ghost(GhoState (id, (x,y), v, o, p, l) vm)):tail) o1 m
                                                                      | o /= o1 = (Ghost(GhoState (id, (x,y), v, o1, p, l) vm)): fantSensor tail o1 m
                                                                      | procuraPeca m (x,y-1) == Wall && o1 == L && o == L = (Ghost(GhoState (id, (x,y), v, o, p, l) vm)): fantSensor tail o1 m
                                                                      | procuraPeca m (x,y+1) == Wall && o1 == R && o == R = (Ghost(GhoState (id, (x,y), v, o, p, l) vm)): fantSensor tail o1 m
                                                                      | procuraPeca m (x-1,y) == Wall && o1 == U && o == U = (Ghost(GhoState (id, (x,y), v, o, p, l) vm)): fantSensor tail o1 m
                                                                      | procuraPeca m (x+1,y) == Wall && o1 == D && o == D = (Ghost(GhoState (id, (x,y), v, o, p, l) vm)): fantSensor tail o1 m
                                                                      | otherwise = movimentoFantasma ((Ghost(GhoState (id, (x,y), v, o, p, l) vm)):tail) o1 m


-- | Funcao que procura peca consoante uma coordenada
procuraPeca :: Maze -> Coords -> Piece
procuraPeca m (x,y) =  (m!!x)!!y 

-- | Funcao que soma pontos consoante a comida ingerida pelo Packman
pontosPacman :: Player -> Maze -> Player
pontosPacman (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) m | procuraPeca m (x,y) == Food Little = (Pacman(PacState (id, (x,y), v, o, p+1, l) t b e))
                                                                | procuraPeca m (x,y) == Food Big = (Pacman(PacState (id, (x,y), v, o, p+5, l) 10 b Mega))
                                                                | otherwise = (Pacman(PacState (id, (x,y), v, o, p, l) t b e))

-- | Funcao que coloca Packman em funcao Mega, coloca Fantasmas e diminui a velocidade
megaPackman :: Player -> [Player] -> [Player]
megaPackman _ [] = []
megaPackman (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) (Ghost (GhoState (id1, (x1,y1), v1, o1, p1, l1) vm):tail) | e == Mega = Ghost (GhoState (id1, (x1,y1), (v1)/2, o1, p1, l1) Dead): megaPackman (Pacman(PacState (id, (x,y), v, o, p, l) t b Mega)) tail
                                                                                                                       | otherwise = (Ghost (GhoState (id1, (x1,y1), v1, o1, p1, l1) vm):tail)

-- | Esta funcao e utilizada quando Packam ou come fantasmas, ou morre, ou perde vidas
fantasmaPacman :: Player -> [Player] -> Player
fantasmaPacman (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) [] = (Pacman(PacState (id, (x,y), v, o, p, l) t b e))
fantasmaPacman (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) (Ghost (GhoState (id1, (x1,y1), v1, o1, p1, l1) vm):tail) | x == x1 && y == y1 && vm == Alive && l == 0 = (Pacman(PacState (id, (x,y), v, o, p, l) t b Dying))
                                                                                                                          | x == x1 && y == y1 && vm == Alive = fantasmaPacman (Pacman(PacState (id, (x,y), v, o, p, l-1) t b e)) tail
                                                                                                                          | e == Mega && x == x1 && y == y1 = fantasmaPacman (Pacman(PacState (id, (x,y), v, o, p+10, l) t b e)) tail
                                                                                                                          | otherwise = fantasmaPacman (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) tail

-- | Funcao que manda Fantasmas para o centro do Labirinto
fantCasa :: Player -> [Player] -> Maze -> [Player]
fantCasa _ [] _ = []
fantCasa (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) (Ghost (GhoState (id1, (x1,y1), v1, o1, p1, l1) vm):tail) m
    | e == Mega && x == x1 && y == y1 = (Ghost (GhoState (id1, (div (length m) 2, div (length(head m)) 2), v1, o1, p1, l1) Alive)): fantCasa (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) tail m
    | otherwise = (Ghost (GhoState (id1, (x1,y1), v1, o1, p1, l1) vm)): fantCasa (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) tail m

-- | Funcao que apos o Packam passar por comida, ela deixa de estar no Labirinto
limpaLabirinto :: Player -> Maze -> Maze
limpaLabirinto (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) m = replaceElemInMaze (x,y) Empty m

-- | Funcao que encontra Pacman
separaPacman :: [Player] -> Player
separaPacman ((Pacman(PacState (id, (x,y), v, o, p, l) t b e)): tail) = (Pacman(PacState (id, (x,y), v, o, p, l) t b e))
separaPacman (Ghost (GhoState (id1, (x1,y1), v1, o1, p1, l1) vm):tail) = separaPacman tail

-- | Funcao que encontra Fantasmas
separaFantasmas :: [Player] -> [Player]
separaFantasmas [] = []
separaFantasmas ((Pacman(PacState (id, (x,y), v, o, p, l) t b e)): tail) = separaFantasmas tail
separaFantasmas ((Ghost (GhoState (id1, (x1,y1), v1, o1, p1, l1) vm)): tail) = (Ghost (GhoState (id1, (x1,y1), v1, o1, p1, l1) vm)): separaFantasmas tail

-- | Funcao que junta todos os jogadores numa lista
juntaJogadores :: Player -> [Player] -> [Player]
juntaJogadores (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) [] = [(Pacman(PacState (id, (x,y), v, o, p, l) t b e))]
juntaJogadores (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) ((Ghost (GhoState (id1, (x1,y1), v1, o1, p1, l1) vm)): tail) = (Ghost (GhoState (id1, (x1,y1), v1, o1, p1, l1) vm)): juntaJogadores (Pacman(PacState (id, (x,y), v, o, p, l) t b e)) tail

proxNivel :: State -> Player -> State
proxNivel (State m ps n) (Pacman(PacState (id, (x,y), v, o, p, l) t b e))
  | p > 300 = (State m ps (n+1))

-- | __Funcao que finaliza a segunda Tarefa__ junta todas as funcoes anteriormente definidas, de forma a completar uma jogada
