= Introdução

Para esta primeira Tarefa, após ler o enunciado, deparámo-nos que tínhamos de criar as funções que colocassem e criassem a casas dos fantasmas ,no centro do labirinto; e funções que colocassem
paredes à volta de todo o labirinto, com abertura para túneis.

= Desenvolvimento / Objetivos

No início da execução do trabalho, deparámo-nos que: tínhamos de fazer funções ainda mais pequenas de forma a juntar tudo numa, de forma a tornar tudo mais simples.
Na função /constroiCasa/, dividiu-se para casas pares e ímpares, dependo do Labirinto.

O mesmo acontece para as funções de criar paredes laterais: uma função para criar paredes em cima e em baixo do labirinto e outra para colocar paredes laterais.
Para colocar a casa dos fantasmas utilizamos outra tática, criamos uma função que /identifica/ os cinco tuneis do meio, outra que, como o nome indica,
/substitui corredores/. Juntando tudo na função /colocarcasa/.

= Conclusão

Sendo esta a primeira Tarefa realizada pelo grupo e o um dos primeiros contactos com /Haskell/ e /Unix/, em geral; o trabalho foi desenvolvido num ritmo mais lento,
utilizando demasiadas funções, que atrasam a sua compilação. 

-}



-- | Given a seed returns a list of n integer randomly generated
geraAleatorios :: Int -> Int -> [Int]
geraAleatorios n seed = let gen = mkStdGen seed -- creates a random generator
                        in take n $ randomRs (0,99) gen -- takes the first n elements from an infinite series of random numbers between 0-9

nrAleatorio :: Int -> Int
nrAleatorio seed = head $ geraAleatorios 1 seed

-- | Converts a list into a list of list of size n
subLista :: Int -> [a] -> [[a]]
subLista _ [] = []
subLista n l = take n l: subLista n (drop n l)

convertePeca :: Int -> Piece
convertePeca n | n == 3 = Food Big
               | 0 <= n && n < 70 = Food Little
               | 70 <= n && n <= 99 = Wall
               | otherwise = Empty

-- | Converts a Corredor to a string
printCorridor :: Corridor -> String
printCorridor [] = "\n"
printCorridor (p: ps) = show p ++ printCorridor ps

-- | Converts a list of integers into a Corredor
converteCorredor :: [Int] -> Corridor
converteCorredor [] = []
converteCorredor (p:ps) = convertePeca p : converteCorredor ps

-- | Converts a list of lists of integers into a Labirinto
converteLabirinto :: [[Int]] -> Maze
converteLabirinto [] = []
converteLabirinto (p:ps) = converteCorredor p : converteLabirinto ps

-- | Gera Labirinto
geraLabirinto :: Int -> Int -> Int -> IO()
geraLabirinto x y s =
                 let random_nrs = geraAleatorios (x*y) s
                 in putStrLn $ printMaze $ colocarcasa $ tudolabirinto y x $ converteLabirinto $ subLista x random_nrs

-- | Funcao que verifica se o labirinto tem comprimento par ou impar e consoante o comprimento escolhe a respetiva casa, dos fantasmas.
constroiCasa :: Int -> Maze
constroiCasa a | even a = constroiCasaPar
               | otherwise = constroiCasaImpar

-- | Casa dos fantasmas par.
constroiCasaPar :: Maze 
constroiCasaPar = [
                    take 10 (repeat Empty),
                    [Empty] ++ take 3 (repeat Wall) ++ [Empty, Empty] ++ take 3 (repeat Wall) ++ [Empty],
                    [Empty, Wall] ++ take 6 (repeat Empty) ++ [Wall, Empty],
                    [Empty] ++ take 8 (repeat Wall) ++ [Empty],
                    take 10 (repeat Empty)
                  ]

-- | Casa dos fantasmas impar.
constroiCasaImpar :: Maze
constroiCasaImpar = [
                      take 11 (repeat Empty),
                      [Empty, Wall, Wall, Wall, Empty, Empty, Empty, Wall, Wall, Wall, Empty],
                      [Empty, Wall] ++ take 7 (repeat Empty) ++ [Wall, Empty],
                      [Empty] ++ take 9 (repeat Wall) ++ [Empty],
                      take 11 (repeat Empty)
                    ]

-- | Esta funcao pega num numero e da-nos uma linha so com paredes /usado para a construcao da parte superior e inferior do labirinto/.
supinfParede :: Int -> Maze
supinfParede a = [take a (repeat Wall)]

-- | __Constroi as paredes laterais__; Pega num labirinto e coloca a volta paredes.
paredeLat :: Maze -> Maze
paredeLat [] = []
paredeLat (h:t) = paredeaux h : paredeLat t
  where paredeaux :: Corridor -> Corridor
        paredeaux l = ([Wall] ++ (init ( tail l ))) ++ [Wall]

-- | Funcao que abre espacos vazios num corredor.
constroiTunel :: Corridor -> Corridor
constroiTunel (h:t) = ([Empty] ++ init t) ++ [Empty]

-- | Funcao que verifica se x e par ou impar para a construcao do tunel.
quandoTunel :: Int -> Maze -> Maze
quandoTunel x (h:t) | even x = constroiTunelPar (h:t) x 0
                    | otherwise = constroiTunelImpar (h:t) x 0

-- | Construcao do tunel caso seja par.
constroiTunelPar :: Maze -> Int -> Int -> Maze
constroiTunelPar [] _ _ = []
constroiTunelPar (h:t) x y | y == (div x 2)+ 1 = constroiTunel h: constroiTunelPar t x (y + 1)
                           | y == ((div x 2) - 1)+1 = constroiTunel h: constroiTunelPar t x (y + 1)
                           | otherwise = h: constroiTunelPar t x (y + 1)

-- | Construcao do tunel caso seja impar.
constroiTunelImpar :: Maze -> Int -> Int -> Maze
constroiTunelImpar [] _ _ = []
constroiTunelImpar (h:t) x y | y == div x 2 = constroiTunel h: constroiTunelImpar t x (y + 1)
                             | otherwise = h: constroiTunelImpar t x (y + 1)

-- | Funcao que pega em duas funcoes anteriormente definidas e retorna as paredes laterais com tuneis, para os diferentes casos.
tuneisparedeslat :: Maze -> Int -> Maze
tuneisparedeslat (h:t) x = quandoTunel x $ paredeLat (h:t)

-- | Funcao que retorna o labirinto com as bordas com paredes superiores, inferioes e laterais, com tuneis.
tudolabirinto :: Int -> Int -> Maze -> Maze
tudolabirinto x y (h:t) = (f ++ (init (tail (tuneisparedeslat (h:t) x)))) ++ f
  where f = supinfParede (y)

-- Funcoes para a Casa dos Fantasmas

-- | Funcao que localiza os corredores centrais para a preparacao da implementacao da casa dos fantasmas.
cincotuneisdomeio :: Maze -> [Corridor]
cincotuneisdomeio [] = []
cincotuneisdomeio l = [(!!) l ((div (length l) 2 )- 2),(!!) l ((div (length l) 2 )-1), (!!) l ((div (length l) 2 ) ), (!!) l ((div (length l) 2 ) +1), (!!) l ((div (length l) 2 ) + 2)]  

-- | Funcao que substitui corredores.
substituircorredor :: Int -> Corridor -> Corridor -> Corridor
substituircorredor 0  (l:ls) x = l : substituircorredor  0 ls (tail x) 
substituircorredor _ [] l  = l 
substituircorredor n (x:xs) (y:ys) = y : substituircorredor (n-1) (x:xs) ys 

-- | Coloca ,a casa dos fantasmas, na parte central do labirinto.
colocarcasa :: Maze -> Maze
colocarcasa [] = []
colocarcasa l | even (length l) = take ((div (length l) 2 ) - 3) l   
                                               ++[substituircorredor ((div (length (head l)) 2)-5) ((!!)  (constroiCasa (length (head l ))) 0 ) ((!!)  (cincotuneisdomeio l) 0 )]
                                               ++[substituircorredor ((div (length (head l)) 2)-5) ((!!)  (constroiCasa (length (head l ))) 1 ) ((!!)  (cincotuneisdomeio l) 1 )]
                                               ++[substituircorredor ((div (length (head l)) 2)-5) ((!!)  (constroiCasa (length (head l ))) 2 ) ((!!)  (cincotuneisdomeio l) 2 )]
                                               ++[substituircorredor ((div (length (head l)) 2)-5) ((!!)  (constroiCasa (length (head l ))) 3 ) ((!!)  (cincotuneisdomeio l) 3 )]
                                               ++[substituircorredor ((div (length (head l)) 2)-5) ((!!)  (constroiCasa (length (head l ))) 4 ) ((!!)  (cincotuneisdomeio l) 4 )]
                                               ++ drop ((div (length l ) 2 ) + 2 ) l
                |otherwise = take ((div (length l) 2 ) - 2) l   
                                               ++[substituircorredor ((div (length (head l)) 2)-5) ((!!)  (constroiCasa (length (head l ))) 0 ) ((!!)  (cincotuneisdomeio l) 0 )]
                                               ++[substituircorredor ((div (length (head l)) 2)-5) ((!!)  (constroiCasa (length (head l ))) 1 ) ((!!)  (cincotuneisdomeio l) 1 )]
                                               ++[substituircorredor ((div (length (head l)) 2)-5) ((!!)  (constroiCasa (length (head l ))) 2 ) ((!!)  (cincotuneisdomeio l) 2 )]
                                               ++[substituircorredor ((div (length (head l)) 2)-5) ((!!)  (constroiCasa (length (head l ))) 3 ) ((!!)  (cincotuneisdomeio l) 3 )]
                                               ++[substituircorredor ((div (length (head l)) 2)-5) ((!!)  (constroiCasa (length (head l ))) 4 ) ((!!)  (cincotuneisdomeio l) 4 )]
                                               ++ drop ((div (length l ) 2 ) + 3 ) l

-- | __Funcao que finaliza a primeira Tarefa__ gera um labirinto, com as dimensoes desejadas, e retorna uma lista de listas de Corredores.
generateMaze :: Int -> Int -> Int -> Maze
generateMaze x y s = 
                 let random_nrs = geraAleatorios (x*y) s
                 in  colocarcasa $ tudolabirinto y x $ converteLabirinto $ subLista x random_nrs


loadManager :: Manager
loadManager = ( Manager (loadMaze "maps/1.txt") 0 0 0 0 defaultDelayTime )

updateControlledPlayer :: Key -> Manager -> Manager
updateControlledPlayer k m@(Manager state pid step before delta delay) | k == KeyUpArrow = m { state = (play (Move pid U) state)}
                                                                       | k == KeyDownArrow = m { state = (play (Move pid D) state)}
                                                                       | k == KeyRightArrow = m { state = (play (Move pid R) state)}
                                                                       | k == KeyLeftArrow = m { state = (play (Move pid L) state)}

updateScreen :: Window  -> ColorID -> Manager -> Curses ()
updateScreen w a man =
                  do
                    updateWindow w $ do
                      clear
                      setColor a
                      moveCursor 0 0 
                      drawString $ show (state man)
                    render
     
currentTime :: IO Integer
currentTime = fmap ( round . (* 1000) ) getPOSIXTime

updateTime :: Integer -> Manager -> Manager
updateTime now man = man {delta=(now-before man)}

resetTimer :: Integer -> Manager -> Manager
resetTimer now man = man {delta=0, before=now} 

nextFrame :: Integer -> Manager -> Manager
nextFrame now man =  let update=(resetTimer now man)
                     in update {state=(passTime(step man) (state man)), step = (step man)+1}


loop :: Window -> Manager -> Curses ()
loop w man@(Manager s pid step bf delt del ) = do 
  color_schema <- newColorID ColorBlue ColorWhite  10
  now <- liftIO  currentTime
  updateScreen w  color_schema man
  if ( delt > del )
    then loop w $ nextFrame now man
    else do
          ev <- getEvent w $ Just 0
          case ev of
                Nothing -> loop w (updateTime now man)
                Just (EventSpecialKey arrow ) -> loop w $ updateControlledPlayer arrow (updateTime now man)
                Just ev' ->
                  if (ev' == EventCharacter 'q')
                    then return ()
                    else loop w (updateTime now man)

main :: IO ()
main =
  runCurses $ do
    setEcho False
    setCursorMode CursorInvisible
    w <- defaultWindow
    loop w loadManager




loadMaze :: String -> State
loadMaze filepath = unsafePerformIO $ readStateFromFile filepath



readStateFromFile :: String -> IO State
readStateFromFile f = do
                content <- readFile f
                let llines = lines content 
                    (new_map,pl) = convertLinesToPiece llines 0 []
                return (State new_map pl 1)



convertLinesToPiece :: [String] -> Int -> [Player] -> (Maze,[Player])
convertLinesToPiece [] _ l = ([],l)
convertLinesToPiece (x:xs) n l  = let (a,b) = convertLineToPiece x n 0 l 
                                      (a1,b1) = convertLinesToPiece xs (n+1) b
                                  in (a:a1,b1)

convertLineToPiece :: String -> Int -> Int -> [Player] -> ([Piece],[Player])
convertLineToPiece [] _ _ l = ([],l)
convertLineToPiece (z:zs) x y l = let (a,b ) = charToPiece z x y l
                                      (a1,b1) = convertLineToPiece zs x (y+1) b 
                                  in (a:a1,b1)


charToPiece :: Char -> Int -> Int -> [Player] -> (Piece,[Player])
charToPiece c x y l
    | c == '{' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Normal ))   :l) )
    | c == '<' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Closed Normal )) :l) )
    | c == '}' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Open Normal ))   :l) )
    | c == '>' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Closed Normal )) :l) )
    | c == 'V' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Open Normal ))   :l) )
    | c == 'v' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Closed Normal )) :l) )
    | c == '^' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Open Normal ))   :l) )
    | c == '|' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Closed Normal )) :l) )
    | c == 'X' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Dying ))    :l) )
    | c == 'M' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Alive))            :l) )
    | c == '?' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Dead))             :l) )
    | c == 'o' =  (Food Big,l)
    | c == '.' =  (Food Little,l)
    | c == '#' =  (Wall,l)
    | otherwise = (Empty,l)



data StateMaze          = Park WalkMaze [Tracks]
data Tracks             = Beco WalkType [WalkType] | Track WalkType WalkType [WalkType] deriving (Eq)

type WalkMaze           = [WalkCorridor]
type WalkCorridor       = [WalkType]
data WalkType           =  Nodo NodoPiece | Walk WalkPiece | Stop deriving (Eq)

type WalkPiece          = (Int, Coords, [(WalkType,Orientation)], (Int, Int))

--- Peças para caminhar = (ID, Coordenadas, Vizinhos com Orientações, Nodos que limitam o caminho desta peça) 
--- Estas peças têm só 2 vizinhos, não são cruzamentos

type NodoPiece = (Int, Coords, [(WalkType,Orientation)], [Int])


--- Peças para caminhar = (ID, Coordenadas, Vizinhos com Orientações, Nodos que podemos alcançar a partir deste)

-- Instance Show for WalkType 
-- Just for tests


instance Show Tracks where
        show (Beco (Nodo (a,(x,y),l,_)) kernel) = show "Beco " ++ show a ++ " " ++ show (x,y) ++ show (last kernel)
        show (Track (Nodo (a,(x,y),l,_)) (Nodo (b,(x2,y2),l2,_)) kernel) =
                show "Track " ++ show a ++ show (x,y) ++ show b ++ show (x2,y2) ++ show (last kernel)
