instance Show WalkType where
   show ( Stop ) = "#" 
   show ( Nodo (a,(b1,b2),c,d) ) = show a ++ "(" ++ show b1 ++ "o" ++ show b2 ++ ")"
   show ( Walk (a,(b1,b2),c,d) ) = show a ++ "(" ++ show b1 ++ "x" ++ show b2 ++ ")" 
    
-}

instance Show WalkType where
   show ( Stop ) = "#" 
   show ( Nodo (a,(b1,b2),c,d) ) = show a 
   show ( Walk (a,(b1,b2),c,d) ) = "-" 




-- | 

printWalkCorridor :: WalkCorridor -> String

printWalkCorridor [] = "\n" 
printWalkCorridor (h:t) = show h ++ printWalkCorridor t


-- | 

printWalkMaze :: WalkMaze -> String 
 
printWalkMaze []  =  ""
printWalkMaze (x:xs) = foldr (++) "" ( map (\y -> show y) x )  ++ "\n" ++ printWalkMaze ( xs )


-- | 

validWalk :: Maze -> Int -> Int -> WalkMaze

validWalk [] _ _ = []
validWalk (h:t) lin c = wCorridor : validWalk t (lin+1) (newC+c)
                where   newC            = length (filter (/= Stop) wCorridor)
                        wCorridor       = auxvalidWalk h lin 0 c

auxvalidWalk :: Corridor -> Int -> Int -> Int -> WalkCorridor

auxvalidWalk [] _ _ _ = []
auxvalidWalk (Wall:t) lin col c         = Stop : auxvalidWalk t lin (col+1) c 
auxvalidWalk (_:t) lin col c            = (Walk (c,(lin, col),[],(0,0))) : auxvalidWalk t lin (col+1) (c+1)


-- | 

findNodos :: WalkMaze -> WalkMaze -> WalkMaze

findNodos [] _ = []
findNodos (h:t) m = auxfindNodos h m : findNodos t m

auxfindNodos :: WalkCorridor -> WalkMaze -> WalkCorridor

auxfindNodos [] _ = []
auxfindNodos (Stop:t) m = Stop : auxfindNodos t m 
auxfindNodos ((Walk (a,b,c,(e1,e2))):t) m
        | (length (trueNeighbours)) > 2   = (Nodo (a,b,neighbours,[])) : auxfindNodos t m
        | (length (trueNeighbours)) == 2  = (Walk (a,b,neighbours,(0, 0))) : auxfindNodos t m
        | otherwise                       = (Walk (a,b,neighbours,(0, (-1)))) : auxfindNodos t m
                where   trueNeighbours  = filter (\x -> fst x /= Stop) (neighbours) 
                        neighbours      = walkNeighborhood b m


-- type NodoPiece = (Int, Coords, [(WalkType,Orientation)] , [Orientation] , [Int])

--- Peças para caminhar = (ID, Coordenadas, Vizinhos com Orientações, Nodos que podemos alcançar a partir deste)

-- | 

walkNeighborhood :: Coords -> WalkMaze -> [(WalkType,Orientation)]

walkNeighborhood (x,y) m 
        | x == 0 && y == 0              = [(Stop,Null), down, (Stop,Null), right]
        | x == 0 && y == l              = [(Stop,Null), down, left, (Stop,Null)]      
        | x == h && y == 0              = [  up, (Stop,Null), (Stop,Null), right]
        | x == h && y == l              = [  up, (Stop,Null), left, (Stop,Null)]
        | x == 0                        = [(Stop,Null), down, left, right]
        | y == 0                        = [  up, down, (Stop,Null), right]
        | x == h                        = [  up, (Stop,Null), left, right]
        | y == l                        = [  up, down, left, (Stop,Null)]
        | otherwise                     = [  up, down, left, right]
                where   up      = ((getWalkinMaze (x-1,y) m), U) 
                        down    = ((getWalkinMaze (x+1,y) m), D)
                        right   = ((getWalkinMaze (x,y+1) m), R)
                        left    = ((getWalkinMaze (x,y-1) m), L)
                        l       = (length (head m)) - 1
                        h       = (length m) - 1 


-- | 

getWalkinMaze :: Coords -> WalkMaze -> WalkType

getWalkinMaze ((-1),y) m = Stop
getWalkinMaze (x,(-1)) m = Stop
getWalkinMaze (x,y) m    = ( (m !! x) !! y)


-- | 

getNodosinMaze :: WalkMaze -> [WalkType]

getNodosinMaze m = concat (map (auxgetNodos) m)

auxgetNodos :: WalkCorridor -> [WalkType]

auxgetNodos [] = []
auxgetNodos ((Nodo a):t) = (Nodo a) : auxgetNodos t
auxgetNodos (_:t) = auxgetNodos t

-- Quando fizer a @transformTracks@ tenho que mudar a expressão:

-- findTracks :: WalkMaze -> [WalkType] -> [Int] 
--                      ||
--                      ||
--                     \||/
--                      \/
-- findTracks :: WalkMaze -> [WalkType] -> [Tracks]


-- | 

totalTracks :: Maze -> [Tracks]

-- Ainda falta adicionar a @compareTracks@ para eliminar os Tracks repetidos 

totalTracks maze = concat (findTracks m' listNodos)
                where   m               = validWalk maze 0 0
                        m'              = findNodos m m  
                        listNodos       = getNodosinMaze m'


-- | 

transformTracks :: [[WalkType]] -> WalkMaze -> [Tracks]

transformTracks (h:t) m = auxtransform h m : transformTracks t m




auxtransform :: [WalkType] -> WalkMaze -> Tracks

auxtransform l m
        | end == Stop                   = Beco begin kernel 
        | otherwise                     = Track begin end kernel   
                where   end     = last l     
                        begin   = head l
                        kernel  = tail (init l)


-- | 

findTracks :: WalkMaze -> [WalkType] -> [[Tracks]]

findTracks m (h:t) = (transformTracks (auxTracks h m) m) : findTracks m t 


auxTracks :: WalkType -> WalkMaze -> [[WalkType]]

auxTracks (Nodo (id,(x,y),[],d)) _ = [] 

auxTracks (Nodo (id,(x,y),(h:t),d)) m = ((Nodo (id,(x,y),(h:t),d)) : nextNodo (fst h) ornt) : auxTracks newNodo m
                where   ornt    = snd h 
                        newNodo = (Nodo (id,(x,y),t,d))


-- | 

nextNodo :: WalkType -> Orientation -> [WalkType] 

nextNodo Stop _ = [Stop]

nextNodo (Nodo (id,(x,y),l,d)) _ = [(Nodo (id,(x,y),l,d))]

nextNodo (Walk (id,(x,y),[a,b],d)) ornt 
        | snd a == ornt180              = (Walk (id,(x,y),[a,b],d)) : nextNodo (fst b) (snd b)
        | otherwise                     = (Walk (id,(x,y),[a,b],d)) : nextNodo (fst a) (snd a)
                where ornt180 = rotate ornt 180



