pieceToPic :: (Piece,[Picture]) -> Picture
pieceToPic (Wall,pics)                                                           = pics !! 29
pieceToPic ((Food Big),pics)                                                     = pics !! 0
pieceToPic ((Food Little),pics)                                                  = pics !! 1
pieceToPic ((PacPlayer (Pacman x)),pics)                                         = pics !! 2
pieceToPic ((PacPlayer (Ghost x)), pics)                                         = pics !! 11
pieceToPic (Empty,pics)                                                          = empty

