stateDrawPic :: [Picture] -> State -> Picture
stateDrawPic pics state = translate (-230) 234 (scale 0.1 0.1 (pictures (drawState (state,pics) (homecoords state))))

drawState :: (State,[Picture]) -> (Int,Int) -> [Picture]

drawState ((State m ps l),pics) (x,y) = (drawMap (playermaze,pics) (x,y)) ++ (drawPontuation (getPacman ps))
           where playermaze = placePlayersOnMap ps m

drawMap :: (Maze,[Picture]) -> (Int,Int) -> [Picture]
drawMap ([],_) _ = []
drawMap ((h:t),pics) (x,y) = (Translate 0 (fromIntegral(y*(-85))) (Pictures (drawLine (h,pics) x))):(drawMap (t,pics) (x,y+1))

drawLine :: ([Piece],[Picture]) -> Int -> [Picture]
drawLine ([],_) _ = []
drawLine ((h:t),pics) x = (Translate (fromIntegral(x*85)) 0 (pieceToPic (h,pics))):(drawLine (t,pics) (x+1))

drawPontuation :: Player -> Picture

