{-# OPTIONS_HADDOCK prune #-}
{- |
= Introduction

This was where we did the logic in order for the pacman to be able to play alone. Basically creating an artificial intelligence 
for the pacman.

= Objective

In Tarefa6 the main objective was to create the function bot that would make the pacman eat everything in the maze without any
human interference. For that we had to create a bot function. One of them was made so that the pacman prioritizes eating every 
food in the maze to win the game. One of them goes after the food and returns a play. The other one checks if it's safe to 
make the paly.   

= Discussion and Conclusion 

This is another task that would have benefited a lot from us having more time to work on it. However we are very happy with the
function bot and its restrictions.

In conclusion, we were of course a little sad that we couldn't spend more time in this task, but all and all we do have a
functioning, working bot function.
-}


{- |
 Given the id of a player and a State, it gives back a possible play for the bot to do.
 The maybe type gives the possibility for the bot to do Nothing.
-}

bot :: Int -> State -> Maybe Play 
bot x state@(State m ps l)
        | goodchoice            = chosenbot'
        | otherwise             = Nothing 
                where   goodchoice      = goodplay state chosenbot' 
                        chosenbot'      = bot' x state
                        pacman          = getPacman ps
                        idPac           = getPlayerID pacman
                        orntPac         = getPlayerOrientation pacman

-- | Checks if it's the right play or if it goes against a wall or a ghost!
-- | This is the best and final decision!

goodplay :: State -> Maybe Play -> Bool

goodplay state@(State m ps l) Nothing 
        | nextpiece == Wall = False
        | findBG == True    = False
        | otherwise         = True 
                where   validN          = filter (\x -> validCoords x heigth lengthM) closedN
                        closedN         = closedvizinhos coordsPac
                        pacman          = getPacman ps
                        coordsPac       = getPlayerCoords pacman
                        heigth          = length m - 1
                        lengthM         = length (head m) - 1
                        nextpiece       = nextmove state (Move idPac orntPac)
                        idPac           = getPlayerID pacman
                        orntPac         = getPlayerOrientation pacman
                        nexhouse        = nexthouse state (Move idPac orntPac)
                        findBG          = foundbadghost ps nexhouse

goodplay state@(State m ps l) (Just (Move id ornt)) 
        | nextpiece == Wall = False
        | findBG == True    = False
        | otherwise         = True 
                where   validN          = filter (\x -> validCoords x heigth lengthM) closedN
                        closedN         = closedvizinhos coordsPac
                        pacman          = getPacman ps
                        coordsPac       = getPlayerCoords pacman
                        heigth          = length m - 1
                        lengthM         = length (head m) - 1
                        nextpiece       = nextmove state (Move idPac ornt)
                        idPac           = getPlayerID pacman
                        nexhouse        = nexthouse state (Move id ornt)
                        findBG          = foundbadghost ps nexhouse

closedvizinhos :: Coords -> [Coords]

closedvizinhos (x,y) = [(x+1,y),(x-1,y),(x,y+1),(x,y-1)]


bot' :: Int -> State -> Maybe Play
bot' x state@(State m ps l)     
        | badghostinLine ps cPac                        = goVertical state      
        | badghostinCol ps cPac                         = goHorizontal state -- Check
        | goodghostinLine ps cPac                       = goGetHimLine state  -- Check
        | goodghostinCol ps cPac                        = goGetHimCol state  -- Check
        | ghostNeighbour ps validvizinhos               = analisaGhosts x state  -- Check
        | nextpiece == Food Little                      = Nothing 
        | nextpiece == Empty                            = go state [L,U,R,D] 
        | nextpiece == Wall                             = go state (delete orntPac [L,U,R,D]) 
        | fLine                                         = Nothing 
        | otherwise                                     = go state [L,U,R,D]
                where   nextpiece       = nextmove state (Move idPac orntPac)
                        foodViz         = foodFindViz state
                        pacman          = getPacman ps
                        orntPac         = getPlayerOrientation pacman 
                        cPac            = getPlayerCoords pacman 
                        fLine           = foodinLine orntPac cPac state 
                        heigth          = length m - 1
                        lengthM         = length (head m) - 1
                        vizinhos        = concat (map (line) (column cPac)) 
                        validvizinhos   = filter (\x -> validCoords x heigth lengthM) vizinhos
                        neighboursG     = findGNeighbour ps validvizinhos 
                        idPac           = getPlayerID pacman


-- | Function responsible for giving back a play when the ghost is in the neighborhood

analisaGhosts :: Int -> State -> Maybe Play 

analisaGhosts x state@(State m ps l)  
        | badNBool neighboursG                  = quickescape state badN 
        | goodNBool neighboursG                 = quickprize state goodN
                where   vizinhos        = concat (map (line) (column coordsPac)) 
                        validvizinhos   = filter (\x -> validCoords x heigth lengthM) vizinhos
                        neighboursG     = findGNeighbour ps validvizinhos 
                        badN            = badNeighbour neighboursG 
                        goodN           = goodNeighbour neighboursG 
                        heigth          = length m - 1 
                        lengthM         = length (head m) - 1
                        coordsPac       = getPlayerCoords pacman 
                        pacman          = getPacman ps

-- | Given a list of players and a list of Coords it gives back a list of tuples with coords and GhostMode

findGNeighbour :: [Player] -> [Coords] -> [(Coords,GhostMode)]

findGNeighbour [] _                                        = []
findGNeighbour _ []                                        = [] 
findGNeighbour ((Ghost (GhoState (a,b,c,d,e,l) mode)):t) x = if elem b x then (b,mode) : findGNeighbour t x else findGNeighbour t x
findGNeighbour ((Pacman (PacState a b c d)):t) x           = findGNeighbour t x

-- | Coords from every Alive Ghost

badNeighbour :: [(Coords,GhostMode)] -> [Coords]

badNeighbour [] = []
badNeighbour ((a,b):t) | b == Alive = a : badNeighbour t
                       | otherwise  = badNeighbour t

-- | Coords from every Dead Ghost

goodNeighbour :: [(Coords,GhostMode)] -> [Coords]

goodNeighbour [] = []
goodNeighbour ((a,b):t) | b == Dead  = a : goodNeighbour t
                        | otherwise  = goodNeighbour t

-- | Checks if there is an Alive Ghost in the Pacman's corridor

badghostinLine :: [Player] -> Coords -> Bool 

badghostinLine [] _ = False
badghostinLine ((Ghost a):t) (xP,yP) =  if (xP == xG) && (modeG == Alive) 
                                        then True 
                                        else badghostinLine t (xP,yP) 
        where   (xG,yG) = getPlayerCoords (Ghost a)
                modeG   = getGhostMode (Ghost a)

badghostinLine (_:t) cPac = badghostinLine t cPac 

-- | Checks if there is a Dead Ghost in the Pacman's corridor

goodghostinLine :: [Player] -> Coords -> Bool 

goodghostinLine [] _ = False
goodghostinLine ((Ghost a):t) (xP,yP) = if (xP == xG) && (modeG == Dead) 
                                        then True 
                                        else goodghostinLine t (xP,yP) 
        where   (xG,yG) = getPlayerCoords (Ghost a)
                modeG   = getGhostMode (Ghost a)

goodghostinLine (_:t) cPac = goodghostinLine t cPac 


-- | Gives back Coords from a Dead Ghost in the Pacman's corridor

getghostinLine :: [Player] -> Coords -> Coords 

getghostinLine ((Ghost a):t) (xP,yP) = if xP == xG then (xG,yG) else getghostinLine t (xP,yP) 
        where (xG,yG) = getPlayerCoords (Ghost a)
getghostinLine (_:t) cPac = getghostinLine t cPac 


-- | Function that changes the Pacman from line in order to escape the Ghost 

goVertical :: State -> Maybe Play 
goVertical state@(State m ps l) 
        | (nextpieceU == Wall) && (nextpieceD /= Wall) = Just (Move idPac D)
        | (nextpieceD == Wall) && (nextpieceU /= Wall) = Just (Move idPac U)
        | nextpiece180 /= Wall                         = Just (Move idPac rotateornt)
        | otherwise                                    = Just (Move idPac toGhostornt)
               where nextpieceU      = nextmove state (Move idPac U)
                     nextpieceD      = nextmove state (Move idPac D)
                     nextpiece180    = nextmove state (Move idPac rotateornt)
                     ghostcoords     = getghostinLine ps coordsPac
                     toGhostornt     = orntCoords coordsPac ghostcoords m
                     rotateornt      = rotate toGhostornt 180
                     pacman          = getPacman ps
                     coordsPac       = getPlayerCoords pacman
                     idPac           = getPlayerID pacman

-- | Function to catch a Dead Ghost in the same line! 

goGetHimLine :: State -> Maybe Play 
goGetHimLine state@(State m ps l) 
                   | nextpiece /= Wall = Just (Move idPac toGhostornt)
                   | otherwise = go state [L,U,R,D]
           where ghostcoords  = getghostinLine ps cPac
                 toGhostornt  = orntCoords cPac ghostcoords m
                 nextpiece    = nextmove  state (Move idPac toGhostornt)
                 pacman       = getPacman ps
                 cPac         = getPlayerCoords pacman
                 idPac        = getPlayerID pacman

-- | Function to catch a Dead Ghost in the same column!  

goGetHimCol :: State -> Maybe Play 
goGetHimCol state@(State m ps l) 
                   | nextpiece /= Wall = Just (Move idPac toGhostornt)
                   | otherwise = go state [L,U,R,D]
           where ghostcoords  = getghostinCol ps cPac
                 toGhostornt  = orntCoords cPac ghostcoords m
                 nextpiece    = nextmove  state (Move idPac toGhostornt)
                 pacman       = getPacman ps
                 cPac         = getPlayerCoords pacman
                 idPac        = getPlayerID pacman


-- | Checks if an Alive Ghost is in the Pacman's Corridor

badghostinCol :: [Player] -> Coords -> Bool 

badghostinCol [] _ = False
badghostinCol ((Ghost a):t) (xP,yP) =   if (yP == yG) && (modeG == Alive) 
                                        then True 
                                        else badghostinCol t (xP,yP) 
        where   (xG,yG) = getPlayerCoords (Ghost a)
                modeG   = getGhostMode (Ghost a)

badghostinCol (_:t) cPac = badghostinCol t cPac 

-- | Checks if a Dead Ghost is in the Pacman's Corridor

goodghostinCol :: [Player] -> Coords -> Bool 

goodghostinCol [] _ = False
goodghostinCol ((Ghost a):t) (xP,yP) = if (yP == yG) && (modeG == Dead) 
                                        then True 
                                        else goodghostinCol t (xP,yP) 
        where   (xG,yG) = getPlayerCoords (Ghost a)
                modeG   = getGhostMode (Ghost a)

goodghostinCol (_:t) cPac = goodghostinCol t cPac 


-- | Checks if a Ghost is in the Pacman's column

ghostinCol :: [Player] -> Coords -> Bool 

ghostinCol [] _ = False
ghostinCol ((Ghost a):t) (xP,yP) = if yG == yP then True else ghostinCol t (xP,yP) 
        where (xG,yG) = getPlayerCoords (Ghost a)
ghostinCol (_:t) cPac = ghostinCol t cPac 

-- | Gives Back de coords from the ghost in the pacman's column

getghostinCol :: [Player] -> Coords -> Coords 

getghostinCol ((Ghost a):t) (xP,yP) = if yG == yP then (xG,yG) else getghostinCol t (xP,yP) 
        where (xG,yG) = getPlayerCoords (Ghost a)
getghostinCol (_:t) cPac = getghostinCol t cPac 


-- | Function that changes the Pacman from column to escape the Ghost 

goHorizontal :: State -> Maybe Play 
goHorizontal state@(State m ps l) 
        | (nextpieceR == Wall) && (nextpieceL /= Wall) = Just (Move idPac L)
        | (nextpieceL == Wall) && (nextpieceR /= Wall) = Just (Move idPac R)
        | nextpiece180 /= Wall                         = Just (Move idPac rotateornt)
        | otherwise                                    = Just (Move idPac toGhostornt)
               where nextpieceR      = nextmove  state (Move idPac R)
                     nextpieceL      = nextmove  state (Move idPac L)
                     ghostcoords     = getghostinCol ps coordsPac
                     toGhostornt     = orntCoords coordsPac ghostcoords m
                     rotateornt      = rotate toGhostornt 180 
                     nextpiece180    = nextmove  state (Move idPac rotateornt)
                     pacman          = getPacman ps
                     coordsPac       = getPlayerCoords pacman
                     idPac           = getPlayerID pacman



ghostNeighbour :: [Player] -> [Coords] -> Bool

ghostNeighbour [] _ = False
ghostNeighbour _ [] = False 
ghostNeighbour ((Ghost (GhoState (a,b,c,d,e,l) mode)):t) x = if elem b x then True else ghostNeighbour t x
ghostNeighbour ((Pacman (PacState a b c d)):t) x = ghostNeighbour t x


badNBool :: [(Coords,GhostMode)] -> Bool

badNBool [] = False 
badNBool ((a,b):t) | b == Alive = True
                   | otherwise  = badNBool t

-- | Makes a quickescape from an Alive Ghost that's in the neigbhourhood

quickescape :: State -> [Coords] -> Maybe Play

quickescape state@(State m ps l) lcoordsBG = go state goodQ 
        where   pacman          = getPacman ps
                coordsPac       = getPlayerCoords pacman 
                goodQ           = takebadQuad state lcoordsBG [L,U,R,D]

-- | Gets the Dead ghosts in the neighbourhood

quickprize :: State -> [Coords] -> Maybe Play

quickprize state@(State m ps l) lcoordsGG = go state goodQ 
        where   pacman          = getPacman ps
                coordsPac       = getPlayerCoords pacman 
                goodQ           = nub (takegoodQuad state lcoordsGG [])



goodNBool :: [(Coords,GhostMode)] -> Bool

goodNBool [] = False 
goodNBool ((a,b):t) | b == Dead  = True
                    | otherwise  = goodNBool t


-- | This function gives back a list with lists for the coordinates of every Big Food in a Maze.

searchBigFood :: Maze -> Int -> [[Coords]]

searchBigFood [] _                      = []
searchBigFood (h:t) x                   = (searchBigFoodLine h x 0) : searchBigFood t (x+1) 

searchBigFoodLine :: Corridor -> Int -> Int -> [Coords]

searchBigFoodLine [] _ _                        = []
searchBigFoodLine ((Food Big):t) x y            = (x,y) : searchBigFoodLine t x (y+1)
searchBigFoodLine (_:t) x y                     = searchBigFoodLine t x (y+1)


-- | This function checks if a Pacman sees Food in a Corridor.

foodinLine :: Orientation -> Coords -> State -> Bool

foodinLine ornt coords state@(State m ps l) 
        | nextpiece == Wall             = False
        | nextpiece == Empty            = foodinLine ornt newC state
        | nextpiece == Food Little      = True 
        | nextpiece == Food Big         = True 
        | otherwise                     = False 
                where   newC = nextcoord coords ornt 
                        nextpiece       = nextmove  state (Move idPac ornt)
                        pacman          = getPacman ps
                        ornt            = getPlayerOrientation pacman 
                        coordsPac       = getPlayerCoords pacman
                        idPac           = getPlayerID pacman 


-- | This function gives back a list with the coordinates and the FoodType of every food within a two block radius.

foodFindViz :: State -> [Coords]

foodFindViz state@(State m ps l) = auxfood validvizinhos state 
            where   vizinhos = concat (map (line) (column coordsPac)) 
                    coordsPac = getPlayerCoords (getPacman ps)
                    validvizinhos = filter (\x -> validCoords x heigth lengthM) vizinhos
                    heigth = length m - 1
                    lengthM = length (head m) - 1
 
auxfood :: [Coords] -> State -> [Coords]

auxfood [] _ = []

auxfood ((x,y):t) state@(State m ps l) 
        | piece == Food Big         = (x,y) : auxfood t state
        | piece == Food Little      = (x,y) : auxfood t state
        | otherwise                 = auxfood t state
            where piece = m!!(abs x)!!(abs y)


column :: Coords -> [Coords]
column (x,y) = [(x-2,y),(x-1,y),(x,y),(x+1,y),(x+2,y)]

line :: Coords -> [Coords]
line (x,y) = [(x,y-2),(x,y-1),(x,y),(x,y+1),(x,y+2)]


orntCoords :: Coords -> Coords -> Maze -> Orientation
orntCoords c cFind m
           | quad == 1          = R
           | quad == 2          = U
           | quad == 3          = L
           | quad == 4          = D
                where quad = quadrante c cFind m


-- | Given a list with the foods that are close to the Pacman, it gives back the closest one.

closeFoodCoord :: [Coords] -> Coords -> Coords

closeFoodCoord (c:t) cPac = auxcloseCoord t cPac (c, (manhattann c cPac))


auxcloseCoord :: [Coords] -> Coords -> (Coords, Int) -> Coords

auxcloseCoord [] _ (oldc,_) = oldc
auxcloseCoord (c:t) cPac ac@(oldC, oldmin) 
        | newMin < oldmin                       = auxcloseCoord t cPac (c,newMin)
        | otherwise                             = auxcloseCoord t cPac ac
                where newMin = manhattann c cPac


-- | Function that calculates the distance between two coordinates.

manhattann :: Coords -> Coords -> Int

manhattann (x1,y1) (x2,y2) = abs (x1-x2) + abs (y1-y2)

-- Examples 

vizinhosZERO            = concat (map (line) (column (1,0))) 
validvizinhos           = filter (\x -> validCoords x heigthT lengthT) vizinhosZERO

heigthT = length sampleMaze1 - 1 
lengthT = length (head sampleMaze1) - 1

sampleMaze1 :: Maze

sampleMaze1 = [
                [Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall],
                [Empty, Food Little, Food Little, Food Big, Food Little, Food Big, Food Little, Empty],
                [Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall]
            ]


-- | Function that gets the quadrant where the pacman may find ghosts!
-- | It Gives back the safe quadrant!

badghostsQuad :: Coords -> [Coords] -> [Int] -> [Int]

badghostsQuad _ [] l = l
badghostsQuad cP (cG:t) l 
        | quadrante1 cP cG = badghostsQuad cP t (delete 1 l)  
        | quadrante2 cP cG = badghostsQuad cP t (delete 2 l)
        | quadrante3 cP cG = badghostsQuad cP t (delete 3 l)
        | quadrante4 cP cG = badghostsQuad cP t (delete 4 l)

-- | It gives back the number of bigfoods in that quadrant!

bigFoodQuad :: Coords -> [Coords] -> (Int,Int,Int,Int) 

bigFoodQuad _ [] = (0,0,0,0)
bigFoodQuad cP (cB:t) 
        | quadrante1 cP cB = (1+a,b,c,d)  
        | quadrante2 cP cB = (a,1+b,c,d)
        | quadrante3 cP cB = (a,b,1+c,d)
        | quadrante4 cP cB = (a,b,c,1+d)
                where   (a,b,c,d) = bigFoodQuad cP t 

-- | These 4 quadrant functions return true if the second coordinate is in the quadrant i corresponding to the first coordinate

quadrante1 (x,y) (a,b) = (a <= x) && (b > y)
quadrante2 (x,y) (a,b) = (a < x) && (b <= y)
quadrante3 (x,y) (a,b) = (a >= x) && (b < y)
quadrante4 (x,y) (a,b) = (a > x) && (b >= y)


-- | Function that gives back a list with the number of foods in all quadrants!

searchSmallFood :: Maze -> Int -> Coords -> [[Int]]

searchSmallFood [] _ _                          = []
searchSmallFood (h:t) x cPac                    = (searchSmallFoodLine h x 0 cPac) : searchSmallFood t (x+1) cPac

searchSmallFoodLine :: Corridor -> Int -> Int -> Coords -> [Int]

searchSmallFoodLine [] _ _ _                            = []
searchSmallFoodLine ((Food Little):t) x y cPac          = nQuad : searchSmallFoodLine t x (y+1) cPac
        where   nQuad = auxsmallFood (x,y) cPac 
searchSmallFoodLine (_:t) x y cPac                      = searchSmallFoodLine t x (y+1) cPac

-- | Gives back the quadrant from the first coord in relation to the second!

auxsmallFood c cPac 
        | quadrante1 cPac c             = 1
        | quadrante2 cPac c             = 2
        | quadrante3 cPac c             = 3
        | quadrante4 cPac c             = 4


-- | Calculates de principal diagonal in a certain position!

diagonalP :: Coords -> Int -> Int -> [Coords]

diagonalP c lengthM heigth = filter (\x -> validCoords x heigth lengthM) (diagonalP' c lengthM)

diagonalP' :: Coords -> Int -> [Coords]

diagonalP' (x,y) lengthM = [(i+x,-i+y) | i <- [(-lengthM)..(lengthM)]]

diagonalS :: Coords -> Int -> Int -> [Coords]

diagonalS c lengthM heigth = filter (\x -> validCoords x heigth lengthM) (diagonalS' c lengthM)

diagonalS' :: Coords -> Int -> [Coords]

diagonalS' (x,y) lengthM = [(i+x,i+y) | i <- [(-lengthM)..(lengthM)]]


-- | Function that evaluates the Quadrants

choseQuad :: [Int] -> (Int,Int,Int,Int) -> [Int]

choseQuad [] _ = []
choseQuad (h:t) (a,b,c,d) 
        | h==1                  = a : choseQuad t (a,b,c,d)
        | h==2                  = b : choseQuad t (a,b,c,d)
        | h==3                  = c : choseQuad t (a,b,c,d)
        | h==4                  = d : choseQuad t (a,b,c,d)





-- | It gives back de quadrant from the second coord in relation to the first

quadrante :: Coords -> Coords -> Maze -> Int

quadrante c cFind  m  
        | downP &&      upS             = 1
        | upP   &&      upS             = 2
        | upP   &&      downS           = 3 
        | downP &&      downS           = 4  
                where   heigth  = (length m) -1
                        lengthM = (length (head m)) -1
                        dP      = diagonalP c lengthM heigth
                        dS      = diagonalS c lengthM heigth
                        upP     = superiordP dP cFind 
                        upS     = superiordS dS cFind 
                        downP   = inferiordP dP cFind 
                        downS   = inferiordS dS cFind 

-- | Checks if the coord is above the principal diagonal

superiordP :: [Coords] -> Coords -> Bool

superiordP dP cFind@(a,b)
        | a < xh                        = True
        | a > xt                        = False 
        | otherwise                     = supdP dP cFind
                where   (xh,yh) = head dP
                        (xt,yt) = last dP

-- | Auxiliary function for superiordP!

supdP :: [Coords] -> Coords -> Bool 

supdP ((x,y):t) (a,b)
        | x == a                = if b <= y then True else False
        | otherwise             = supdP t (a,b)


-- | Verifies if a coord is below the principal diagonal

inferiordP :: [Coords] -> Coords -> Bool

inferiordP dP cFind@(a,b)
        | a > xt                        = True
        | a < xh                        = False
        | otherwise                     = infdP dP cFind
                where   (xh,yh) = head dP
                        (xt,yt) = last dP




-- | Auxiliary function for inferiordP!

infdP :: [Coords] -> Coords -> Bool

infdP ((x,y):t) (a,b)
        | x == a                = if b >= y then True else False
        | otherwise             = infdP t (a,b)



-- | Verifies if a coordinate is above the secondary diagonal

superiordS :: [Coords] -> Coords -> Bool

superiordS dS cFind@(a,b)
        | a < xh                        = True
        | a > xt                        = False 
        | otherwise                     = supdS dS cFind
                where   (xh,yh) = head dS
                        (xt,yt) = last dS

-- | Auxiliary function for superiordS!

supdS :: [Coords] -> Coords -> Bool 

supdS ((x,y):t) (a,b)
        | x == a                = if b >= y then True else False
        | otherwise             = supdS t (a,b)


-- | Verifies if a coordinate is below the secondary diagonal

inferiordS :: [Coords] -> Coords -> Bool

inferiordS dS cFind@(a,b)
        | a > xt                        = True
        | a < xh                        = False
        | otherwise                     = infdS dS cFind
                where   (xh,yh) = head dS
                        (xt,yt) = last dS




-- | Auxiliary function for inferiordS!

infdS :: [Coords] -> Coords -> Bool

infdS ((x,y):t) (a,b)
        | x == a                = if b <= y then True else False
        | otherwise             = infdS t (a,b)



-- |

data Quad = Q Int (Int,Int) 

instance Show Quad where
        show (Q a (f,g)) = show a

contaghostsQ :: Quad -> Int 

contaghostsQ (Q _ (food,ghost)) = ghost 

contafoodQ :: Quad -> Int

contafoodQ (Q _ (food,ghost)) = food 

-- | Returns a list of lists with the numbers of the quadrants that have food!

makeQuadMaze :: Maze -> Maze -> Coords -> Int  -> [[Int]]

makeQuadMaze [] _ _ _                  = []
makeQuadMaze (h:t) m cPac x            = (makeQuadLine h cPac m x 0) : makeQuadMaze t m cPac (x+1)

makeQuadLine :: Corridor -> Coords -> Maze -> Int -> Int -> [Int]

makeQuadLine [] _ _ _ _                 = []
makeQuadLine (h:t) cPac m x y         
        | h == Food Big                 = i : makeQuadLine t cPac m x (y+1)
        | h == Food Little              = i : makeQuadLine t cPac m x (y+1)
        | otherwise                     = makeQuadLine t cPac m x (y+1)
                where   i       = quadrante cPac (x,y) m 

-- | Quadrants after the treatment!

quad1 :: State -> Quad

quad1 state@(State m ps l) = Q 1 (f,g)
        where   f               = length (filter (\x -> x == 1) (concat (makeQuadMaze m m cPac 0)))
                cPac            = getPlayerCoords pacman
                pacman          = getPacman ps
                g               = length (filter (\x -> x == 1) (makeQuadGhosts state ps))
quad2 :: State -> Quad

quad2 state@(State m ps l) = Q 2 (f,g)
        where   f               = length (filter (\x -> x == 2) (concat (makeQuadMaze m m cPac 0)))
                cPac            = getPlayerCoords pacman
                pacman          = getPacman ps
                g               = length (filter (\x -> x == 2) (makeQuadGhosts state ps))

quad3 :: State -> Quad

quad3 state@(State m ps l) = Q 3 (f,g)
        where   f               = length (filter (\x -> x == 3) (concat (makeQuadMaze m m cPac 0)))
                cPac            = getPlayerCoords pacman
                pacman          = getPacman ps
                g               = length (filter (\x -> x == 3) (makeQuadGhosts state ps))

quad4 :: State -> Quad

quad4 state@(State m ps l) = Q 4 (f,g)
        where   f               = length (filter (\x -> x == 4) (concat (makeQuadMaze m m cPac 0)))
                cPac            = getPlayerCoords pacman
                pacman          = getPacman ps
                g               = length (filter (\x -> x == 4) (makeQuadGhosts state ps))

-- | Returns a list with the quadrants that have ghosts

makeQuadGhosts :: State -> [Player] -> [Int]

makeQuadGhosts state [] = []

makeQuadGhosts state@(State m ps l) ((Ghost a):t) = i : makeQuadGhosts state t
        where   i       = quadrante cPac cG m 
                cG      = getPlayerCoords (Ghost a)
                cPac    = getPlayerCoords pacman
                pacman  = getPacman ps

makeQuadGhosts state@(State m ps l) (_:t) = makeQuadGhosts state t


--- | Tests for the quadrants

m1 = sampleMaze1 
lM = length (head m1) -1 
hM = (length m) -1

dP = diagonalP (1,5) lM hM
dS = diagonalS (1,5) lM hM



-- | Function responsible for getting the food in the quadrants with no imminent threats!

go :: State -> [Orientation] -> Maybe Play

go state@(State m ps l) lori
        | length lori == 1      = Just (Move idPac (head lori))
        | otherwise             = Just (Move idPac bestori)
                where   validori = nowall state lori 
                        pacman = getPacman ps
                        cPac = getPlayerCoords pacman 
                        bestori = bestQuad state validori (head validori) 0
                        idPac = getPlayerID pacman


-- | Chooses the quadrant with more food!

bestQuad :: State -> [Orientation] -> Orientation -> Int -> Orientation

bestQuad _ [] bestori _ = bestori

bestQuad state@(State m ps l) (R:t) bestori nFood
        | newfood > nFood               = bestQuad state t R newfood
        | otherwise                     = bestQuad state t bestori nFood
                where   newfood = contafoodQ (quad1 state)

bestQuad state@(State m ps l) (U:t) bestori nFood
        | newfood > nFood               = bestQuad state t U newfood
        | otherwise                     = bestQuad state t bestori nFood
                where   newfood = contafoodQ (quad2 state) 

bestQuad state@(State m ps l) (L:t) bestori nFood
        | newfood > nFood               = bestQuad state t L newfood
        | otherwise                     = bestQuad state t bestori nFood
                where   newfood = contafoodQ (quad3 state)

bestQuad state@(State m ps l) (D:t) bestori nFood
        | newfood > nFood               = bestQuad state t D newfood
        | otherwise                     = bestQuad state t bestori nFood
                where   newfood = contafoodQ (quad4 state)

nowall :: State -> [Orientation] -> [Orientation]

nowall _ [] = []
nowall state@(State m ps l) (h:t)
        | nextpiece == Wall                     = nowall state t
        | otherwise                             = h : nowall state t
                where   nextpiece       = nextmove  state (Move idPac h)
                        pacman          = getPacman ps
                        idPac           = getPlayerID pacman                 


-- | Removes the quadrants that have ghosts 

takebadQuad :: State -> [Coords] -> [Orientation] -> [Orientation]

takebadQuad _ [] lori = lori  
takebadQuad state@(State m ps l) (h:t) lori
        | quad == 1                     = delete R lori
        | quad == 2                     = delete U lori
        | quad == 3                     = delete L lori
        | quad == 4                     = delete D lori
                where   quad    = quadrante cPac h m  
                        pacman  = getPacman ps
                        cPac    = getPlayerCoords pacman

-- 

takegoodQuad :: State -> [Coords] -> [Orientation] -> [Orientation]

takegoodQuad _ [] lori = lori
takegooQuad state@(State m ps l) (h:t) lori
        | quad == 1                     = R : (takegoodQuad state t lori) 
        | quad == 2                     = U : (takegoodQuad state t lori)
        | quad == 3                     = L : (takegoodQuad state t lori)
        | quad == 4                     = D : (takegoodQuad state t lori)
                where   quad    = quadrante cPac h m  
                        pacman  = getPacman ps
                        cPac    = getPlayerCoords pacman
