{- |
= Introduction

In Tarefa5 we had to give life to the Ghosts, that means we made them go after the Pacman when he isn't mega or run away when 
the Pacman is mega.

= Objective

The objective in this task was to create the function ghostPlay that finally gives the ghost some artificial intelengence that
make them go after the Pacman or not depending if course on the restrictions written in the code.

= Discussion and Conclusion 

When we first started doing these task we were creating a different strategy (WalkinMaze), but then we realized that there hasn't 
enough time to finish and perfect it. So we dicided that we would take a different aproach to the Tarefa5, we went with a 
strategy that closer resenbles our functions in Tarefa6.

In conclusion, we weren't clearily able to do what we originally intended. That doesn't mean that we are not happy with how it 
came out, but with a little more time we think we could have done a much better job.
-}


-- | Given a State it gives back a list of Plays, one for each Ghost, with the best alternative to catch Pacman.

ghostPlay :: State -> [Play]

ghostPlay (State m ps l) = auxghostPlay (dropPacman ps) (State m ps l) 

auxghostPlay :: [Player] -> State -> [Play]

auxghostPlay [] state = []

auxghostPlay (h:t) state@(State m ps l) 
        | homealone cG m                = escapeHome state id : auxghostPlay t state
        | mode == Alive                 = chaseMode state id : auxghostPlay t state
        | mode == Dead                  = scatterMode state id : auxghostPlay t state
                where   id = getPlayerID h
                        mode = getGhostMode h
                        cG = getPlayerCoords (draftplayer ps id)

-- | Checks to see if the Ghost is in the ghostHome

homealone :: Coords -> Maze -> Bool

homealone c m 
        | elem c homeG          = True 
        | otherwise             = False
                where   homeG = hauntinghouse (homecoords m)

-- | Coords from the ghost's house, so that they can run away from it in escapeHome

hauntinghouse :: Coords -> [Coords]

hauntinghouse (x,y) = [(x,y-2),(x,y-1),(x,y),(x,y+1),(x,y+2),(x-1,y-1),(x-1,y)]

-- | Play so that the ghost does go into the ghost house

escapeHome :: State -> Int -> Play 

escapeHome state@(State m ps l) id = Move id ornt 
        where   ornt    = orntCoords cG (a-4,b) m
                (a,b)   = beginhome m 
                cG      = getPlayerCoords ghost
                ghost   = draftplayer ps id 

-- | This function is used when the mode of the Ghosts turn to Dead and it makes the Ghosts run away from the Pacman. 

scatterMode :: State -> Int -> Play

scatterMode (State m ps l) id = Move id ornt
                where   ornt            = rotate (orntCoords cG cPac m) 180
                        pacman          = getPacman ps 
                        cG              = getPlayerCoords ghost
                        cPac            = getPlayerCoords pacman 
                        ghost           = draftplayer ps id
                        nextpiece       = nextmove (State m ps l) (trackerPacker (State m ps l) id) 
                        rightPlay       = rotate90R (trackerPacker (State m ps l) id)

-- | This function given a State and an ID from a ghost, it gives back the best Play for the Ghost to persue the Pacman, if the Ghost is Alive.

chaseMode :: State -> Int -> Play

chaseMode (State m ps l) id = Move id ornt
                where   ornt            = orntCoords cG cPac m
                        pacman          = getPacman ps 
                        cG              = getPlayerCoords ghost
                        cPac            = getPlayerCoords pacman 
                        ghost           = draftplayer ps id
                        nextpiece       = nextmove (State m ps l) (trackerPacker (State m ps l) id) 
                        rightPlay       = rotate90R (trackerPacker (State m ps l) id)


-- | Given a State and a Player, the Ghost, it gives back the best Play in order to persue the Pacman.

hunt :: State -> Player -> Play 

hunt (State m ps l) ghost 
        | ornt == L || ornt == R                = if a > 0 then (Move id U) else (Move id D) 
        | otherwise                             = if b > 0 then (Move id L) else (Move id R)
                where   (pacx, pacy)    = getPlayerCoords (getPacman ps) 
                        (x, y)          = getPlayerCoords ghost
                        (a, b)          = ((x-pacx), (y-pacy))
                        ornt            = getPlayerOrientation ghost
                        id              = getPlayerID ghost


-- | Verify's if there is a Pacman in the ghost's line

pacinLine :: [Player] -> Coords -> Bool 

pacinLine [] _ = False
pacinLine ((Pacman a):t) (xG,yG) = if xG == xP then True else pacinLine t (xG,yG) 
        where (xP,yP) = getPlayerCoords (Pacman a)
pacinLine (_:t) cGhost = pacinLine t cGhost

-- | It gives back de Coords from the Pacman in the same line as the ghost

getpacinLine :: [Player] -> Coords -> Coords 

getpacinLine ((Pacman a):t) (xG,yG) = if xG == xP then (xP,yP) else getpacinLine t (xG,yG) 
        where (xP,yP) = getPlayerCoords (Pacman a)
getpacinLine (_:t) cGhost = getpacinLine t cGhost 


-- | Verify's if there is a Pacman in the ghost's column

pacinCol :: [Player] -> Coords -> Bool 

pacinCol [] _ = False
pacinCol ((Pacman a):t) (xG,yG) = if yG == yP then True else pacinCol t (xP,yP) 
        where (xP,yP) = getPlayerCoords (Pacman a)
pacinCol (_:t) cGhost = pacinCol t cGhost 

-- | It gives back de Coords from the Pacman in the same column as the ghost

getpacinCol :: [Player] -> Coords -> Coords 

getpacinCol ((Pacman a):t) (xG,yG) = if yG == yP then (xG,yG) else getpacinCol t (xP,yP) 
        where (xP,yP) = getPlayerCoords (Pacman a)
getpacinCol (_:t) cGhost = getpacinCol t cGhost


-- | Tracks the pacman down

trackerPacker :: State -> Int -> Play

trackerPacker state@(State m ps l) idG = Move idG toPacornt
               where ghostcoords = getPlayerCoords drawghost
                     toPacornt   = orntCoords ghostcoords cPac m
                     pacman      = getPacman ps
                     cPac        = getPlayerCoords pacman
                     drawghost   = draftplayer ps idG
