defaultDelayTime = 250 -- 250 ms

{- |
   Given a step and a State, alters the State of the game in one iteracion.
   This function also results in all the players, Ghosts and Pacmans, always having a play for them.
-}

passTime :: Int  -> State -> State
passTime step state@(State m ps l) = State (maze newState) finalplayers (level newState)
        where   timeMegaPac     = getPacmanTime (getPacman ps)
                checkedState    = checkMega state timeMegaPac 
                newState        = auxpassTime (makePlays step state) checkedState
                finalplayers    = auxplay (playersState newState)


-- | This function is responsible for giving a Play to every player.

auxpassTime :: [Play] -> State -> State

auxpassTime [] state = state
auxpassTime (h:t) state@(State m ps l) = auxpassTime t (play h state)


-- | This function serves to decrease the time of the Pacman.

auxplay :: [Player] -> [Player]

auxplay [] = []
auxplay ((Pacman (PacState (a, b, c, d, e, f) g Closed h)):t)   = (Pacman (PacState (a, b, c, d, e, f) (g-0.25) Open h)) : auxplay t      
auxplay ((Pacman (PacState (a, b, c, d, e, f) g Open h)):t)     = (Pacman (PacState (a, b, c, d, e, f) (g-0.25) Closed h)) : auxplay t 
auxplay (h:t) = h : auxplay t


-- | This function given a number and a State gives back a list of random Plays.

makePlays :: Int -> State -> [Play] 

makePlays step state@(State m ps l) 
            | even step             = ghostPlay state ++ (repeatplays a (Move id ornt))
            | otherwise             = ghostPlay state ++ (repeatplays b (Move id ornt))
                where   id      = getPlayerID pac
                        ornt    = getPlayerOrientation pac 
                        (a,b)   = makevelocity (getPlayerVel pac)
                        pac     = getPacman ps

{- |
  checkMega applies the function verifyMega to a State.
@    
    checkMega (State m ps l) time = State m (verifyMega ps time) l
@
-}
checkMega :: State -> Double -> State

checkMega (State m ps l) time = State m (verifyMega ps time) l 

{- |
  This function given a list of Players and a number that represntes time gives back the list of Players with their modes updated.
   
   __For example:__
      If time <= 0 then the mode of a Pacman is Normal and the mode of a Ghost is Alive;
      If time > 0 then the mode of a Pacman is Mega and the mode of a Ghost will depende on thne fact that he migth have been eaten by a Pacman condition later added.
-}
verifyMega :: [Player] -> Double -> [Player]

verifyMega [] _ = []

verifyMega ((Pacman (PacState a b c d)):t) time 
            | time <= 0             = (Pacman (PacState a b c Normal)) : verifyMega t time
            | otherwise             = (Pacman (PacState a b c Mega)) : verifyMega t time
          

verifyMega ((Ghost (GhoState a mode)):t) 0 = ((Ghost (GhoState a Alive)) : verifyMega t 0)
verifyMega ((Ghost (GhoState a mode)):t) time 
            | time <= 0             = (Ghost (GhoState a Alive)) : verifyMega t time
            | otherwise             = (Ghost (GhoState a mode)) : verifyMega t time 


-- | This function repeats the same play a certain number of times 

repeatplays :: Int -> Play -> [Play]

repeatplays 0 play = []
repeatplays n play = play : repeatplays (n-1) play



---- Funções que não influenciam output!!!

makevelocity :: Double -> (Int,Int) 

makevelocity 0      = (0,0)
makevelocity 0.5    = (0,1)
makevelocity 1      = (1,1)  
makevelocity 1.5    = (2,1)
makevelocity 2      = (2,2)
