-- | Compacte Maze. Given a Maze, the function gives Instructions back

compactMaze :: Maze -> Instructions

compactMaze m = map (snd) (dataperfect (compactrand m 0)) 


-- | Organizes all the data, from the other functions, nicely 

dataperfect :: [(Int, Instruction)] -> [(Int, Instruction)]

dataperfect [] = []
dataperfect ((a,Repeat c):t) = (a, Repeat c) : dataperfect t 
                
dataperfect ((a,b):t) = (a,b) : dataperfect (auxperfect t (a,b))

-- | Compacts Maze with Repeat

auxperfect :: [(Int, Instruction)] -> (Int, Instruction) -> [(Int, Instruction)]

auxperfect [] _ = []
auxperfect ((a,b):t) (id,instru) 
                | b == instru           = ((-1),Repeat id) : auxperfect t (id,instru)            
                | otherwise             = (a,b) : auxperfect t (id,instru)


-- | Compacts @Maze@ without paiyng attencion to @Repeat@

compactrand :: Maze -> Int -> [(Int, Instruction)]

compactrand [] _ = []
compactrand (h:t) ac = (ac, compactline h) : (compactrand t (ac+1))


-- | Compacts only a @Corridor@

compactline :: Corridor -> Instruction

compactline l = Instruct (auxcompactline l)


auxcompactline :: Corridor -> [(Int, Piece)]

auxcompactline [] = []
auxcompactline (h:t) = (1 + (length as) , h) : auxcompactline bs 
                        where (as,bs) = greatbreak t h 


-- | Separates different @Pieces@ from @Corridors@

greatbreak :: Eq a => [a] -> a -> ([a],[a])

greatbreak [] _ = ([],[])
greatbreak (h:t) boss
        | h == boss         = (h:as, bs)
        | otherwise         = ([],(h:t))
            where (as,bs) = greatbreak t boss
