-- | Analyzes the Piece that the player will reach

validir ::  [Player] -> Play -> Bool

validir (player : t) (Move id ornt) 
            | getPlayerID player == id = if getPlayerOrientation player == ornt then True else False
            | otherwise = validir t (Move id ornt)


-- | Changes the orientation of a player

changedir :: [Player] -> Play -> [Player]

changedir [] _ = []
changedir ((Pacman (PacState (idP,  (x,y), velocity, orientation, points, lives) timeM mouth mode)) : t) (Move id ornt) 
            | idP == id = ((Pacman (PacState (idP,  (x,y), velocity, ornt, points, lives) timeM mouth mode)) : t)
            | otherwise = (Pacman (PacState (idP,  (x,y), velocity, orientation, points, lives) timeM mouth mode)) : changedir t (Move id ornt)
changedir ((Ghost (GhoState (idP,  (x,y), velocity, orientation, points, lives) mode)) : t) (Move id ornt) 
            | idP == id = ((Ghost (GhoState (idP,  (x,y), velocity, ornt, points, lives) mode)) : t)
            | otherwise = (Ghost (GhoState (idP,  (x,y), velocity, orientation, points, lives) mode)) : changedir t (Move id ornt)


-- | Pacman's encounter with a Ghost with State Alive

aliveghost :: [Player] -> Int -> [Player]

aliveghost [] _ = []
aliveghost (player:t) id 
        | getPlayerID player == id  = justliveonce player : t
        | otherwise                 = player : aliveghost t id
            where wanted = draftplayer (player:t) id


-- | This function analyzes the amount of lives Pacman has. If the number of loves is equal to 0 then is State turns to @Dying@

justliveonce :: Player -> Player

justliveonce (Pacman (PacState (i, c, v, o, p, l) tM m mode))  
        | l == 0    = (Pacman (PacState (i, c, v, o, p, l) tM m Dying))
        | otherwise     = (Pacman (PacState (i, c, v, o, p, (l - 1)) tM m mode))
      

-- | Function that adds points

addpoints :: [Player] -> Int ->Int -> [Player]

addpoints [] id n = []
addpoints ((Pacman (PacState (x,y,z,t,h,l) b c d )) : xs) id n 
                | id == x = ((Pacman (PacState (x,y,z,t,h+n,l) b c d )) : xs)
                | otherwise = (Pacman (PacState (x,y,z,t,h,l) b c d )) : addpoints xs id n
addpoints (player:xs) id n = player : addpoints xs id n


{- |
= __Functions for confrontation with Dead Ghost__
        Add 10 points
        Ghost returns Alive to the Ghost House 
-}
-- | This function takes a Ghost to the ghost house

homeGhost :: Player -> State -> [Player]

homeGhost player (State m players level) =
   returnhome (getPlayerID player) (homecoords m) players


-- | Function for the Ghost to be reborn Alive

reborn :: Player -> Player

reborn (Ghost (GhoState (x,y,z,t,h,l) b )) = (Ghost (GhoState (x,y,z,t,h,1) Alive ))


returnhome :: Int -> Coords -> [Player] -> [Player] 

returnhome id home (player:t)
        | getPlayerID player == id      = (ghostinHome : t) 
        | otherwise                     = player : returnhome id home t
                where ghostinHome = (setPlayerOrientation (setPlayerCoords (reborn player) home) U)

-- | Function that gives us the Ghost's Home coordinates

homecoords :: Maze -> Coords

homecoords m
    | even  (length (head m)) && even   (length m) = ((div (length m) 2) - 1, (div (length (head m)) 2) - 1) 
    | even  (length (head m)) && odd    (length m) = ((div (length m) 2), (div (length (head m)) 2) - 1)
    | odd   (length (head m)) && even   (length m) = ((div (length m) 2) - 1, (div (length (head m)) 2))
    | odd   (length (head m)) && odd    (length m) = ((div (length m) 2), (div (length (head m)) 2))


-- | Function that brings both functions together: adding points and returning the Ghost Alive to the Ghost House!!!

eatGhost :: State -> Play -> Int -> State

eatGhost (State m players level) (Move id ornt) idG = State m (addpoints (homeGhost (draftplayer players idG) (State m players level)) id 10) level


{- |
= __Function for Big Food__

Topics:
- add 5 points;
- PacState to Mega;
- GhoState to Dead;
- Half of the Ghosts velocity;
- Add Mega's time.
-}


megapacman :: [Player] -> [Player]

megapacman [] = []
megapacman ((Pacman (PacState (x,y,z,t,h,l) b c mode )) : xs) = (Pacman (PacState (x,y,1,t,h+5,l) 8 c Mega )) : megapacman xs
megapacman ((Ghost (GhoState (x1,y1,z1,t1,h1,l1) mode )) : xs) = (Ghost (GhoState (x1,y1,1,newt1,h1,0) Dead )) : megapacman xs
                        where newt1 = rotate t1 180
-- play :: Play -> State -> State 

-- Adicionar as restrições pedidas na 2ª fase sem alterar a estrutrua da play da 1ª fase
-- play1 fica para a função que estava feita na Tarefa2... Pacman
-- play2 fica para o movimento dos fantasmas

play :: Play -> State -> State  

play (Move id ornt) (State m ps l) 
        | isghost player                = play2 (Move id ornt) (State m ps l)
        | otherwise                     = play1 (Move id ornt) (State m ps l)
                 where  player = draftplayer ps id

-- Função provisória para os fantasmas andarem!!!

play2 :: Play -> State -> State

play2 (Move id ornt) state@(State m ps l)
        | (foundPacman ps actualCoords) && (ghostMode == Alive)         = eatPacman state (Move id ornt) idPac
        | (foundPacman ps actualCoords) && (ghostMode == Dead)          = getsEaten state (Move id ornt) 
        | validir ps (Move id ornt) == False                            = State m (changedir ps (Move id ornt)) l
        | (foundPacman ps nextHouse) && (ghostMode == Alive)            = eatPacman state (Move id ornt) idPac
        | (foundPacman ps nextHouse) && (ghostMode == Dead)             = getsEaten state (Move id ornt) 
        | nextpiece == Wall                                             = State m ps l
        | otherwise                                                     = movepacman state (Move id ornt)
                where   nextpiece       = nextmove  (State m ps l)  (Move id ornt) 
                        nextHouse       = nexthouse (State m ps l)  (Move id ornt)
                        ghostMode       = getGhostMode (draftplayer ps id)
                        idPac           = getPlayerID (getPacman ps)
                        actualCoords    = getPlayerCoords (draftplayer ps id)


-- | This function allows valide plays in a Maze

play1 :: Play -> State -> State

play1 (Move id ornt) (State m ps l)
        | foundbadghost ps actualCoords                                 = (State destroy (gameover ps id begin) l)
        | foundgoodghost ps actualCoords                                = movepacman (eatGhost (State m ps l)  (Move id ornt) (idghost ps nextHouse))                   (Move id ornt)
        | validir ps (Move id ornt) == False                            = (State m (changedir ps (Move id ornt)) l) 
        | nextpiece == Wall                                             = (State m ps l)
        | ((foundgoodghost ps nextHouse) && (nextpiece == Food Big))    = movepacman (eatGhost (State m  (megapacman ps)  l) (Move id ornt) (idghost ps nextHouse))        (Move id ornt)
        | ((foundgoodghost ps nextHouse) && (nextpiece == Food Little)) = eatGhost (movepacman (State destroy (addpoints ps id 1) l) (Move id ornt)) (Move id ornt) (idghost ps nextHouse)
        | foundbadghost ps nextHouse                                    = (State destroy (gameover ps id begin) l)
        | foundgoodghost ps nextHouse                                   = movepacman (eatGhost (State m ps l)  (Move id ornt) (idghost ps nextHouse))                   (Move id ornt)
        | nextpiece == Empty                                            = movepacman (State m ps l)                                                                     (Move id ornt)
        | nextpiece == Food Little                                      = movepacman (State destroy (addpoints ps id 1) l)                                              (Move id ornt) 
        | nextpiece == Food Big                                         = movepacman (State destroy (megapacman ps)  l)                                                  (Move id ornt) 
        | otherwise                                                     = (State m ps l)
            where   nextpiece           = nextmove  (State m ps l)  (Move id ornt)
                    nextHouse           = nexthouse (State m ps l)  (Move id ornt) 
                    begin               = beginhome m 
                    destroy             = replaceElemInMaze nextHouse Empty m
                    actualCoords        = getPlayerCoords (draftplayer ps id)

-- | This functions determine the initial location of the Pacman player

beginhome :: Maze -> Coords 

beginhome m = (x + 2, y)
        where (x,y) = homecoords m


-- | Determines if the game ends (i.e. the player has 0 lives)

gameover :: [Player] -> Int -> Coords -> [Player]

gameover (player:t) id begin
        | getPlayerID player == id  = justliveonce (setPlayerCoords player begin) : t
        | otherwise                 = player : (gameover t id begin)


-- | Determines a Ghodt's id

idghost :: [Player] -> Coords -> Int

idghost ((Ghost ghostate) : t) coords  
        | getPlayerCoords (Ghost ghostate) == coords = getPlayerID (Ghost ghostate)
        | otherwise = idghost t coords
idghost (h:t) coords = idghost t coords


-- | Pacman's encounter with a Ghost that is Alive

foundbadghost :: [Player] -> Coords -> Bool

foundbadghost [] _ = False 
foundbadghost ((Ghost (GhoState (i,c,x,y,z,l) Alive)) : t) coords  
        | c == coords = True 
        | otherwise = foundbadghost t coords
foundbadghost (h:t) coords = foundbadghost t coords


-- | Pacman's encounter with a Ghost that is Dead

foundgoodghost :: [Player] -> Coords -> Bool

foundgoodghost [] _ = False 
foundgoodghost ((Ghost (GhoState (i,c,x,y,z,l) Dead)) : t) coords  
        | c == coords = True 
        | otherwise = foundgoodghost t coords
foundgoodghost (h:t) coords = foundgoodghost t coords

-- | Ghost's encounter with a Pacman 

foundPacman :: [Player] -> Coords -> Bool

foundPacman [] _ = False
foundPacman ((Pacman (PacState (i,c,x,y,z,l) a b d)):t) coords 
        | c == coords           = True 
        | otherwise             = foundPacman t coords 
foundPacman (h:t) coords = foundPacman t coords

-- = __Movement Functions__ -- 


-- | This function allows valid moves through the @Maze@
-- Tenho que mudar isto depois, meter o isTunnel em primeiro se calhar? 



movepacman :: State -> Play -> State

movepacman (State m ps l) (Move id ornt)
    | isTunnel m (draftplayer ps id) (Move id ornt)     = (State m (moveintunel ps (Move id ornt) m) l)
    | otherwise                                         = (State m (moveinmaze ps  (Move id ornt)  ) l)


-- | This function is used to know if the player is set next to a Tunel

isTunnel :: Maze ->  Player -> Play -> Bool

isTunnel m player (Move id ornt)
        | (y==0) && (ornt==L)       = True 
        | (y==lengthM) && (ornt==R) = True
        | (x==0) && (ornt==U)       = True
        | (x==heigthM) && (ornt==D) = True                                                                         
        | otherwise = False
            where   (x,y) = getPlayerCoords player
                    lengthM = length (head m) - 1
                    heigthM = (length m) -1

-- | This function allows valid moves through the Tunel

moveintunel :: [Player] -> Play -> Maze -> [Player]

moveintunel [] _ _ = []
moveintunel (player:t) (Move id ornt) maze 
        | (getPlayerID player == id) && (ornt == L)    = setPlayerCoords player (x, y + (lenmaze - 1))  : t   
        | (getPlayerID player == id) && (ornt == D)    = setPlayerCoords player (x - (heigth - 1) , y)   : t 
        | (getPlayerID player == id) && (ornt == R)    = setPlayerCoords player (x, y - (lenmaze - 1))  : t 
        | (getPlayerID player == id) && (ornt == U)    = setPlayerCoords player (x + (heigth - 1) , y)   : t   
        | otherwise = player : moveintunel t (Move id ornt) maze
            where       (x,y)           = getPlayerCoords player
                        lenmaze         = length (head maze)
                        heigth          = length maze 

-- | Auxilary for the function @movepacman@

moveinmaze :: [Player] -> Play -> [Player]

moveinmaze [] _ = []
moveinmaze (player:t) (Move id ornt)  
        | getPlayerID player == id      = (setPlayerCoords player (nextcoord (getPlayerCoords player) ornt)) : t
        | otherwise                     = player : moveinmaze t (Move id ornt) 
            where (x,y) = getPlayerCoords player


-- | Determines the coordinates to wich the player will move after an @Orientation@ is given

nextcoord :: Coords -> Orientation -> Coords

nextcoord (x,y) ornt 
        | ornt == L = (x,y - 1)
        | ornt == D = (x + 1,y)
        | ornt == R = (x,y + 1)
        | otherwise = (x - 1,y)


nextcoordT :: Coords -> Orientation -> Maze -> Coords

nextcoordT (x,y) L m = (x, y + (lenmaze - 1))
                where lenmaze = length (head m)
                      heigth  = length m
nextcoordT (x,y) R m = (x, y - (lenmaze - 1))
                where lenmaze = length (head m)
                      heigth  = length m
nextcoordT (x,y) U m = (x + (heigth - 1), y)
                where lenmaze = length (head m)
                      heigth  = length m
nextcoordT (x,y) D m = (x - (heigth - 1), y)
                where lenmaze = length (head m)
                      heigth  = length m


-- | Determines the @Piece@ that exists in the coordinates of the next play

nextmove :: State -> Play -> Piece

nextmove (State m ps l) (Move id ornt) = m!!(abs a)!!(abs b)
            where (a,b) = nexthouse (State m ps l) (Move id ornt)


nexthouse :: State -> Play -> Coords

nexthouse (State m ps l) (Move id ornt)
    | isTunnel m (draftplayer ps id) (Move id ornt)     = nextcoordT    (getPlayerCoords (draftplayer ps id)) ornt m 
    | otherwise                                         = nextcoord     (getPlayerCoords (draftplayer ps id)) ornt          

---- Funções da 2ª Fase ----

homePacman :: Player -> State -> [Player]

homePacman player (State m players level)            = returnPacmanHome (getPlayerID player) (beginhome m) players

returnPacmanHome :: Int -> Coords -> [Player] -> [Player] 

returnPacmanHome id home (player:t)
              | getPlayerID player == id             = ((setPlayerCoords player home) : t) 
              | otherwise                            = player : returnPacmanHome id home t

eatPacman :: State -> Play -> Int -> State

eatPacman (State m players level) (Move id ornt) idP = State m (homePacman (draftplayer players idP) (State m players level)) level


getsEaten :: State -> Play -> State

getsEaten (State m players level) (Move id ornt) = State m (homeGhost (draftplayer players id) (State m players level)) level

