drawState :: (State,[Picture]) -> (Int,Int) -> [Picture]

drawState ((State m ps l),pics) (x,y) = (drawMap (playermaze,pics) (x,y)) ++ [drawPontuation (getPacman ps)]
           where playermaze = placePlayersOnMap ps m

drawMap :: (Maze,[Picture]) -> (Int,Int) -> [Picture]
drawMap ([],_) _ = []
drawMap ((h:t),pics) (x,y) = (Translate 0 (fromIntegral(y*(-85))) (Pictures (drawLine (h,pics) x))):(drawMap (t,pics) (x,y+1))

drawLine :: ([Piece],[Picture]) -> Int -> [Picture]
drawLine ([],_) _ = []
drawLine ((h:t),pics) x = (Translate (fromIntegral(x*85)) 0 (pieceToPic (h,pics))):(drawLine (t,pics) (x+1))

stateDrawPic :: [Picture] -> Picture
stateDrawPic pics = translate (-230) 234 (scale 0.1 0.1 (pictures (drawState (statelv1,pics) (homecoords (maze statelv1)))))

drawPontuation :: Player -> Picture

-- Falta adicionar um translate probably

drawPontuation player = text string 
        where string = stringpontuation player

stringpontuation :: Player -> String
 
stringpontuation player = "ID: " ++ (show id) ++ "\nPontuation: " ++ (show points) ++ "\nLives: " ++ (show lives) 
        where   points  = getPlayerPoints player
                lives   = getPlayerlife player
                id      = getPlayerID player    



