changeSpace (EventKey (SpecialKey KeyUp)  Down _ _ )     (Space (MiniGames GMM) GoMenu _ _ _) = (Space (MiniGames Portal) GoMenu statelv1 0 0)
changeSpace _                                            (Space (MiniGames GMM) GoMenu _ _ _) = (Space (MiniGames GMM) GoMenu statelv1 0 0)



















loadManager :: Manager
loadManager = ( Manager (loadMaze "maps/5.txt") 0 0 0 0 defaultDelayTime )

updateControlledPlayer :: Key -> Manager -> Manager

updateControlledPlayer KeyLeftArrow man   =   rotatePlayer (Move (pid man) L) man 
updateControlledPlayer KeyRightArrow man  =   rotatePlayer (Move (pid man) R) man
updateControlledPlayer KeyUpArrow man     =   rotatePlayer (Move (pid man) U) man
updateControlledPlayer KeyDownArrow man   =   rotatePlayer (Move (pid man) D) man


rotatePlayer :: Play -> Manager -> Manager

rotatePlayer play (Manager st pid step now delta delay) = 
          Manager (State (maze st) (changedir (playersState st) play) (level st)) pid step now delta delay


updateScreen :: Window  -> ColorID -> Manager -> Curses ()
updateScreen w a man =
                  do
                      updateWindow w $ do
                        --clear
                        setColor a
                        moveCursor 0 0 
                        drawString $ show (state man)
                      render
     
currentTime :: IO Integer
currentTime = fmap ( round . (* 1000) ) getPOSIXTime

updateTime :: Integer -> Manager -> Manager
updateTime now (Manager st pid step b d delay) = Manager st pid step now delta delay   
                                                  where delta = d + now - b 

resetTimer :: Integer -> Manager -> Manager
resetTimer now (Manager st pid step b d delay) = Manager st pid step now 0 delay   
                                                   
nextFrame :: Integer -> Manager -> Manager
nextFrame now (Manager st pid step b d delay) = resetTimer now (Manager (passTime step st) pid (step+1) b d delay)  


loop :: Window -> Manager -> Curses ()
loop w man@(Manager s pid step bf delt del ) = do 
  color_schema <- newColorID ColorWhite ColorBlack 10
  now <- liftIO  currentTime
  updateScreen w  color_schema man
  if ( delt > del )
    then loop w $ nextFrame now man
    else do
          ev <- getEvent w $ Just 0
          case ev of
                Nothing -> loop w (updateTime now man)
                Just (EventSpecialKey arrow ) -> loop w $ updateControlledPlayer arrow (updateTime now man)
                Just ev' ->
                  if (ev' == EventCharacter 'q')
                    then return ()
                    else loop w (updateTime now man)


main :: IO ()
main =
  runCurses $ do
    setEcho False
    setCursorMode CursorInvisible
    w <- defaultWindow
    loop w loadManager

