getTimeMega :: Player -> Double 
getTimeMega (Pacman (PacState (x,y,z,t,h,l) q c d )) = q
getTimeMega  (Ghost (GhoState (x,y,z,t,h,l) q )) = 0

getPlayerID :: Player -> Int
