{- | 

= Introdução

Nesta Tarefa, o objetivo foi criar um /bot/ que fosse o mais eficiente possível a obter pontos.

= Desenvolvimento

Para que o /bot/ se adaptasse a cada situação do jogo, criamos três modos diferentes que ele pode adotar:

 * Escape Mode: quando existem /Ghosts/ próximos do /bot/, este vai se mover de forma a aumentar a distância entre ele e os /Ghosts/.

 * Chase Mode: quando o /bot/ encontra uma /Food Big/, começa a perseguir um dos /Ghosts/ até o conseguir comer.

 * Look For Food Mode: quando nenhumas das condições que invocam os modos acimas são satisfeitas, o /bot/ apenas procura por /Foods/. 

= Conclusão

Consideramos que o /bot/, após comer o primeiro fantasma, devesse sair do Chase Mode uma vez que haver /Ghosts/ no modo /Alive/
o deixa vulnerável.

Esta Tarefa, apesar de exigir bastantes testes, não revelou muita dificuldade ao grupo, uma vez que já tinhamos entendido a lógica
da Tarefa 5. 

-} 

{-# OPTIONS_HADDOCK prune #-}



-- | Dado uma lista de /Players/, devolve as coordenadas de todos os /Ghosts/.
ghostCoords :: [Player] -> [Coords]
ghostCoords [] = []
ghostCoords (x:xs) = if ghostORPacmanvalor x == 1 
                     then getPlayerCoords x : ghostCoords xs 
                     else ghostCoords xs 

biggestDistAux :: [(Coords,Coords)] -> Coords
biggestDistAux [(a,b)] = a
biggestDistAux ((a,b):(c,d):xs) = if dist a b < dist c d 
                                  then biggestDistAux ((c,d):xs)
                                  else biggestDistAux ((a,b):xs)

-- | Ao contrário da função __smallerDist__ (Tarefa 4), esta função calcula a coordenada para o qual o /bot/
-- se deverá mover para aumentar a distância aos adversários.
biggestDist :: [Coords] -> [Coords] -> Coords
biggestDist choices pacs = biggestDistAux (allOptions choices pacs) 

-- | Função responsável pelo Escape Mode. 

-- | Determinada a /Play/ que o /bot/ terá que executar para aumentar a distância aos /Ghosts/.
escapeGhostsMode :: Int -> State -> Maybe Play 
escapeGhostsMode id st@(State maze players level)  
    | choices (x,y) maze == [] = Nothing
    | ch == [] = Just $ Move id $ downs orPac
    | biggestDist ch ghos == (x-1,y) = Just $ Move id U 
    | biggestDist ch ghos == (x+1,y) = Just $ Move id D 
    | biggestDist ch ghos == (x,y-1) = Just $ Move id L 
    | biggestDist ch ghos == (x,y+1) = Just $ Move id R 
    | otherwise = Just $ Move id orPac 
   where ch =  {- filter (/= coordback pac) $ -} choices (x,y) maze 
         (x,y) = getPlayerCoords pac
         ghos = map getPlayerCoords $ rmPacmans players  
         pac = encID id players
         orPac = getPlayerOrientation pac

-- | Função responsável pelo Chase Mode.

-- | Usa a função __smallerDist__ da Tarefa 4 como auxiliar para determinar que /Play/ o /bot/ terá de executar para 
-- que diminua a sua distância aos /Ghosts/.
chaseGhostsMode :: Int -> State -> Maybe Play 
chaseGhostsMode id st@(State maze players level)  
    | choices (x,y) maze == [] = Nothing
    | ch == [] = Just $ Move id (downs orPac)
    | smallerDist ch pacs == (x-1,y) = Just $ Move id U 
    | smallerDist ch pacs == (x+1,y) = Just $ Move id D 
    | smallerDist ch pacs == (x,y-1) = Just $ Move id L 
    | smallerDist ch pacs == (x,y+1) = Just $ Move id R 
    | otherwise = Just $ Move id orPac 
   where ch = filter (/= coordback pac) $ choices (x,y) maze 
         (x,y) = getPlayerCoords pac
         pacs = ghostCoords players  
         pac = encID id players
         orPac = getPlayerOrientation pac

coordsWithFoodAux :: Maze -> [Coords] -> [Coords]
coordsWithFoodAux _ [] = []
coordsWithFoodAux m (x:xs) = if revealPiece x m == Food Big || revealPiece x m == Food Little 
                             then x : coordsWithFoodAux m xs 
                             else coordsWithFoodAux m xs
                             
corridorToCoords :: Int -> Corridor -> [Coords]
corridorToCoords line c = [(line,s) | s <- [0..((length c)-1)]]

-- | Dado um /Maze/, calcula todas as coordenadas que lhe pertencem (Esta função recebe um acumulador que deverá ser colocado a 0).
mazeToCoords :: Int -> Maze -> [Coords]
mazeToCoords _ [] = []
mazeToCoords ac (x:xs) = (corridorToCoords ac x) ++ mazeToCoords (ac+1) xs

-- | Dado um /Maze/, determina a lista de coordenadas que contêm /Foods/ usando a função anterior como auxiliar. 
coordsWithFood :: Maze -> [Coords]
coordsWithFood m = coordsWithFoodAux m $ mazeToCoords 0 m

-- | Função que representa o Look For Food Mode. 

-- | Esta função usa também a função __smallerDist__ (Tarefa 4) para determinar a /Play/ que deverá executar para minimizar a distância às /Foods/. 
lookForFoodMode :: Int -> State -> Maybe Play 
lookForFoodMode id st@(State maze players lvl)  
    | choices (x,y) maze == [] = Nothing
    | ch == [] = Just $ Move id (downs orPac)
    | smallerDist ch foods == (x-1,y) = Just $ Move id U 
    | smallerDist ch foods == (x+1,y) = Just $ Move id D 
    | smallerDist ch foods == (x,y-1) = Just $ Move id L 
    | smallerDist ch foods == (x,y+1) = Just $ Move id R 
    | otherwise = Just $ Move id orPac
   where ch = filter (/= coordback pac) $ choices (x,y) maze 
         (x,y) = getPlayerCoords pac
         foods = coordsWithFood maze  
         pac = encID id players
         orPac = getPlayerOrientation pac

-- | Dada uma coordenada, devolve uma lista de coordenadas que constituem um "bloco" 5 por 5 em que o centro é a coordenada de input.
coordsProx :: Coords -> [Coords]
coordsProx (a,b) = [(c,d) | c <- [a-4..a+4] , d <- [b-4..b+4]]

-- | Determina se pertencem /Ghosts/ às coordenadas próximas do /bot/ usando a função __coordsProx__ como auxiliar.
elemGhostProx :: Coords -> [Player] -> Bool 
elemGhostProx _ [] = False 
elemGhostProx coordPac (x:xs) = if elem (getPlayerCoords x) proxPac 
                                then True 
                                else elemGhostProx coordPac xs
      where proxPac = coordsProx coordPac 

numberOfFoodsCorridor :: Corridor -> Int 
numberOfFoodsCorridor [] = 0 
numberOfFoodsCorridor (x:xs) = if x == Food Little || x == Food Big
                               then 1 + numberOfFoodsCorridor xs 
                               else numberOfFoodsCorridor xs 

-- | Calcula o número de /Foods/ de um /Maze/.
numberOfFoodsMaze :: Maze -> Int 
numberOfFoodsMaze m = sum $ map numberOfFoodsCorridor m 

-- | Testa se, num /Maze, existe apenas uma /Food/ (ou zero).
thereIsOneFood :: Maze -> Bool 
thereIsOneFood m = numberOfFoodsMaze m <= 1 

-- | Esta é a função objetivo desta Tarefa.

-- | A função __bot__ compila todos os modos de agir do Pacman com as suas restrições. Uma vez que, no nosso MiniGame, __KillPacman__, havia dois Pacmans, 
-- então, quando um deles comia a última /Food/ e o outro não recebia coordenadas algumas sobre posições de /Foods/, o que constituia uma excessão.
-- Para dar a volta a esse problema, adicionamos a restrição no __bot__ para que, quando sobra apenas uma /Food/, a função retorna __Nothing__. 
bot :: Int -> State -> Maybe Play
bot id st@(State maze players lvl)
      | thereIsOneFood maze = Nothing
      | elem Alive ghoModes && elemGhostProx paccoord (rmPacmans players) = escapeGhostsMode id st
      | ghoModes == replicate (length ghoModes) Dead = chaseGhostsMode id st
      | otherwise = lookForFoodMode id st
   where ghosmorecl = rmPacmans players  
         ghoModes = map getGhostMode ghosmorecl 
         paccoord = getPlayerCoords $ encID id players
         ghocoords = map getPlayerCoords ghosmorecl

-- | Para que pudessemos utilizar a função __bot__ no __passTime__ da Tarefa 4, tivemos que criar uma função que convertesse __Maybe Play__ para __Play__

-- | No caso da função __bot__ devolver __Nothing__, a função  __botMaybeToPlay__ devolve __Move id Null__, sendo __id__ o ID do /bot/.
botMaybeToPlay :: Int -> State -> Play 
botMaybeToPlay id st = case (bot id st) of 
                          Just p -> p 
                          Nothing -> Move id Null
{- |

= Introdução 

O objetivo desta tarefa foi fazer com os /Ghosts/ se movimentassem pelo /Maze/ de forma independente do utilizador e que perseguissem o(s) Pacman(s). 

= Desenvolvimento 

Para implementar este /bot/ usamos quatro maneiras distintas para o /Ghost/ agir: 

 * Chase Mode: sempre que o fantasma está em modo Alive e a mais de quatro peças de distância de todos os Pacmans, este decide a jogada que deve 
   executar quando à sua fente (seguinto a sua orientação) se encontra uma /Wall/. Para isto, calcula a distância entre todas as opções aos Pacmans
   pela métrica de Manhattan, sendo que só reccore à orientação oposta se não houver qualquer outra opção.

 * Chase Mode "four or less": Ao contrário do anterior, este modo é aplicado a cada instante do jogo quando o /Ghost/ está
   próximo de um Pacman. A sua funcionalidade é aumentar a eficácia do /Ghost/ e impedir situações em que o /Ghost/ se movia 
   próximo ao Pacman e não ia ao encontro do mesmo.

 * Scatter Mode: Este modo de agir, invocado quando o /Ghost/ passa para modo /Dead/, faz com que o mesmo, ao encontrar uma /Wall/, se mova para a 
   sua direita (relativa à orientação). Em alternativa, se a direita não constituir uma opção, o /Ghost/ pode virar-se para a esquerda relativa
   e, em último caso, para trás. O /bot/, quando se encontra em Scatter Mode, tende a rodear objetos no sentido horário, sendo este o efeito objetivo
   deste modo.

 * Leave Home: Para evitar que os /Ghosts/ fiquem dentro casa no início e decorrer do jogo, foi criado o modo Leave Home que faz com que eles se retirem
   da casa caso nao haja um /Ghost/ com maior ID dentro da mesma. Esta última condição faz com que saia um de cada vez e evita, na maior parte da vezes,
   que dois /Ghosts/ fiquem na mesma coordenada.    

= Conclusão 

Esta Tarefa exigiu bastantes testes para perceber qual seria a melhor forma de cada /Ghost/ agir consoante as diversas situações em que se encontrava. 
Após resolver todos os pequenos problemas que foram surgindo no decorrer do desenvolvimento desta /bot/, pensamos ter atingido aquilo
que esperavamos.
-}

{-# OPTIONS_HADDOCK prune #-}



-- | Calcula todas as coordenadas vizinhas de uma determinada coordenada, isto é, as coordenadas que estão acima, abaixo, à direita e à esquerda dessa coordenada.
neighborhoodCoords :: Coords -> [Coords] 
neighborhoodCoords (x,y) = [(x+1,y),(x-1,y),(x,y+1),(x,y-1)]

-- | Dada uma coordenada, revela as peças que se encontram na sua vizinhança.
neighborhoodPieces :: Coords -> Maze -> [Piece]
neighborhoodPieces (x,y) maze = map (revealPieceReverse maze) (neighborhoodCoords (x,y))

-- | Dada uma lista de tuplos (/Coords/,/Piece/), remove os tuplos cuja segunda componente seja uma /Wall/.
rmWalls :: Maze -> [(Coords,Piece)] -> [(Coords,Piece)]
rmWalls _ [] = []
rmWalls m (x:xs) = if snd x == Wall || (elem (fst x) $ aberturaCasa m)  
                   then rmWalls m xs 
                   else x : rmWalls m xs  

-- | Usa todas as funções anteriores como auxiliares e, a partir de uma coordenada e um /Maze/, calcula a lista de coordenadas para o qual o /Player/
-- se pode movimentar.
choices :: Coords -> Maze -> [Coords]
choices (x,y) maze = map fst $ rmWalls maze $ zip (neighborhoodCoords (x,y)) (neighborhoodPieces (x,y) maze)

-- | Calcula distâncias entre coordenadas segundo a métrica de Manhattan.
dist :: Coords -> Coords -> Int 
dist (a,b) (c,d) = abs (a-c) + abs (b-d)

-- | Extrai as coordenadas dos Pacmans num determinado instante.
pacmansCoords :: [Player] -> [Coords]
pacmansCoords [] = []
pacmansCoords (x:xs) = if ghostORPacmanvalor x == 2 
                       then getPlayerCoords x : pacmansCoords xs 
                       else pacmansCoords xs 

-- | A partir das coordenadas possíveis do /bot/ e das coordenadas dos adversários, calcula a lista de possibilidades como tuplos constituidos
-- por uma determinada opção do /bot/ e a coordenada de um adversário.
allOptions :: [Coords] -> [Coords] -> [(Coords,Coords)]
allOptions choices pacs = [(a,b) | a <- choices, b <- pacs]  

smallerDistAux :: [(Coords,Coords)] -> Coords
smallerDistAux [(a,b)] = a
smallerDistAux ((a,b):(c,d):xs) = if dist a b > dist c d 
                                  then smallerDistAux ((c,d):xs)
                                  else smallerDistAux ((a,b):xs)

-- | Recebe dois conjuntos de /Coords/ como input (que representam as opções do /bot/ e as coordenadas
-- dos adversários) e seleciona a opção do /bot/ que lhe permite ficar mais próximo ao adversário.
smallerDist :: [Coords] -> [Coords] -> Coords
smallerDist choices pacs = smallerDistAux (allOptions choices pacs) 

-- | Esta função testa se a coordenada seguinte do /bot/ (considerando a sua orientação) tem uma /Wall/ ou pertence 
-- ao conjunto de coordenadas da abertura da casa. Em caso afirmativo, move-se para outra direção de forma a ficar mais próximo ao adversário (usando a __smallerDist__ como auxiliar).
-- Caso não se verifique essa condição, continua a mover-se de acordo com a sua orientação.
chaseMode :: State -> Int -> Play 
chaseMode st@(State maze players level) id 
    | ch == [] = Move id Null
    | (condition1 || condition2) && smallerDist ch pacs == (x-1,y) = Move id U 
    | (condition1 || condition2) && smallerDist ch pacs == (x+1,y) = Move id D 
    | (condition1 || condition2) && smallerDist ch pacs == (x,y-1) = Move id L 
    | (condition1 || condition2) && smallerDist ch pacs == (x,y+1) = Move id R 
    | otherwise = Move id orGho 
   where ch = choices (x,y) maze 
         (x,y) = getPlayerCoords plgho
         pacs = pacmansCoords players  
         plgho = encID id players
         orGho = getPlayerOrientation plgho
         condition1 = revealPieceOr (Move id orGho) st == Wall
         condition2 = elem (movimento (x,y) orGho) (aberturaCasa maze)

-- | A estruta desta função é semelhante à anterior, porém, não existem restrições quando à informação próxima /Piece/. Como tal, o /Ghost/
-- fica mais eficiente quando estiver próximo do seu alvo. 
chaseMode4orless :: State -> Int -> Play 
chaseMode4orless st@(State maze players level) id 
    | choices (x,y) maze == [] = Move id Null
    | ch == [] = Move id (downs orGho)
    | smallerDist ch pacs == (x-1,y) = Move id U 
    | smallerDist ch pacs == (x+1,y) = Move id D 
    | smallerDist ch pacs == (x,y-1) = Move id L 
    | smallerDist ch pacs == (x,y+1) = Move id R 
    | otherwise = Move id orGho 
   where ch = filter (/= coordback plgho) $ choices (x,y) maze 
         (x,y) = getPlayerCoords plgho
         pacs = pacmansCoords players  
         plgho = encID id players
         orGho = getPlayerOrientation plgho

-- | Calcula a coordenada atrás do /Player/ relativamente à sua orientação.
coordback :: Player -> Coords 
coordback p 
   | orI == U = (x+1,y)
   | orI == D = (x-1,y)
   | orI == R = (x,y-1)
   | orI == L = (x,y+1)
   | orI == Null = (x,y)
       where (x,y) = getPlayerCoords p 
             orI = getPlayerOrientation p  

-- | Calcula a direita relativa do /Player/.
rights :: Orientation -> Orientation 
rights R = D 
rights L = U 
rights U = R 
rights D = L 
rights Null = Null

-- | Calcula a esquerda relativa do /Player.
lefts :: Orientation -> Orientation 
lefts R = U 
lefts L = D 
lefts U = L 
lefts D = R 
lefts Null = Null

-- | Compila as funções anteriores e a função __downs__ (Tarefa 2) para calcular a orientação relativa de um /Player/, dada uma orientação (orientação relativa que
-- queremos determinar) e um /Player/.
relativeOr :: Orientation -> Player -> Play 
relativeOr or p 
    | or == R = Move id $ rights orI  
    | or == L = Move id $ lefts orI 
    | or == D = Move id $ downs orI
       where orI = getPlayerOrientation p
             id = getPlayerID p

-- | Esta função cria um modo de se movimentar de forma a que, cada vez que o /bot/ se depare com uma parede, se mova para a direita (caso esta não contenha 
-- também uma parede, nesse caso, escolherá a esquerda relativa ou voltar para trás, por esta ordem).
scatterMode :: State -> Int -> Play
scatterMode st@(State maze players lvl) id 
     | revealPieceOr (Move id orI) st /= Wall = Move id orI 
     | revealPieceOr (relativeOr R gho) st /= Wall = relativeOr R gho
     | revealPieceOr (relativeOr L gho) st /= Wall = relativeOr L gho
     | revealPieceOr (relativeOr D gho) st /= Wall = relativeOr D gho
     | otherwise = Move id Null 
    where gho = encID id players
          orI = getPlayerOrientation gho 

-- | Dado um /Maze/, calcula a lista de coordenadas que constituem a casa dos fantasmas e a sua abertura.
homeCoords :: Maze -> [Coords]  
homeCoords m = if even y 
               then aberturaCasa m ++ zip (repeat (a+1)) [ym-3,ym-2,ym,ym,ym+1,ym+2]
               else aberturaCasa m ++ zip (repeat (a+1)) [ym-3,ym-2,ym-1,ym,ym+1,ym+2,ym+3]
      where (a,b) = (aberturaCasa m)!!1 
            x = length m 
            y = length $ head m
            ym = div y 2 

-- | Recebe um /Maze/ e uma lista de /Players/ e testa se algum deles está dentro da casa dos fantasmas.
insideHome :: Maze -> [Player] -> Bool 
insideHome _ [] = False 
insideHome m (x:xs) = if elem (getPlayerCoords x) $ homeCoords m
                      then True 
                      else insideHome m xs   

-- | A partir de um /Int/ (que representa um ID) e uma lista de /Players/, devolve uma lista com todos os /Players/ que têm ID superior ao 
-- valor fornecido como primeiro argumento. No caso de não existirem /Players/ com essa condição, devolve a lista vazia. 
ghoMaiorID :: Int -> [Player] -> [Player]
ghoMaiorID _ [] = []
ghoMaiorID id (x:xs) = if getPlayerID x > id 
                       then x : ghoMaiorID id xs 
                       else ghoMaiorID id xs 

leaveHomeOnePlayer :: Player -> Maze -> Play 
leaveHomeOnePlayer (Ghost (GhoState (i,(x,y),v,o,xp,hp) mode)) maze 
   | revealPiece (x-1,y) maze == Empty = Move i U 
   | elem (x-1,y+1) (aberturaCasa maze) || elem (x-1,y+2) (aberturaCasa maze) = Move i R 
   | elem (x-1,y-1) (aberturaCasa maze) || elem (x-1,y-2) (aberturaCasa maze) = Move i L

-- | Recebe um /State/ e um valor /Int/ e testa se existe /Ghost/ com ID maior do que o valor so segundo argumento.
-- No caso de não se verificar a condição, o /bot/ que tem como ID o segundo argumento move-se de forma a sair da casa dos fantasmas.
-- Pelo contrário, se a condição se verificar, o /bot/ em questão relaliza apenas a /Play/ "Move id Null" (sendo "id", o ID do /bot/), não se movendo.
leaveHome :: State -> Int -> Play 
leaveHome (State maze players level) id = if insideHome maze ghosmaiorID
                                          then Move id Null 
                                          else leaveHomeOnePlayer (encID id players) maze
              where ghosmaiorID = ghoMaiorID id $ rmPacmans players  

-- | Calcula a distância entre o /bot/ e o adversário mais próximo dele.
minDist :: Coords -> [Coords] -> Int 
minDist coord pacs = dist coord (pacmorecloser coord pacs)
    where pacmorecloser _ [c] = c 
          pacmorecloser coord (c1:c2:cs) = if dist c1 coord > dist c2 coord 
                                           then pacmorecloser coord (c2:cs)
                                           else pacmorecloser coord (c1:cs) 

-- | Dado um /State/ e um /Int/ calcula a /Play/ que o /bot/ cujo ID coincide com o segundo argumento deve realizar, tendo em conta todos os modos 
-- de se comportar acima descritos.
ghostPlayOnePlayer :: State -> Int -> Play  
ghostPlayOnePlayer st@(State maze players level) id  
      | elem (getPlayerCoords plgho) hCoords = leaveHome st id 
      | getPlayerOrientation plgho == Null = Move id D
      | getGhostMode plgho == Alive && minDist coord paccoords <= 4 = chaseMode4orless st id
      | getGhostMode plgho == Alive && id == 2 = chaseMode4orless st id -- isto aumenta a eficiencia no chase
      | getGhostMode plgho == Alive = chaseMode st id 
      | getGhostMode plgho == Dead = scatterMode st id 
    where plgho = encID id players 
          hCoords = homeCoords maze 
          paccoords = map getPlayerCoords $ rmGhosts players 
          coord = getPlayerCoords plgho

-- | Esta função tem a mesma estrura da função __ghostPlayOnePlayer__, porém, não usa usa o modo "Leave Home" para que o /bot/ se possa comportar em /Mazes/
-- que não têm a mesma estruta que os /Mazes/ da Tarefa 1.  
ghostPlayOnePlayerAnyMaps :: State -> Int -> Play 
ghostPlayOnePlayerAnyMaps st@(State maze players level) id  
      | getGhostMode plgho == Alive && minDist coord paccoords <= 4 = chaseMode4orless st id
      | getGhostMode plgho == Alive && id == 2 = chaseMode4orless st id 
      | getGhostMode plgho == Alive = chaseMode st id 
      | getGhostMode plgho == Dead = scatterMode st id 
    where plgho = encID id players 
          hCoords = homeCoords maze 
          paccoords = map getPlayerCoords $ rmGhosts players 
          coord = getPlayerCoords plgho

-- | Esta é a função objetivo da Tarefa 5 e calcula a lista de /Plays/ de todos os /Ghosts/ num determinado /State/.
ghostPlay :: State -> [Play]
ghostPlay st@(State maze players level) = map (ghostPlayOnePlayer st) ids 
      where ids = map getPlayerID (rmPacmans players) 
{- |

= Introdução 

Nesta Tarefa, o objetivo foi fazer com que todos os jogadores reagissem à passagem do tempo e executassem jogadas (definidas na Tarefa 2). 

= Desenvolvimento

Neste documento, para além das funções da Tarefa 4, estão também as funções do MiniGame __PacDungeon__ uma vez que este MiniGame usa funções da Tarefa 4 no seu /passTime/
e a Tarefa 4 passou também a envolver funções do miniGame para que o jogo funcionasse com todos os seus modos. Desta forma, como se criaria ciclo de /imports/ entre 
a Tarefa 4 e o __PacDungeon__, decidimos juntar o Minigame ao documento da Tarefa.

A Tarefa 4 foi progamada de forma a que o /Player/ a ser controlado se mova para a direção que consta na sua informação do /PalayerState/ uma casa (caso tenha velocidade de
de uma jogada por iteração) e os restantes ajam como predefinido nas Tarefas seguintes (/bots/).

Esta Tarefa revelou-se desafiadora pois exigiu de nós uma maior capacidade para pensar sobre os tempos e velocidades e como usar todas essas variáveis para
chegar à resolução do problema, no caso, a passagem do tempo. 

O __PacDungeon__ foi um dos MiniGames que o grupo planeava e tencionava fazer. O seu objetivo é comer todas as comidas do mapa e salvar o Pacman preso entre /Walls/ num mapa
com outros seis /Ghosts/ presos.
Para aumentar a dificuldade, a cada dez segundos (quatro iterações) novos /Ghosts/ são libertados, sendo que dentro do último conjunto de /Walls/ há uma
comida grande, o que torna impossível acabar o jogo antes de todos os fantasmas serem libertados.

O grupo concordou que, entre os dois, este era o MiniGame mais completo uma vez que tem o seu próprio /passTime/ e um /bot/.

= Conclusão 

Tanto a Tarefa 4 quanto o MiniGame tiveram os seus aspetos mais complicados mas tivemos sucesso em executar o que tinhamos em mente.

Esta Tarefa foi sendo atualizada a cada Tarefa posterior concluída e este é o resultado final:

-}

{-# OPTIONS_HADDOCK prune #-}



defaultDelayTime = 250 -- 250 ms

-- * Tarefa 4

-- | Dado um ID, remove um /Player/ de uma lista de /Players/.
rmPlayer :: Int -> [Player] -> [Player]
rmPlayer _ [] = []
rmPlayer id (x:xs) = if getPlayerID x == id 
                     then xs
                     else x : rmPlayer id xs

-- | Obtém o valor correspondente à velocidade do /Player/.
getPlayerSpeed :: Player -> Double 
getPlayerSpeed (Pacman (PacState (x,y,z,t,h,l) q c d )) = z
getPlayerSpeed (Ghost (GhoState (x,y,z,t,h,l) q )) = z

-- | A partir de um /Double/ que representa a velocidade de um /Player/, produz um par de /Int/ que determinam o número de jogadas que esse /Player/ 
-- fará em cada iteração.
nPlayPerStep :: Double -- velocidade 
             -> (Int,Int) -- (jogadas em step par, jogadas em step impar)
nPlayPerStep 0 = (0,0)             
nPlayPerStep 0.5 = (1,0)
nPlayPerStep 1 = (1,1)
nPlayPerStep 1.5 = (2,1)
nPlayPerStep 2 = (2,2) 

-- | Testa se não existe qualquer tipo de comida no /Maze/.
cleanedMaze :: Maze -> Bool 
cleanedMaze maze = and $ map cleanedLine maze

cleanedLine :: Corridor -> Bool 
cleanedLine [] = True 
cleanedLine (x:xs) = if x == Food Big || x == Food Little 
                     then False
                     else cleanedLine xs 
                                           
-- | Faz com que todos os /Ghosts/ fiquem em modo /Alive/ e com velocidade de 1.
backGhostToAlive :: [Player] -> [Player] 
backGhostToAlive [] = []
backGhostToAlive ((Ghost (GhoState (i,c,v,or,q,z) Dead)):xs) = Ghost (GhoState (i,c,1,or,q,z) Alive) : backGhostToAlive xs 
backGhostToAlive (x:xs) = x : backGhostToAlive xs

lostTimeMegaOnePlayer :: Double -> Player -> Player 
lostTimeMegaOnePlayer x (Pacman (PacState (i,(x1,y), v, o, p, l) tM mo Mega)) = if x < tM  
                                                                                then Pacman $ PacState (i,(x1,y), v, o, p, l) (tM - x) mo Mega 
                                                                                else Pacman $ PacState (i,(x1,y), 1, o, p, l) 0 mo Normal 
lostTimeMegaOnePlayer _ gho = gho

lostTimeMega :: Double -> [Player] -> [Player]
lostTimeMega _ [] = []
lostTimeMega x (p:ps) = if ghostORPacmanvalor p == 2 && getTimeMega p /= 0
                        then lostTimeMegaOnePlayer x p : lostTimeMega x ps 
                        else p : (lostTimeMega x ps)

-- | Regula todo o sistema de tempo do /Mega/ e modos dos /Players/ em função disso. Se um Pacman está em modo /Mega/, faz com que o mesmo
-- perca 250 unidades (ms) a cada iteração e quando não existem Pacmans no modo Mega, todos os /Ghosts/ passam para o modo /Alive/.                         
lostTimeMegaST :: State -> State 
lostTimeMegaST (State maze players level) = if elem Dead allGModes && timesMega == replicate (length timesMega) 0    
                                            then State maze (backGhostToAlive $ lostTimeMega 250 players) level 
                                            else State maze (lostTimeMega 250 players) level                                          
       where allGModes = map getGhostMode $ rmPacmans players
             allPModes = map getPacmanMode $ rmGhosts players 
             timesMega = map getTimeMega $ rmGhosts players 

-- | Função auxiliar do __passTime__ que aplica a função __play__ (Tarefa 2) ao /Player/ que o utilizador está a controlar.
passTimeOnePlayerPID :: Int -- ID 
                     -> Int -> State -> State 
passTimeOnePlayerPID _ 0 st = st                  
passTimeOnePlayerPID id nStep st@(State maze players level) = if even nStep 
                                                              then quickP evenStep id plOr st 
                                                              else quickP oddStep id plOr st
                                     where player = encID id players
                                           (evenStep,oddStep) = nPlayPerStep $ getPlayerSpeed player
                                           plOr = getPlayerOrientation player    

-- | Função auxiliar do __passTime__ que produz os movimentos dos /Ghosts/. Esta função recorre à função __ghostPlayOnePlayer__ da Tarefa 5.
passTimeOnePlayerBotGhost :: Int -> Int -> State -> State 
passTimeOnePlayerBotGhost _ 0 st = st
passTimeOnePlayerBotGhost id nStep st@(State maze players level) = if even nStep 
                                                                   then quickP evenStep id or st 
                                                                   else quickP oddStep id or st
                                     where player = encID id players
                                           (evenStep,oddStep) = nPlayPerStep $ getPlayerSpeed player
                                           (Move idGho or) = ghostPlayOnePlayer st id 

-- | Esta função determina as duas jogadas consecutivas do Pacman quando este se comporta como /bot/ e, em algumas iterações faz duas jogadas seguidas (quando 
-- se encontra no modo /Mega/).                                           
twoPlaysBotPac :: Int -> State -> State  
twoPlaysBotPac id st = play mov2 (play mov1 st)
           where mov1 = botMaybeToPlay id st 
                 futureSt = play mov1 st 
                 mov2 = botMaybeToPlay id futureSt   

-- | Função auxiliar do __passTime__ que usa a função __botMaybeToPlay__ da Tarefa 6 e a função __twoPlaysBotPac__ para movimentar o /bot/ Pacman.
passTimeOnePlayerBotPac :: Int -> Int -> State -> State 
passTimeOnePlayerBotPac _ 0 st = st
passTimeOnePlayerBotPac id nStep st@(State maze players level) 
    | even nStep && evenStep == 2 = twoPlaysBotPac id st 
    | even nStep = quickP evenStep id or st 
    | odd nStep && oddStep == 2 = twoPlaysBotPac id st 
    | otherwise = quickP oddStep id or st
   where player = encID id players
         (evenStep,oddStep) = nPlayPerStep $ getPlayerSpeed player
         (Move idPac or) = botMaybeToPlay id st

-- | Calcula, em função do PID e tipo de /Player/ (/Ghost/ ou Pacman), as ações de cada /Player/ numa determindada iteração. 
passTimeAux :: Int -> Int -> State -> [Int] -> State 
passTimeAux x pid st@(State maze players level) [] = st 
passTimeAux x pid st@(State maze players level) (id:ids) = if cleanedMaze maze 
                                                           then levelUp st maze1 
                                                           else if id == pid 
                                                                then passTimeAux x pid (passTimeOnePlayerPID id x st) ids
                                                                else if (ghostORPacmanvalor $ encID id players) == 1
                                                                     then passTimeAux x pid (passTimeOnePlayerBotGhost id x st) ids
                                                                     else passTimeAux x pid (passTimeOnePlayerBotPac id x st) ids 

pacsfst :: [Player] -> [Player]
pacsfst [] = []
pacsfst (x:xs) = if ghostORPacmanvalor x == 1 
                 then pacsfst xs ++ [x]
                 else x : pacsfst xs

-- | Recebe a função anterior para completar, desta forma, a Tarefa 4 e ainda é utilizada uma condição para poder usar o __passTime__ no MiniGame __PacDungeon__, uma vez
-- que a interface do jogo completo podia apenas ter um tipo de __passTime__. 
passTime :: Int -> Int -> State -> State
passTime x pid st@(State maze players level) = if (length maze) == 23
                                               then passTimePacDungeon x pid st 
                                               else lostTimeMegaST $ passTimeAux x pid (State maze (pacsfst players) level) ids
        where ids = map getPlayerID $ pacsfst players 

