-- Verifica se algum jogador vai para determinada coordenada; será usada para verificar se o pacman encontra algum fantasma
isGhost2 :: [Player] -> Play -> Bool
isGhost2 (_:[]) _ = False
isGhost2 [] _ = False
isGhost2 (h:t) (Move id ori)  
  | getPlayerCoords k == coord = True
  | otherwise = isGhost2 ks (Move id ori) 
    where coord = (getPlayerCoords (whereTo2 (last ks) ori))
          (k:ks) = (dropPlayer) ++ (searchPlayer (noClone (h:t)) id)
          dropPlayer = filter (\x -> getPlayerID x /= getPlayerID k) (h:t)

-- Dado o identificador de um jogador e um estado do jogo, devolve uma possível jogada a realizar pelo robô
bot :: Int -> State -> Maybe Play
bot id (State m js n) 
  | (getGhostMode (getGhost js) == Alive) && goodPlay (State m js n) play1 == True = Just play1
  | (getGhostMode (getGhost js) == Dead)  && goodPlay (State m js n) play2 == True = Just play2
  | otherwise = Nothing
    where play1 = (restricoesFuga id (State m js n))
          play2 = (restricoesPers id (State m js n))

-- Esta função testa se uma dada jogada é válida, ou seja, se impede o Pacman de encontrar uma parede.
goodPlay :: State -> Play -> Bool
goodPlay (State m js n) (Move id ori) = v /= Wall 
   where v = coordToPiece m c
         c = getPlayerCoords (whereTo2 (head (searchPlayer js id)) ori )

-- Gera uma jogada que torna a distância entre o Pacman e um Ghost maior
restricoesFuga :: Int -> State -> Play
restricoesFuga id (State m js n)
  | (dist coordG coordP) < (dist coordG (y1+1,x1)) = (Move id D)
  | (dist coordG coordP) < (dist coordG (y1-1,x1)) = (Move id U)
  | (dist coordG coordP) < (dist coordG (y1,x1+1)) = (Move id R)
  | (dist coordG coordP) < (dist coordG  (y1,x1-1)) = (Move id L)
  | otherwise = (Move id ori)
    where coordP = getPlayerCoords (getPacman js)
          coordG = getPlayerCoords (getGhost js)
          (y1,x1) = coordP
          ori = getPlayerOrientation (head (searchPlayer js id))

-- Gera uma jogada que torna a distância entre o Pacman e um Ghost menor
restricoesPers :: Int -> State -> Play
restricoesPers id (State m js n)
  | (dist coordG coordP) > (dist coordG (y1+1,x1)) = (Move id D)
  | (dist coordG coordP) > (dist coordG (y1-1,x1)) = (Move id U)
  | (dist coordG coordP) > (dist coordG (y1,x1+1)) = (Move id R)
  | (dist coordG coordP) < (dist coordG  (y1,x1-1)) = (Move id L)
  | otherwise = (Move id ori)
    where coordP = getPlayerCoords (getPacman js)
          coordG = getPlayerCoords (getGhost js)
          (y1,x1) = coordP
          ori = getPlayerOrientation (head (searchPlayer js id))

-- Dadas duas coordenadas devolve um inteiro que corresponde à distância entre ambas as coordenadas
dist :: Coords -> Coords -> Int
dist (x1,y1) (x2,y2) 
  | ((x1-x2) >= 0) && ((y1-y2) >= 0) = (x1-x2) + (y1-y2)
  | ((x1-x2) <= 0 ) && ((y1-y2) >= 0) = ((-1) * (x1-x2)) + (y1-y2)
  | ((x1-x2) >= 0 ) && ((y1-y2) <= 0) = (x1-x2) + ((-1) * (y1-y2))
  | ((x1-x2) <= 0 ) && ((y1-y2) <= 0) = ((-1) * (x1-x2)) + ((-1) * (y1-y2))
  | otherwise = 0 
{- | 

=Introdução 

Nesta tarefa, primeiro tivemos que implementar a biblioteca ncurses para monitorar a 
passagem de tempo no jogo e reagir devidamente aos eventos de pressionamento
 de teclas por parte do utilizador. De seguida, tendo em conta o seu estado e 
 velocidade fizemos funções para movimentar os jogadores.

=Objetivos 
 
O nosso maior objetivo nesta tarefa foi calcular o efeito da passagem de 
um instante de tempo num estado do jogo, isto é, relacionar o tempo com a mudança
de estado.
Determinar um tempo Mega para quando o Pacman quando se encontra em modo Mega,e 
fazer com que ele perca uma parte desse tempo a cada jogada e no fim de um numero
de jogadas volte ao modo normal 
Fazer com que o Pacman tenha um movimento alternado entre cada jogada onde abre e fecha a boca.
Permitir efetuar N jogadas em cada iteração da função, em que N é um número inteiro inferido a partir da velocidade do jogador e paridade da iteração (step) da jogada. Ou seja:
Se um jogador tiver velocidade 0.5, avança de 2 em s iterações; 
Se um jogador tiver velocidade 1.5, avança 3 jogadas a cada 2 iterações;
Se um jogador tiver velocidade 1, deve progredir apenas 1 jogada em cada iteração.

-}



defaultDelayTime = 250

-- A função vai receber cada um dos jogadores de uma lista e irá atribuir a respetiva jogada
doPlay :: Int -> State -> Player -> [(Int,Play)] 
doPlay step (State m ps l) h 
  | vel == 0.5 && mod step 2 == 0 = [(1,(Move id ori))]   
  | vel == 1 = [(1,(Move id ori))]   
  | vel == 1.5 && mod step 2 == 0 = [(1,(Move id ori))]   
  | vel == 1.5 && mod step 2 == 1 = [(2,(Move id ori))]
  | otherwise = [(0,(Move id ori))]
    where vel = getPlayerVelo h 
          id = getPlayerID h
          ori = getPlayerOrientation h

-- Vai buscar as jogadas todas de um State
getPlays :: Int -> State -> [Player] -> [(Int,Play)] 
getPlays _ _ [] = []
getPlays step (State m ps l) (h:t) = doPlay step (State m ps l) h ++ getPlays step (State m ps l) t 

-- Atualiza um estado perante um conjunto de jogadas. Aqui é que irá acontecer a atribuição de várias jogadas ao jogador, de acordo com o Int que recebe
updateState :: [(Int,Play)] -> State -> State
updateState [] s = s 
updateState ((h,t):ts) s = updateState ts (auxUpdateState (h,t) s)

-- Atualiza um estado perante uma jogada
auxUpdateState :: (Int,Play) -> State -> State
auxUpdateState (num,jogada) s
  | num == 0 = s
  | num == 1 = s1
  | num == 2 = play jogada s1 
    where s1 = play jogada s

-- Atualiza um estado perante um conjuntos de jogadas sendo estas correspondentes aos fantasmas
updateStateGhost :: [Play] -> State -> State
updateStateGhost [] s = s
updateStateGhost (h:t) s = updateStateGhost t (auxUpdateStateGhost h s) 

-- Atualiza um estado perante uma jogada de um fantasma
auxUpdateStateGhost :: Play -> State -> State
auxUpdateStateGhost jogada s = play jogada s 

-- Função que controla a boca do Pacman
ocMouth :: Player -> Player
ocMouth (Ghost a) = Ghost a
ocMouth (Pacman (PacState (id,c,v,o,p,l) d m pM)) = if m == Open
                                                    then (Pacman (PacState (id,c,v,o,p,l) d Closed pM))
                                                    else (Pacman (PacState (id,c,v,o,p,l) d Open pM))


-- Função que manipula o tempo Mega e que fica responsável pelas respetivas consequências
looseTimeMega :: Double -> [Player] -> [Player]
looseTimeMega _ [] = []
looseTimeMega t (x:xs) 
  | t <= 0 = (setPacmanMode (ocMouth x) Normal) : setGhostMode2 xs Alive
  | otherwise = looseTimeMega (t-250) (x:xs)

-- Função que para um dado step e estado, altera o estado do jogo em uma iteração
passTime :: Int  -> State -> State  
passTime step (State m ps l) = updateStateGhost (ghostPlay (State m ps l)) (updateState jogadas (State m (looseTimeMega timeMega ps) l))
  where jogadas = getPlays step (State m ps l) ps
        timeMega = getTimeMega (getPacman ps) 
{- | 

=Introdução 

Nesta tarefa, primeiro tivemos que implementar a biblioteca ncurses para monitorar a 
passagem de tempo no jogo e reagir devidamente aos eventos de pressionamento
 de teclas por parte do utilizador. De seguida, tendo em conta o seu estado e 
 velocidade fizemos funções para movimentar os jogadores.

=Objetivos 
 
O nosso maior objetivo nesta tarefa foi calcular o efeito da passagem de 
um instante de tempo num estado do jogo, isto é, relacionar o tempo com a mudança
de estado.
Determinar um tempo Mega para quando o Pacman quando se encontra em modo Mega,e 
fazer com que ele perca uma parte desse tempo a cada jogada e no fim de um numero
de jogadas volte ao modo normal 
Fazer com que o Pacman tenha um movimento alternado entre cada jogada onde abre e fecha a boca.
Permitir efetuar N jogadas em cada iteração da função, em que N é um número inteiro inferido a partir da velocidade do jogador e paridade da iteração (step) da jogada. Ou seja:
Se um jogador tiver velocidade 0.5, avança de 2 em s iterações; 
Se um jogador tiver velocidade 1.5, avança 3 jogadas a cada 2 iterações;
Se um jogador tiver velocidade 1, deve progredir apenas 1 jogada em cada iteração.

-}



defaultDelayTime = 250

-- A função vai receber cada um dos jogadores de uma lista e irá atribuir a respetiva jogada
doPlay :: Int -> State -> Player -> [(Int,Play)] 
doPlay step (State m ps l) h 
  | vel == 0.5 && mod step 2 == 0 = [(1,(Move id ori))]   
  | vel == 1 = [(1,(Move id ori))]   
  | vel == 1.5 && mod step 2 == 0 = [(1,(Move id ori))]   
  | vel == 1.5 && mod step 2 == 1 = [(2,(Move id ori))]
  | otherwise = [(0,(Move id ori))]
    where vel = getPlayerVelo h 
          id = getPlayerID h
          ori = getPlayerOrientation h

-- Vai buscar as jogadas todas de um State
getPlays :: Int -> State -> [Player] -> [(Int,Play)] 
getPlays _ _ [] = []
getPlays step (State m ps l) (h:t) = doPlay step (State m ps l) h ++ getPlays step (State m ps l) t 

-- Atualiza um estado perante um conjunto de jogadas. Aqui é que irá acontecer a atribuição de várias jogadas ao jogador, de acordo com o Int que recebe
updateState :: [(Int,Play)] -> State -> State
updateState [] s = s 
updateState ((h,t):ts) s = updateState ts (auxUpdateState (h,t) s)

-- Atualiza um estado perante uma jogada
auxUpdateState :: (Int,Play) -> State -> State
auxUpdateState (num,jogada) s
  | num == 0 = s
  | num == 1 = s1
  | num == 2 = play jogada s1 
    where s1 = play jogada s

-- Atualiza um estado perante um conjuntos de jogadas sendo estas correspondentes aos fantasmas
updateStateGhost :: [Play] -> State -> State
updateStateGhost [] s = s
updateStateGhost (h:t) s = updateStateGhost t (auxUpdateStateGhost h s) 

-- Atualiza um estado perante uma jogada de um fantasma
auxUpdateStateGhost :: Play -> State -> State
auxUpdateStateGhost jogada s = play jogada s 

-- Função que controla a boca do Pacman
ocMouth :: Player -> Player
ocMouth (Ghost a) = Ghost a
ocMouth (Pacman (PacState (id,c,v,o,p,l) d m pM)) = if m == Open
                                                    then (Pacman (PacState (id,c,v,o,p,l) d Closed pM))
                                                    else (Pacman (PacState (id,c,v,o,p,l) d Open pM))


-- Função que manipula o tempo Mega e que fica responsável pelas respetivas consequências
looseTimeMega :: Double -> [Player] -> [Player]
looseTimeMega _ [] = []
looseTimeMega t (x:xs) 
  | t <= 0 = (setPacmanMode (ocMouth x) Normal) : setGhostMode2 xs Alive
  | otherwise = looseTimeMega (t-250) (x:xs)

-- Função que para um dado step e estado, altera o estado do jogo em uma iteração
passTime :: Int  -> State -> State  
passTime step (State m ps l) = updateStateGhost (ghostPlay (State m ps l)) (updateState jogadas (State m (looseTimeMega timeMega ps) l))
  where jogadas = getPlays step (State m ps l) ps
        timeMega = getTimeMega (getPacman ps)


-- tranformar corredores de peças numa lista pares   
transforme1 :: Corridor -> [(Int,Piece)]
transforme1 [] = []
transforme1 (c:cs) = ((1,c) : transforme1 cs)

-- ver se o inteiro é o mesmo para usar na função
sameInt :: Eq a => a -> a -> Bool
sameInt a b |a==b = True
            |otherwise = False

-- verificar se a peça é a mesma para usar na função transform2
samePiece:: Piece -> Piece -> Bool
samePiece x y = x == y

-- compactar peças iguais em listas
transforme2 :: [(Int,Piece)] -> [(Int,Piece)]
transforme2 [] =[]
transforme2 [x] = [x]
transforme2 ((a1,p1) : (a2,p2) :as) |samePiece p1 p2 = (a1+a2,p1) : transforme2 (as)
                                    |otherwise = (a1,p1) : transforme2 ((a2,p2) :as) 
            
-- compactar um corredor do labirinto 
reverse1 :: Corridor -> Instruction
reverse1 (x:xs) = Instruct (transforme2 (transforme1 (x:xs)))

--compactar o labirinto horizontalmente
reverse2 :: Maze -> Instructions
reverse2 [] = []
reverse2 (y:ys) = reverse1 y : reverse2 ys   

-----------------------------
--verificar se duas instruções são iguais
sameInstruct :: Instruction -> Instruction -> Bool
sameInstruct (Instruct []) (Instruct []) = True
sameInstruct (Instruct []) _ = False 
sameInstruct _ (Instruct []) = False
sameInstruct (Instruct ((n1, p1) : t)) (Instruct ((n2 , p2) : ts)) | sameInt n1 n2 && samePiece p1 p2 = sameInstruct (Instruct t) (Instruct ts)
                                           | otherwise = False

--verifica se uma instrução pertence a uma certa lista de instruções
belongToList :: Instruction -> [Instruction] -> Bool
belongToList _ [] = False
belongToList x (h:ts) = sameInstruct x h || belongToList x ts

-- esta função apaga uma instrução igual a si mesma de uma lista de instruções
deleteIn :: Instruction -> Instructions -> Instructions
deleteIn _ [] = []
deleteIn x (y:ys) | sameInstruct x y = deleteIn x ys 
                  |otherwise = y : deleteIn x ys 

removeEqualInstruction :: [Instruction] -> [Instruction]
removeEqualInstruction (x:xs) | length (x:xs) ==1 = []
removeEqualInstruction (x:y:z) | belongToList x (y:z) = x : removeEqualInstruction (deleteIn x (y:z))
                               |otherwise = removeEqualInstruction (y:z) 

-- a função descobre a posição de um elemento numa lista
elemIndices :: Eq a => a -> [a] -> [Int]
elemIndices _ [] = []
elemIndices x l  = aux 0 x l
                  where
                    aux _ _ [] = []
                    aux i x (h:t) = if x==h
                                    then i:aux (i+1) x t
                                    else aux (i+1) x t

----
samein :: Instructions -> Instructions -> [[Int]]
samein _ [] = []
samein [] _ = []
samein (x:y) (z:zs) = tail (elemIndices x (z:zs)) : samein y (z:zs)

-- esta da as posições onde os Repeats tem que ser inseridos
sameInstr :: Instructions -> [[Int]]
sameInstr (x:xs) = samein (removeEqualInstruction (x:xs)) (x:xs)

sameRepeat:: Instructions -> Instructions -> [Int]
sameRepeat _ [] = []
sameRepeat [] _ = []
sameRepeat (x:xs) (y:ys) = head (elemIndices x (y:ys)) : sameRepeat xs (y:ys)


irepeat:: Instructions -> [Int]
irepeat (h:t) = sameRepeat (removeEqualInstruction (h:t)) (h:t)


-- vai criar uma lista com repeats para usar nas funções seguintes
geraRepeats :: [Int] -> Instructions
geraRepeats [] = []
geraRepeats (x:xs) = (Repeat x) : geraRepeats xs 
 
-- recebe a lista de instruções e devolve a lista de repeats a adicionar nessas instruções 
listRepeats :: Instructions -> Instructions
listRepeats (h:t:ts) = geraRepeats (irepeat (h:t:ts))

-- Substitui um elemento numa lista
replace22 :: [a] -> Int -> a -> [a]
replace22 xs i e = case splitAt i xs of
   (before, _:after) -> before ++ e: after
   _ -> xs

-- Substitui um elemento de uma lista de instrucoes
all' :: [Instruction] -> Instructions
all' l = aux l 0
  where aux :: [Instruction] -> Int -> Instructions
        aux [] _ = []
        aux [x] _ = [x]
        aux (x:y:ys) ac = if x == y 
                          then ([x]++replace22 (x:y:ys) (ac+1) (Repeat ac))++aux (y:ys) (ac+1)
                          else [x] ++ (aux (y:ys) (ac+1))

