-- Vai buscar as vidas de um jogador
getPlayerLives :: Player -> Int
getPlayerLives (Pacman (PacState (x,y,z,t,h,l) q c d )) = l
getPlayerLives (Ghost (GhoState (x,y,z,t,h,l) q )) = l

------------------------------------------------------------------------------
--
setPlayerLives :: Player -> Int -> Player
setPlayerLives (Pacman (PacState (x,y,z,t,h,l) q c d)) live = (Pacman (PacState (x,y,z,t,h,live) q c d))
setPlayerLives (Ghost (GhoState (x,y,z,t,h,l) q )) live = (Ghost (GhoState (x,y,z,t,h,live) q ))

-- Vai buscar o modo de um fantasma
getGhostMode :: Player -> GhostMode
getGhostMode (Ghost (GhoState a d)) = d

-- Atribui um modo a vários fantasmas
setGhostMode2 :: [Player] -> GhostMode -> [Player]
setGhostMode2 [] _ = []
setGhostMode2 ((Ghost (GhoState (x,y,z,t,h,l) q )):gs) mode = (Ghost (GhoState (x,y,z,t,h,l) mode)) : setGhostMode2 gs mode
setGhostMode2 ((Pacman a):xs) mode = ((Pacman a):setGhostMode2 xs mode)

-- Atribui pontos a um jogador
auxSetPlayerPoints :: Player -> Int -> Player
auxSetPlayerPoints (Pacman (PacState (x,y,z,t,h,l) q c d)) p = (Pacman (PacState (x,y,z,t,(h+p),l) q c d)) 

-- Atribui um modo a um jogador
setPacmanMode :: Player -> PacMode -> Player
setPacmanMode (Pacman (PacState (x,y,z,t,h,l) q c d)) mode = (Pacman (PacState (x,y,z,t,h,l) q c mode))
setPacmanMode (Ghost a) mode = Ghost a

-- Vai buscar os IDs de uma lista de jogadores
getPlayerID' :: [Player] -> [Int]
getPlayerID' [] = []
getPlayerID' (Pacman (PacState (x,y,z,t,h,l) q c d ):xs) = x : getPlayerID' xs
getPlayerID' (Ghost (GhoState (x,y,z,t,h,l) q ):xs) = x : getPlayerID' xs

-- Verifica se o id dado pertence a algum fantasma de uma lista de jogadores
isGhostID :: [Player] -> Int -> Bool
isGhostID [] _ = False
isGhostID (h:t) id  
  | getPlayerID h == id = True
  | otherwise = isGhostID t id 

-- Verifica se algum jogador vai para determinada coordenada; será usada para verificar se o pacman encontra algum fantasma
isGhost :: [Player] -> Coords -> Bool
isGhost [] _ = False
isGhost (h:t) coord  
  | getPlayerCoords h == coord = True
  | otherwise = isGhost t coord 

-- Recolhe os fantasmas de uma lista de jogadores 
takeGhost :: [Player] -> [Player]
takeGhost [] = []
takeGhost ((Pacman (PacState (x,y,z,t,h,l) q c d)):xs) = takeGhost xs      
takeGhost ((Ghost (GhoState (x,y,z,t,h,l) d)):xs) = w : takeGhost xs 
    where w = (Ghost (GhoState (x,y,z,t,h,l) d))

-- Vai buscar o(s) Player(s) que corresponde(m) ao id dado
searchPlayer :: [Player] -> Int -> [Player]
searchPlayer [] _ = error "Lista vazia... Tente novamente!"
searchPlayer [x] id = if getPlayerID x == id 
                                 then [x]
                                 else []
searchPlayer (h:t) id 
  | getPlayerID h == id = h : searchPlayer (filter (/= h) t) id 
  | otherwise = searchPlayer t id

-- Garante que não há ids repetidos numa lista de jogadores
noClone :: [Player] -> [Player]
noClone [] = []
noClone (x:xs) = if filter (== getPlayerID x) (getPlayerID' xs) == []
                 then x : noClone xs
                 else error "Ids repetidos... Tente novamente!"

-- Dá a peça de determinada coordenada
coordToPiece :: Maze -> Coords -> Piece
coordToPiece [] _ = error "Labirinto inválido...Tente novamente!"
coordToPiece m (a,b) 
  | b == (length (head m)) || b == -1 = Empty
  | otherwise = (m !! a) !! b

-- Indica as coordenadas que um jogador adquire perante os diferentes movimentos
whereTo :: Player -> Orientation -> Player
whereTo j x 
  | x == getPlayerOrientation j && getPlayerOrientation j == R = setPlayerCoords j (a,b+1)
  | x == getPlayerOrientation j && getPlayerOrientation j == L = setPlayerCoords j (a,b-1)
  | x == getPlayerOrientation j && getPlayerOrientation j == U = setPlayerCoords j (a-1,b)
  | x == getPlayerOrientation j && getPlayerOrientation j == D = setPlayerCoords j (a+1,b)
  | otherwise = setPlayerOrientation (setPlayerCoords j (a,b)) x
    where (a,b) = getPlayerCoords j 

-- Indica as coordenadas que um jogador adquire perante os diferentes movimentos, tendo em conta que atribui na mesma uma orientação ao Player mesmo que esta seja diferente da orientação original do mesmo
whereTo2 :: Player -> Orientation -> Player
whereTo2 j x 
  | x == R = setPlayerOrientation (setPlayerCoords j (a,b+1)) R 
  | x == L = setPlayerOrientation (setPlayerCoords j (a,b-1)) L 
  | x == U = setPlayerOrientation (setPlayerCoords j (a-1,b)) U
  | otherwise = setPlayerOrientation (setPlayerCoords j (a+1,b)) D
    where (a,b) = getPlayerCoords j 

-- Caso o jogador entre no túnel; as únicas coordenadas que o jogador obtem, sendo o y == 0 é no túnel, logo não preciso de especificar.
tunnelCoords :: Coords -> Maze -> Coords   
tunnelCoords (a,b) (h:t) 
  | b == (length h) = (a,0)    
  | b == -1 = (a,length h - 1)
  | otherwise = (a,b)

-- Atribuir novas coordenadas ao jogador caso entre no tunel
setTunnelCoords :: Coords -> Player -> Player
setTunnelCoords coord p = setPlayerCoords p coord

-- Coordenada da casa dos fantasmas para ressuscitar
houseCoords :: Maze -> Coords
houseCoords m = if even (length m) && even (length (middleCorridors m))
                then ((div (length m) 2) -1, div (length (head (middleCorridors m))) 2)
                else if odd (length m) && even (length (middleCorridors m))
                     then (div (length m) 2, div (length (head (middleCorridors m))) 2)
                     else  if even (length m) && odd (length (middleCorridors m))
                           then ((div (length m) 2) -1, div (length (head (middleCorridors m))) 2)
                           else (div (length m) 2, div (length (head (middleCorridors m))) 2)
                                                                                                     
-- Coordenadas que o pacman irá receber assim que perde uma vida (enquanto não forem =0)
pacmanRespawn :: Maze -> Coords 
pacmanRespawn m = (x+2,y)
    where (x,y) = houseCoords m

-- Atribui os pontos do jogador de acordo com as diferentes situações  O PACMAN MANTEM SEMPRE AS COORDS ORIGINAIS
setPlayerPoints :: Maze -> [Player] -> Coords -> [Player]
setPlayerPoints m [] _ = []
setPlayerPoints m (j:js) coord   
  | (isGhost js coord) && getGhostMode ghost1 == Dead = (setPlayerCoords (auxSetPlayerPoints j 10) coord) : (setPlayerCoords (head (setGhostMode2 [ghost1] Alive)) (houseCoords m)) : dropghost1
  | p == Food Big = (setTimeMega (setPacmanMode (auxSetPlayerPoints j 5) Mega) 10000) : (setGhostMode2 js Dead)
  | p == Food Little = (auxSetPlayerPoints j 1) : js
  | otherwise = (j:js)
    where p = coordToPiece m coord 
          ghost1 = meetGh js coord    
          dropghost1 = filter (\x -> getPlayerID x /= getPlayerID ghost1) js  --retira da lista de fantasmas o fantasma que encontrou o pacman

-- Dada uma coord e uma lista de jogadores devolve o fantasma que corresponde a essa coord
meetGh :: [Player] -> Coords -> Player
meetGh [(Ghost ghostate)] c = (Ghost ghostate)
meetGh ((Ghost ghostate) : t) c
  | getPlayerCoords (Ghost ghostate) == c = (Ghost ghostate)
  | otherwise = meetGh t c
meetGh l c = meetGh (tail l) c    

-- Consequencias de encontrar um fantasma; vai receber as coords de onde o Pacman está e vai analisar a situacao na casa para onde vai  DEPOIS DO SET POINTS 
meetGhost :: Maze -> [Player] -> [Player]  
meetGhost m (j:js) 
  | getPacmanMode j == Mega && getGhostMode ghost1 == Dead = setPlayerPoints m (j:js) a  
  | getPacmanMode j == Mega && getGhostMode ghost1 == Alive && getPlayerLives j > 0 = (setPlayerCoords (setPlayerOrientation (setPlayerLives j ((getPlayerLives j) - 1)) U) (pacmanRespawn m)) : js
  | getPacmanMode j == Mega && getGhostMode ghost1 == Alive && getPlayerLives j == 0 = (setPacmanMode j Dying) : js
  | getPacmanMode j == Normal && getPlayerLives j > 0 = (setPlayerCoords (setPlayerOrientation (setPlayerLives j ((getPlayerLives j) - 1)) U) (pacmanRespawn m)) : js
  | getPacmanMode j == Normal && getPlayerLives j == 0 = (setPacmanMode j Dying) : js
  | otherwise = (j:js)
    where a = getPlayerCoords (whereTo j ori)
          ori = getPlayerOrientation j  
          ghost1 = meetGh js a     

-- Consequencias de uma jogada num fantasma                 
moveGhost :: Maze -> [Player] -> Play -> [Player]
moveGhost _ [] _ = []                                  
moveGhost m (h:t) (Move id ori)
  | (getPlayerCoords (whereTo2 (head (searchPlayer t id)) ori)) == (getPlayerCoords h) = meetGhost m (h:t) 
  | v == Wall = (h:t)
  | (x,y) == (x,-1) = h : (setPlayerCoords (head (searchPlayer t id)) (tunnelCoords (x,-1) m)) : dropghost
  | (x,y) == (x,length (head m)+1) = h : (setPlayerCoords (head (searchPlayer t id)) (x,0)) : dropghost
  | otherwise = h : (whereTo2 (head (searchPlayer t id)) ori) : dropghost 
    where v = coordToPiece m (getPlayerCoords (whereTo (head (searchPlayer t id)) ori))
          dropghost = filter (\x -> getPlayerID x /= getPlayerID (head (searchPlayer t id))) t    
          (x,y) = (getPlayerCoords (whereTo2 (head (searchPlayer t id)) ori))

-- Recebendo uma jogada e um estado do labirinto, gera um novo estado afetado por essa jogada
play :: Play -> State -> State 
play (Move id ori) st@(State m js l)
    | isGhostID (takeGhost js) id == True = (State m (moveGhost m js (Move id ori)) l) 
    | getPacmanMode k == Dying = error "O Pacman está morto."   
    | v == Wall = st
    | isGhost ks a == True = (State m (meetGhost m (k:ks)) l)  
    | v == Empty = (State m ((setTunnelCoords (tunnelCoords a m) k):ks) l)
    | v == Food Big = (State m1 (setPlayerPoints m ((setTunnelCoords (tunnelCoords a m) k):ks) a) l)
    | v == Food Little = (State m1 (setPlayerPoints m ((setTunnelCoords (tunnelCoords a m) k):ks) a) l)
    | otherwise = error "Dados invalidos... Tente novamente!"
      where (k:ks) = (searchPlayer (noClone js) id) ++ (dropPlayer)
            v = coordToPiece m (getPlayerCoords (whereTo k ori))
            a = getPlayerCoords (whereTo k ori)
            m1 = replaceElemInMaze a Empty m
            dropPlayer = filter (\x -> getPlayerID x /= getPlayerID k) js


type Maze = [Corridor]
type Corridor = [Piece]
data Piece = Food FoodType | Wall | Empty  
data FoodType = Big | Little

instance Show Piece where
  show (Food Big) = "o"
  show (Food Little) = "."
  show (Wall) = "#"
  show (Empty) = " "

-- Given a seed returns a list of n integer randomly generated
geraAleatorios :: Int -> Int -> [Int]
geraAleatorios n seed = let gen = mkStdGen seed         -- creates a random generator
                        in take n $ randomRs (0,99) gen -- takes the first n elements from an infinite series of random numbers between 0-99

-- Given a seed returns an integer randomly generated
nrAleatorio :: Int -> Int
nrAleatorio seed = head $ geraAleatorios 1 seed

-- Converte uma lista numa lista de listas de tamanho n
subList :: Int -> [a] -> [[a]]
subList _ [] = []
subList n l = take n l: subList n (drop n l)

-- Converte um Integer num peça e dá as define condições para uma peça determinada 
convertePeca :: Int -> Piece
convertePeca x 
  | x == 3 = Food Big
  | x >= 0 && x < 70 = Food Little
  | otherwise = Wall 

{-- Converte um corredor em uma string, i.e vai usar as definições
 dadas para tornar o corredor em palavras, para mais tarde serem lidas e interpertadas no ghci--}
printCorridor :: Corridor -> String
printCorridor [] = "\n"
printCorridor (p:ps) = show p ++ (printCorridor ps)

-- Converte o labirinto numa string 
printMaze :: Maze -> String
printMaze [] = []
printMaze (c:cs) = printCorridor c ++ printMaze cs

-- Converts a list of integers into a Corridor
convertCorridor :: [Int] -> Corridor
convertCorridor [] = []
convertCorridor (p:ps) = convertePeca p : convertCorridor ps

-- Converts a list of lists of integers into a Maze
convertMaze :: [[Int]] -> Maze
convertMaze [] = []
convertMaze (x:xs) = ([Wall] ++ (convertCorridor x) ++ [Wall]) : convertMaze xs 

-- Gera um corredor com um determinado número de paredes
onlyWall :: Int -> [Piece]
onlyWall 0 = []
onlyWall x = [Wall] ++ onlyWall (x-1)

-- Divide o labirinto em 2 (length maze = altura labirinto)
middleHeight :: Maze -> Int
middleHeight maze = div (length maze) 2 

-- Vai buscar o corredor correspondente ao corredor do túnel
middleCorridors :: Maze -> [Corridor]
middleCorridors maze
  | even (length maze) = take 2 (drop ((middleHeight maze) - 1) maze)
  | otherwise = take 1 (drop (middleHeight maze) maze)

-- Gera um corredor onde o primeiro elemento e o último é vazio 
breakWall :: [Corridor] -> [Corridor]
breakWall [] = []
breakWall (x:xs) = ([Empty] ++ init (tail x) ++ [Empty]) : breakWall xs 

-- Gera um corredor vazio
breakWall2 :: Corridor -> Corridor
breakWall2 [] = []
breakWall2 x 
  | even (length x) = replicate 10 Empty 
  | otherwise = replicate 11 Empty  

-- Gera as duas linhas "vazias" antes e depois da casa
emptyCorridor :: Corridor -> Corridor
emptyCorridor x = take w x ++ breakWall2 x ++ (drop (length x - w) x)
  where w = if even (length x) 
            then div (length x - 10) 2
            else div (length x - 11) 2

-- Gera a primeira linha da casa dos fantasmas
firstLine :: Corridor -> Corridor
firstLine x 
  | even (length x) = take w x ++ [Empty] ++ replicate 3 Wall ++ replicate 2 Empty ++ replicate 3 Wall ++ [Empty] ++ (drop (length x - w) x)
  | otherwise = take w x ++ [Empty] ++ replicate 3 Wall ++ replicate 3 Empty ++ replicate 3 Wall ++ [Empty] ++ (drop (length x - w) x)
  where w = if even (length x) 
            then div (length x - 10) 2
            else div (length x - 11) 2

-- Gera a segunda linha da casa dos fantasmas
secondLine :: Corridor -> Corridor
secondLine x 
  | even (length x) = take w x ++ [Empty] ++ [Wall] ++ replicate 6 Empty ++ [Wall] ++ [Empty] ++ (drop (length x - w) x)
  | otherwise = take w x ++ [Empty] ++ [Wall] ++ replicate 7 Empty ++ [Wall] ++ [Empty] ++ (drop (length x - w) x)
  where w = if even (length x) 
            then div (length x - 10) 2
            else div (length x - 11) 2

-- Gera a terceira linha da casa dos fantasmas
thirdLine :: Corridor -> Corridor
thirdLine x 
  | even (length x) = take w x ++ [Empty] ++ replicate 8 Wall ++ [Empty] ++ (drop (length x - w) x)
  | otherwise = take w x ++ [Empty] ++ replicate 9 Wall ++ [Empty] ++ (drop (length x - w) x)
  where w = if even (length x) 
            then div (length x - 10) 2
            else div (length x - 11) 2

-- Gera um túnel diferenciando caso o comprimento do tunel seja impar ou par
openTunnel :: Maze -> Maze
openTunnel maze 
  | even (length maze) = (take (midH - 1) maze) ++ tunnel ++ (drop (midH + 1) maze)   
  | otherwise  = (take midH maze) ++ tunnel ++ (drop (midH + 1) maze)
  where midH = middleHeight maze  
        tunnel = breakWall (middleCorridors maze)

-- Funcao que cria a casa dos fantasmas
buildHouse :: Maze -> Maze
buildHouse (a:b:c:d:e:f:g:xs) 
  | even (length w) && (length w) == 8 = [a] ++ [(emptyCorridor b)] ++ [(firstLine c)] ++ [(secondLine d)] ++ [(thirdLine e)] ++ [(emptyCorridor f)] ++ (drop (length w - y-1) w)
  | even (length w) && (length w) /=8 = (take y w) ++ [(emptyCorridor c)] ++ [(firstLine d)] ++ [(secondLine e)] ++ [(thirdLine f)] ++ [(emptyCorridor g)] ++ (drop (length w - y-1) w)
  | odd (length w) && (length w) == 7 = [a] ++ [(emptyCorridor b)] ++ [(firstLine c)] ++ [(secondLine d)] ++ [(thirdLine e)] ++ [(emptyCorridor f)] ++ [g]
  | odd (length w) && (length w) /=7 = (take y w) ++ [(emptyCorridor c)] ++ [(firstLine d)] ++ [(secondLine e)] ++ [(thirdLine f)] ++ [(emptyCorridor g)] ++ (drop (length w - y) w)
  where w = (a:b:c:d:e:f:g:xs)
        y = if even (length w)
              then div (length w - 6) 2
              else div (length w - 5) 2 

-- Gera um labirinto
geraLabirinto :: Int -> Int -> Int -> Maze
geraLabirinto x y s = convertMaze(subList x (geraAleatorios (x*y) s))    

-- Gera a zona interior, sem as paredes laterais 
innerZone :: Int -> Int -> Int -> Maze
innerZone x y s = convertMaze (subList x (geraAleatorios (x*y) s))

-- Gera o labirinto final
generateMaze :: Int -> Int -> Int -> Maze
generateMaze x y s = openTunnel (buildHouse(onlyWall x : (innerZone (x-2) (y-2) s) ++ [onlyWall x]))

-- Mostra o labirinto final no ecra
displayMaze :: Maze -> IO ()
displayMaze m = putStr $ printMaze m


data Manager = Manager  
    {   
        state   :: State
    ,    pid    :: Int 
    ,    step   :: Int
    ,    before :: Integer
    ,    delta  :: Integer
    ,    delay  :: Integer --250ms
    } deriving (Show)

loadManager :: Manager
loadManager = (Manager (loadMaze "maps/1.txt") 0 0 0 0 defaultDelayTime)

----------------------------------------------------------------------------------

-- Partimos do principio que selecionamos uma das teclas das setas. Quero apenas rodar o jogador porque o movimento vai ser feito pela mudança do tempo 
updateControlledPlayer :: Key -> Manager -> Manager
updateControlledPlayer KeyLeftArrow (Manager (State maze ps l) pid step now delta delay) = (Manager (State maze (recuSetPlayerOrientation ps L pid) l) pid step now delta delay)
updateControlledPlayer KeyRightArrow (Manager (State maze ps l) pid step now delta delay) = (Manager (State maze (recuSetPlayerOrientation ps R pid) l) pid step now delta delay) 
updateControlledPlayer KeyUpArrow (Manager (State maze ps l) pid step now delta delay) = (Manager (State maze (recuSetPlayerOrientation ps U pid) l) pid step now delta delay)
updateControlledPlayer KeyDownArrow (Manager (State maze ps l) pid step now delta delay) = (Manager (State maze (recuSetPlayerOrientation ps D pid) l) pid step now delta delay)                   

--
updateScreen :: Window  -> ColorID -> Manager -> Curses ()
updateScreen w a man =
                  do
                    updateWindow w $ do
                      clear
                      setColor a
                      moveCursor 0 0 
                      drawString $ show (state man)
                    render

currentTime :: IO Integer
currentTime = fmap (round . (* 1000)) getPOSIXTime

updateTime :: Integer -> Manager -> Manager
updateTime now (Manager s pid step b delta delay) = (Manager s pid step now (delta + (now-b)) delay)

resetTimer :: Integer -> Manager -> Manager
resetTimer now (Manager s pid step b delta delay) = (Manager s pid step now 0 delay)        


nextFrame :: Integer -> Manager -> Manager
nextFrame n (Manager s pid step b d dt) = resetTimer n (Manager (passTime step s) pid step b d dt)
  

loop :: Window -> Manager -> Curses ()
loop w man@(Manager s pid step bf delt del ) = do 
  color_schema <- newColorID ColorCyan ColorDefault 10
  now <- liftIO  currentTime
  updateScreen w  color_schema man
  if ( delt > del )
    then loop w $ nextFrame now man
    else do
          ev <- getEvent w $ Just 0
          case ev of
                Nothing -> loop w (updateTime now man)
                Just (EventSpecialKey arrow ) -> loop w $ updateControlledPlayer arrow (updateTime now man)
                Just ev' ->
                  if (ev' == EventCharacter 'q')
                    then return ()
                    else loop w (updateTime now man)

main :: IO ()
main =
  runCurses $ do
    setEcho False
    setCursorMode CursorInvisible
    w <- defaultWindow
    loop w loadManager



loadMaze :: String -> State
loadMaze filepath = unsafePerformIO $ readStateFromFile filepath

readStateFromFile :: String -> IO State
readStateFromFile f = do
                content <- readFile f
                let llines = lines content 
                    (new_map,pl) = convertLinesToPiece llines 0 []
                return (State new_map pl 1)

convertLinesToPiece :: [String] -> Int -> [Player] -> (Maze,[Player])
convertLinesToPiece [] _ l = ([],l)
convertLinesToPiece (x:xs) n l  = let (a,b) = convertLineToPiece x n 0 l 
                                      (a1,b1) = convertLinesToPiece xs (n+1) b
                                  in (a:a1,b1)

convertLineToPiece :: String -> Int -> Int -> [Player] -> ([Piece],[Player])
convertLineToPiece [] _ _ l = ([],l)
convertLineToPiece (z:zs) x y l = let (a,b) = charToPiece z x y l
                                      (a1,b1) = convertLineToPiece zs x (y+1) b 
                                  in (a:a1,b1)

charToPiece :: Char -> Int -> Int -> [Player] -> (Piece,[Player])
charToPiece c x y l                          --ID(?),coord,veloci,dire,pontos,vidas
    | c == '{' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Normal ))   :l) )
    | c == '<' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Closed Normal )) :l) )
    | c == '}' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Open Normal ))   :l) )
    | c == '>' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Closed Normal )) :l) )
    | c == 'V' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Open Normal ))   :l) )
    | c == 'v' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Closed Normal )) :l) )
    | c == '^' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Open Normal ))   :l) )
    | c == '|' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Closed Normal )) :l) )
    | c == 'X' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Dying ))    :l) )
    | c == 'M' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Alive))            :l) )
    | c == '?' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Dead))             :l) )
    | c == 'o' =  (Food Big,l)
    | c == '.' =  (Food Little,l)
    | c == '#' =  (Wall,l)
    | otherwise = (Empty,l)  
    -- Empty -> o lugar fica vazio quando o jogador está nele; o que estava nele antes passa a vazio.
    -- A velocidade corresponde à quantidade de "quadrados" que o jogador anda?
    {--nos exemplos dados no pdf, as coordenadas ((x,y)) correspondem ao lugar onde 
    o jogador se encontra sem contar com a primeira linha e a primeira coluno do maze--}
-- | This module contains all sorts of auxiliary types and datas used on the project along with some extra functions and examples of Mazes and a list of Players used in testing

-- * Auxiliary data types for "Tarefa1.hs" 
type Maze = [Corridor] -- always horizontal
type Corridor = [Piece]
data Piece = Food FoodType | PacPlayer Player| Wall | Empty deriving (Eq)
data FoodType = Big | Little deriving (Eq)

-- | Shows Pieces as String and attributes a colour
instance Show Piece where
   show (Wall) = coloredString "#" None
   show (Empty) = coloredString " " None
   show (Food z) = coloredString (show z )   Green
   show (PacPlayer (Pacman (PacState (i,c,x,y,z,l) o m Normal))) = coloredString (show(PacState (i, c, x, y,z,l) o m Normal)) Yellow
   show (PacPlayer (Pacman (PacState (i,c,x,y,z,l) o m Mega)))   = coloredString (show(PacState (i, c, x, y,z,l) o m Mega))   Blue
   show (PacPlayer (Pacman (PacState (i,c,x,y,z,l) o m Dying)))  = coloredString (show(PacState (i, c, x, y,z,l) o m Dying))  Red
   show (PacPlayer (Ghost z)) = coloredString (show z)  Purple

-- | Distinguishes food according to size
instance Show FoodType where
   show (Big) =  "o"
   show (Little) =  "."

-- * Auxiliary data types for "Tarefa2.hs" 

data Play = Move Int Orientation deriving (Eq,Show)
data Orientation = L | R | U | D | Null deriving (Eq,Show)
data Mouth = Open | Closed deriving (Eq,Show)
data PacMode = Dying | Mega | Normal deriving (Eq,Show)
data GhostMode = Dead  | Alive deriving (Eq,Show)
data Color = Blue | Green | Purple | Red | Yellow | None deriving Eq 
data State = State 
    {
           maze :: Maze
     ,     playersState :: [Player]
     ,     level :: Int
    }
data Player   =  Pacman PacState | Ghost GhoState deriving (Eq)
data PacState =  PacState 
    {   
        pacState :: PlayerState
    ,   timeMega :: Double
    ,   openClosed :: Mouth
    ,   pacmanMode :: PacMode
   
    } deriving Eq
data GhoState= GhoState 
    {
        ghostState :: PlayerState
    ,   ghostMode :: GhostMode

    } deriving Eq
type Coords = (Int,Int)
type PlayerState = (Int, Coords, Double , Orientation, Int, Int)

-- | Shows States
instance Show State where
  show (State m ps p) = printMaze mz ++ "Level: " ++ show p ++ "\n Players: \n" ++ (foldr (++) "\n" (map (\y-> printPlayerStats y) ps))
                          where mz = placePlayersOnMap ps m

-- | Shows the different characters used to represent Pacman according PacMode, orientation and if it's mouth is open or closed
instance Show PacState where
     show (PacState (_, (_,_), _, _, _, _) _ _ Dying)  =  "X"
     show (PacState (_, (_,_), _, R, _, _) _ Open _)   = "{"
     show (PacState (_, (_,_), _, L, _, _) _ Open _)   = "}"
     show (PacState (_, (_,_), _, U, _, _) _ Open _)   = "V"
     show (PacState (_, (_,_), _, D, _, _) _ Open _)   = "^" 
     show (PacState (_, (_,_), _, R, _, _) _ Closed _) = "<"
     show (PacState (_, (_,_), _, L, _, _) _ Closed _) = ">"
     show (PacState (_, (_,_), _, U, _, _) _ Closed _) = "v"
     show (PacState (_, (_,_), _, D, _, _) _ Closed _) = "|" 

-- | Shows Player
instance Show Player where
   show (Pacman x) =  show x
   show (Ghost x)  =  show x

-- | Shows ghost according to GhostMode
instance Show GhoState where
   show (GhoState x Dead)  =  "?"
   show (GhoState x Alive) =  "M"


