-- | Given a string converts it to a corridor
mazeCorridor :: String -> Corridor
mazeCorridor [] = []
mazeCorridor c = foldr (\x acc -> sToPiece x : acc) [] c


-- | Converts a char into a piece
sToPiece :: Char -> Piece
sToPiece '#' = Wall
sToPiece ' ' = Empty
sToPiece '.' = Food Little
sToPiece 'o' = Food Big

