-- | Main Function of Tarefa5: given a State makes a list of Plays for every ghost deppending on their Ghosts Mode
ghostPlay :: State -> [Play]
ghostPlay (State m [] l) = []
ghostPlay (State m lp@(Ghost (GhoState pL@(i,(gx,gy),v,o,p,l) gm):xs) le) | sameCoords lp && (tx,ty) == (0,0) = differentPlay (gx,gy) i lp m gm : ghostPlay (State m xs le)
                                                                          | (tx,ty) /= (0,0) && closeTunnel m (gx,gy) && gm == Alive = (playTunnelChase m i xs (gx,gy) (tx,ty) pr pl) : ghostPlay (State m xs le) 
                                                                          | (tx,ty) /= (0,0) && closeTunnel m (gx,gy) && gm == Dead = (playTunnelScatter m i (gx,gy) (tx,ty) pr pl) : ghostPlay (State m xs le) 
                                                                          | elem (gx,gy) lc = (playHouse pu dp dv dvp i (gx,gy) lc) : ghostPlay (State m xs le)
                                                                          | gm == Alive = (chaseMode (State m (Ghost (GhoState pL Alive):xs) le) i)  : ghostPlay (State m xs le)
                                                                          | otherwise   = (scatterMode (State m (Ghost (GhoState pL Dead):xs) le) i) : ghostPlay (State m xs le)
                                            where
                                              lc = houseCoords m
                                              pu = pieceCoords (gy+1,gx)   m  -- Up Piece 
                                              dv = gy - (snd (head lc)) 
                                              (cx,cy) = closestPacman xs (gx,gy) (px,py)
                                              (px,py) = firstPacman xs 
                                              dp = gy - cy
                                              dvp = gx - cx
                                              pl = pieceCoords (gy,gx+1)   m -- Left Piece
                                              pr = pieceCoords (gy+2,gx+1) m -- Right Piece 
                                              (tx,ty) = getCloseTunnelP m xs                                                                                         
ghostPlay (State m (p:ps) le) | verifyPlayerList ps = []
                              | otherwise = ghostPlay (State m (ps ++ [p]) le)

-- | Analyzes if at least two Ghosts on the same list of players have the same coordinates
sameCoords :: [Player] -> Bool
sameCoords [] = False
sameCoords l = elem (head lm) (tail lm)
  where
    lm = map getCoordsPlayer l

-- | Auxiliary function of sameCoords used to get the coordinates of the player
getCoordsPlayer :: Player -> Coords
getCoordsPlayer (Pacman (PacState (_,y,_,_,_,_) _ _ _)) = (0,0)
getCoordsPlayer (Ghost (GhoState (_,y,_,_,_,_) _ ))  = y

-- | Verifies if a list of players is composed just by Pacmans
verifyPlayerList :: [Player] -> Bool
verifyPlayerList [] = True
verifyPlayerList (Pacman (PacState (i,(px,py),v,o,p,l) t m pm):xs) = verifyPlayerList xs
verifyPlayerList _ = False

-- | Makes a play with the intention to get close to Pacmans
chaseMode :: State -> Int -> Play
chaseMode (State m (Ghost (GhoState (i,(x,y),_,_,_,_) _):xs) le) id | id == i   = bestPlayChase (x,y) id xs m
                                                                    | otherwise = chaseMode (State m xs le) id
chaseMode (State m (p:ps) le) id = chaseMode (State m (ps ++ [p]) le) id

-- | Analyzes what Pacman is closer the Ghost and decides what play to do based on the coordinates of the Ghost and the closest Pacman when the ghostMode is Alive
bestPlayChase :: (Int,Int) -> Int -> [Player] -> Maze -> Play
bestPlayChase (gx,gy) id lp m | cy < gy && pieceCoords (gy,gx+1)   m /= Wall && pm == Normal && haveWalls ptC = Move id L
                              | cy > gy && pieceCoords (gy+2,gx+1) m /= Wall && pm == Normal && haveWalls ptC = Move id R
                              | cx < gx && pieceCoords (gy+1,gx)   m /= Wall && pm == Normal = Move id U
                              | cx > gx && pieceCoords (gy+1,gx+2) m /= Wall && pm == Normal = Move id D
                              | cy < gy || cy > gy && pm == Normal = verticalPlayChase pu pd pl pr dv id
                              | cx < gx || cx > gx && pm == Normal = horizontalPlay pu pd pl pr id dv Alive
                              | pm == Mega = bestPlayScatter (gx,gy) id lp m
                              | otherwise = Move id R
              where
                   (cx,cy) = closestPacman lp (gx,gy) (px,py)
                   (px,py) = firstPacman lp 
                   pm = getPacMode lp (px,py)
                   pl = pieceCoords (gy,gx+1)   m -- Left Piece
                   pr = pieceCoords (gy+2,gx+1) m -- Right Piece
                   pu = pieceCoords (gy+1,gx)   m -- Up Piece
                   pd = pieceCoords (gy+1,gx+2) m -- Down Piece
                   dv = gx - cx                   -- Diference between the height of ghost and the closest pacman
                   dc = gy - py                   -- The length between the pacman and the closest ghost
                   ptC = getColumn m gx (cx,cy)   -- Gets a little part of one specific corridor

-- | Makes the best vertical play for the Ghost when ghosMode is Alive
verticalPlayChase :: Piece -> Piece -> Piece -> Piece -> Int -> Int -> Play
verticalPlayChase pu pd pl pr dv id | dv < 0 && pd /= Wall = Move id D
                                    | dv > 0 && pu /= Wall = Move id U
                                    | otherwise = horizontalPlay pu pd pl pr id dv Alive 

-- | Makes the best horizontal play for a Ghost (or a Pacman when used in Tarefa6) when given the ID of the player
horizontalPlay :: Piece -> Piece -> Piece -> Piece -> Int -> Int  -> GhostMode-> Play
horizontalPlay pu pd pl pr id dv gm | pl /= Wall = Move id L
                                    | pr /= Wall = Move id R
                                    | dv < 0 && pd /= Wall && gm == Alive = Move id D
                                    | dv > 0 && pu /= Wall && gm == Alive = Move id U 
                                    | dv < 0 && pu /= Wall && gm == Dead = Move id U
                                    | otherwise = Move id D

-- | Analyzes what Pacman is closer the Ghost and decides what play to do based on the coordinates of the Ghost and the closest Pacman when the ghostMode is Dead
scatterMode :: State -> Int -> Play
scatterMode (State m (Ghost (GhoState (i,(gx,gy),_,_,_,_) _):xs) le) id | id == i   = bestPlayScatter (gx,gy) id xs m
                                                                        | otherwise = scatterMode (State m xs le) id
scatterMode (State m (p:ps) le) id = scatterMode (State m (ps ++ [p]) le) id

-- | Makes the best play for a Ghost is in Dead ghostMode 
bestPlayScatter :: (Int,Int) -> Int -> [Player] -> Maze -> Play
bestPlayScatter (gx,gy) id lp m | closeCorner m (gx,gy)  = playCorner (gx,gy) (px,py) id
                                | cy < gy && pieceCoords (gy+2,gx+1) m /= Wall = Move id R
                                | cy > gy && pieceCoords (gy,gx+1)   m /= Wall = Move id L
                                | cx < gx && pieceCoords (gy+1,gx+2) m /= Wall = Move id D
                                | cx > gx && pieceCoords (gy+1,gx)   m /= Wall = Move id U
                                | cy < gy || cy > gy = verticalPlayScatter pu pd pl pr dv id
                                | cx < gx || cx > gx = horizontalPlay pu pd pl pr id dv Dead
              where
                   (cx,cy) = closestPacman lp (gx,gy) (px,py)
                   (px,py) = firstPacman lp
                   pl = pieceCoords (gy,gx+1)   m -- Left Piece
                   pr = pieceCoords (gy+2,gx+1) m -- Right Piece
                   pu = pieceCoords (gy+1,gx)   m -- Up Piece
                   pd = pieceCoords (gy+1,gx+2) m -- Down Piece
                   dv = gx - cx                 -- Diference between the height of ghost and the closest pacman 
                   cC = cornersCoords m 

-- | Given a maze and the coordinates of player, checks if that player is near a corner of the given maze
closeCorner :: Maze -> Coords -> Bool
closeCorner m (x,y) | elemsCoords [0,1,2] (filter (<=2) (map (distanceCoords (x,y)) cc)) = True
                    | otherwise = False
                where
                  cc = cornersCoords m


-- | Gets the coordinates of the corners of the maze
cornersCoords :: Maze -> [Coords]
cornersCoords m = [(0,0),(0,lc),(lh,0),(lh,lc)]
        where
          lc = length (head m) - 2
          lh = length m - 2                  

-- | Makes the best vertical play for the Ghost in Dead ghostMode
verticalPlayScatter :: Piece -> Piece -> Piece -> Piece -> Int -> Int  -> Play
verticalPlayScatter pu pd pl pr dv id | dv < 0 && pu /= Wall = Move id U
                                      | dv > 0 && pd /= Wall = Move id D
                                      | otherwise = horizontalPlay pu pd pl pr id dv Dead 



-- | Gives the coordinates of the first Pacman of a list of players
firstPacman :: [Player] -> Coords
firstPacman [] = (0,0)
firstPacman (Pacman (PacState (_,(px,py),_,_,_,_) _ _ _):xs) = (px,py)
firstPacman ( _ : xs) = firstPacman xs

-- | Verifies which is the closest Pacman to a Ghost
closestPacman :: [Player] -> Coords -> Coords -> Coords
closestPacman [] _ (cx,cy) = (cx,cy)
closestPacman (Pacman (PacState (_,(px,py),_,_,_,_) _ _ _):xs) (gx,gy) (cx,cy) | od >= nd  = closestPacman xs (gx,gy) (px,py)
                                                                               | otherwise = closestPacman xs (gx,gy) (cx,cy)
                      where
                           nd = distanceCoords (gx,gy) (px,py) -- new distance
                           od = distanceCoords (gx,gy) (cx,cy) -- old distance
closestPacman ( _ : xs) (gx,gy) (cx,cy) = closestPacman xs (gx,gy) (cx,cy)


-- | Calculates distance between a Pacman and the closest Ghost using Taxicab Geometry
distanceCoords :: Coords -> Coords -> Int
distanceCoords (px,py) (gx,gy) = abs (px - gx) + abs (py - gx)


-- | Gets the coordinates of the Ghost house
houseCoords :: Maze -> [Coords]
houseCoords [] = []
houseCoords m@(c:cs) | odd l = [(x-2,y),(x-2,y+1),(x-2,y+2),(x-1,y),(x-1,y+1),(x-1,y+2),(x,y-2),(x,y-1),(x,y),(x,y+1),(x,y+2),(x,y+3),(x,y+4)]
                     | otherwise = [(x-2,y-1),(x-2,y),(x-1,y-1),(x-1,y),(x,y-3),(x,y-2),(x,y-1),(x,y),(x,y+1),(x,y+2)]
      where
        (x,y) = newCoordsGhost m
        l = length c

-- | Makes the best play when the Ghost is inside the Ghost house
playHouse :: Piece -> Int -> Int -> Int -> Int -> Coords -> [Coords] -> Play
playHouse pu dp dv dvp id gc hc | elem gc ohc && dvp > 0 = Move id U
                                | elem gc ohc && dp < 0 = Move id R
                                | elem gc ohc = Move id L
                                | pu == Wall && dv < 0 = Move id R
                                | pu == Wall && dv > 0 = Move id L
                                | otherwise = Move id U
                      where
                        x1 = fst (head hc)
                        ohc = outsidehouse hc x1

-- | Verifies if there's a Wall on a list of Pieces
haveWalls :: [Piece] -> Bool
haveWalls [] = True
haveWalls p = elem Empty p || elem (Food Big) p || elem (Food Little) p

-- | Get the list of pieces on the column of where the Ghost is
getColumn :: Maze -> Int -> Coords -> [Piece]
getColumn m px (ox,oy) = getPart (mt !! oy) px ox           
            where
              mt = transposeMaze m

-- | Gets a part of the column of pieces where the opponent (Ghost if the player is a Pacman, Pacman if the player is a Ghost) is, with that part being located between the the height of the Player and the height the opponent 
getPart :: Corridor -> Int -> Int -> Corridor
getPart [] _ _ = []
getPart _ 0 0  = []
getPart (x:xs) 0 ox = x : getPart xs 0 (ox-1)
getPart (x:xs) px 0 = x : getPart xs (px-1) 0
getPart (x:xs) px ox = getPart xs (px-1) (ox-1) 

-- | Transpoze a maze (swaps columns with the corridors)
transposeMaze :: Maze -> Maze
transposeMaze [] = []
transposeMaze m | null (head m) = []
                | otherwise     = (map head m) : transposeMaze (map tail m) 

-- | Returns the coordinates of the entrance of the Ghost house when given a list of coordinates and an Int
outsidehouse :: [Coords] -> Int -> [Coords]
outsidehouse [] _ = []
outsidehouse (x:xs) n | fst x == n = x : outsidehouse xs n
                      | otherwise = []

-- | Verifies if a player is close to the tunnel 
closeTunnel :: Maze -> Coords -> Bool
closeTunnel m (x,y) | elemsCoords [0,1,2] (filter (<=2) (map (distanceCoords (x,y)) cc)) = True
                    | otherwise = False
                where
                  cc = getCoordsTunnel m

-- | Gets the coordinates of the tunnel
getCoordsTunnel :: Maze -> [Coords]
getCoordsTunnel m | odd l = [(div l 2,0),(div l 2,lc - 1)]
                  | even l = [(div l 2 - 1,0),(div l 2, 0),(div l 2 - 1, lc -1),(div l 2,lc - 1)]
            where
              l = length m
              lc = length (head m)

-- | Verifies if there is at least one element of the first list in the second list
elemsCoords :: [Int] -> [Int] -> Bool
elemsCoords [] _ = True
elemsCoords _ [] = False
elemsCoords (x:xs) cy | elem x cy = True
                      | otherwise = elemsCoords xs cy

-- | Makes plays when the Ghosts are close to the tunnel and they want to get close to the opponent
playTunnelChase :: Maze -> Int -> [Player] -> Coords -> Coords -> Piece -> Piece -> Play
playTunnelChase m id lp (gx,gy) (cx,cy) pr pl | dp > 0 && (gx,gy) == tunnelL && pm == Normal = Move id R 
                                              | dp < 0 && (gx,gy) == tunnelS && pm == Normal = Move id L
                                              | dt == 0 && gy > mm && pr /= Wall && pm == Normal = Move id R
                                              | dt == 0 && gy < mm && pl /= Wall && pm == Normal = Move id L
                                              | dt < 0 && pm == Normal = Move id D
                                              | dt > 0 && pm == Normal = Move id U
                                              | otherwise = bestPlayScatter (gx,gy) id lp m
                where
                  pm = getPacMode lp (cx,cy)
                  dp = gy - cy
                  mm = div (length (head m)) 2
                  tunnelL = last (getCoordsTunnel m)
                  tunnelS = head (getCoordsTunnel m)
                  dt = gx - fst tunnelL


-- | Verifies if there is a Pacman close to the tunnel
getCloseTunnelP :: Maze -> [Player] -> Coords
getCloseTunnelP _ [] = (0,0)
getCloseTunnelP m (Pacman (PacState (_,(px,py),_,_,_,_) _ _ _):xs) | closeTunnel m (px,py) = (px,py)
                                                                   | otherwise = getCloseTunnelP m xs
getCloseTunnelP m (_:ps) = getCloseTunnelP m ps

-- | Makes plays when the Players are close to the tunnel and they want to get away to the opponent
playTunnelScatter :: Maze -> Int -> Coords -> Coords -> Piece -> Piece -> Play
playTunnelScatter m id (gx,gy) (cx,cy) pr pl | gy == 0 = Move id R
                                             | gy == lc - 1 = Move id L
                                             | dp > 0 && pr /= Wall && dt /= 0 = Move id R
                                             | dp < 0 && pl /= Wall && dt /= 0 = Move id L
                                             | dv < 0 = Move id U
                                             | dv > 0 = Move id D
                where
                  dp = gy - cy
                  dv = gx - cx
                  mm = div (length (head m)) 2
                  tunnelL = last (getCoordsTunnel m)
                  tunnelS = head (getCoordsTunnel m)
                  dt = gx - fst tunnelL
                  lc = length (head m)

-- | Makes plays when a player is in the corner when given the coordinates of the opponent
playCorner :: Coords -> Coords -> Int  -> Play
playCorner (1,1) (x,y) id   | x < y     = Move id D
                            | otherwise = Move id R
playCorner (1,lc) (x,y) id  | x < y     = Move id D
                            | otherwise = Move id L
playCorner (lh,1) (x,y) id  | x < y     = Move id U
                            | otherwise = Move id R
playCorner (lh,lc) (x,y) id | x < y     = Move id U
                            | otherwise = Move id L

-- | If more than one Ghost are on the same coordinates this function gives a different play to the first of those Ghosts on a list of players, so they don't overlap
differentPlay :: (Int,Int) -> Int -> [Player] -> Maze  -> GhostMode -> Play
differentPlay (gx,gy) id lp m Alive | cx < gx && pieceCoords (gy+1,gx)   m /= Wall = Move id U
                                    | cx > gx && pieceCoords (gy+1,gx+2) m /= Wall = Move id D
                                    | cy < gy && pieceCoords (gy,gx+1)   m /= Wall = Move id L
                                    | cy > gy && pieceCoords (gy+2,gx+1) m /= Wall = Move id R
                                    | cx < gx || cx > gx = horizontalPlay pu pd pl pr id dv Alive
                                    | cy < gy || cy > gy = verticalPlayChase pu pd pl pr dv id
              where
                   (cx,cy) = closestPacman lp (gx,gy) (px,py)
                   (px,py) = firstPacman lp 
                   pl = pieceCoords (gy,gx+1)   m -- Left Piece
                   pr = pieceCoords (gy+2,gx+1) m -- Right Piece
                   pu = pieceCoords (gy+1,gx)   m -- Up Piece
                   pd = pieceCoords (gy+1,gx+2) m -- Down Piece
                   dv = gx - cx                   -- Diference between the height of ghost and the closest pacman
differentPlay (gx,gy) id lp m Dead | cx < gx && pieceCoords (gy+1,gx+2) m /= Wall = Move id D
                                   | cx > gx && pieceCoords (gy+1,gx)   m /= Wall = Move id U
                                   | cy < gy && pieceCoords (gy+2,gx+1) m /= Wall = Move id R
                                   | cy > gy && pieceCoords (gy,gx+1)   m /= Wall = Move id L
                                   | cx < gx || cx > gx = horizontalPlay pu pd pl pr id dv Dead
                                   | cy < gy || cy > gy = verticalPlayScatter pu pd pl pr dv id
              where
                   (cx,cy) = closestPacman lp (gx,gy) (px,py)
                   (px,py) = firstPacman lp
                   pl = pieceCoords (gy,gx+1)   m -- Left Piece
                   pr = pieceCoords (gy+2,gx+1) m -- Right Piece
                   pu = pieceCoords (gy+1,gx)   m -- Up Piece
                   pd = pieceCoords (gy+1,gx+2) m -- Down Piece
                   dv = gx - cx                 -- Diference between the height of ghost and the closest pacman 

-- | Given a list of players and the coordinates of a player returns the PacMode of the player
getPacMode :: [Player] -> Coords -> PacMode
getPacMode ((Pacman (PacState (i,(x,y),v,o,p,l) t m pm)):xs) (px,py) | px == x && py == y = pm
                                                                     | otherwise = getPacMode xs (px,py)
getPacMode (_:xs) c = getPacMode xs c
{- |

= Introduction of the Task

This is the first task of the second phase.
On this task we had to create the function passTime that moves every player based on their orientation.

= Objectives of the task:

1- Every player on the list of players must move after a certain number of interactions.

2- Apply the main function of Tarefa2 (play function) to every player.

3- Change the Mouth of the Pacmans when the number of interactions is odd.

4- Change the PacMode and the GhostMode of every player on the list of players when the time of Mega ends,
   if the time of PacMode Mega does not end, the time of Mega must be reduced, based on the number of 
   interactions.

= How we solved these issues?

1- We made two functions megaEnd and megaEndPlayers that given the number of steps check if the time of
   PacMode Mega will end after ocurring all the given steps.

2- We started working on the main function of the task, passTime, and made it so, that if the number of 
   interactions is higher or equal to 2 it will evoke itself recursively but the number of steps will be 
   reduced twice. In this case, it will check if in the middle of the two interactions, the time of Pacmode
   Mega will end using the function megaEnd with two steps.

2.1- In the case where megaEnd returns True we created a function named changeModes that changes the
     player Modes.

2.2- On the other cases it will reduce the time of Mega two times.

3- When the number of interactions is equal to 1 we made passTime do either:

3.1- In the case where megaEnd returns True we created a function named changeModes that changes the
     player Modes, and it will also change the Mouth of the Pacmans by evoking a function that is called
     changeMouthState.

3.2- On the other cases it will reduce the time of Mega once and it will also change the Mouth of the
     Pacmans through changeMouthState.

4- The function passTime after doing the points 2 and 3 will evoke the function playPasstime by giving the
   state after the changes, the minimum ID of the list of players and the number 1 or 2, it will depend like
   we mentioned before if the number of interactions is higher than or equal to 2 or equal to 1.

5- We created a function named playPassTime that will move every player one or two steps, given by the main
   function of the task.

5.1 - If the number of steps is two it will make two times the velocity the play for the ID given, using the
      function playApply that applies n times the play function defined on Tarefa2. After this playPassTime
      will evoke itself recursively by adding 1 to the ID, maintaining the number of steps, 2 on this case.

5.2 - When the number of steps is one it will do the same thing as when the number of steps is 2, but it will
      not apply the play for players with fractional velocity, and the number of times that it will make the
      play for players with Int velocity will be the same number as the velocity .

5.3 - When the ID given is higher than the maximum ID of the player list, the function will give the same
      State, as the one given.

6- When the number of steps is 0 it will give the same State as the one given.

7- We created auxiliary functions throughout the task to give us some information about specific player
   attriutes of a player with a given ID on a player list. 

8- We added to the code the function passTimeFractional that will be called on Main in a specific case and
   it does the same thing as passtime, but for players with fractional velocities.

= Discussion and Conclusion

This task was a bit confusing but when we understood the instructions, it became clear and we managed to
complete the task without many issues.
We could have done this task with simpler code, but in the end we completed our established goals so we 
decided to advance on the project instead of optimizing the code to save time.
We enjoyed this task since it let us play our game for the first time in the terminal.

-}



-- | Default delay time
defaultDelayTime = 250 -- 250 ms

-- | Main function of the task
passTime :: Int -> State -> State
passTime 0  s = s
passTime st s | st >= 2 && megaEnd s 2 = passTime (st-2) $ playPassTime (changeModes s) i 2
              | st >= 2                = passTime (st-2) $ playPassTime (reduceTimeMega $ reduceTimeMega s) i 2
              | megaEnd s 1            = playPassTime (changeMouthState $ changeModes s) i 1
              | otherwise              = playPassTime (changeMouthState $ reduceTimeMega  s) i 1
          where
            i  = minIDState s 

-- | Makes the movement for all players (Pacmans and Ghosts) on the State
playPassTime :: State -> Int -> Int -> State
playPassTime (State maze [] le) i _ = State maze [] le
playPassTime (State maze lp le) i 1 | i <= maxID lp 0 && intElemList v generateIntList = playPassTime (playApply (State maze lp le) v i) (i+1) 1
                                    | i <= maxID lp 0 = playPassTime (State maze lp le) (i+1) 1
                                    | otherwise       = (State maze lp le)
                    where           v = getVelocity lp i  
playPassTime (State maze lp le) i 2 | i <= maxID lp 0 = playPassTime (playApply (State maze lp le) (2*v) i) (i+1) 2
                                    | otherwise       = State maze lp le
                    where           v = getVelocity lp i

-- | Calculates how many times we need to apply the function play from Tarefa 2
playApply :: State -> Double -> Int -> State 
playApply s 0  _  = s    
playApply (State maze lp le) nv id = playApply (play (Move id (getIdOrientation lp id)) (State maze lp le)) (nv-1) id

-- | Gets the highest ID on a list of players
maxID :: [Player] -> Int -> Int
maxID [] id = id
maxID (Pacman (PacState (id,(_,_),_,_,_,_) _ _ _):xs) i | id > i    = maxID xs id
                                                        | otherwise = maxID xs i
maxID (Ghost  (GhoState (id,(_,_),_,_,_,_) _):xs) i | id > i    = maxID xs id
                                                    | otherwise = maxID xs i

-- | Gets the value of the velocity on the state of one player when given the ID of that player 
getVelocityState :: State -> Int -> Double
getVelocityState (State m lp le) id = getVelocity lp id

-- | Gets the value of the velocity of a Player with a given ID on a list of Players 
getVelocity :: [Player] -> Int -> Double
getVelocity [] _ = 0
getVelocity (Pacman (PacState (id,(_,_),v,_,_,_) _ _ _):xs) i | i == id   = v
                                                              | otherwise = getVelocity xs i
getVelocity (Ghost  (GhoState (id,(_,_),v,_,_,_) _):xs) i | i == id   = v
                                                          | otherwise = getVelocity xs i

-- | Gets the value of the orientation of a Player with a given ID on a list of Players
getIdOrientation :: [Player] -> Int -> Orientation
getIdOrientation [] _ = Null
getIdOrientation (Pacman (PacState (id,(_,_),_,o,_,_) _ _ _):xs) i | i == id = o
                                                                   | otherwise = getIdOrientation xs i
getIdOrientation (Ghost  (GhoState (id,(_,_),_,o,_,_) _):xs) i | i == id = o
                                                               | otherwise = getIdOrientation xs i

-- | Gets the orientation on the State of one player given its own id 
getIdOState :: State -> Int -> Orientation
getIdOState (State maze lp le) id = getIdOrientation lp id

-- | Checks if PacMode Mega is going to end given a state and the number of steps
megaEnd :: State -> Int -> Bool
megaEnd (State _ pl _) st = megaEndPlayers pl st

-- | Verifies if a Pacman is ending Mega mode given and the number of steps 
megaEndPlayers :: [Player] -> Int -> Bool
megaEndPlayers [] _ = False
megaEndPlayers (Pacman (PacState _ t _ pm):xs) st | pm == Mega && t <= std = True
                                                  | otherwise  = megaEndPlayers xs st
                              where std = fromIntegral st
megaEndPlayers (x:xs) st = megaEndPlayers xs st

-- | Change the mouth of the pacmans in the state  
changeMouthState :: State -> State
changeMouthState (State m pl l) = State m (changeMouth pl) l

-- | Change the mouth of every Pacman  
changeMouth :: [Player] -> [Player]
changeMouth [] = []
changeMouth (Pacman (PacState p t Open pm):ps)   = Pacman (PacState p t Closed pm) : changeMouth ps
changeMouth (Pacman (PacState p t Closed pm):ps) = Pacman (PacState p t Open pm) : changeMouth ps
changeMouth (p:ps) = (p : changeMouth ps)

-- | Changes the modes of the Ghosts and the Pacmans when the PacMode Mega ends
changeModes :: State -> State
changeModes (State m pl l) = State m (changePacMode (changeGhostAlive pl)) l

-- | Reduce the time of PacMode mega
reduceTimeMega :: State -> State
reduceTimeMega (State m pl l) = State m (map reduceTimeMegaPlayer pl) l

-- | Changes the Pacmode from Mega to Normal when the time of PacMode Mega ends
changePacMode :: [Player] -> [Player]
changePacMode [] = []
changePacMode (Pacman (PacState p t mm Mega):xs) = Pacman (PacState p 0 mm Normal)   : changePacMode xs
changePacMode (x:xs) = x : changePacMode xs 

-- | Auxiliary function of reduceTimeMega
reduceTimeMegaPlayer :: Player -> Player
reduceTimeMegaPlayer (Pacman (PacState p t mm Mega)) = Pacman (PacState p (t-0.25) mm Mega) 
reduceTimeMegaPlayer x = x 

-- | Changes the ghostMode from Dead to Alive when Pacman has ended is time of PacMode Mega
changeGhostAlive :: [Player] -> [Player]
changeGhostAlive [] = []
changeGhostAlive (Ghost(GhoState (id,(x,y),v,o,p,l) Dead) :xs) = (Ghost (GhoState (id,(x,y),v*2,o,p,l) Alive)) :  changeGhostAlive xs   
changeGhostAlive (p:ps) = p : changeGhostAlive ps

-- | Gets the minimum ID of the players on a State
minIDState :: State -> Int
minIDState (State m lp le) = minID lp (maxID lp 0)

-- | Gets the minimum ID of the list of players
minID :: [Player] -> Int -> Int
minID [] id = id
minID (Pacman (PacState (id,(_,_),_,_,_,_) _ _ _):xs) i | id <= i = minID xs id
                                                        | otherwise = minID xs i
minID (Ghost  (GhoState (id,(_,_),_,_,_,_) _):xs) i | id <= i = minID xs id
                                                    | otherwise = minID xs i

-- | Generates a list with every integer
generateIntList :: [Integer]
generateIntList = [0 ..]

-- | Checks if the velocity of the player is an integer
intElemList :: Double -> [Integer] -> Bool
intElemList _ [] = False
intElemList n (x:xs) | n == xin = True
                     | n < xin = False
                     | otherwise = intElemList n xs
    where xin = fromIntegral x


-- | This is the passTime funtion for players with fracional velocity  
passTimeFracional :: Int -> State -> State
passTimeFracional n s@(State m lp le) = playTimeFracional n s 0 (maxID lp 0)

-- | Applies the play for every player that has fracional velocity
playTimeFracional :: Int -> State -> Int -> Int -> State
playTimeFracional n s@(State maze lp@(Ghost (GhoState (id,(x,y),v,o,p,l) gm):xs) le) i idm | i > idm = s
                                                                                           | intElemList v generateIntList && i == id = playTimeFracional n s (i+1) idm
                                                                                           | i == id = playTimeFracional n (playApply s nv i) (i+1) idm
                                                                                           | otherwise =  playTimeFracional n (State maze (xs ++ [Ghost (GhoState (id,(x,y),v,o,p,l) gm)]) le) i idm
                                                                            where
                                                                              nv = fromIntegral n

playTimeFracional n s@(State maze lp@(Pacman (PacState (id,(x,y),v,o,p,l) t m pm) :xs) le) i idm | i > idm = s
                                                                                                 | intElemList v generateIntList && i == id = playTimeFracional n s (i+1) idm
                                                                                                 | i == id = playTimeFracional n (playApply s nv i) (i+1) idm
                                                                                                 | otherwise =  playTimeFracional n (State maze (xs ++ [Pacman (PacState (id,(x,y),v,o,p,l) t m pm)]) le) i idm 
                                                                                      where
                                                                                        nv = fromIntegral n                                              
{- |

= Introduction of the task:

This task consists of compacting a maze. A compact maze is a way to understand easily the maze, as it becomes
a list with it's elements being tuples preceded by a constructor named "Instruct" if a corridor does not repeat
itself, if it repeats, instead of "Instruct [tuples]", it will show as "Repeat n" with n being the number of
the corridor it repeats. The tuples mentioned are of form (Int,Piece), with the Int being the number of times
the Piece repeats itself consecutively on a corridor.

= Objectives of the task:

1- Verify if a corridor is repeated.
2- Transform corridors into an Instruct.


= How we solved these issues?

1- We converted a corridor into a list of tuples, where the tuples are (1,Piece).

2- We created the samePiece function that receives the list of tuples mentioned before and if there are two 
   tuples with the same piece the function sums both Ints.

3- We created the compactAllMaze function that converts a maze into an Instructions.

4- After doing the three previous points for every corridor, we created the repeatCorridor function that 
   receives the instructions and analyses if there are any Intructs that repeat.

= Discussion and Conclusion

At this task we could have used higher order functions such as foldr or map, but we were not familiar with
this type of programming since at the time it were just starting to learn these functions and we choose to
not use them, instead of not knowing what to do.
We did not enjoy this task as much, as we still do not really understand the purpose of compacting mazes.


-}



