       ]

-- * Functions used to generate the Maze

-- ** Functions given by the professors

-- | Given a seed returns a list of n integer randomly generated
--
generateRandoms :: Int -> Int -> [Int]
generateRandoms n seed = let gen = mkStdGen seed -- creates a random generator
                         in take n $ randomRs (0,99) gen -- takes the first n elements from an infinite series of random numbers between 0-9

-- | Given a seed returns an integer randomly generated
randomNumber :: Int -> Int
randomNumber seed = head $ generateRandoms 1 seed

-- ** Funtions we made

-- ** Funtions made to build the ghost house

-- | Decides the dimension of the ghost house if the x is odd or even 
buildHouse :: Int -> Int -> Int-> [Corridor]
buildHouse x y s| odd x = buildHouseOdd x y s
                | otherwise = buildHouseEven x y s

-- | Builds the corridors of the ghost house including the tunnel if the y (maze height) is odd or even and x (maze length) is odd
buildHouseOdd :: Int-> Int -> Int-> [Corridor]
buildHouseOdd x y s = if (odd y) then [[Wall]  ++ parteCorridorgenerate x s     ++ [Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty]         ++ parteCorridorgenerate x (s+5) ++ [Wall],
                                       [Wall]  ++ parteCorridorgenerate x (s+1) ++ [Empty, Wall, Wall, Wall, Empty, Empty, Empty, Wall, Wall, Wall, Empty]     ++ parteCorridorgenerate x (s+6) ++ [Wall],
                                       [Empty] ++ parteCorridorgenerate x (s+2) ++ [Empty, Wall, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Wall, Empty] ++ parteCorridorgenerate x (s+7) ++ [Empty],
                                       [Wall]  ++ parteCorridorgenerate x (s+3) ++ [Empty, Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall,Empty]         ++ parteCorridorgenerate x (s+8) ++ [Wall],
                                       [Wall]  ++ parteCorridorgenerate x (s+4) ++ [Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty]         ++ parteCorridorgenerate x (s+9) ++ [Wall]]  
-- This else is for when y is even
                      else             [[Wall]  ++ parteCorridorgenerate x s     ++ [Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty]         ++ parteCorridorgenerate x (s+5) ++ [Wall],
                                        [Wall]  ++ parteCorridorgenerate x (s+1) ++ [Empty, Wall, Wall, Wall, Empty, Empty, Empty, Wall, Wall, Wall, Empty]     ++ parteCorridorgenerate x (s+6) ++ [Wall],
                                        [Empty] ++ parteCorridorgenerate x (s+2) ++ [Empty, Wall, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Wall, Empty] ++ parteCorridorgenerate x (s+7) ++ [Empty],
                                        [Empty] ++ parteCorridorgenerate x (s+3) ++ [Empty, Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall,Empty]         ++ parteCorridorgenerate x (s+8) ++ [Empty],
                                        [Wall]  ++ parteCorridorgenerate x (s+4) ++ [Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty]         ++ parteCorridorgenerate x (s+9) ++ [Wall]]        

-- | Builds the corridors of the ghost house house including the tunnel if the y (maze height) is odd or even and x (maze length) is even
buildHouseEven :: Int-> Int -> Int->[Corridor]
buildHouseEven x y s = if (odd y) then [[Wall]  ++ parteCorridorgenerate x s     ++ [Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty]        ++ parteCorridorgenerate x (s+5) ++ [Wall],
                                        [Wall]  ++ parteCorridorgenerate x (s+1) ++ [Empty, Wall, Wall, Wall, Empty, Empty, Wall, Wall, Wall, Empty]     ++ parteCorridorgenerate x (s+6) ++ [Wall],
                                        [Empty] ++ parteCorridorgenerate x (s+2) ++ [Empty, Wall, Empty, Empty, Empty, Empty, Empty, Empty, Wall, Empty] ++ parteCorridorgenerate x (s+7) ++ [Empty],
                                        [Wall]  ++ parteCorridorgenerate x (s+3) ++ [Empty, Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall,Empty]        ++ parteCorridorgenerate x (s+8) ++ [Wall],
                                        [Wall]  ++ parteCorridorgenerate x (s+4) ++ [Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty]        ++ parteCorridorgenerate x (s+9) ++ [Wall]]  
-- This else is for when y is even
                      else             [[Wall]  ++ parteCorridorgenerate x s     ++ [Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty]         ++ parteCorridorgenerate x (s+5) ++ [Wall],
                                        [Wall]  ++ parteCorridorgenerate x (s+1) ++ [Empty, Wall, Wall, Wall, Empty, Empty, Wall, Wall, Wall, Empty]      ++ parteCorridorgenerate x (s+6) ++ [Wall],
                                        [Empty] ++ parteCorridorgenerate x (s+2) ++ [Empty, Wall, Empty, Empty, Empty, Empty, Empty, Empty, Wall, Empty]  ++ parteCorridorgenerate x (s+7) ++ [Empty],
                                        [Empty] ++ parteCorridorgenerate x (s+3) ++ [Empty, Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall,Empty]         ++ parteCorridorgenerate x (s+8) ++ [Empty],
                                        [Wall]  ++ parteCorridorgenerate x (s+4) ++ [Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty,Empty]         ++ parteCorridorgenerate x (s+9) ++ [Wall]]        
-- *** Auxiliary functions
-- | Generates Corridores that start and finish with a wall piece
generateCorridor :: Int -> Int -> Corridor
generateCorridor 0 seed = []
generateCorridor c seed = [Wall] ++ convertCorridor(generateRandoms (c-2) seed) ++ [Wall]

-- Builds the corridor section between the wall and the ghost house
parteCorridorgenerate :: Int-> Int -> Corridor
parteCorridorgenerate x s = convertCorridor(generateRandoms c s) 
   where
    c = div x 2- 6

-- ** Helpful funtions to convert data types
-- | Convert one integer number into one piece
convertPiece :: Int -> Piece
convertPiece x | x == 3 = Food Big
               | x >= 0 && x <70 = Food Little
               | x >= 70 && x <= 99 = Wall


-- | Convert a list of integers into a corridor
convertCorridor :: [Int] -> Corridor
convertCorridor l = map convertPiece l

-- | Convert a list of lists of integers into a maze
convertMaze :: [[Int]] -> Maze
convertMaze  l = map convertCorridor l

-- ** Funtions used to generate a valid maze

-- | Generates the roof and the floor of the maze
generateRoof :: Int -> Corridor
generateRoof 0 = []
generateRoof c = Wall : generateRoof (c-1)

-- | Main function of "Tarefa1.hs" using the functions generateCorridor and generateRoof this fuction generates a propper maze with walls and no tunnel limiting the play area in list form
generateMaze :: Int -> Int -> Int -> Maze
generateMaze x y seed = [generateRoof x] ++
                        (if(even y) then aux1 y1 x seed else aux3 y3 x seed) ++
                        buildHouse x y seed ++
                        (if(even y) then aux2 y2 x (seed+y1) else aux3 y3 x (seed+y3)) ++
                        [generateRoof x]
                where                     
                    y1 = div y 2 - 4
                    y2 = div y 2 - 3
                    y3 = div y 2 - 3

-- *** Auxiliary functions of generateMaze
aux1 :: Int -> Int -> Int -> [Corridor]
aux1 0 _ _ = []
aux1 y1 x seed = generateCorridor x seed : aux1 (y1-1) x (seed +1)

aux2 :: Int -> Int -> Int -> [Corridor]
aux2 0 _ _ = []
aux2 y2 x seed = generateCorridor x seed : aux2 (y2-1) x (seed +1)

aux3 :: Int -> Int -> Int -> [Corridor]
aux3 0 _ _ = []
aux3 y3 x seed = generateCorridor x seed : aux1 (y3-1) x (seed +1)    

-- | Shows a Maze with given 3 integers in IO() form. This function is based on the mazeGenerate function 
showMaze :: Int -> Int -> Int -> IO ()
showMaze x y s = putStrLn (printMaze (generateMaze x y s))
{- |
= General Introduction

Information

This in the summary of our work on the profect we made for "Laboratórios de Informática 1" where we
made a clone of the popular game Pacman using the Haskell programming language. The students were
divided into groups of two. Our group consists of José Carvalho (a94913) and Miguel Cidade Silva
(a97031) both students of the first year of "Mestrado Integrado em Engenharia Informática" at
University of Minho in the 2020-2021 academic year.
This project started on October 2020 and finished on January 2021.

Starting Point

The project was split into two phases, each containing three tasks. On the first phase we developed
the general cases that occur during a game of Pacman, created mazes, made plays and compacted mazes.
While during the second phase we were tasked with working with the passage of time through NCurses,
and we developed artificial inteligence for both types of players, Ghosts and Pacman.





=  First Task: Tarefa1

Introduction of the task:

On this stage of the project we were tasked with creating mazes that would be generated according
to length, height and a seed, with the seed being any Int number.

Objectives of the task:

A playable maze must have the following properties that became problems to solve:

1- Walls must surround the play area of the maze except a section in the middle which is the tunnel.

2- The tunnel must be alligned with the Ghost house, with it's size depending on the height of the 
   maze.

3- The maze must have a Ghost house on the middle where the Ghosts spawn and go after being eaten by
   a Pacman, similarly to the tunnel, the Ghost house changes it's size according to the length of the
   maze.

How we solved these issues?

1- Firstly, we know that the first and last lines of the maze are composed by Wall pieces only, so we
   created the generateRoof function that created corridors of a certain length only made by Walls.

2- To create the tunnel and the Ghost house in the correct positions we made the buildHouse functions
   that generate the tunnel and the Ghost house at the same time, according to the length and height
   of the maze.

3- To generate the rest of the maze we created the generateCorridor function that generates corridors
   for the maze that start and finish with Wall pieces with the middle being made by the combination
   of two functions, generateRandoms and convertCorridor, both given by the professors that generate
   a random corridor based on a seed.

The main function (generateMaze) of this task when given the length, the height and the seed (three 
Ints) starts by doing the first point (corridor made by walls) and generates a part of the maze, then
inserts the Ghost house and the tunnel (second point) and generates the rest of the maze inserting a 
last corridor only composed by Walls.






= Second Task: Tarefa2

Introduction of the task:

With maze genaration completed, now we had to do the functions that made the plays that would 
occur durring the game.

Objectives of the task:

1- The result of a play must move a player one unit in one of the four directions of two axis
(horizontal and vertical), Up, Down, Left and Right, never diagonally.

2- A player can't go through Walls.

3- When a player touches the tunnel, it must be teleported to the other side of the maze.

4- When a player moves to a Empty piece it just moves without changing any of it's attributes.

5- If a Pacman moves to a Little Food, he gains 1 point and makes the move.

6- If a Pacman moves to a Big Food, he gains 5 point, makes the move and changes pacMode to Mega if
   it was Normal with Mega time 10, if Pacman is already on Pacmode Mega before eating the Big Food, he
   just regains Mega time, which goes back to 10 and in both cases Ghosts change their GhostMode to dead.

7- When a Pacman and a Ghost collide, if Pacman is Normal, Pacman looses a life and nothing happens to
   the Ghost, otherwise, when Pacman is Mega, he eats the Ghost, gains 10 points and the Ghost changes
   the GhostMode to Alive and moves to the GhostHouse.

8- When the orientation of the play is different from the orientation of the player the player changes
   only it's orientation and does not move.

How we solved these issues?

1- When the orientation is different from the the player that has the same ID as the one in the play,
   it only changes orientation.

2- When the ID of the play is the same  as the one in the head of a list of players, and orientation
   of the play is the same as the player and it is Rigth: 
    2.1- When the vertical component of the player's coordinates is equal to the (length of the maze-1)
         he moves to the other side with it's vertical component updated to 0.

3- When the ID the play is the same  as the one in the head of a list of players, and orientation of
   the play is the same as the player and it is Left: 
    3.1- When the vertical component of the player's coordinates is equal to 0 he moves to the other side 
         with it's vertical component updated to the (length of the maze-1).

4- When the ID of the play is the same  as the one in the head of a list of players, for all orientations:
    4.1- For when Pacman moves to a piece where there is a Ghost or when a Ghost moves to piece where there
         is a Pacman, we created the touchGhostResult function that decides the outcome, based on the PacMode.
    4.2- For when the Pacman moves to a safe piece (without a Ghost), we created the placeResult function 
         that given the piece and the State with the Pacman at the head of the player list, makes the changes 
         to the Pacman's attributes based on what the piece is.
    4.3- For when a Ghost moves to a safe piece (without a Pacman) we created the placeResultGhost function that 
         if the piece is not a Wall the Ghost just changes it's coordinates without changing any other attribute. 

5- When the ID doesn't exist on a player list the main function of the task gives the starting State with
   no changes.






= Third Task: Tarefa3

Introduction of the task:

This task consists of compacting a maze. A compact maze is a way to understand easily the maze, as it becomes
a list with it's elements being tuples preceded by a constructor named "Instruct" if a corridor does not repeat
itself, if it repeats, instead of "Instruct [tuples]", it will show as "Repeat n" with n being the number of
the corridor it repeats. The tuples mentioned are of form (Int,Piece), with the Int being the number of times
the Piece repeats itself consecutively on a corridor.

Objectives of the task:

1- Verify if a corridor is repeated.
2- Transform corridors into an Instruct.


How we solved these issues?

1- We converted a corridor into a list of tuples, where the tuples are (1,Piece).

2- We created the samePiece function that receives the list of tuples mentioned before and if there are two 
   tuples with the same piece the function sums both Ints.

3- We created the compactAllMaze function that converts a maze into an Instructions.

4- After doing the three previous points for every corridor, we created the repeatCorridor function that 
   receives the instructions and analyses if there are any Intructs that repeat.






= Fourth Task: Tarefa4

Introduction of the Task

This is the first task of the second phase.
On this task we had to create the function passTime that moves every player based on their orientation.

Objectives of the task:

1- Every player on the list of players must move after a certain number of interactions.

2- Apply the main function of Tarefa2 (play function) to every player.

3- Change the Mouth of the Pacmans when the number of interactions is odd.

4- Change the PacMode and the GhostMode of every player on the list of players when the time of Mega ends,
   if the time of PacMode Mega does not end, the time of Mega must be reduced, based on the number of 
   interactions.

How we solved these issues?

1- We made two functions megaEnd and megaEndPlayers that given the number of steps check if the time of
   PacMode Mega will end after ocurring all the given steps.

2- We started working on the main function of the task, passTime, and made it so, that if the number of 
   interactions is higher or equal to 2 it will evoke itself recursively but the number of steps will be 
   reduced twice. In this case, it will check if in the middle of the two interactions, the time of Pacmode
   Mega will end using the function megaEnd with two steps.
   2.1- In the case where megaEnd returns True we created a function named changeModes that changes the
        player Modes.
   2.2- On the other cases it will reduce the time of Mega two times.

3- When the number of interactions is equal to 1 we made passTime do either:
   3.1- In the case where megaEnd returns True we created a function named changeModes that changes the
        player Modes, and it will also change the Mouth of the Pacmans by evoking a function that is called
        changeMouthState.
   3.2- On the other cases it will reduce the time of Mega once and it will also change the Mouth of the
        Pacmans through changeMouthState.

4- The function passTime after doing the points 2 and 3 will evoke the function playPasstime by giving the
   state after the changes, the minimum ID of the list of players and the number 1 or 2, it will depend like
   we mentioned before if the number of interactions is higher than or equal to 2 or equal to 1.

5- We created a function named playPassTime that will move every player one or two steps, given by the main
   function of the task.
   5.1 - If the number of steps is two it will make two times the velocity the play for the ID given, using the
         function playApply that applies n times the play function defined on Tarefa2. After this playPassTime
         will evoke itself recursively by adding 1 to the ID, maintaining the number of steps, 2 on this case.
   5.2 - When the number of steps is one it will do the same thing as when the number of steps is 2, but it will
         not apply the play for players with fractional velocity, and the number of times that it will make the
         play for players with Int velocity will be the same number as the velocity .
   5.3 - When the ID given is higher than the maximum ID of the player list, the function will give the same
         State, as the one given.

6- When the number of steps is 0 it will give the same State as the one given.

7- We created auxiliary functions throughout the task to give us some information about specific player
   attriutes of a player with a given ID on a player list. 

8- We added to the code the function passTimeFractional that will be called on Main in a specific case and
   it does the same thing as passtime, but for players with fractional velocities.






= Fifth Task: Tarefa5

Introduction of the Task

In this task we have to make plays for every Ghost on a player list, so that the Ghosts move on the game,
based on the current State.
This in a way makes it so that we created AI for the Ghosts, with that in mind there were many possibilities
to consider to try and make the most intelingent Ghosts possible, which ended up making our game a bit harder
than the original one, but the AI could be easily tweaked to become a bit less challenging to a player, making
the Ghosts make bad plays in certain cases allowing Pacman to move with more freedom.

Objectives of the task:


1- Decide what will be the best play to separate two or more Ghosts on the same position, so they don't
   overlap during their movement.

2- Decide what will be the best play if there is a Pacman and Ghost, both close to the tunnel.

3- Decide the best play for a Ghost when it is at the Ghost House.

4- Decide what will be the best play to do based on a Ghost's GhostMode and the Pacmans PacMode.

How we solved these issues?

1- We started by creating a function, sameCoords, that analyzes the player list and checks if the Ghost at 
   the head of the player list of a given state, is in the same position as another Ghost. When this happens,
   the Ghost that is on the head of the player list will make a play given by the function called differentPlay,
   that prioritizes the vertical play.

2- When the Ghost at the head of the player list is close to the tunnel and there is a Pacman also close to the 
   tunnel:
   2.1- If the Ghost is Alive, the play will be determined by the function playTunnelChase given the maze, the 
        ID of the Ghost, the tail of the player list, the coordinates of the Ghost and the Pacman close to the 
        tunnel and the pieces to the right and the left of the Ghost.
   2.2- If the Ghost is Dead the play will be determined by the function playTunnelScatter given the maze,
        the ID of the Ghost, the coordinates of the Ghost and the Pacman closest to the tunnel the pieces to 
        the right and the left of the Ghost.

3- When the Ghost is in the Ghost house the best play will be given by the function playHouse that when given
   the piece one vertical unit higher than the Ghost's coordinates, the difference between the horizontal
   and vertical components of the Ghost and the closest Pacman to it, the ID of the Ghost, the coordinates of
   the Ghost and the list of coordinates of the Ghost house.

4- If the conditions present on the previous points were not verified the play will be given by the function
   chaseMode that recieves the current State of the game and the ID of a Ghost.
   4.1- The function chaseMode will call another function named bestPlayChase that when given the coordinates
        of the Ghost, the ID of the Ghost, a list of players without the Ghost we want to move and the maze.  
        On this function, bestPlayChase, the play prioritizes horizontal plays rather than vertical ones, but
        if a part of the column where the closest Pacman is, with that part being located between the the height
        of the Player and the height the Pacman, is only composed by walls then the function will make a vertical 
        play. 


5- If the conditions present on the previous points were not verified the play will be given by the function
   scatterMode that recieves the current State of the game and the ID of a Ghost.
   5.1- The function scatterMode will call another function named bestPlayScatter that when given the coordinates
        of the Ghost, the ID of the Ghost, a list of players without the Ghost we want to move and the maze.  

6- If the head of the player list is a Pacman and there are Ghosts at the tail of the list, this Pacman will
   move to the end of the list.

7- When there is not any Ghost on the player list, the main function of the task retrieves an empty list.






= Sixth Task: Tarefa6

Introduction of the Task:

This was the last task that we were assigned, excluding the usage of gloss to make a graphical interface.
Here we were tasked with creating an artificial inteligence similar to the one on Tarefa5, but for a Pacman.
There were many scenarios we had to consider to try and make the most efficient AI possible.

Objectives of the task:

1- Get the bot go closer to Big Foods if there are no Ghosts to make it loose a life.

2- Make the best play when the bot is close to the tunnel.

3- Make the bot decide which will be the best play based on his PacMode.

4- Make it so the bot tries to eat Little Food until he is close to the Ghost and it might loose a life.


How we solved these issues?

1- If the ID given does not exist return Nothing

2- If there is a Ghost close to the tunnel and the Pacman is also close to tunnel:
   2.1- If his PacMode is Mega makes a play given by the function playTunnelMega which which needs the maze, 
        the ID of the Pacman, the coordinates of the Pacman, the coordinates of the Ghost closest to the tunnel,
        the pieces to right and the left of the Pacman in to work.
   2.2- If his PacMode is Normal makes the play given by the function playTunnelScatter (definied in Tarefa5) which 
        needs the maze, the ID of the Pacman, the coordinates of the Pacman, the coordinates of the ghost close to 
        the tunnel, he pieces to right and the left of the Pacman in order to work.

3- If the Pacman is closer to the Big Food than the closest Ghost to the Big Food makes the play returned by the 
   function playPacmanMega, that is given the coordinates of the Pacman, the coordinates of the Big Food, the ID of 
   the bot and the maze.

4- If the PacMode from the Pacman is Mega and the previous point were not verified he makes the play returned by the 
   function  playPacmanMega, that is given the coordinates of the Pacman, the coordinates of the closest Ghost to the
   Pacman, the ID of the bot and the maze.
   On this function, playPacmanMega, the play prioritizes horizontal plays rather than vertical ones, but
   if a part of the column where the closest Ghost is, with that part being located between the the height
   of the Player and the height the Ghost, is only composed by walls then the function will make a vertical play. 

5- In every case If the Orientation of the play is the same as the Pacman's return Nothing, otherwise Just the returns 
   the best play based on the previuos .
   conditions







